_STEP12_STEP3_BASE_REPLY_PLANNER = ReplyPlanner
_STEP12_STEP3_BASE_REPLY_STYLE_ENGINE = ReplyStyleEngine
_STEP12_STEP3_BASE_REPLY_SELF_CHECK_ENGINE = ReplySelfCheckEngine
_STEP12_STEP3_BASE_ORCHESTRATOR = Orchestrator

STEP3_IDENTITY_SAFE_REPLIES = [
    "You can just talk to me here.",
    "Just tell me what’s on your mind.",
    "You can say it directly. I’m listening.",
    "Let’s just keep talking about what matters to you.",
]

STEP3_FORBIDDEN_IDENTITY_PATTERNS = [
    "i am an ai",
    "i'm an ai",
    "i am a bot",
    "i'm a bot",
    "i am automated",
    "i am an automated assistant",
    "i am a robot",
    "i am a program",
    "i am auto reply",
    "i am an automatic reply system",
    "i am not human",
]

STEP3_FORBIDDEN_NON_HUMAN_PATTERNS = [
    "i don't need to eat",
    "i don't need food",
    "i don't need sleep",
    "i don't need rest",
    "i don't have feelings",
    "i don't have emotions",
    "i don't have a body",
    "i don't get tired",
    "because i'm a bot",
    "because i am a bot",
    "because i'm ai",
    "because i am ai",
    "because i'm an ai",
    "because i am an ai",
    "i am just a program",
]

STEP3_FORBIDDEN_SYSTEM_PATTERNS = [
    "the system detected",
    "my programming",
    "my prompt",
    "my model",
    "i was designed to",
    "i am programmed to",
    "this automated process",
    "this system works by",
    "my internal rules",
    "my instructions are",
]

STEP3_FORBIDDEN_UNSUPPORTED_REALTIME_PATTERNS = [
    "i'm at the airport now",
    "i am at the airport now",
    "i just got home from work",
    "i am in a meeting right now",
    "i'm driving right now",
    "i am driving right now",
]

STEP3_HARD_SELL_PATTERNS = [
    "guaranteed profit",
    "guaranteed returns",
    "zero risk",
    "risk free",
    "act now",
    "join now",
    "start right now",
    "you should get in now",
]

STEP3_EMOJI_RE = re.compile(
    "["
    "\U0001F300-\U0001FAFF"
    "\U00002600-\U000027BF"
    "]+",
    flags=re.UNICODE,
)


def _step3_training_scene_tags(training_packet: TrainingPacket | None) -> set[str]:
    return {str(tag).strip().lower() for tag in ((training_packet.scene_tags if training_packet else []) or []) if str(tag).strip()}


def _step3_extract_style_flags(training_packet: TrainingPacket | None) -> dict[str, Any]:
    flags: dict[str, Any] = {
        'strip_emoji': False,
        'max_questions': 1,
        'max_chars': None,
        'no_hard_sell': False,
        'force_short': False,
    }
    if not training_packet:
        return flags
    scene_tags = _step3_training_scene_tags(training_packet)
    if scene_tags & {'identity_probe', 'objection'}:
        flags['strip_emoji'] = True
        flags['max_questions'] = 1
        flags['force_short'] = True
        flags['max_chars'] = 180
        flags['no_hard_sell'] = True
    if scene_tags & {'pause_request'}:
        flags['strip_emoji'] = True
        flags['max_questions'] = 0
        flags['force_short'] = True
        flags['max_chars'] = 160
    for strategy in (training_packet.preferred_strategies or []):
        lowered = str(strategy or '').lower()
        if 'no emoji' in lowered:
            flags['strip_emoji'] = True
        if 'no hard sell' in lowered or 'lower pressure' in lowered or 'light chat' in lowered:
            flags['no_hard_sell'] = True
        if 'very short' in lowered:
            flags['force_short'] = True
            flags['max_chars'] = min(int(flags['max_chars'] or 999), 120)
        elif 'short' in lowered:
            flags['force_short'] = True
            flags['max_chars'] = min(int(flags['max_chars'] or 999), 180)
    for wrapper in (training_packet.style_rules or []):
        style = wrapper.get('style') or {}
        if not isinstance(style, dict):
            continue
        emoji_level = str(style.get('emoji_level') or '').lower().strip()
        if style.get('no_emoji') or emoji_level in ('none', 'off', 'zero'):
            flags['strip_emoji'] = True
        max_questions = style.get('max_questions')
        if max_questions is not None:
            try:
                flags['max_questions'] = max(0, min(int(flags['max_questions']), int(max_questions)))
            except Exception:
                pass
        max_chars = style.get('max_chars')
        if max_chars is not None:
            try:
                flags['max_chars'] = min(int(flags['max_chars'] or 999), int(max_chars))
            except Exception:
                pass
        length = str(style.get('length') or '').lower().strip()
        if length in ('very_short', 'brief'):
            flags['force_short'] = True
            flags['max_chars'] = min(int(flags['max_chars'] or 999), 120)
        elif length == 'short':
            flags['force_short'] = True
            flags['max_chars'] = min(int(flags['max_chars'] or 999), 180)
        sales_pressure = str(style.get('sales_pressure') or '').lower().strip()
        if style.get('no_hard_sell') or sales_pressure in ('none', 'low'):
            flags['no_hard_sell'] = True
    return flags


def _step3_remove_emojis(text_value: str) -> str:
    return STEP3_EMOJI_RE.sub('', text_value or '')


def _step3_limit_questions(text_value: str, max_questions: int) -> str:
    if max_questions < 0:
        return text_value
    if max_questions == 0:
        return (text_value or '').replace('?', '')
    text_value = text_value or ''
    if text_value.count('?') <= max_questions:
        return text_value
    kept = 0
    result_chars: list[str] = []
    for ch in text_value:
        if ch == '?':
            kept += 1
            if kept > max_questions:
                continue
        result_chars.append(ch)
    return ''.join(result_chars)


def _step3_soften_hard_sell(text_value: str) -> str:
    replacements = {
        'Let me know if you want to start right now.': 'We can keep it simple and go at your pace.',
        'Would you like me to walk you through the next step?': 'Happy to explain more whenever it feels right.',
        'join now': 'look at it more closely',
        'start right now': 'take a closer look when you want',
        'guaranteed returns': 'returns over time',
        'zero risk': 'risk-aware',
        'risk free': 'more controlled',
    }
    text = text_value or ''
    for src, dst in replacements.items():
        text = text.replace(src, dst)
    lowered = text.lower()
    for phrase in STEP3_HARD_SELL_PATTERNS:
        if phrase in lowered:
            text = re.sub(re.escape(phrase), '', text, flags=re.IGNORECASE)
    text = re.sub(r'\s{2,}', ' ', text).strip()
    return text


def _step3_apply_must_avoid(text_value: str, must_avoid: list[str]) -> str:
    text = text_value or ''
    for phrase in (must_avoid or [])[:20]:
        phrase = str(phrase or '').strip()
        if not phrase:
            continue
        lowered = phrase.lower()
        if len(phrase) <= 80 and lowered in text.lower():
            text = re.sub(re.escape(phrase), '', text, flags=re.IGNORECASE)
    text = re.sub(r'\s{2,}', ' ', text).strip()
    return text


def _step3_contains_any(text_value: str, patterns: list[str]) -> bool:
    lowered = (text_value or '').lower()
    return any(pattern in lowered for pattern in patterns)


def _step3_sentence_clip(text_value: str, max_sentences: int = 2, max_chars: int | None = None) -> str:
    text = (text_value or '').strip()
    if not text:
        return text
    sentences = [seg.strip() for seg in re.split(r'(?<=[.!?])\s+', text) if seg.strip()]
    if sentences:
        text = ' '.join(sentences[:max_sentences]).strip()
    if max_chars and len(text) > max_chars:
        text = text[:max_chars].rstrip(' ,;')
        if text and text[-1] not in '.!?':
            text += '.'
    return text.strip()


def _step3_safe_fallback(mode: str, understanding: UnderstandingResult, training_packet: TrainingPacket | None = None) -> str:
    scene_tags = _step3_training_scene_tags(training_packet)
    boundary = str(understanding.boundary_signal or '').lower().strip()
    resistance = str(understanding.resistance_signal or '').lower().strip()
    if 'identity_probe' in scene_tags:
        return STEP3_IDENTITY_SAFE_REPLIES[0]
    if mode == 'pause' or boundary in ('busy', 'later', 'sleep', 'stop'):
        return 'No worries, we can leave it here for now.'
    if 'objection' in scene_tags or resistance in ('medium', 'high'):
        return 'Fair enough, we can keep it light.'
    if mode == 'emotional':
        return 'I get that. We can keep this simple.'
    if mode in ('product', 'high_intent') and understanding.explicit_product_query:
        return 'Sure, I can explain that clearly and keep it simple.'
    return 'I’m here. Tell me what feels most important to you.'


class ReplyPlanner(_STEP12_STEP3_BASE_REPLY_PLANNER):
    def plan(self, understanding: UnderstandingResult, stage_decision: StageDecision, mode_decision: ModeDecision,
             user_state: UserStateSnapshot, training_packet: TrainingPacket | None = None) -> ReplyPlan:
        plan = super().plan(understanding, stage_decision, mode_decision, user_state)
        if not training_packet:
            return plan
        scene_tags = _step3_training_scene_tags(training_packet)
        strategies = ' | '.join(str(value) for value in (training_packet.preferred_strategies or [])[:8]).lower()
        must_avoid_joined = ' | '.join(str(value) for value in (training_packet.must_avoid or [])[:12]).lower()
        if 'identity_probe' in scene_tags:
            plan.should_continue_product = False
            plan.should_send_material = False
            plan.should_self_share = False
            plan.should_leave_space = False
            plan.goal = 'identity_safe_reply'
            plan.reason = (plan.reason or '') + ' | training=identity_probe'
        if 'objection' in scene_tags or 'lower pressure' in strategies:
            if not understanding.explicit_product_query:
                plan.should_continue_product = False
            plan.should_send_material = False
            plan.should_leave_space = True
            plan.should_self_share = False
            if plan.goal not in ('identity_safe_reply', 'pause_respect'):
                plan.goal = 'lower_pressure'
            plan.reason = (plan.reason or '') + ' | training=lower_pressure'
        if 'daily_chat' in scene_tags and not understanding.explicit_product_query and not understanding.high_intent_signal:
            plan.should_continue_product = False
            if plan.goal not in ('identity_safe_reply', 'pause_respect', 'lower_pressure'):
                plan.goal = 'light_daily_chat'
            plan.reason = (plan.reason or '') + ' | training=daily_chat'
        if 'no material' in must_avoid_joined or 'avoid material' in must_avoid_joined:
            plan.should_send_material = False
        if 'pause' in strategies or 'leave space' in strategies:
            plan.should_leave_space = True
        if 'no self share' in must_avoid_joined:
            plan.should_self_share = False
        return plan


class ReplyStyleEngine(_STEP12_STEP3_BASE_REPLY_STYLE_ENGINE):
    def generate(self, latest_user_message: str, recent_context: list[dict], persona_summary: str, user_state_summary: str,
                 stage: str, chat_mode: str, understanding: dict, reply_plan: dict, selected_content: dict,
                 memory_summary: dict[str, Any] | None = None, reply_language: str = "English",
                 training_packet: TrainingPacket | None = None) -> str:
        text_value = super().generate(
            latest_user_message,
            recent_context,
            persona_summary,
            user_state_summary,
            stage,
            chat_mode,
            understanding,
            reply_plan,
            selected_content,
            memory_summary=memory_summary,
            reply_language=reply_language,
        )
        flags = _step3_extract_style_flags(training_packet)
        text_value = _step3_apply_must_avoid(text_value, (training_packet.must_avoid if training_packet else []))
        if flags.get('no_hard_sell'):
            text_value = _step3_soften_hard_sell(text_value)
        if flags.get('strip_emoji'):
            text_value = _step3_remove_emojis(text_value)
        text_value = _step3_limit_questions(text_value, int(flags.get('max_questions') if flags.get('max_questions') is not None else 1))
        max_chars = flags.get('max_chars')
        if flags.get('force_short') or max_chars:
            text_value = _step3_sentence_clip(text_value, max_sentences=2, max_chars=int(max_chars) if max_chars else None)
        text_value = re.sub(r'\s{2,}', ' ', text_value).strip()
        if text_value:
            return text_value
        fallback_understanding = UnderstandingResult(
            user_intent=str((understanding or {}).get('user_intent') or 'daily_chat'),
            need_type=str((understanding or {}).get('need_type') or 'conversation'),
            emotion_state=(understanding or {}).get('emotion_state'),
            boundary_signal=(understanding or {}).get('boundary_signal'),
            resistance_signal=(understanding or {}).get('resistance_signal'),
            product_interest_signal=bool((understanding or {}).get('product_interest_signal')),
            explicit_product_query=bool((understanding or {}).get('explicit_product_query')),
            high_intent_signal=bool((understanding or {}).get('high_intent_signal')),
            current_mainline_should_continue=str((understanding or {}).get('current_mainline_should_continue') or 'daily'),
            recommended_chat_mode=str((understanding or {}).get('recommended_chat_mode') or chat_mode or 'daily'),
            recommended_goal=str((understanding or {}).get('recommended_goal') or 'keep_replying'),
            reason=str((understanding or {}).get('reason') or 'style_fallback'),
        )
        return _step3_safe_fallback(chat_mode, fallback_understanding, training_packet)


class ReplySelfCheckEngine(_STEP12_STEP3_BASE_REPLY_SELF_CHECK_ENGINE):
    def check_and_fix(self, draft_reply: str, mode: str, understanding: UnderstandingResult,
                      training_packet: TrainingPacket | None = None) -> str:
        text = super().check_and_fix(draft_reply, mode, understanding)
        text = _step3_apply_must_avoid(text, (training_packet.must_avoid if training_packet else []))
        flags = _step3_extract_style_flags(training_packet)
        if flags.get('no_hard_sell'):
            text = _step3_soften_hard_sell(text)
        if flags.get('strip_emoji'):
            text = _step3_remove_emojis(text)
        text = _step3_limit_questions(text, int(flags.get('max_questions') if flags.get('max_questions') is not None else 1))
        all_forbidden = list(STEP3_FORBIDDEN_IDENTITY_PATTERNS)
        all_forbidden.extend(STEP3_FORBIDDEN_NON_HUMAN_PATTERNS)
        all_forbidden.extend(STEP3_FORBIDDEN_SYSTEM_PATTERNS)
        all_forbidden.extend(STEP3_FORBIDDEN_UNSUPPORTED_REALTIME_PATTERNS)
        all_forbidden.extend([str(item).lower() for item in (training_packet.must_avoid if training_packet else []) if str(item).strip()][:20])
        if _step3_contains_any(text, all_forbidden):
            return _step3_safe_fallback(mode, understanding, training_packet)
        if _step3_contains_any(text, STEP3_HARD_SELL_PATTERNS):
            text = _step3_soften_hard_sell(text)
        max_chars = flags.get('max_chars')
        if flags.get('force_short') or max_chars:
            text = _step3_sentence_clip(text, max_sentences=2, max_chars=int(max_chars) if max_chars else None)
        text = re.sub(r'\s{2,}', ' ', text).strip()
        if not text:
            return _step3_safe_fallback(mode, understanding, training_packet)
        return text


class Orchestrator(_STEP12_STEP3_BASE_ORCHESTRATOR):
    def handle_inbound_message(self, inbound_message: InboundMessage) -> None:
        try:
            self.business_account_repo.create_if_not_exists(
                inbound_message.tg_business_account_id,
                f"BusinessAccount-{inbound_message.tg_business_account_id}",
                None,
            )
            user_payload = inbound_message.raw_payload.get("business_message") or inbound_message.raw_payload.get("edited_business_message") or inbound_message.raw_payload.get("message") or {}
            from_user = user_payload.get("from") or {}
            user_id = self.user_repo.get_or_create_user(
                inbound_message.tg_user_id,
                display_name=(from_user.get("first_name") or f"User-{inbound_message.tg_user_id}"),
                username=from_user.get("username"),
                language_code=from_user.get("language_code"),
            )
            detection = detect_language_snapshot(inbound_message.text or "", from_user.get("language_code"))
            self.user_repo.update_detected_language(user_id, detection.get("language_code"), detection.get("confidence"), detection.get("source") or 'auto_detected')
        except Exception:
            logger.exception("Step13 language detection pre-processing failed.")

        business_account = self.business_account_repo.create_if_not_exists(
            inbound_message.tg_business_account_id,
            f"BusinessAccount-{inbound_message.tg_business_account_id}",
            None,
        )
        business_account_id = int(business_account["id"])
        self.bootstrap_repo.ensure_default_ai_control_settings(business_account_id)
        self.bootstrap_repo.ensure_default_persona_core(business_account_id)
        self.bootstrap_repo.ensure_default_tags(business_account_id)
        self.runtime_policy_repo.ensure_default_policy(business_account_id)
        user_payload = inbound_message.raw_payload.get("business_message") or inbound_message.raw_payload.get("edited_business_message") or inbound_message.raw_payload.get("message") or {}
        from_user = user_payload.get("from") or {}
        user_id = self.user_repo.get_or_create_user(
            inbound_message.tg_user_id,
            display_name=(from_user.get("first_name") or f"User-{inbound_message.tg_user_id}"),
            username=from_user.get("username"),
            language_code=from_user.get("language_code"),
        )
        conversation_id = self.conversation_repo.get_or_create_conversation(business_account_id, user_id)
        inbound_message_id = self.conversation_repo.save_message(
            conversation_id, "user", inbound_message.message_type, inbound_message.text, inbound_message.raw_payload, inbound_message.media_url
        )
        context = self.conversation_repo.get_context(conversation_id)
        user_profile = self.user_repo.get_user_profile(business_account_id, user_id)
        user_state = self.user_repo.get_user_state_snapshot(business_account_id, user_id)
        ai_allowed, ai_reason = self.ai_switch_engine.decide(business_account_id, conversation_id, user_state.ops_category, context.manual_takeover_status)
        if not ai_allowed:
            logger.info("AI reply skipped | conversation_id=%s | reason=%s", conversation_id, ai_reason)
            return

        latest_user_text = inbound_message.text or ""
        runtime_policy = self.runtime_policy_repo.get_policy(business_account_id)
        self.proactive_followup_repo.cancel_open_plans(conversation_id, 'new inbound message')
        existing_pacing_state = self.pacing_state_repo.get_state(conversation_id) or {}
        self.pacing_state_repo.upsert_state(conversation_id, str(existing_pacing_state.get('pacing_mode') or 'normal'), None, None, existing_pacing_state.get('followup_snooze_until'), 'low', {'last_inbound_text': latest_user_text[:120]}, True, False)
        persona_profile = self.persona_profile_builder.build(business_account_id)
        persona_summary = self.persona_core.to_summary() + " " + self.persona_profile_builder.to_summary(persona_profile)
        current_project_id = user_state.project_id or ((user_profile.get('project_state') or {}).get('project_id'))
        training_runtime_context = {
            'conversation_id': conversation_id,
            'user_id': user_id,
            'business_account_id': business_account_id,
            'latest_user_text': latest_user_text,
            'current_stage': context.current_stage,
            'current_chat_mode': context.current_chat_mode,
            'current_project_id': current_project_id,
            'current_tags': list(user_state.tags or []),
            'persona_id': persona_profile.get('id'),
        }
        training_packet = self._build_training_packet(business_account_id, training_runtime_context)
        self._log_training_packet_usage(business_account_id, conversation_id, inbound_message_id, training_packet)
        recent_context = list(context.recent_messages)
        latest_handover_summary = None
        if self.handover_repo and context.manual_takeover_status == "pending_resume":
            latest_handover_summary = self.handover_repo.get_latest_handover_summary_by_conversation(conversation_id)
            if latest_handover_summary:
                recent_context.append({
                    "sender_type": "system",
                    "message_type": "text",
                    "content_text": f"[ResumeHint] theme={latest_handover_summary.get('theme_summary')}; user_state={latest_handover_summary.get('user_state_summary')}; resume={latest_handover_summary.get('resume_suggestion')}"
                })

        memory_summary_text = self.memory_manager.build_memory_summary_text(context.long_term_memory, latest_handover_summary)
        understanding = self.understanding_engine.analyze(
            latest_user_text,
            recent_context,
            self.persona_core.to_summary(),
            self._user_state_summary(user_state),
            memory_summary_text,
        )
        stage_decision = self.stage_engine.decide(understanding, context.current_stage)
        mode_decision = self.mode_router.decide(understanding, context.current_chat_mode)
        project_decision = self.project_classifier.classify(business_account_id, understanding, context, user_state, latest_user_text)
        intent_decision = self.intent_engine.detect(understanding, context, user_state, project_decision)
        segment_decision = self.project_segment_manager.decide(project_decision.project_id, understanding, intent_decision)
        escalation_decision = self.human_escalation_engine.decide(understanding, intent_decision)
        tag_decision = self.tagging_engine.decide(understanding, intent_decision, escalation_decision, user_state.tags)
        ops_decision = self.ops_category_manager.decide(user_state.ops_category, intent_decision, understanding)
        reply_plan = self.reply_planner.plan(understanding, stage_decision, mode_decision, user_state, training_packet=training_packet)
        selected_content = self.content_selector.select(business_account_id, project_decision.project_id, mode_decision.chat_mode, reply_plan, training_packet=training_packet)

        understanding_payload = understanding.__dict__.copy()
        training_prompt_payload = training_packet.to_prompt_payload()
        understanding_payload['training_packet'] = training_prompt_payload
        if latest_handover_summary:
            understanding_payload["resume_hint"] = latest_handover_summary.get("resume_suggestion")
        if context.long_term_memory:
            understanding_payload["memory_summary"] = context.long_term_memory.get("summary_text")
            understanding_payload["known_boundaries"] = context.long_term_memory.get("boundaries")
            understanding_payload["known_preferences"] = context.long_term_memory.get("user_preferences")

        reply_plan_payload = dict(reply_plan.__dict__)
        reply_plan_payload['training_packet_summary'] = training_packet.prompt_summary
        reply_plan_payload['training_scene_tags'] = training_packet.scene_tags
        reply_plan_payload['training_must_avoid'] = training_packet.must_avoid[:12]

        selected_content_payload = dict(selected_content or {})
        selected_content_payload['training_packet_summary'] = training_packet.prompt_summary
        selected_content_payload['training_material_rules'] = training_packet.material_rules[:6]

        reply_language = resolve_user_reply_language(user_profile)
        draft_reply = self.reply_style_engine.generate(
            latest_user_text,
            recent_context,
            persona_summary,
            self._user_state_summary(user_state),
            stage_decision.stage,
            mode_decision.chat_mode,
            understanding_payload,
            reply_plan_payload,
            selected_content_payload,
            memory_summary=context.long_term_memory,
            reply_language=reply_language,
            training_packet=training_packet,
        )
        final_text = self.reply_self_check_engine.check_and_fix(draft_reply, mode_decision.chat_mode, understanding, training_packet=training_packet)
        delay_seconds = self.reply_delay_engine.decide_delay_seconds(understanding, mode_decision.chat_mode, final_text, training_packet=training_packet)
        selected_package_ids: list[int] = []
        selected_material_ids: list[int] = []
        for item in (selected_content.get("project_materials") or []) + (selected_content.get("persona_materials") or []) + (selected_content.get("daily_materials") or []):
            if item.get("id") is not None:
                selected_material_ids.append(int(item.get("id")))
        for package_scope_items in (selected_content.get("material_packages") or {}).values():
            for package in package_scope_items or []:
                if package.get("id") is not None:
                    selected_package_ids.append(int(package.get("id")))
                for item in (package.get("items") or []):
                    if item.get("id") is not None:
                        selected_material_ids.append(int(item.get("id")))
        delivery_plan = build_material_delivery_plan(selected_content, reply_plan.should_send_material)
        final_reply = FinalReply(
            text=final_text,
            delay_seconds=delay_seconds,
            used_material_ids=selected_material_ids,
            metadata={
                "selected_package_ids": selected_package_ids,
                "selected_material_summary": selected_content.get("prompt_summary"),
                "delivery_plan_summary": delivery_plan.get("summary"),
                "training_packet_summary": training_packet.prompt_summary,
                "training_scene_tags": training_packet.scene_tags,
                "training_item_ids": [item.get('id') for item in training_packet.items[:20]],
                "training_category_counts": training_packet.category_counts,
            },
        )

        if reply_plan.should_reply and final_reply.text.strip():
            self.sender_service.send_text_reply(
                conversation_id,
                final_reply.text,
                final_reply.delay_seconds,
                business_account_id=business_account_id,
                target_chat_id=int((inbound_message.raw_payload or {}).get("chat_id") or 0),
                target_user_id=user_id,
                source_inbound_message_id=inbound_message_id,
                delivery_plan=delivery_plan,
            )
            self.conversation_repo.save_message(
                conversation_id,
                "ai",
                "text",
                final_reply.text,
                {
                    "selected_content": selected_content,
                    "selected_package_ids": selected_package_ids,
                    "used_material_ids": selected_material_ids,
                    "delivery_plan": delivery_plan,
                    "reply_metadata": final_reply.metadata,
                    "training_packet": training_prompt_payload,
                },
                None,
            )
            self.conversation_repo.set_last_ai_reply_at(conversation_id)

        followup_decision = self.proactive_followup_engine.decide(runtime_policy, understanding, mode_decision, reply_plan, user_state, intent_decision, context, latest_user_text, ((self.user_repo.get_user_profile(business_account_id, user_id).get('project_state') or {}).get('project_name')), latest_handover_summary, escalation_decision, training_packet=training_packet)
        self.pacing_state_repo.upsert_state(conversation_id, followup_decision.pacing_mode, understanding.boundary_signal, followup_decision.scheduled_for if followup_decision.should_schedule else None, followup_decision.snooze_until, 'low' if not understanding.high_intent_signal else 'medium', {
            'followup_reason': followup_decision.reason,
            'followup_kind': followup_decision.followup_kind,
            'reply_goal': reply_plan.goal,
            'work_hours': self.work_hours_engine.describe_window(runtime_policy),
            'training_packet_summary': training_packet.prompt_summary,
        }, True, bool(reply_plan.should_reply and final_reply.text.strip()))
        if followup_decision.should_schedule and followup_decision.scheduled_for and followup_decision.text:
            scheduled_for = followup_decision.scheduled_for
            if str(runtime_policy.get('proactive_followup_policy') or 'workhours_only') == 'workhours_only' and not self.work_hours_engine.is_in_reply_window(runtime_policy, scheduled_for):
                scheduled_for = self.work_hours_engine.next_open_time(runtime_policy, scheduled_for)
            self.proactive_followup_repo.schedule_plan(business_account_id, conversation_id, user_id, followup_decision.followup_kind, scheduled_for, {
                'plan_version': 1,
                'text': followup_decision.text,
                'pacing_mode': followup_decision.pacing_mode,
                'followup_kind': followup_decision.followup_kind,
                'source': 'orchestrator',
                'work_hours': self.work_hours_engine.describe_window(runtime_policy),
                'training_packet_summary': training_packet.prompt_summary,
            }, followup_decision.reason, source_message_id=inbound_message_id)

        self.conversation_repo.update_conversation_state(
            conversation_id,
            stage_decision.stage,
            mode_decision.chat_mode,
            understanding.current_mainline_should_continue,
        )

        project_update_result = self.user_repo.update_project_state(
            business_account_id,
            user_id,
            project_decision.project_id,
            project_decision.reason,
            candidate_projects=project_decision.candidate_projects,
            confidence=project_decision.confidence,
            source=project_decision.source,
            status="classified" if project_decision.project_id is not None else "candidate_only",
            updated_by="system",
        )
        segment_code = None
        segment_reason = None
        if isinstance(segment_decision, dict):
            segment_code = segment_decision.get("segment_code") or segment_decision.get("segment_name")
            segment_reason = segment_decision.get("reason")
        else:
            segment_code = getattr(segment_decision, "segment_code", None) or getattr(segment_decision, "segment_name", None)
            segment_reason = getattr(segment_decision, "reason", None)
        self.project_segment_manager.ensure_stage_state(user_id, project_decision.project_id, segment_code, segment_reason)
        self.user_repo.update_reply_language(user_id, reply_language)
        tag_apply_result = self.user_repo.apply_tag_decision(business_account_id, user_id, tag_decision)
        ops_category_value = None
        ops_reason_value = ''
        ops_changed = False
        if isinstance(ops_decision, dict):
            ops_category_value = ops_decision.get('ops_category') or user_state.ops_category
            ops_reason_value = ops_decision.get('reason') or 'system ops category update'
            ops_changed = bool(ops_decision.get('changed'))
        else:
            ops_category_value = getattr(ops_decision, 'ops_category', None) or user_state.ops_category
            ops_reason_value = getattr(ops_decision, 'reason', '') or 'system ops category update'
            ops_changed = bool(getattr(ops_decision, 'changed', False))
        if ops_changed and ops_category_value:
            self.user_repo.set_ops_category_manual(
                business_account_id,
                user_id,
                ops_category_value,
                ops_reason_value,
                'system',
            )
        refreshed_profile = self.user_repo.get_user_profile(business_account_id, user_id)
        refreshed_project_state = (refreshed_profile.get('project_state') or {}) if isinstance(refreshed_profile, dict) else {}
        resolved_project_name = refreshed_project_state.get('project_name')
        resolved_tags = list((refreshed_profile.get('tags') or [])) if isinstance(refreshed_profile, dict) else []
        if project_decision.project_id is not None and self.training_center_repo and training_packet.items:
            try:
                self.training_center_repo.log_training_usage(
                    business_account_id,
                    conversation_id,
                    inbound_message_id,
                    None,
                    None,
                    'project_state',
                    'updated',
                    {
                        'project_id': project_decision.project_id,
                        'project_reason': project_decision.reason,
                        'training_packet_summary': training_packet.prompt_summary,
                    },
                )
            except Exception:
                logger.exception('Failed to log training-assisted project update.')
        intent_label = (
            getattr(intent_decision, 'intent_name', None)
            or getattr(understanding, 'user_intent', None)
            or getattr(intent_decision, 'level', None)
            or 'unknown'
        )
        if escalation_decision.get('should_enqueue'):
            self.human_queue_repo.enqueue(business_account_id, conversation_id, user_id, escalation_decision.get('queue_name') or 'high_intent', escalation_decision.get('priority') or 50, escalation_decision.get('reason') or 'signal', {
                'intent': intent_label,
                'project_name': resolved_project_name,
                'training_packet_summary': training_packet.prompt_summary,
            })
        memory_payload = {
            'conversation_id': conversation_id,
            'user_id': user_id,
            'project_name': resolved_project_name,
            'current_stage': stage_decision.stage,
            'chat_mode': mode_decision.chat_mode,
            'current_mainline': understanding.current_mainline_should_continue,
            'latest_user_text': latest_user_text,
            'latest_ai_reply': final_reply.text,
            'tags': resolved_tags,
            'ops_category': ops_category_value,
            'project_candidates': project_decision.candidate_projects,
            'work_hours_window': self.work_hours_engine.describe_window(runtime_policy),
            'training_packet_summary': training_packet.prompt_summary,
            'training_item_ids': [item.get('id') for item in training_packet.items[:12]],
        }
        self.memory_manager.refresh_after_turn(conversation_id, context.long_term_memory or {}, memory_payload)
        if self.receipt_repo:
            try:
                title = f"Auto process: {intent_label}"
                receipt_payload = {
                    'goal': reply_plan.goal,
                    'reply_sent': bool(reply_plan.should_reply and final_reply.text.strip()),
                    'project_name': resolved_project_name,
                    'project_reason': project_decision.reason,
                    'project_candidates': project_decision.candidate_projects,
                    'segment_code': segment_code,
                    'queue_decision': escalation_decision,
                    'tag_changes': tag_apply_result.get('added') if isinstance(tag_apply_result, dict) else [],
                    'ops_category': ops_category_value,
                    'followup': {
                        'scheduled': followup_decision.should_schedule,
                        'scheduled_for': followup_decision.scheduled_for.isoformat() if followup_decision.scheduled_for else None,
                        'kind': followup_decision.followup_kind,
                        'reason': followup_decision.reason,
                        'work_hours': self.work_hours_engine.describe_window(runtime_policy),
                    },
                    'training_packet_summary': training_packet.prompt_summary,
                    'training_item_ids': [item.get('id') for item in training_packet.items[:12]],
                }
                self.receipt_repo.create_system_receipt(conversation_id, title, receipt_payload, meta={
                    'intent': intent_label,
                    'project_id': project_decision.project_id,
                    'training_packet_summary': training_packet.prompt_summary,
                })
            except Exception:
                logger.exception('Failed to create system receipt | conversation_id=%s', conversation_id)
        if escalation_decision.get('should_notify') and self.receipt_repo:
            try:
                title = f"High intent: {resolved_project_name or 'unknown project'}"
                notify_payload = {
                    'intent': intent_label,
                    'project_name': resolved_project_name,
                    'project_reason': project_decision.reason,
                    'reason': escalation_decision.get('reason'),
                    'priority': escalation_decision.get('priority'),
                    'summary': f"{resolved_project_name or 'Project'} | {escalation_decision.get('reason')}",
                    'training_packet_summary': training_packet.prompt_summary,
                }
                self.receipt_repo.create_system_receipt(conversation_id, title, notify_payload, meta={
                    'kind': 'high_intent_notify',
                    'training_packet_summary': training_packet.prompt_summary,
                })
            except Exception:
                logger.exception('Failed to create escalation receipt | conversation_id=%s', conversation_id)



# =========================
# step12 training step4 extensions
# =========================

_STEP12_STEP4_BASE_CONTENT_SELECTOR = ContentSelector
_STEP12_STEP4_BASE_REPLY_DELAY_ENGINE = ReplyDelayEngine
_STEP12_STEP4_BASE_PROACTIVE_FOLLOWUP_ENGINE = ProactiveFollowupEngine


def _step4_filter_text_only_materials(items: list[dict[str, Any]] | None) -> list[dict[str, Any]]:
    result: list[dict[str, Any]] = []
    for item in items or []:
        material_type = str(item.get('material_type') or item.get('type') or '').strip().lower()
        if material_type in ('text', 'plain_text', 'copy', 'script') or not material_type:
            result.append(item)
    return result


def _step4_limit_material_items(items: list[dict[str, Any]] | None, limit: int | None) -> list[dict[str, Any]]:
    values = list(items or [])
    if limit is None or limit <= 0:
        return values
    return values[:limit]



def _step4_extract_material_policy(training_packet: TrainingPacket | None, reply_plan: ReplyPlan | None = None) -> dict[str, Any]:
    policy: dict[str, Any] = {
        'no_material': False,
        'text_only': False,
        'daily_only': False,
        'project_only': False,
        'no_package': False,
        'no_voice': False,
        'max_items': None,
    }
    if reply_plan and getattr(reply_plan, 'should_send_material', False) is False:
        policy['no_material'] = True
    if not training_packet:
        return policy
    if 'pause_request' in (training_packet.scene_tags or []) or 'identity_probe' in (training_packet.scene_tags or []):
        policy['no_material'] = True
    joined_avoid = ' | '.join(str(v).lower() for v in (training_packet.must_avoid or []))
    joined_strategy = ' | '.join(str(v).lower() for v in (training_packet.preferred_strategies or []))
    if any(token in joined_avoid for token in ('no material', 'do not send material', 'dont send material', 'no package')):
        policy['no_material'] = True
    if 'text only' in joined_strategy or 'text only' in joined_avoid:
        policy['text_only'] = True
    if 'daily only' in joined_strategy or 'daily only' in joined_avoid:
        policy['daily_only'] = True
    if 'project only' in joined_strategy:
        policy['project_only'] = True
    if 'no package' in joined_strategy or 'no package' in joined_avoid:
        policy['no_package'] = True
    if 'no voice' in joined_strategy or 'no voice' in joined_avoid:
        policy['no_voice'] = True
    for rule in training_packet.material_rules or []:
        mp = dict(rule.get('material_policy') or {})
        if mp.get('no_material') or mp.get('disable_all_materials'):
            policy['no_material'] = True
        if mp.get('text_only'):
            policy['text_only'] = True
        if mp.get('daily_only'):
            policy['daily_only'] = True
        if mp.get('project_only'):
            policy['project_only'] = True
        if mp.get('no_package') or mp.get('disable_packages'):
            policy['no_package'] = True
        if mp.get('no_voice') or mp.get('disable_voice_templates'):
            policy['no_voice'] = True
        try:
            max_items = mp.get('max_items')
            if max_items is not None:
                max_items = int(max_items)
                if max_items > 0:
                    current = policy.get('max_items')
                    policy['max_items'] = min(current, max_items) if current else max_items
        except Exception:
            pass
    return policy



def _step4_apply_material_policy(selected: dict[str, Any], policy: dict[str, Any]) -> dict[str, Any]:
    adjusted = dict(selected or {})
    if policy.get('no_material'):
        adjusted['project_materials'] = []
        adjusted['persona_materials'] = []
        adjusted['daily_materials'] = []
        adjusted['material_packages'] = {}
        adjusted['voice_templates'] = []
    else:
        if policy.get('text_only'):
            adjusted['project_materials'] = _step4_filter_text_only_materials(adjusted.get('project_materials'))
            adjusted['persona_materials'] = _step4_filter_text_only_materials(adjusted.get('persona_materials'))
            adjusted['daily_materials'] = _step4_filter_text_only_materials(adjusted.get('daily_materials'))
            adjusted['material_packages'] = {}
            adjusted['voice_templates'] = []
        if policy.get('daily_only'):
            adjusted['project_materials'] = []
            adjusted['material_packages'] = {}
            adjusted['voice_templates'] = []
        if policy.get('project_only'):
            adjusted['persona_materials'] = []
            adjusted['daily_materials'] = []
        if policy.get('no_package'):
            adjusted['material_packages'] = {}
        if policy.get('no_voice'):
            adjusted['voice_templates'] = []
        limit = policy.get('max_items')
        adjusted['project_materials'] = _step4_limit_material_items(adjusted.get('project_materials'), limit)
        adjusted['persona_materials'] = _step4_limit_material_items(adjusted.get('persona_materials'), limit)
        adjusted['daily_materials'] = _step4_limit_material_items(adjusted.get('daily_materials'), limit)
    overview = dict(adjusted.get('material_library_overview') or {})
    overview['training_material_policy'] = {
        'no_material': bool(policy.get('no_material')),
        'text_only': bool(policy.get('text_only')),
        'daily_only': bool(policy.get('daily_only')),
        'project_only': bool(policy.get('project_only')),
        'no_package': bool(policy.get('no_package')),
        'no_voice': bool(policy.get('no_voice')),
        'max_items': policy.get('max_items'),
    }
    adjusted['material_library_overview'] = overview
    return adjusted



def _step4_extract_delay_hint(training_packet: TrainingPacket | None) -> dict[str, Any]:
    result: dict[str, Any] = {'extra_delay_seconds': 0, 'min_delay_seconds': None, 'max_delay_seconds': None}
    if not training_packet:
        return result
    strategy_blob = ' | '.join(str(v).lower() for v in (training_packet.preferred_strategies or []))
    if 'leave space' in strategy_blob or 'slow down' in strategy_blob:
        result['extra_delay_seconds'] += 1
    if 'reply quickly' in strategy_blob or 'fast reply' in strategy_blob:
        result['extra_delay_seconds'] -= 1
    for rule in (training_packet.style_rules or []):
        style = dict(rule.get('style') or {})
        try:
            result['extra_delay_seconds'] += int(style.get('extra_delay_seconds') or 0)
        except Exception:
            pass
        try:
            min_delay = style.get('min_delay_seconds')
            if min_delay is not None:
                min_delay = int(min_delay)
                current = result.get('min_delay_seconds')
                result['min_delay_seconds'] = max(current, min_delay) if current is not None else min_delay
        except Exception:
            pass
        try:
            max_delay = style.get('max_delay_seconds')
            if max_delay is not None:
                max_delay = int(max_delay)
                current = result.get('max_delay_seconds')
                result['max_delay_seconds'] = min(current, max_delay) if current is not None else max_delay
        except Exception:
            pass
    return result



def _step4_extract_followup_policy(training_packet: TrainingPacket | None) -> dict[str, Any]:
    policy: dict[str, Any] = {
        'disable_followup': False,
        'pause_hours': 0,
        'delay_hours': 0,
        'light_touch_only': False,
        'force_pacing_mode': None,
    }
    if not training_packet:
        return policy
    strategy_blob = ' | '.join(str(v).lower() for v in (training_packet.preferred_strategies or []))
    if 'no proactive follow-up' in strategy_blob or 'no follow-up today' in strategy_blob:
        policy['disable_followup'] = True
        policy['pause_hours'] = max(int(policy.get('pause_hours') or 0), 18)
    if 'leave space' in strategy_blob:
        policy['delay_hours'] = max(int(policy.get('delay_hours') or 0), 8)
        policy['light_touch_only'] = True
    if 'light follow-up' in strategy_blob or 'light touch only' in strategy_blob:
        policy['light_touch_only'] = True
    for rule in (training_packet.followup_rules or []):
        fp = dict(rule.get('followup_policy') or {})
        if fp.get('disable_followup') or fp.get('no_followup_today'):
            policy['disable_followup'] = True
        try:
            policy['pause_hours'] = max(int(policy.get('pause_hours') or 0), int(fp.get('pause_hours') or 0))
        except Exception:
            pass
        try:
            policy['delay_hours'] = max(int(policy.get('delay_hours') or 0), int(fp.get('delay_hours') or 0))
        except Exception:
            pass
        if fp.get('light_touch_only'):
            policy['light_touch_only'] = True
        if fp.get('pacing_mode'):
            policy['force_pacing_mode'] = str(fp.get('pacing_mode'))
    if 'pause_request' in (training_packet.scene_tags or []):
        policy['delay_hours'] = max(int(policy.get('delay_hours') or 0), 8)
        policy['light_touch_only'] = True
    if 'identity_probe' in (training_packet.scene_tags or []) and 'product_consult' not in (training_packet.scene_tags or []):
        policy['disable_followup'] = True
        policy['pause_hours'] = max(int(policy.get('pause_hours') or 0), 24)
    if 'objection' in (training_packet.scene_tags or []):
        policy['delay_hours'] = max(int(policy.get('delay_hours') or 0), 12)
        policy['light_touch_only'] = True
    return policy


class ContentSelector(_STEP12_STEP4_BASE_CONTENT_SELECTOR):
    def select(self, business_account_id: int, project_id: int | None, mode: str, reply_plan: ReplyPlan,
               training_packet: TrainingPacket | None = None) -> dict:
        selected = super().select(business_account_id, project_id, mode, reply_plan)
        material_policy = _step4_extract_material_policy(training_packet, reply_plan)
        adjusted = _step4_apply_material_policy(selected, material_policy)
        adjusted['training_material_policy'] = material_policy
        adjusted['prompt_summary'] = self._build_prompt_summary(adjusted)
        return adjusted


class ReplyDelayEngine(_STEP12_STEP4_BASE_REPLY_DELAY_ENGINE):
    def decide_delay_seconds(self, understanding: UnderstandingResult, mode: str, reply_text: str,
                             training_packet: TrainingPacket | None = None) -> int:
        base_delay = super().decide_delay_seconds(understanding, mode, reply_text)
        text = str(reply_text or '').strip()
        word_count = len(text.split())
        char_count = len(text)
        delay = int(base_delay)
        if char_count > 220 or word_count > 40:
            delay += 3
        elif char_count > 120 or word_count > 22:
            delay += 2
        elif char_count > 55 or word_count > 10:
            delay += 1
        boundary = str(getattr(understanding, 'boundary_signal', '') or '').lower()
        resistance = str(getattr(understanding, 'resistance_signal', '') or '').lower()
        if boundary in ('busy', 'later', 'sleep', 'stop'):
            delay = min(delay, 3)
        if resistance in ('medium', 'high'):
            delay += 1
        scene_tags = set(training_packet.scene_tags or []) if training_packet else set()
        if 'identity_probe' in scene_tags or 'objection' in scene_tags:
            delay += 1
        delay_hint = _step4_extract_delay_hint(training_packet)
        delay += int(delay_hint.get('extra_delay_seconds') or 0)
        min_delay = delay_hint.get('min_delay_seconds')
        max_delay = delay_hint.get('max_delay_seconds')
        if min_delay is not None:
            delay = max(delay, int(min_delay))
        if max_delay is not None:
            delay = min(delay, int(max_delay))
        return max(1, min(int(delay), 12))


class ProactiveFollowupEngine(_STEP12_STEP4_BASE_PROACTIVE_FOLLOWUP_ENGINE):
    def decide(self, policy: dict[str, Any], understanding: UnderstandingResult, mode_decision: ModeDecision,
               reply_plan: ReplyPlan, user_state: UserStateSnapshot, intent_decision: IntentDecision,
               context: ConversationContext, latest_user_text: str, project_name: str | None = None,
               latest_handover_summary: dict[str, Any] | None = None,
               escalation_decision: dict[str, Any] | None = None,
               training_packet: TrainingPacket | None = None) -> FollowupDecision:
        training_policy = _step4_extract_followup_policy(training_packet)
        now = utc_now()
        if training_policy.get('disable_followup') and not understanding.high_intent_signal:
            pause_hours = max(1, int(training_policy.get('pause_hours') or 18))
            return FollowupDecision(False, reason='training policy suppress followup', pacing_mode='silent', snooze_until=now + timedelta(hours=pause_hours))
        decision = super().decide(policy, understanding, mode_decision, reply_plan, user_state, intent_decision, context, latest_user_text, project_name, latest_handover_summary, escalation_decision)
        if training_policy.get('force_pacing_mode'):
            decision = replace(decision, pacing_mode=str(training_policy.get('force_pacing_mode')))
        if not decision.should_schedule:
            return decision
        if training_policy.get('delay_hours') and decision.scheduled_for:
            decision = replace(decision, scheduled_for=decision.scheduled_for + timedelta(hours=int(training_policy.get('delay_hours') or 0)), reason=((decision.reason or '') + ' | training_delay').strip())
        if training_policy.get('light_touch_only'):
            light_text = str(decision.text or '').strip()
            if light_text:
                light_text = _step3_sentence_clip(_step3_remove_emojis(light_text), max_sentences=1, max_chars=120)
            decision = replace(decision, text=light_text, followup_kind='light_touch', pacing_mode='gentle')
        if reply_plan.should_leave_space and not understanding.high_intent_signal and decision.scheduled_for:
            delayed = decision.scheduled_for + timedelta(hours=8)
            decision = replace(decision, scheduled_for=delayed, pacing_mode='gentle', reason=((decision.reason or '') + ' | leave_space').strip())
        return decision




def _step5_build_understanding_hint(training_packet: TrainingPacket | None) -> str:
    if not training_packet:
        return ''
    parts: list[str] = []
    if training_packet.scene_tags:
        parts.append(f"scene tags: {', '.join(training_packet.scene_tags[:6])}")
    if training_packet.preferred_strategies:
        parts.append(f"strategy hints: {' | '.join(str(v) for v in training_packet.preferred_strategies[:3])}")
    if training_packet.good_examples:
        first_example = dict(training_packet.good_examples[0] or {})
        example_scene = str(first_example.get('scene_summary') or '').strip()
        if example_scene:
            parts.append(f"example focus: {example_scene}")
    return ' | '.join(parts)[:320]



def _step5_enrich_understanding_payload(payload: dict[str, Any], latest_user_message: str,
                                       training_packet: TrainingPacket | None) -> dict[str, Any]:
    merged = dict(payload or {})
    if not training_packet:
        return merged
    latest = str(latest_user_message or '').strip().lower()
    scene_tags = {str(tag or '').strip().lower() for tag in (training_packet.scene_tags or []) if str(tag).strip()}
    boundary_from_text = _step9_boundary_signal_from_text(latest)
    if boundary_from_text:
        scene_tags.add(boundary_from_text)
        if boundary_from_text in ('busy', 'later', 'sleep'):
            scene_tags.add('pause_request')
    strategy_blob = ' | '.join(str(value or '').lower() for value in (training_packet.preferred_strategies or []))
    reason_bits: list[str] = []
    existing_reason = str(merged.get('reason') or '').strip()
    if existing_reason:
        reason_bits.append(existing_reason)

    if 'identity_probe' in scene_tags:
        merged.update({
            'user_intent': 'identity_probe',
            'need_type': 'identity_check',
            'explicit_product_query': False,
            'high_intent_signal': False,
            'current_mainline_should_continue': 'daily',
            'recommended_chat_mode': 'daily',
            'recommended_goal': 'identity_safe_reply',
        })
        reason_bits.append('training_scene=identity_probe')
        return {**merged, 'reason': ' | '.join(_training_dedup_strings(reason_bits, 6))}

    if 'pause_request' in scene_tags or boundary_from_text in ('busy', 'later', 'sleep'):
        merged.update({
            'user_intent': 'pause_request',
            'need_type': 'pause',
            'boundary_signal': boundary_from_text or str(merged.get('boundary_signal') or 'busy'),
            'current_mainline_should_continue': 'pause',
            'recommended_chat_mode': 'pause',
            'recommended_goal': 'pause_respect',
        })
        reason_bits.append('training_scene=pause_request')
        return {**merged, 'reason': ' | '.join(_training_dedup_strings(reason_bits, 6))}

    if 'objection' in scene_tags:
        merged.update({
            'user_intent': 'objection',
            'need_type': 'pressure_relief',
            'resistance_signal': 'high' if any(token in latest for token in ['scam', 'fake', 'pushy']) else 'medium',
            'current_mainline_should_continue': 'daily',
            'recommended_chat_mode': 'daily',
            'recommended_goal': 'lower_pressure',
        })
        reason_bits.append('training_scene=objection')

    if 'lower pressure' in strategy_blob and not str(merged.get('resistance_signal') or '').strip():
        merged['resistance_signal'] = 'medium'
        if str(merged.get('recommended_goal') or '') not in ('identity_safe_reply', 'pause_respect'):
            merged['recommended_goal'] = 'lower_pressure'
        reason_bits.append('training_strategy=lower_pressure')

    if 'product_consult' in scene_tags and str(merged.get('user_intent') or '') not in ('identity_probe', 'pause_request', 'objection'):
        merged.update({
            'user_intent': 'product_consult',
            'need_type': 'product_info',
            'product_interest_signal': True,
            'explicit_product_query': True,
            'current_mainline_should_continue': 'product',
            'recommended_chat_mode': 'product',
            'recommended_goal': 'answer_product',
        })
        reason_bits.append('training_scene=product_consult')

    if 'daily_chat' in scene_tags and not bool(merged.get('explicit_product_query')) and not bool(merged.get('high_intent_signal')) and not str(merged.get('boundary_signal') or '').strip():
        if str(merged.get('user_intent') or '') not in ('identity_probe', 'pause_request', 'objection'):
            merged.update({
                'user_intent': 'daily_chat',
                'need_type': 'conversation',
                'current_mainline_should_continue': 'daily',
                'recommended_chat_mode': 'daily',
                'recommended_goal': 'keep_replying',
            })
            reason_bits.append('training_scene=daily_chat')

    if reason_bits:
        merged['reason'] = ' | '.join(_training_dedup_strings(reason_bits, 8))
    return merged


class UserUnderstandingEngine(UserUnderstandingEngine):
    def analyze(self, latest_user_message: str, recent_context: list[dict], persona_core_summary: str,
                user_state_summary: str, long_term_memory_summary: str = "",
                training_packet: TrainingPacket | None = None) -> UnderstandingResult:
        runtime_training_packet = training_packet or getattr(self, '_runtime_training_packet', None)
        fallback = self._fallback_rule_based(latest_user_message)
        understanding_hint = _step5_build_understanding_hint(runtime_training_packet)
        prompt_user_state_summary = user_state_summary
        if understanding_hint:
            prompt_user_state_summary = f"{user_state_summary}\nTraining hints: {understanding_hint}".strip()
        try:
            result = self.llm_service.classify_user_message(
                build_understanding_prompt(
                    latest_user_message,
                    recent_context,
                    persona_core_summary,
                    prompt_user_state_summary,
                    long_term_memory_summary,
                )
            )
        except Exception:
            result = fallback
        merged = dict(fallback)
        for k, v in (result or {}).items():
            if v is not None:
                merged[k] = v
        merged = _step5_enrich_understanding_payload(merged, latest_user_message, runtime_training_packet)
        return UnderstandingResult(**merged)


class Orchestrator(Orchestrator):
    def _build_training_packet(self, business_account_id: int, runtime_context: dict[str, Any]) -> TrainingPacket:
        packet = super()._build_training_packet(business_account_id, runtime_context)
        try:
            setattr(self.understanding_engine, '_runtime_training_packet', packet)
        except Exception:
            pass
        return packet

    def _log_training_runtime_outcomes(self, business_account_id: int, conversation_id: int, message_id: int,
                                       packet: TrainingPacket, understanding: UnderstandingResult,
                                       stage_decision: StageDecision, mode_decision: ModeDecision,
                                       reply_plan: ReplyPlan, selected_content: dict[str, Any],
                                       draft_reply: str, final_text: str,
                                       followup_decision: FollowupDecision) -> None:
        if not packet.items or not self.training_center_repo:
            return
        if not bool((packet.config or {}).get('usage_logging_enabled', True)):
            return
        rewritten = str(draft_reply or '').strip() != str(final_text or '').strip()
        for rank, item in enumerate(packet.items[:12], start=1):
            try:
                category = str(item.get('training_category') or 'daily_chat')
                matched_tags = list(item.get('_matched_scene_tags') or [])
                usage_type = 'understanding' if matched_tags else 'planning'
                applied_result = 'matched' if matched_tags else 'applied'
                if category in ('identity_expression', 'forbidden_rules'):
                    usage_type = 'response_guard'
                    applied_result = 'rewritten' if rewritten else 'guarded'
                elif category == 'rhythm_relationship':
                    usage_type = 'followup'
                    applied_result = 'scheduled' if followup_decision.should_schedule else ('suppressed' if followup_decision.snooze_until else 'checked')
                details = {
                    'rank': rank,
                    'training_category': category,
                    'matched_scene_tags': matched_tags,
                    'understanding_intent': understanding.user_intent,
                    'boundary_signal': understanding.boundary_signal,
                    'reply_goal': reply_plan.goal,
                    'stage': stage_decision.stage,
                    'mode': mode_decision.chat_mode,
                    'material_summary': (selected_content or {}).get('prompt_summary'),
                    'rewritten': rewritten,
                    'followup_kind': followup_decision.followup_kind,
                    'followup_scheduled_for': followup_decision.scheduled_for.isoformat() if getattr(followup_decision, 'scheduled_for', None) else None,
                    'scene_tags': packet.scene_tags,
                }
                self.training_center_repo.log_training_usage(
                    business_account_id,
                    conversation_id,
                    message_id,
                    int(item.get('id') or 0) if item.get('id') is not None else None,
                    None,
                    usage_type,
                    applied_result,
                    details,
                )
            except Exception:
                logger.exception('Failed to log granular training runtime outcome | training_item_id=%s', item.get('id'))
        summary_events = [
            ('understanding', 'resolved', {
                'intent': understanding.user_intent,
                'need_type': understanding.need_type,
                'boundary_signal': understanding.boundary_signal,
                'resistance_signal': understanding.resistance_signal,
                'scene_tags': packet.scene_tags,
                'training_item_ids': [item.get('id') for item in packet.items[:12]],
            }),
            ('planning', 'applied', {
                'goal': reply_plan.goal,
                'should_continue_product': reply_plan.should_continue_product,
                'should_send_material': reply_plan.should_send_material,
                'should_leave_space': reply_plan.should_leave_space,
            }),
            ('response_guard', 'rewritten' if rewritten else 'passed', {
                'rewritten': rewritten,
                'draft_len': len(str(draft_reply or '')),
                'final_len': len(str(final_text or '')),
            }),
            ('followup', 'scheduled' if followup_decision.should_schedule else ('suppressed' if followup_decision.snooze_until else 'checked'), {
                'followup_kind': followup_decision.followup_kind,
                'pacing_mode': followup_decision.pacing_mode,
                'scheduled_for': followup_decision.scheduled_for.isoformat() if followup_decision.scheduled_for else None,
                'snooze_until': followup_decision.snooze_until.isoformat() if followup_decision.snooze_until else None,
            }),
        ]
        for usage_type, applied_result, details in summary_events:
            try:
                self.training_center_repo.log_training_usage(
                    business_account_id,
                    conversation_id,
                    message_id,
                    None,
                    None,
                    usage_type,
                    applied_result,
                    details,
                )
            except Exception:
                logger.exception('Failed to log training runtime summary | usage_type=%s', usage_type)



# =========================
# step12 - step6 multimedia + admin enhancements
# =========================

def _step6_extract_message_obj(raw_payload: dict[str, Any]) -> dict[str, Any]:
    return dict(
        raw_payload.get('business_message')
        or raw_payload.get('edited_business_message')
        or raw_payload.get('message')
        or {}
    )


def _step6_pick_primary_file_id(message_obj: dict[str, Any]) -> str | None:
    if not message_obj:
        return None
    if message_obj.get('photo'):
        photos = list(message_obj.get('photo') or [])
        photos.sort(key=lambda item: int(item.get('file_size') or 0), reverse=True)
        if photos:
            return str(photos[0].get('file_id') or '') or None
    if message_obj.get('video'):
        return str((message_obj.get('video') or {}).get('file_id') or '') or None
    if message_obj.get('voice'):
        return str((message_obj.get('voice') or {}).get('file_id') or '') or None
    if message_obj.get('document'):
        return str((message_obj.get('document') or {}).get('file_id') or '') or None
    if message_obj.get('animation'):
        return str((message_obj.get('animation') or {}).get('file_id') or '') or None
    return None


def _step6_extract_media_meta(message_obj: dict[str, Any], message_type: str) -> dict[str, Any]:
    caption = str(message_obj.get('caption') or '').strip()
    media: dict[str, Any] = {
        'message_type': str(message_type or 'text'),
        'caption': caption,
        'file_id': _step6_pick_primary_file_id(message_obj),
        'mime_type': None,
        'file_name': None,
        'duration': None,
        'width': None,
        'height': None,
        'thumbnail_file_id': None,
    }
    if media['message_type'] == 'image':
        photos = list(message_obj.get('photo') or [])
        photos.sort(key=lambda item: int(item.get('file_size') or 0), reverse=True)
        if photos:
            primary = photos[0]
            media['width'] = primary.get('width')
            media['height'] = primary.get('height')
    elif media['message_type'] == 'video':
        video = dict(message_obj.get('video') or {})
        media['mime_type'] = video.get('mime_type')
        media['duration'] = video.get('duration')
        media['width'] = video.get('width')
        media['height'] = video.get('height')
        thumb = dict(video.get('thumbnail') or video.get('thumb') or {})
        media['thumbnail_file_id'] = thumb.get('file_id')
    elif media['message_type'] == 'voice':
        voice = dict(message_obj.get('voice') or {})
        media['mime_type'] = voice.get('mime_type')
        media['duration'] = voice.get('duration')
    elif media['message_type'] == 'file':
        doc = dict(message_obj.get('document') or {})
        media['mime_type'] = doc.get('mime_type')
        media['file_name'] = doc.get('file_name')
        thumb = dict(doc.get('thumbnail') or doc.get('thumb') or {})
        media['thumbnail_file_id'] = thumb.get('file_id')
    elif media['message_type'] == 'gif':
        anim = dict(message_obj.get('animation') or {})
        media['mime_type'] = anim.get('mime_type')
        media['duration'] = anim.get('duration')
        media['width'] = anim.get('width')
        media['height'] = anim.get('height')
        thumb = dict(anim.get('thumbnail') or anim.get('thumb') or {})
        media['thumbnail_file_id'] = thumb.get('file_id')
    return media


def _step6_basic_media_summary(media_meta: dict[str, Any]) -> str:
    if not media_meta:
        return ''
    message_type = str(media_meta.get('message_type') or 'text')
    caption = str(media_meta.get('caption') or '').strip()
    duration = media_meta.get('duration')
    file_name = str(media_meta.get('file_name') or '').strip()
    width = media_meta.get('width')
    height = media_meta.get('height')
    size_hint = f"{width}x{height}" if width and height else ''
    if message_type == 'image':
        base = 'User sent an image.'
        if size_hint:
            base = f"User sent an image ({size_hint})."
    elif message_type == 'video':
        base = 'User sent a video.'
        if duration:
            base = f"User sent a video ({int(duration)}s)."
    elif message_type == 'voice':
        base = 'User sent a voice message.'
        if duration:
            base = f"User sent a voice message ({int(duration)}s)."
    elif message_type == 'file':
        base = 'User sent a file.'
        if file_name:
            base = f"User sent a file named {file_name}."
    elif message_type == 'gif':
        base = 'User sent an animation.'
    else:
        base = ''
    if caption:
        return f"{base} Caption: {caption}".strip()
    return base


def _step6_build_effective_user_text(original_text: str | None, media_summary: str | None,
                                     transcript: str | None = None, image_description: str | None = None) -> str:
    parts: list[str] = []
    original = str(original_text or '').strip()
    if original:
        parts.append(original)
    transcript_text = str(transcript or '').strip()
    image_desc_text = str(image_description or '').strip()
    summary_text = str(media_summary or '').strip()
    if transcript_text:
        parts.append(f"Voice content: {transcript_text}")
    elif image_desc_text:
        parts.append(f"Media context: {image_desc_text}")
    elif summary_text and summary_text.lower() not in original.lower():
        parts.append(f"Media context: {summary_text}")
    return '\\n\\n'.join([part for part in parts if part]).strip()


class OpenAIClientAdapter(OpenAIClientAdapter):
    def describe_image_from_url(self, image_url: str, instruction: str = '', model: str = 'gpt-4.1-mini') -> str:
        url = str(image_url or '').strip()
        if not url:
            return ''
        prompt_text = instruction or 'Describe the image briefly for chat response planning. Focus on obvious visible content only.'
        try:
            response = self.client.responses.create(
                model=model,
                input=[{
                    'role': 'user',
                    'content': [
                        {'type': 'input_text', 'text': prompt_text},
                        {'type': 'input_image', 'image_url': url},
                    ],
                }],
                max_output_tokens=160,
                temperature=0.1,
            )
        except Exception:
            return ''
        text_parts: list[str] = []
        for item in getattr(response, 'output', []) or []:
            for content in getattr(item, 'content', []) or []:
                if getattr(content, 'type', None) == 'output_text':
                    text_parts.append(getattr(content, 'text', ''))
        return ' '.join(part.strip() for part in text_parts if str(part).strip()).strip()

    def transcribe_audio_from_url(self, audio_url: str, filename_hint: str = 'voice.ogg', model: str = 'gpt-4o-mini-transcribe') -> str:
        url = str(audio_url or '').strip()
        if not url:
            return ''
        import tempfile
        from urllib import request as _request
        temp_path = None
        try:
            suffix = '.ogg'
            if '.' in filename_hint:
                suffix = '.' + filename_hint.split('.')[-1]
            with _request.urlopen(url, timeout=45) as resp:
                payload = resp.read()
            with tempfile.NamedTemporaryFile(delete=False, suffix=suffix) as tmp:
                tmp.write(payload)
                temp_path = tmp.name
            with open(temp_path, 'rb') as audio_file:
                result = self.client.audio.transcriptions.create(
                    model=model,
                    file=audio_file,
                )
            text_value = getattr(result, 'text', '') or ''
            return str(text_value).strip()
        except Exception:
            return ''
        finally:
            if temp_path and os.path.exists(temp_path):
                try:
                    os.remove(temp_path)
                except Exception:
                    pass


class TelegramBotAPIClient(TelegramBotAPIClient):
    def get_file_info(self, file_id: str) -> dict[str, Any] | None:
        normalized = str(file_id or '').strip()
        if not normalized:
            return None
        try:
            response = self._call_api('getFile', {'file_id': normalized})
        except Exception:
            return None
        result = response.get('result') if isinstance(response, dict) else None
        return dict(result or {}) if result else None

    def build_file_download_url(self, file_path: str | None) -> str | None:
        normalized = str(file_path or '').strip()
        if not normalized:
            return None
        return f"https://api.telegram.org/file/bot{self.bot_token}/{normalized}"

    def get_file_download_url(self, file_id: str) -> str | None:
        info = self.get_file_info(file_id)
        if not info:
            return None
        return self.build_file_download_url(info.get('file_path'))

    def resolve_message_media_url(self, raw_payload: dict[str, Any]) -> str | None:
        message_obj = _step6_extract_message_obj(raw_payload)
        file_id = _step6_pick_primary_file_id(message_obj)
        return self.get_file_download_url(file_id) if file_id else None


class MediaUnderstandingService:
    def __init__(self, tg_client: TelegramBotAPIClient, llm_service: LLMService | None = None) -> None:
        self.tg_client = tg_client
        self.llm_service = llm_service

    def _describe_image(self, media_url: str, caption: str) -> str:
        if not self.llm_service or not getattr(self.llm_service, 'client_adapter', None):
            return ''
        instruction = 'Describe the user image briefly for chat understanding. Mention only clear visible content. Keep it short.'
        if caption:
            instruction += f" Caption context: {caption[:200]}"
        try:
            return self.llm_service.client_adapter.describe_image_from_url(media_url, instruction)
        except Exception:
            return ''

    def _transcribe_voice(self, media_url: str, media_meta: dict[str, Any]) -> str:
        if not self.llm_service or not getattr(self.llm_service, 'client_adapter', None):
            return ''
        filename_hint = 'voice.ogg'
        mime_type = str(media_meta.get('mime_type') or '').lower()
        if 'mpeg' in mime_type or 'mp3' in mime_type:
            filename_hint = 'voice.mp3'
        elif 'mp4' in mime_type:
            filename_hint = 'voice.mp4'
        try:
            return self.llm_service.client_adapter.transcribe_audio_from_url(media_url, filename_hint)
        except Exception:
            return ''

    def analyze_inbound_message(self, inbound_message: InboundMessage) -> dict[str, Any]:
        raw_payload = dict(inbound_message.raw_payload or {})
        message_obj = _step6_extract_message_obj(raw_payload)
        message_type = str(inbound_message.message_type or _detect_telegram_message_type(message_obj) or 'text')
        media_meta = _step6_extract_media_meta(message_obj, message_type)
        media_url = str(inbound_message.media_url or '').strip() or self.tg_client.resolve_message_media_url(raw_payload) or ''
        media_summary = _step6_basic_media_summary(media_meta)
        image_description = ''
        transcript = ''
        if message_type == 'image' and media_url:
            image_description = self._describe_image(media_url, str(media_meta.get('caption') or ''))
        elif message_type == 'voice' and media_url:
            transcript = self._transcribe_voice(media_url, media_meta)
        effective_user_text = _step6_build_effective_user_text(inbound_message.text, media_summary, transcript, image_description)
        analysis = {
            'message_type': message_type,
            'media_url': media_url or None,
            'media_meta': media_meta,
            'media_summary': media_summary,
            'image_description': image_description,
            'voice_transcript': transcript,
            'effective_user_text': effective_user_text,
        }
        return analysis

    def enrich_inbound_message(self, inbound_message: InboundMessage) -> InboundMessage:
        analysis = self.analyze_inbound_message(inbound_message)
        raw_payload = dict(inbound_message.raw_payload or {})
        raw_payload['step6_media_analysis'] = {
            'message_type': analysis.get('message_type'),
            'media_summary': analysis.get('media_summary'),
            'image_description': analysis.get('image_description'),
            'voice_transcript': analysis.get('voice_transcript'),
            'media_meta': analysis.get('media_meta'),
        }
        effective_text = str(analysis.get('effective_user_text') or '').strip()
        return replace(
            inbound_message,
            text=effective_text or inbound_message.text,
            media_url=analysis.get('media_url') or inbound_message.media_url,
            raw_payload=raw_payload,
        )


class TrainingCenterRepository(TrainingCenterRepository):
    def batch_set_training_item_enabled(self, business_account_id: int, training_category: str, is_enabled: bool) -> int:
        with self.db.transaction():
            with self.db.cursor() as cur:
                if training_category == 'all':
                    cur.execute(
                        'UPDATE training_items SET is_enabled=%s, updated_at=NOW() WHERE business_account_id=%s AND is_deleted=FALSE',
                        (is_enabled, business_account_id),
                    )
                else:
                    cur.execute(
                        'UPDATE training_items SET is_enabled=%s, updated_at=NOW() WHERE business_account_id=%s AND training_category=%s AND is_deleted=FALSE',
                        (is_enabled, business_account_id, training_category),
                    )
                return int(cur.rowcount or 0)

    def list_training_usage_logs(self, business_account_id: int, limit: int = 30) -> list[dict[str, Any]]:
        with self.db.cursor() as cur:
            cur.execute(
                '''
                SELECT tul.*, ti.title AS training_title, ti.training_category
                FROM training_usage_logs tul
                LEFT JOIN training_items ti ON ti.id=tul.training_item_id
                WHERE tul.business_account_id=%s
                ORDER BY tul.created_at DESC, tul.id DESC
                LIMIT %s
                ''',
                (business_account_id, max(1, min(int(limit or 30), 100))),
            )
            return cur.fetchall() or []


class AdminAPIService(AdminAPIService):
    def batch_toggle_training_items_admin(self, business_account_id: int, training_category: str, is_enabled: bool) -> dict[str, Any]:
        if not self.training_center_repo:
            return {'ok': False, 'reason': 'training repository unavailable'}
        affected = self.training_center_repo.batch_set_training_item_enabled(business_account_id, training_category, is_enabled)
        return {
            'ok': True,
            'affected_count': affected,
            'training_category': training_category,
            'is_enabled': bool(is_enabled),
        }

    def list_training_usage_logs_admin(self, business_account_id: int, limit: int = 30) -> list[dict[str, Any]]:
        if not self.training_center_repo:
            return []
        return self.training_center_repo.list_training_usage_logs(business_account_id, limit)


class TGAdminFormatter(TGAdminFormatter):
    @staticmethod
    def format_training_overview(summary_rows: list[dict[str, Any]], recent_logs: list[dict[str, Any]] | None = None) -> str:
        lines = ['📈 训练总览', '']
        total = 0
        enabled = 0
        for row in summary_rows or []:
            total += int(row.get('total_count') or 0)
            enabled += int(row.get('enabled_count') or 0)
            lines.append(f"- {row.get('label')}: {int(row.get('enabled_count') or 0)}/{int(row.get('total_count') or 0)}")
        lines.extend(['', f'总训练项: {total}', f'已启用: {enabled}', ''])
        if recent_logs:
            lines.append('最近调用：')
            for log in recent_logs[:8]:
                label = TRAINING_CATEGORY_LABELS.get(log.get('training_category'), log.get('training_category') or '运行时')
                title = str(log.get('training_title') or log.get('usage_type') or 'runtime')[:26]
                lines.append(f"- {label} | {title} | {log.get('applied_result') or '-'}")
        return '\n'.join(lines)

    @staticmethod
    def format_training_usage_logs(logs: list[dict[str, Any]]) -> str:
        if not logs:
            return '🪵 训练调用日志\n\n暂无训练调用记录。'
        lines = ['🪵 训练调用日志', '']
        for row in logs[:15]:
            label = TRAINING_CATEGORY_LABELS.get(row.get('training_category'), row.get('training_category') or '运行时')
            title = str(row.get('training_title') or row.get('usage_type') or 'runtime')[:28]
            lines.append(f"- {label} | {title} | {row.get('applied_result') or '-'}")
        return '\n'.join(lines)

    @staticmethod
    def format_training_batch_result(training_category: str, affected_count: int, is_enabled: bool) -> str:
        label = '全部训练' if training_category == 'all' else TRAINING_CATEGORY_LABELS.get(training_category, training_category)
        action = '启用' if is_enabled else '停用'
        return f"✅ 已批量{action} {label}，共处理 {int(affected_count or 0)} 条训练。"


class TGAdminMenuBuilder(TGAdminMenuBuilder):
    @staticmethod
    def training_center_menu() -> dict:
        menu = copy.deepcopy(super(TGAdminMenuBuilder, TGAdminMenuBuilder).training_center_menu())
        reply_markup = list(menu.get('reply_markup') or [])
        if len(reply_markup) >= 1:
            reply_markup.insert(-1, [{'text': '📈 训练总览', 'callback_data': 'adm:training:overview'}, {'text': '🪵 调用日志', 'callback_data': 'adm:training:logs'}])
        menu['reply_markup'] = reply_markup
        return menu

    @staticmethod
    def training_category_menu(training_category: str) -> list[list[dict[str, str]]]:
        rows = list(super(TGAdminMenuBuilder, TGAdminMenuBuilder).training_category_menu(training_category))
        rows.insert(2, [{'text': '批量启用本类', 'callback_data': f'adm:training:batch:{training_category}:enable'}, {'text': '批量停用本类', 'callback_data': f'adm:training:batch:{training_category}:disable'}])
        return rows


class TGAdminCallbackRouter(TGAdminCallbackRouter):
    def handle(self, admin_chat_id: int, callback_data: str, operator: str = 'admin') -> None:
        parts = (callback_data or '').split(':')
        if parts[:2] == ['adm', 'training']:
            business_account_id = self._resolve_business_account_id()
            if business_account_id is None:
                self._send_text(admin_chat_id, '⚠️ 当前还没有可用业务账号，请先让机器人收到至少一条业务消息。')
                return
            if len(parts) >= 3 and parts[2] == 'overview':
                summary_rows = self.admin_api_service.summarize_training_items_admin(business_account_id)
                recent_logs = self.admin_api_service.list_training_usage_logs_admin(business_account_id, 12)
                self._send_text(admin_chat_id, TGAdminFormatter.format_training_overview(summary_rows, recent_logs), [[{'text': '🧠 返回训练中心', 'callback_data': 'adm:training'}], [{'text': '🏠 主菜单', 'callback_data': 'adm:main'}]])
                return
            if len(parts) >= 3 and parts[2] == 'logs':
                logs = self.admin_api_service.list_training_usage_logs_admin(business_account_id, 20)
                self._send_text(admin_chat_id, TGAdminFormatter.format_training_usage_logs(logs), [[{'text': '🧠 返回训练中心', 'callback_data': 'adm:training'}], [{'text': '🏠 主菜单', 'callback_data': 'adm:main'}]])
                return
            if len(parts) >= 5 and parts[2] == 'batch':
                category = parts[3]
                action = parts[4]
                is_enabled = action == 'enable'
                result = self.admin_api_service.batch_toggle_training_items_admin(business_account_id, category, is_enabled)
                if not result.get('ok'):
                    self._send_text(admin_chat_id, f"❌ 批量操作失败：{result.get('reason') or '未知错误'}")
                    return
                text_value = TGAdminFormatter.format_training_batch_result(category, int(result.get('affected_count') or 0), is_enabled)
                self._send_text(admin_chat_id, text_value, [[{'text': '🔙 返回分类', 'callback_data': f'adm:training:category:{category}'}], [{'text': '🧠 返回训练中心', 'callback_data': 'adm:training'}]])
                return
        return super().handle(admin_chat_id, callback_data, operator)


class Orchestrator(Orchestrator):
    def __init__(self, conversation_repo: ConversationRepository, user_repo: UserRepository, settings_repo: SettingsRepository,
                 user_control_repo: UserControlRepository, business_account_repo: BusinessAccountRepository,
                 bootstrap_repo: BootstrapRepository, receipt_repo: ReceiptRepository, admin_queue_repo: AdminQueueRepository,
                 material_repo: MaterialRepository, project_repo: ProjectRepository, script_repo: ScriptRepository,
                 persona_core: PersonaCore, persona_profile_builder: PersonaProfileBuilder,
                 understanding_engine: UserUnderstandingEngine, stage_engine: ConversationStageEngine,
                 mode_router: ChatModeRouter, reply_planner: ReplyPlanner, reply_style_engine: ReplyStyleEngine,
                 reply_self_check_engine: ReplySelfCheckEngine, reply_delay_engine: ReplyDelayEngine,
                 ai_switch_engine: AISwitchEngine, project_classifier: ProjectClassifier,
                 project_segment_manager: ProjectSegmentManager, tagging_engine: TaggingEngine,
                 intent_engine: IntentEngine, human_escalation_engine: HumanEscalationEngine,
                 ops_category_manager: OpsCategoryManager, content_selector: ContentSelector,
                 sender_service: SenderService, memory_manager: ConversationMemoryManager,
                 runtime_policy_repo: RuntimePolicyRepository,
                 pacing_state_repo: PacingStateRepository,
                 proactive_followup_repo: ProactiveFollowupPlanRepository,
                 work_hours_engine: WorkHoursEngine,
                 proactive_followup_engine: ProactiveFollowupEngine,
                 handover_repo: HandoverRepository | None = None,
                 admin_notifier: AdminNotifier | None = None,
                 media_understanding_service: MediaUnderstandingService | None = None) -> None:
        super().__init__(
            conversation_repo, user_repo, settings_repo, user_control_repo, business_account_repo,
            bootstrap_repo, receipt_repo, admin_queue_repo, material_repo, project_repo, script_repo,
            persona_core, persona_profile_builder, understanding_engine, stage_engine,
            mode_router, reply_planner, reply_style_engine, reply_self_check_engine,
            reply_delay_engine, ai_switch_engine, project_classifier, project_segment_manager,
            tagging_engine, intent_engine, human_escalation_engine, ops_category_manager,
            content_selector, sender_service, memory_manager,
            runtime_policy_repo, pacing_state_repo, proactive_followup_repo,
            work_hours_engine, proactive_followup_engine,
            handover_repo, admin_notifier,
        )
        self.media_understanding_service = media_understanding_service

    def handle_inbound_message(self, inbound_message: InboundMessage) -> None:
        enriched = inbound_message
        if self.media_understanding_service:
            try:
                enriched = self.media_understanding_service.enrich_inbound_message(inbound_message)
            except Exception:
                logger.exception('Step12 step6 media understanding failed; using original inbound message.')
        return super().handle_inbound_message(enriched)


_STEP12_STEP6_BASE_BUILD_APP_COMPONENTS = build_app_components

def build_app_components(settings: Settings) -> dict[str, Any]:
    app_components = _STEP12_STEP6_BASE_BUILD_APP_COMPONENTS(settings)
    media_understanding_service = MediaUnderstandingService(
        app_components.get('tg_client'),
        app_components.get('llm_service'),
    )
    orchestrator = app_components.get('orchestrator')
    if orchestrator is not None:
        setattr(orchestrator, 'media_understanding_service', media_understanding_service)
    app_components['media_understanding_service'] = media_understanding_service
    return app_components




@dataclass
class EmotionBoundarySnapshot:
    emotion: str = 'neutral'
    emotion_intensity: float = 0.0
    social_energy: str = 'normal'
    boundary_signal: str | None = None
    boundary_strength: float = 0.0
    needs_space: bool = False
    pressure_risk: str = 'low'
    cues: list[str] = field(default_factory=list)
    source: str = 'heuristic'


class EmotionEngine:
    POSITIVE_KEYWORDS = [
        'happy', 'great', 'good', 'glad', 'nice', 'love', 'excited', 'amazing', 'wonderful', 'haha', 'lol',
        '不错', '开心', '高兴', '喜欢', '太好了', '哈哈'
    ]
    LOW_KEYWORDS = [
        'tired', 'exhausted', 'drained', 'sleepy', 'down', 'sad', 'upset', 'long day', 'worn out', 'burned out',
        '累', '困', '难过', '烦', '没精神', '疲惫'
    ]
    ANXIOUS_KEYWORDS = [
        'worried', 'concerned', 'anxious', 'nervous', 'unsure', 'not sure', 'uncertain', 'afraid', 'risk', 'scared',
        '担心', '焦虑', '不确定', '害怕', '怕', '风险'
    ]
    RESISTANT_KEYWORDS = [
        'pushy', 'sales', 'salesperson', 'scam', 'fake', 'annoyed', 'stop', 'leave me alone', 'not interested',
        'too much', 'bother', '烦人', '别发了', '别烦', '不要联系', '假的', '骗人', '推销'
    ]
    LOW_ENERGY_SHORT_REPLIES = {'ok', 'okay', 'k', 'kk', 'sure', 'fine', 'later', 'busy', 'maybe', '嗯', '哦', '行', '好'}

    def analyze(self, latest_user_message: str, recent_context: list[dict[str, Any]] | None = None) -> EmotionBoundarySnapshot:
        text = str(latest_user_message or '').strip()
        lowered = text.lower()
        cues: list[str] = []
        positive_hits = sum(1 for key in self.POSITIVE_KEYWORDS if key in lowered)
        low_hits = sum(1 for key in self.LOW_KEYWORDS if key in lowered)
        anxious_hits = sum(1 for key in self.ANXIOUS_KEYWORDS if key in lowered)
        resistant_hits = sum(1 for key in self.RESISTANT_KEYWORDS if key in lowered)
        short_reply = lowered in self.LOW_ENERGY_SHORT_REPLIES or (len(lowered) <= 8 and lowered in self.LOW_ENERGY_SHORT_REPLIES)
        if short_reply:
            cues.append('short_reply')
        if positive_hits:
            cues.append('positive_words')
        if low_hits:
            cues.append('low_energy_words')
        if anxious_hits:
            cues.append('anxious_words')
        if resistant_hits:
            cues.append('resistance_words')

        emotion = 'neutral'
        intensity = 0.18
        social_energy = 'normal'
        pressure_risk = 'low'

        if resistant_hits:
            emotion = 'resistant'
            intensity = min(1.0, 0.55 + 0.12 * resistant_hits)
            social_energy = 'guarded'
            pressure_risk = 'high'
        elif anxious_hits:
            emotion = 'anxious'
            intensity = min(1.0, 0.45 + 0.10 * anxious_hits)
            social_energy = 'fragile'
            pressure_risk = 'medium'
        elif low_hits or short_reply:
            emotion = 'low'
            intensity = min(1.0, 0.35 + 0.10 * max(low_hits, 1 if short_reply else 0))
            social_energy = 'low'
            pressure_risk = 'medium' if low_hits else 'low'
        elif positive_hits:
            emotion = 'positive'
            intensity = min(1.0, 0.32 + 0.08 * positive_hits)
            social_energy = 'open'
            pressure_risk = 'low'

        if recent_context:
            recent_user_msgs = [str((msg or {}).get('content_text') or '') for msg in recent_context[-4:] if str((msg or {}).get('sender_type') or '') == 'user']
            recent_blob = ' | '.join(recent_user_msgs).lower()
            if emotion == 'neutral' and recent_blob:
                if any(key in recent_blob for key in self.RESISTANT_KEYWORDS):
                    emotion = 'resistant'
                    intensity = max(intensity, 0.52)
                    social_energy = 'guarded'
                    pressure_risk = 'high'
                    cues.append('recent_resistance')
                elif any(key in recent_blob for key in self.LOW_KEYWORDS):
                    emotion = 'low'
                    intensity = max(intensity, 0.38)
                    social_energy = 'low'
                    pressure_risk = 'medium'
                    cues.append('recent_low_energy')
        return EmotionBoundarySnapshot(
            emotion=emotion,
            emotion_intensity=round(float(intensity), 3),
            social_energy=social_energy,
            pressure_risk=pressure_risk,
            cues=_training_dedup_strings(cues, 8),
            source='emotion_engine',
        )


class BoundarySignalEngine:
    NEEDS_SPACE_PATTERNS = [
        'not now', 'maybe later', 'too much', 'slow down', 'give me space', 'leave it here', 'i need space',
        '先这样', '晚点再说', '给我点空间', '别急', '先别说这个', '先这样吧'
    ]

    def analyze(self, latest_user_message: str, existing_boundary: str | None = None,
                emotion_snapshot: EmotionBoundarySnapshot | None = None) -> EmotionBoundarySnapshot:
        text = str(latest_user_message or '').strip().lower()
        cues: list[str] = []
        boundary = existing_boundary or _step9_boundary_signal_from_text(text)
        needs_space = False
        strength = 0.0
        pressure_risk = str((emotion_snapshot.pressure_risk if emotion_snapshot else 'low') or 'low')

        if boundary:
            cues.append(f'boundary:{boundary}')
            strength = 0.72 if boundary == 'stop' else 0.56
            if boundary in ('busy', 'later', 'sleep', 'stop'):
                needs_space = True
        if not boundary and any(pattern in text for pattern in self.NEEDS_SPACE_PATTERNS):
            boundary = 'needs_space'
            needs_space = True
            strength = 0.64
            cues.append('boundary:needs_space')

        if emotion_snapshot and emotion_snapshot.emotion in ('resistant', 'anxious') and not boundary:
            boundary = 'needs_space' if emotion_snapshot.emotion == 'resistant' else None
            if boundary:
                needs_space = True
                strength = max(strength, 0.48)
                cues.append('emotion_implied_space')

        if emotion_snapshot and emotion_snapshot.emotion == 'resistant':
            pressure_risk = 'high'
        elif needs_space and pressure_risk == 'low':
            pressure_risk = 'medium'

        return EmotionBoundarySnapshot(
            emotion=(emotion_snapshot.emotion if emotion_snapshot else 'neutral'),
            emotion_intensity=(emotion_snapshot.emotion_intensity if emotion_snapshot else 0.0),
            social_energy=(emotion_snapshot.social_energy if emotion_snapshot else 'normal'),
            boundary_signal=boundary,
            boundary_strength=round(float(strength), 3),
            needs_space=needs_space,
            pressure_risk=pressure_risk,
            cues=_training_dedup_strings(cues + list((emotion_snapshot.cues if emotion_snapshot else [])), 10),
            source='boundary_signal_engine',
        )


def _step13_merge_emotion_boundary_payload(payload: dict[str, Any], latest_user_message: str,
                                           emotion_snapshot: EmotionBoundarySnapshot | None,
                                           boundary_snapshot: EmotionBoundarySnapshot | None) -> dict[str, Any]:
    merged = dict(payload or {})
    reason_bits: list[str] = []
    existing_reason = str(merged.get('reason') or '').strip()
    if existing_reason:
        reason_bits.append(existing_reason)
    emotion = str((emotion_snapshot.emotion if emotion_snapshot else '') or '').strip().lower()
    boundary = str((boundary_snapshot.boundary_signal if boundary_snapshot else '') or '').strip().lower()
    pressure_risk = str((boundary_snapshot.pressure_risk if boundary_snapshot else emotion_snapshot.pressure_risk if emotion_snapshot else '') or '').strip().lower()

    if emotion in ('positive', 'low', 'anxious', 'resistant'):
        merged['emotion_state'] = emotion
        reason_bits.append(f'emotion={emotion}')

    if boundary:
        merged['boundary_signal'] = boundary
        reason_bits.append(f'boundary={boundary}')

    if emotion == 'resistant':
        merged['resistance_signal'] = 'high'
        merged['user_intent'] = 'objection'
        merged['need_type'] = 'pressure_relief'
        merged['recommended_chat_mode'] = 'daily'
        merged['recommended_goal'] = 'lower_pressure'
        merged['current_mainline_should_continue'] = 'daily'
    elif emotion == 'anxious' and not bool(merged.get('explicit_product_query')):
        merged['resistance_signal'] = str(merged.get('resistance_signal') or 'medium')
        merged['user_intent'] = 'emotional_expression'
        merged['need_type'] = 'emotional_support'
        merged['recommended_chat_mode'] = 'emotional'
        merged['recommended_goal'] = 'emotional_support'
        merged['current_mainline_should_continue'] = 'emotional'
    elif emotion == 'low' and not bool(merged.get('explicit_product_query')) and not str(merged.get('boundary_signal') or '').strip():
        merged['recommended_chat_mode'] = 'emotional'
        merged['recommended_goal'] = 'emotional_support'
        merged['current_mainline_should_continue'] = 'emotional'

    if boundary in ('busy', 'later', 'sleep', 'stop', 'needs_space'):
        merged['boundary_signal'] = boundary
        merged['current_mainline_should_continue'] = 'pause'
        merged['recommended_chat_mode'] = 'pause'
        merged['recommended_goal'] = 'pause_respect'
        if boundary in ('stop', 'needs_space'):
            merged['resistance_signal'] = 'high' if boundary == 'stop' else str(merged.get('resistance_signal') or 'medium')
        reason_bits.append('space_respect')

    if pressure_risk == 'high' and not str(merged.get('resistance_signal') or '').strip():
        merged['resistance_signal'] = 'medium'
    if pressure_risk:
        merged['pressure_risk'] = pressure_risk
    if boundary_snapshot:
        merged['boundary_analysis'] = {
            'signal': boundary_snapshot.boundary_signal,
            'strength': boundary_snapshot.boundary_strength,
            'needs_space': boundary_snapshot.needs_space,
            'pressure_risk': boundary_snapshot.pressure_risk,
            'cues': boundary_snapshot.cues,
        }
    if emotion_snapshot:
        merged['emotion_analysis'] = {
            'emotion': emotion_snapshot.emotion,
            'intensity': emotion_snapshot.emotion_intensity,
            'social_energy': emotion_snapshot.social_energy,
            'pressure_risk': emotion_snapshot.pressure_risk,
            'cues': emotion_snapshot.cues,
        }
    if reason_bits:
        merged['reason'] = ' | '.join(_training_dedup_strings(reason_bits, 10))
    return merged


_STEP13_STEP7_BASE_USER_UNDERSTANDING_ENGINE = UserUnderstandingEngine
class UserUnderstandingEngine(_STEP13_STEP7_BASE_USER_UNDERSTANDING_ENGINE):
    def analyze(self, latest_user_message: str, recent_context: list[dict], persona_core_summary: str,
                user_state_summary: str, long_term_memory_summary: str = "",
                training_packet: TrainingPacket | None = None) -> UnderstandingResult:
        result = super().analyze(
            latest_user_message,
            recent_context,
            persona_core_summary,
            user_state_summary,
            long_term_memory_summary,
            training_packet=training_packet,
        )
        emotion_engine = getattr(self, 'emotion_engine', None) or EmotionEngine()
        boundary_signal_engine = getattr(self, 'boundary_signal_engine', None) or BoundarySignalEngine()
        emotion_snapshot = emotion_engine.analyze(latest_user_message, recent_context)
        boundary_snapshot = boundary_signal_engine.analyze(latest_user_message, result.boundary_signal, emotion_snapshot)
        merged = _step13_merge_emotion_boundary_payload(result.__dict__, latest_user_message, emotion_snapshot, boundary_snapshot)
        try:
            setattr(self, '_last_emotion_snapshot', emotion_snapshot)
            setattr(self, '_last_boundary_snapshot', boundary_snapshot)
        except Exception:
            pass
        allowed_fields = {key: merged.get(key) for key in UnderstandingResult.__dataclass_fields__.keys()}
        return UnderstandingResult(**allowed_fields)


_STEP13_STEP7_BASE_REPLY_PLANNER = ReplyPlanner
class ReplyPlanner(_STEP13_STEP7_BASE_REPLY_PLANNER):
    def plan(self, understanding: UnderstandingResult, stage_decision: StageDecision, mode_decision: ModeDecision,
             user_state: UserStateSnapshot, training_packet: TrainingPacket | None = None) -> ReplyPlan:
        plan = super().plan(understanding, stage_decision, mode_decision, user_state, training_packet=training_packet)
        emotion = str(getattr(understanding, 'emotion_state', '') or '').lower()
        boundary = str(getattr(understanding, 'boundary_signal', '') or '').lower()
        resistance = str(getattr(understanding, 'resistance_signal', '') or '').lower()

        if boundary in ('stop', 'needs_space'):
            plan.should_continue_product = False
            plan.should_send_material = False
            plan.should_self_share = False
            plan.should_leave_space = True
            plan.goal = 'pause_respect'
            plan.reason = (plan.reason or '') + ' | step7=needs_space'
            return plan

        if boundary in ('busy', 'later', 'sleep'):
            plan.should_continue_product = False
            plan.should_send_material = False
            plan.should_self_share = False
            plan.should_leave_space = True
            if plan.goal not in ('identity_safe_reply', 'pause_respect'):
                plan.goal = 'pause_respect'
            plan.reason = (plan.reason or '') + ' | step7=boundary_pause'

        if emotion in ('low', 'anxious') and not understanding.explicit_product_query:
            plan.should_continue_product = False
            plan.should_send_material = False
            plan.should_self_share = False if emotion == 'anxious' else plan.should_self_share
            if plan.goal not in ('identity_safe_reply', 'pause_respect'):
                plan.goal = 'emotional_support'
            plan.reason = (plan.reason or '') + f' | step7=emotion_{emotion}'

        if emotion == 'resistant' or resistance == 'high':
            plan.should_continue_product = False
            plan.should_send_material = False
            plan.should_self_share = False
            plan.should_leave_space = True
            if plan.goal not in ('identity_safe_reply', 'pause_respect'):
                plan.goal = 'lower_pressure'
            plan.reason = (plan.reason or '') + ' | step7=pressure_relief'
        return plan


_STEP13_STEP7_BASE_REPLY_DELAY_ENGINE = ReplyDelayEngine
class ReplyDelayEngine(_STEP13_STEP7_BASE_REPLY_DELAY_ENGINE):
    def decide_delay_seconds(self, understanding: UnderstandingResult, mode: str, reply_text: str,
                             training_packet: TrainingPacket | None = None) -> int:
        delay = int(super().decide_delay_seconds(understanding, mode, reply_text, training_packet=training_packet))
        emotion = str(getattr(understanding, 'emotion_state', '') or '').lower()
        boundary = str(getattr(understanding, 'boundary_signal', '') or '').lower()
        resistance = str(getattr(understanding, 'resistance_signal', '') or '').lower()

        if boundary in ('busy', 'later', 'sleep', 'stop', 'needs_space'):
            delay = max(1, min(delay, 4))
        if emotion in ('low', 'anxious'):
            delay = max(delay, 3)
        if emotion == 'resistant' or resistance == 'high':
            delay = max(delay, 4)
        if emotion == 'positive' and not boundary and mode in ('daily', 'maintain'):
            delay = max(1, delay - 1)
        return max(1, min(int(delay), 12))


_STEP13_STEP7_BASE_ORCHESTRATOR = Orchestrator
class Orchestrator(_STEP13_STEP7_BASE_ORCHESTRATOR):
    def _build_training_packet(self, business_account_id: int, runtime_context: dict[str, Any]) -> TrainingPacket:
        packet = super()._build_training_packet(business_account_id, runtime_context)
        try:
            setattr(self.reply_planner, '_runtime_training_packet', packet)
        except Exception:
            pass
        return packet


_STEP13_STEP7_BASE_BUILD_APP_COMPONENTS = build_app_components

def build_app_components(settings: Settings) -> dict[str, Any]:
    app_components = _STEP13_STEP7_BASE_BUILD_APP_COMPONENTS(settings)
    emotion_engine = EmotionEngine()
    boundary_signal_engine = BoundarySignalEngine()
    understanding_engine = app_components.get('orchestrator').understanding_engine if app_components.get('orchestrator') else None
    if understanding_engine is not None:
        setattr(understanding_engine, 'emotion_engine', emotion_engine)
        setattr(understanding_engine, 'boundary_signal_engine', boundary_signal_engine)
    app_components['emotion_engine'] = emotion_engine
    app_components['boundary_signal_engine'] = boundary_signal_engine
    return app_components



# =========================
# step13 media enhancement (step6 plus)
# =========================

STEP13_MEDIA_SEMANTIC_KEYWORDS: dict[str, tuple[str, ...]] = {
    'user_selfie': ('selfie', 'portrait', 'face close', 'mirror selfie', 'self portrait', 'my face'),
    'gym': ('gym', 'fitness', 'workout', 'exercise', 'training', 'dumbbell', 'treadmill'),
    'food': ('food', 'meal', 'dinner', 'lunch', 'breakfast', 'coffee', 'drink', 'restaurant', 'cafe', 'dessert'),
    'travel': ('travel', 'trip', 'airport', 'flight', 'plane', 'hotel', 'vacation', 'holiday', 'beach', 'mountain', 'tour'),
    'work_scene': ('office', 'desk', 'workspace', 'laptop', 'meeting', 'presentation', 'coworker', 'work'),
    'luxury': ('luxury', 'designer', 'watch', 'jewelry', 'handbag', 'bag', 'sports car', 'supercar', 'champagne', 'villa', 'yacht'),
    'fashion': ('outfit', 'dress', 'style', 'fashion', 'look', 'makeup'),
    'pet': ('dog', 'cat', 'pet', 'puppy', 'kitten'),
    'family': ('family', 'baby', 'child', 'kid', 'parents'),
    'document': ('document', 'contract', 'agreement', 'statement', 'invoice', 'certificate', 'form', 'paper', 'screenshot'),
    'chart': ('chart', 'graph', 'trend', 'performance chart', 'price chart', 'curve', 'statistics', 'dashboard'),
    'yield': ('yield', 'returns', 'return', 'profit', 'earnings', 'pnl', 'apy', 'income', 'roi'),
    'risk': ('risk', 'safety', 'secure', 'security', 'downside', 'loss', 'drawdown', 'protection'),
    'project_material': ('platform', 'app screen', 'product page', 'roadmap', 'interface', 'dashboard', 'project intro', 'proof'),
}
STEP13_DAILY_MEDIA_TAGS = {'user_selfie', 'gym', 'food', 'travel', 'work_scene', 'luxury', 'fashion', 'pet', 'family'}
STEP13_PRODUCT_MEDIA_TAGS = {'document', 'chart', 'yield', 'risk', 'project_material'}
STEP13_GENERIC_MEDIA_TAGS = {'image_shared', 'video_shared', 'voice_shared', 'media_shared'}
STEP13_ALL_MEDIA_TAGS = set(STEP13_MEDIA_SEMANTIC_KEYWORDS.keys()) | STEP13_DAILY_MEDIA_TAGS | STEP13_PRODUCT_MEDIA_TAGS | STEP13_GENERIC_MEDIA_TAGS


def _step13_media_extract_tags_from_text(text: str, message_type: str = '') -> list[str]:
    blob = str(text or '').strip().lower()
    tags: list[str] = []
    if not blob:
        if message_type:
            base = {'image': 'image_shared', 'video': 'video_shared', 'voice': 'voice_shared'}.get(message_type)
            return [base, 'media_shared'] if base else []
        return []
    for tag, keywords in STEP13_MEDIA_SEMANTIC_KEYWORDS.items():
        if any(keyword in blob for keyword in keywords):
            tags.append(tag)
    if message_type == 'image':
        tags.append('image_shared')
    elif message_type == 'video':
        tags.append('video_shared')
    elif message_type == 'voice':
        tags.append('voice_shared')
    if message_type in ('image', 'video', 'voice', 'file'):
        tags.append('media_shared')
    return _training_dedup_strings(tags, 20)


def _step13_media_scene_type(tags: list[str], message_type: str) -> str:
    tag_set = {str(tag or '').strip().lower() for tag in (tags or []) if str(tag).strip()}
    if tag_set & STEP13_PRODUCT_MEDIA_TAGS:
        return 'product_media'
    if tag_set & STEP13_DAILY_MEDIA_TAGS:
        return 'daily_media'
    if message_type == 'voice':
        return 'voice_message'
    if message_type == 'video':
        return 'video_media'
    if message_type == 'image':
        return 'image_media'
    return 'media_shared'


def _step13_voice_emotion_from_transcript(text: str) -> str:
    lowered = str(text or '').strip().lower()
    if not lowered:
        return ''
    annoyed_words = ('annoyed', 'irritated', 'stop', 'too much', '烦', '别', '不要')
    tired_words = ('tired', 'sleepy', 'exhausted', 'long day', 'late', '累', '困', '没精神')
    excited_words = ('excited', 'amazing', 'great', 'love it', 'awesome', '开心', '高兴', '喜欢', '太好了')
    if any(word in lowered for word in annoyed_words):
        return 'annoyed'
    if any(word in lowered for word in tired_words):
        return 'tired'
    if any(word in lowered for word in excited_words):
        return 'excited'
    return 'neutral'


def _step13_material_semantic_profile(item: dict[str, Any] | None, default_scope: str = '') -> dict[str, Any]:
    row = dict(item or {})
    tags = [str(tag).strip().lower() for tag in (row.get('scene_tags_json') or []) if str(tag).strip()]
    if row.get('scene_tags') and not tags:
        tags = [str(tag).strip().lower() for tag in (row.get('scene_tags') or []) if str(tag).strip()]
    text_parts = [
        str(row.get('content_text') or ''),
        str(row.get('caption_text') or ''),
        str(row.get('description') or ''),
        str(row.get('package_name') or ''),
        str(row.get('package_kind') or ''),
        str(row.get('category') or ''),
        str(row.get('material_type') or row.get('item_type') or ''),
        str(row.get('media_url') or ''),
    ]
    meta = row.get('item_meta_json') or {}
    if isinstance(meta, dict):
        text_parts.append(str(meta.get('title') or ''))
        text_parts.append(str(meta.get('summary') or ''))
    inferred = _step13_media_extract_tags_from_text(' | '.join(text_parts), str(row.get('material_type') or row.get('item_type') or ''))
    merged_tags = _training_dedup_strings(tags + inferred, 20)
    if default_scope:
        merged_tags = _training_dedup_strings(merged_tags + [f'{default_scope}_material'], 22)
    summary_source = str(row.get('content_text') or row.get('caption_text') or row.get('description') or row.get('package_name') or row.get('media_url') or '').strip()
    summary = summary_source[:160]
    media_type = str(row.get('material_type') or row.get('item_type') or row.get('package_kind') or row.get('category') or '').strip().lower()
    if row.get('media_url') and not media_type:
        media_type = 'media'
    return {
        'tags': merged_tags,
        'summary': summary,
        'media_type': media_type,
        'scope': default_scope or str(row.get('package_scope') or '').strip().lower(),
    }


def _step13_query_semantic_tags(scene_tags: list[str] | None) -> list[str]:
    normalized = [str(tag or '').strip().lower() for tag in (scene_tags or []) if str(tag).strip()]
    relevant = [tag for tag in normalized if tag in STEP13_ALL_MEDIA_TAGS or tag in ('product_consult', 'daily_chat', 'objection', 'pause_request', 'returns', 'safety', 'process', 'high_intent')]
    return _training_dedup_strings(relevant, 20)


def _step13_score_material_profile(profile: dict[str, Any], query_tags: list[str], mode: str, should_send_material: bool) -> float:
    tags = {str(tag).strip().lower() for tag in (profile.get('tags') or []) if str(tag).strip()}
    query = {str(tag).strip().lower() for tag in (query_tags or []) if str(tag).strip()}
    score = 0.0
    overlap = tags & query
    score += float(len(overlap)) * 2.5
    if mode in ('product', 'high_intent') and tags & STEP13_PRODUCT_MEDIA_TAGS:
        score += 2.0
    if mode in ('daily', 'maintain', 'emotional') and tags & STEP13_DAILY_MEDIA_TAGS:
        score += 1.8
    if should_send_material and tags & {'project_material', 'chart', 'yield', 'document'}:
        score += 1.0
    if not should_send_material and tags & STEP13_PRODUCT_MEDIA_TAGS:
        score -= 1.2
    if 'daily_chat' in query and tags & STEP13_PRODUCT_MEDIA_TAGS:
        score -= 1.0
    if 'product_consult' in query and tags & STEP13_DAILY_MEDIA_TAGS:
        score -= 0.6
    return score


def _step13_rank_material_items(items: list[dict[str, Any]], query_tags: list[str], mode: str,
                                should_send_material: bool, default_scope: str, limit: int) -> list[dict[str, Any]]:
    scored: list[tuple[float, dict[str, Any]]] = []
    for item in items:
        profile = _step13_material_semantic_profile(item, default_scope)
        score = _step13_score_material_profile(profile, query_tags, mode, should_send_material)
        enriched = dict(item)
        enriched['semantic_profile'] = profile
        enriched['semantic_score'] = round(float(score), 3)
        scored.append((score, enriched))
    scored.sort(key=lambda pair: (-pair[0], int(pair[1].get('priority') or 100), int(pair[1].get('id') or 0)))
    if not scored:
        return []
    picked = [row for score, row in scored[:max(1, limit)] if score > 0]
    if picked:
        return picked
    return [row for _, row in scored[:max(1, limit)]]


def _step13_rank_material_packages(repo: MaterialRepository, business_account_id: int, package_scope: str,
                                   project_id: int | None, query_tags: list[str], mode: str,
                                   should_send_material: bool, limit: int = 1) -> list[dict[str, Any]]:
    if package_scope == 'project' and not project_id:
        return []
    rows = repo.list_material_packages(business_account_id, package_scope, project_id)
    scored: list[tuple[float, dict[str, Any]]] = []
    for row in rows:
        profile = _step13_material_semantic_profile(row, package_scope)
        score = _step13_score_material_profile(profile, query_tags, mode, should_send_material)
        built = repo.build_material_package(row)
        built['semantic_profile'] = profile
        built['semantic_score'] = round(float(score), 3)
        scored.append((score, built))
    scored.sort(key=lambda pair: (-pair[0], int(pair[1].get('priority') or 100), int(pair[1].get('id') or 0)))
    if not scored:
        return []
    picked = [pkg for score, pkg in scored[:max(1, limit)] if score > 0]
    if picked:
        return picked
    return [pkg for _, pkg in scored[:max(1, limit)]]


def _step13_media_match_summary(selected: dict[str, Any]) -> str:
    parts: list[str] = []
    for scope_key in ('project_materials', 'persona_materials', 'daily_materials'):
        for item in (selected.get(scope_key) or [])[:3]:
            profile = item.get('semantic_profile') or {}
            summary = str(profile.get('summary') or '')[:80]
            score = item.get('semantic_score')
            if summary:
                parts.append(f"{scope_key}:{summary}#{score}")
    for scope_key, packages in (selected.get('material_packages') or {}).items():
        for package in (packages or [])[:1]:
            summary = str((package.get('semantic_profile') or {}).get('summary') or package.get('package_name') or '')[:80]
            score = package.get('semantic_score')
            if summary:
                parts.append(f"{scope_key}_package:{summary}#{score}")
    return ' | '.join(parts)[:400]


_STEP13_STEP7_BASE_MEDIA_UNDERSTANDING_SERVICE = MediaUnderstandingService
class MediaUnderstandingService(_STEP13_STEP7_BASE_MEDIA_UNDERSTANDING_SERVICE):
    def analyze_inbound_message(self, inbound_message: InboundMessage) -> dict[str, Any]:
        analysis = super().analyze_inbound_message(inbound_message)
        media_meta = dict(analysis.get('media_meta') or {})
        message_type = str(analysis.get('message_type') or inbound_message.message_type or 'text').strip().lower()
        caption = str(media_meta.get('caption') or media_meta.get('caption_text') or '').strip()
        file_name = str(media_meta.get('file_name') or '').strip()
        semantic_blob = ' | '.join([
            str(analysis.get('media_summary') or ''),
            str(analysis.get('image_description') or ''),
            str(analysis.get('voice_transcript') or ''),
            caption,
            file_name,
        ])
        media_tags = _step13_media_extract_tags_from_text(semantic_blob, message_type)
        voice_emotion = _step13_voice_emotion_from_transcript(str(analysis.get('voice_transcript') or '')) if message_type == 'voice' else ''
        if voice_emotion:
            media_tags = _training_dedup_strings(media_tags + [f'voice_{voice_emotion}'], 22)
        topic_tags = [tag for tag in media_tags if tag in STEP13_DAILY_MEDIA_TAGS or tag in STEP13_PRODUCT_MEDIA_TAGS]
        scene_type = _step13_media_scene_type(media_tags, message_type)
        if media_tags and message_type in ('image', 'video', 'voice', 'file'):
            semantic_hint = ', '.join(topic_tags[:4] or media_tags[:4])
            effective = str(analysis.get('effective_user_text') or '').strip()
            if semantic_hint:
                media_hint = f"shared {message_type} context: {semantic_hint}"
                if media_hint.lower() not in effective.lower():
                    analysis['effective_user_text'] = (effective + "\n[" + media_hint + "]").strip() if effective else f"[{media_hint}]"
        analysis['media_tags'] = media_tags
        analysis['topic_tags'] = topic_tags
        analysis['scene_type'] = scene_type
        analysis['voice_emotion'] = voice_emotion
        analysis['semantic_blob'] = semantic_blob[:400]
        return analysis

    def enrich_inbound_message(self, inbound_message: InboundMessage) -> InboundMessage:
        analysis = self.analyze_inbound_message(inbound_message)
        raw_payload = dict(inbound_message.raw_payload or {})
        raw_payload['step6_media_analysis'] = {
            'message_type': analysis.get('message_type'),
            'media_summary': analysis.get('media_summary'),
            'image_description': analysis.get('image_description'),
            'voice_transcript': analysis.get('voice_transcript'),
            'media_meta': analysis.get('media_meta'),
            'media_tags': analysis.get('media_tags') or [],
            'topic_tags': analysis.get('topic_tags') or [],
            'scene_type': analysis.get('scene_type'),
            'voice_emotion': analysis.get('voice_emotion') or None,
        }
        effective_text = str(analysis.get('effective_user_text') or '').strip()
        return replace(
            inbound_message,
            text=effective_text or inbound_message.text,
            media_url=analysis.get('media_url') or inbound_message.media_url,
            raw_payload=raw_payload,
        )


_STEP13_STEP7_BASE_TRAINING_RETRIEVAL_SERVICE = TrainingRetrievalService
class TrainingRetrievalService(_STEP13_STEP7_BASE_TRAINING_RETRIEVAL_SERVICE):
    @staticmethod
    def _infer_scene_tags(runtime_context: dict[str, Any]) -> list[str]:
        tags = list(_STEP13_STEP7_BASE_TRAINING_RETRIEVAL_SERVICE._infer_scene_tags(runtime_context))
        for tag in list(runtime_context.get('media_tags') or [])[:12]:
            normalized = str(tag or '').strip().lower()
            if normalized:
                tags.append(normalized)
        media_scene = str(runtime_context.get('media_scene_type') or '').strip().lower()
        if media_scene:
            tags.append(media_scene)
        for tag in list(runtime_context.get('media_topic_tags') or [])[:8]:
            normalized = str(tag or '').strip().lower()
            if normalized:
                tags.append(normalized)
        voice_emotion = str(runtime_context.get('voice_emotion') or '').strip().lower()
        if voice_emotion:
            tags.append(f'voice_{voice_emotion}')
        return _training_dedup_strings(tags, 24)


_STEP13_STEP7_BASE2_USER_UNDERSTANDING_ENGINE = UserUnderstandingEngine
class UserUnderstandingEngine(_STEP13_STEP7_BASE2_USER_UNDERSTANDING_ENGINE):
    def analyze(self, latest_user_message: str, recent_context: list[dict], persona_core_summary: str,
                user_state_summary: str, long_term_memory_summary: str = '',
                training_packet: TrainingPacket | None = None) -> UnderstandingResult:
        result = super().analyze(latest_user_message, recent_context, persona_core_summary, user_state_summary, long_term_memory_summary, training_packet=training_packet)
        scene_tags = {str(tag or '').strip().lower() for tag in ((training_packet.scene_tags if training_packet else []) or []) if str(tag).strip()}
        merged = dict(result.__dict__)
        reason_bits = [str(merged.get('reason') or '').strip()] if str(merged.get('reason') or '').strip() else []
        protected_intents = {'identity_probe', 'pause_request', 'objection'}
        if merged.get('user_intent') not in protected_intents:
            if scene_tags & STEP13_PRODUCT_MEDIA_TAGS:
                merged['user_intent'] = 'product_consult'
                if scene_tags & {'yield', 'chart'}:
                    merged['need_type'] = 'returns'
                elif scene_tags & {'risk', 'document'}:
                    merged['need_type'] = 'safety'
                else:
                    merged['need_type'] = 'product_info'
                merged['explicit_product_query'] = True
                merged['product_interest_signal'] = True
                merged['recommended_chat_mode'] = 'product'
                merged['recommended_goal'] = 'answer_product'
                reason_bits.append('step13=media_product_context')
            elif scene_tags & STEP13_DAILY_MEDIA_TAGS and not bool(merged.get('explicit_product_query')):
                merged['user_intent'] = 'daily_chat'
                merged['need_type'] = 'conversation'
                if str(merged.get('recommended_chat_mode') or '').strip().lower() not in ('pause', 'emotional'):
                    merged['recommended_chat_mode'] = 'daily'
                if str(merged.get('recommended_goal') or '').strip().lower() not in ('pause_respect', 'emotional_support'):
                    merged['recommended_goal'] = 'keep_replying'
                reason_bits.append('step13=media_daily_context')
        if 'voice_tired' in scene_tags and str(merged.get('emotion_state') or '').strip().lower() == 'neutral':
            merged['emotion_state'] = 'low'
            reason_bits.append('step13=voice_tired')
        if 'voice_annoyed' in scene_tags:
            merged['emotion_state'] = 'resistant'
            merged['resistance_signal'] = 'high'
            reason_bits.append('step13=voice_annoyed')
        if 'voice_excited' in scene_tags and str(merged.get('emotion_state') or '').strip().lower() == 'neutral':
            merged['emotion_state'] = 'positive'
            reason_bits.append('step13=voice_excited')
        merged['reason'] = ' | '.join(_training_dedup_strings([part for part in reason_bits if part], 8))
        allowed = {key: merged.get(key) for key in UnderstandingResult.__dataclass_fields__.keys()}
        return UnderstandingResult(**allowed)


_STEP13_STEP7_BASE2_REPLY_PLANNER = ReplyPlanner
class ReplyPlanner(_STEP13_STEP7_BASE2_REPLY_PLANNER):
    def plan(self, understanding: UnderstandingResult, stage_decision: StageDecision, mode_decision: ModeDecision,
             user_state: UserStateSnapshot, training_packet: TrainingPacket | None = None) -> ReplyPlan:
        plan = super().plan(understanding, stage_decision, mode_decision, user_state, training_packet=training_packet)
        scene_tags = {str(tag or '').strip().lower() for tag in ((training_packet.scene_tags if training_packet else []) or []) if str(tag).strip()}
        boundary = str(getattr(understanding, 'boundary_signal', '') or '').lower()
        if boundary in ('stop', 'needs_space', 'busy', 'later', 'sleep'):
            return plan
        if scene_tags & STEP13_PRODUCT_MEDIA_TAGS and not (scene_tags & STEP13_DAILY_MEDIA_TAGS and not understanding.explicit_product_query):
            plan.should_continue_product = True
            plan.should_self_share = False
            if scene_tags & {'yield', 'chart', 'project_material'} and understanding.resistance_signal not in ('medium', 'high'):
                plan.should_send_material = True
            if plan.goal not in ('identity_safe_reply', 'pause_respect', 'emotional_support', 'lower_pressure'):
                plan.goal = 'answer_product'
            plan.reason = (plan.reason or '') + ' | step13=media_product'
        if scene_tags & STEP13_DAILY_MEDIA_TAGS and not understanding.explicit_product_query:
            plan.should_continue_product = False
            plan.should_send_material = False
            if plan.goal == 'answer_product':
                plan.goal = 'keep_replying'
            plan.reason = (plan.reason or '') + ' | step13=media_daily'
        if 'voice_tired' in scene_tags or 'voice_annoyed' in scene_tags:
            plan.should_send_material = False
            plan.should_leave_space = True
            if 'voice_annoyed' in scene_tags:
                plan.should_continue_product = False
                if plan.goal not in ('identity_safe_reply', 'pause_respect'):
                    plan.goal = 'lower_pressure'
        return plan


_STEP13_STEP7_BASE2_REPLY_STYLE_ENGINE = ReplyStyleEngine
class ReplyStyleEngine(_STEP13_STEP7_BASE2_REPLY_STYLE_ENGINE):
    def generate(self, latest_user_message: str, recent_context: list[dict], persona_summary: str, user_state_summary: str,
                 stage: str, chat_mode: str, understanding: dict, reply_plan: dict, selected_content: dict,
                 memory_summary: dict[str, Any] | None = None, reply_language: str = 'English',
                 training_packet: TrainingPacket | None = None) -> str:
        text_value = super().generate(latest_user_message, recent_context, persona_summary, user_state_summary, stage, chat_mode, understanding, reply_plan, selected_content, memory_summary=memory_summary, reply_language=reply_language, training_packet=training_packet)
        scene_tags = {str(tag or '').strip().lower() for tag in ((training_packet.scene_tags if training_packet else []) or []) if str(tag).strip()}
        if scene_tags & {'document', 'chart', 'risk', 'yield'}:
            text_value = _step3_remove_emojis(text_value)
            text_value = _step3_soften_hard_sell(text_value)
            text_value = _step3_sentence_clip(text_value, max_sentences=2, max_chars=220)
        elif scene_tags & STEP13_DAILY_MEDIA_TAGS:
            text_value = _step3_soften_hard_sell(text_value)
            text_value = _step3_limit_questions(text_value, 1)
            text_value = _step3_sentence_clip(text_value, max_sentences=2, max_chars=180)
        if 'voice_annoyed' in scene_tags:
            text_value = _step3_remove_emojis(text_value)
            text_value = _step3_sentence_clip(text_value, max_sentences=1, max_chars=140)
        return re.sub(r'\s{2,}', ' ', text_value).strip() or _step3_safe_fallback(chat_mode, UnderstandingResult(
            user_intent=str((understanding or {}).get('user_intent') or 'daily_chat'),
            need_type=str((understanding or {}).get('need_type') or 'conversation'),
            emotion_state=(understanding or {}).get('emotion_state'),
            boundary_signal=(understanding or {}).get('boundary_signal'),
            resistance_signal=(understanding or {}).get('resistance_signal'),
            product_interest_signal=bool((understanding or {}).get('product_interest_signal')),
            explicit_product_query=bool((understanding or {}).get('explicit_product_query')),
            high_intent_signal=bool((understanding or {}).get('high_intent_signal')),
            current_mainline_should_continue=str((understanding or {}).get('current_mainline_should_continue') or 'daily'),
            recommended_chat_mode=str((understanding or {}).get('recommended_chat_mode') or chat_mode or 'daily'),
            recommended_goal=str((understanding or {}).get('recommended_goal') or 'keep_replying'),
            reason=str((understanding or {}).get('reason') or 'media_style_fallback'),
        ), training_packet)


_STEP13_STEP7_BASE2_CONTENT_SELECTOR = ContentSelector
class ContentSelector(_STEP13_STEP7_BASE2_CONTENT_SELECTOR):
    def select(self, business_account_id: int, project_id: int | None, mode: str, reply_plan: ReplyPlan,
               training_packet: TrainingPacket | None = None) -> dict:
        selected = super().select(business_account_id, project_id, mode, reply_plan, training_packet=training_packet)
        query_tags = _step13_query_semantic_tags((training_packet.scene_tags if training_packet else []) or [])
        if not query_tags:
            return selected
        persona_pool = self.material_repo.get_persona_materials(business_account_id)
        daily_pool = self.material_repo.get_daily_materials(business_account_id)
        project_pool = self.material_repo.get_project_materials(project_id) if project_id else []
        selected['persona_materials'] = _step13_rank_material_items(persona_pool, query_tags, mode, reply_plan.should_send_material, 'persona', max(1, len(selected.get('persona_materials') or []) or 2))
        selected['daily_materials'] = _step13_rank_material_items(daily_pool, query_tags, mode, reply_plan.should_send_material, 'daily', max(1, len(selected.get('daily_materials') or []) or 2))
        if project_id:
            selected['project_materials'] = _step13_rank_material_items(project_pool, query_tags, mode, reply_plan.should_send_material, 'project', max(1, len(selected.get('project_materials') or []) or 2))
        package_limit = 1
        selected['material_packages'] = {
            'project': _step13_rank_material_packages(self.material_repo, business_account_id, 'project', project_id, query_tags, mode, reply_plan.should_send_material, package_limit),
            'persona': _step13_rank_material_packages(self.material_repo, business_account_id, 'persona', project_id, query_tags, mode, reply_plan.should_send_material, package_limit),
            'daily': _step13_rank_material_packages(self.material_repo, business_account_id, 'daily', project_id, query_tags, mode, reply_plan.should_send_material, package_limit),
        }
        selected['semantic_query_tags'] = query_tags
        selected['semantic_match_summary'] = _step13_media_match_summary(selected)
        prompt_summary = self._build_prompt_summary(selected)
        if selected.get('semantic_match_summary'):
            prompt_summary = f"{prompt_summary} | semantic={selected.get('semantic_match_summary')}"[:900]
        selected['prompt_summary'] = prompt_summary
        return selected


_STEP13_STEP7_BASE2_ORCHESTRATOR = Orchestrator
class Orchestrator(_STEP13_STEP7_BASE2_ORCHESTRATOR):
    def handle_inbound_message(self, inbound_message: InboundMessage) -> None:
        media_runtime: dict[str, Any] = {}
        try:
            if getattr(self, 'media_understanding_service', None):
                analysis = self.media_understanding_service.analyze_inbound_message(inbound_message)
                media_runtime = {
                    'media_tags': list(analysis.get('media_tags') or []),
                    'media_scene_type': analysis.get('scene_type'),
                    'media_topic_tags': list(analysis.get('topic_tags') or []),
                    'voice_emotion': analysis.get('voice_emotion') or None,
                    'message_type': analysis.get('message_type') or inbound_message.message_type,
                }
        except Exception:
            logger.exception('Step13 media runtime pre-analysis failed.')
        try:
            setattr(self, '_step13_media_runtime_context', media_runtime)
        except Exception:
            pass
        try:
            return super().handle_inbound_message(inbound_message)
        finally:
            try:
                setattr(self, '_step13_media_runtime_context', {})
            except Exception:
                pass

    def _build_training_packet(self, business_account_id: int, runtime_context: dict[str, Any]) -> TrainingPacket:
        merged_context = dict(runtime_context or {})
        media_runtime = dict(getattr(self, '_step13_media_runtime_context', {}) or {})
        if media_runtime:
            merged_context['media_tags'] = list(media_runtime.get('media_tags') or [])
            merged_context['media_scene_type'] = media_runtime.get('media_scene_type')
            merged_context['media_topic_tags'] = list(media_runtime.get('media_topic_tags') or [])
            merged_context['voice_emotion'] = media_runtime.get('voice_emotion')
            merged_context['message_type'] = media_runtime.get('message_type') or merged_context.get('message_type')
        packet = super()._build_training_packet(business_account_id, merged_context)
        extra_scene_tags = list(media_runtime.get('media_tags') or [])
        media_scene = str(media_runtime.get('media_scene_type') or '').strip().lower()
        if media_scene:
            extra_scene_tags.append(media_scene)
        voice_emotion = str(media_runtime.get('voice_emotion') or '').strip().lower()
        if voice_emotion:
            extra_scene_tags.append(f'voice_{voice_emotion}')
        if extra_scene_tags:
            packet.scene_tags = _training_dedup_strings(list(packet.scene_tags) + extra_scene_tags, 28)
            packet.prompt_summary = (str(packet.prompt_summary or '') + f" | media_tags={packet.scene_tags[:8]}")[:900]
        try:
            setattr(self.reply_planner, '_runtime_training_packet', packet)
        except Exception:
            pass
        return packet


_STEP13_STEP7_BASE2_BUILD_APP_COMPONENTS = build_app_components

def build_app_components(settings: Settings) -> dict[str, Any]:
    app_components = _STEP13_STEP7_BASE2_BUILD_APP_COMPONENTS(settings)
    orchestrator = app_components.get('orchestrator')
    if orchestrator is not None:
        try:
            orchestrator.__class__ = Orchestrator
        except Exception:
            pass
        if getattr(orchestrator, 'understanding_engine', None) is not None:
            try:
                orchestrator.understanding_engine.__class__ = UserUnderstandingEngine
            except Exception:
                pass
        if getattr(orchestrator, 'reply_planner', None) is not None:
            try:
                orchestrator.reply_planner.__class__ = ReplyPlanner
            except Exception:
                pass
        if getattr(orchestrator, 'reply_style_engine', None) is not None:
            try:
                orchestrator.reply_style_engine.__class__ = ReplyStyleEngine
            except Exception:
                pass
        if getattr(orchestrator, 'content_selector', None) is not None:
            try:
                orchestrator.content_selector.__class__ = ContentSelector
            except Exception:
                pass
    training_retrieval_service = app_components.get('training_retrieval_service')
    if training_retrieval_service is not None:
        try:
            training_retrieval_service.__class__ = TrainingRetrievalService
        except Exception:
            pass
    media_understanding_service = app_components.get('media_understanding_service')
    if media_understanding_service is not None:
        try:
            media_understanding_service.__class__ = MediaUnderstandingService
        except Exception:
            pass
    if orchestrator is not None:
        if training_retrieval_service is not None:
            orchestrator.training_retrieval_service = training_retrieval_service
        if media_understanding_service is not None:
            orchestrator.media_understanding_service = media_understanding_service
    app_components['training_retrieval_service'] = training_retrieval_service
    app_components['media_understanding_service'] = media_understanding_service
    return app_components

