_STEP15_BASE_REPLY_PLANNER = ReplyPlanner
class ReplyPlanner(_STEP15_BASE_REPLY_PLANNER):
    def plan(self, understanding: UnderstandingResult, stage_decision: StageDecision, mode_decision: ModeDecision,
             user_state: UserStateSnapshot, training_packet: TrainingPacket | None = None) -> ReplyPlan:
        plan = super().plan(understanding, stage_decision, mode_decision, user_state, training_packet=training_packet)
        profile = getattr(user_state, "evolved_profile_snapshot", None)
        if isinstance(profile, UserProfileEvolutionSnapshot):
            if profile.prefers_short_reply:
                plan.should_leave_space = bool(plan.should_leave_space or mode_decision.chat_mode in ("daily", "maintain"))
                plan.reason = (plan.reason or "") + " | step9=prefers_short"
            if profile.marketing_tolerance_score < 0.34 and not understanding.explicit_product_query:
                plan.should_continue_product = False
                plan.should_send_material = False
                if plan.goal not in ("identity_safe_reply", "pause_respect", "emotional_support", "post_sale_maintenance"):
                    plan.goal = "build_trust"
                plan.reason = (plan.reason or "") + " | step9=low_marketing_tolerance"
            if "hard_sell" in profile.disliked_patterns and not understanding.explicit_product_query:
                plan.should_send_material = False
                plan.reason = (plan.reason or "") + " | step9=avoid_hard_sell"
            if "multiple_questions" in profile.disliked_patterns:
                plan.should_leave_space = True
            if any(topic in profile.interest_topics for topic in ("risk_control", "stability")) and understanding.explicit_product_query:
                plan.should_continue_product = True
                plan.reason = (plan.reason or "") + " | step9=risk_stability_interest"
        try:
            setattr(self, "_last_reply_plan", plan)
        except Exception:
            pass
        return plan


_STEP15_BASE_REPLY_STYLE_ENGINE = ReplyStyleEngine
class ReplyStyleEngine(_STEP15_BASE_REPLY_STYLE_ENGINE):
    def generate(self, latest_user_message: str, recent_context: list[dict], persona_summary: str, user_state_summary: str,
                 stage: str, chat_mode: str, understanding: dict, reply_plan: dict, selected_content: dict,
                 memory_summary: dict[str, Any] | None = None, reply_language: str = "English",
                 training_packet: TrainingPacket | None = None) -> str:
        text_value = super().generate(latest_user_message, recent_context, persona_summary, user_state_summary, stage, chat_mode, understanding, reply_plan, selected_content, memory_summary=memory_summary, reply_language=reply_language, training_packet=training_packet)
        profile = getattr(self, "_runtime_profile_snapshot", None)
        if isinstance(profile, UserProfileEvolutionSnapshot):
            if profile.prefers_short_reply or profile.preferred_reply_length == "short":
                text_value = _step3_sentence_clip(text_value, max_sentences=2, max_chars=160)
            if profile.marketing_tolerance_score < 0.34:
                text_value = _step3_soften_hard_sell(text_value)
                text_value = _step3_limit_questions(text_value, 1)
            if "long_replies" in profile.disliked_patterns:
                text_value = _step3_sentence_clip(text_value, max_sentences=2, max_chars=150)
            if "multiple_questions" in profile.disliked_patterns:
                text_value = _step3_limit_questions(text_value, 1)
            if "hard_sell" in profile.disliked_patterns:
                text_value = _step3_soften_hard_sell(text_value)
        try:
            setattr(self, "_last_draft_reply", text_value)
        except Exception:
            pass
        return text_value


_STEP15_BASE_REPLY_SELF_CHECK_ENGINE = ReplySelfCheckEngine
class ReplySelfCheckEngine(_STEP15_BASE_REPLY_SELF_CHECK_ENGINE):
    def check_and_fix(self, draft_reply: str, mode: str, understanding: UnderstandingResult,
                      training_packet: TrainingPacket | None = None) -> str:
        text_value = super().check_and_fix(draft_reply, mode, understanding, training_packet=training_packet)
        try:
            setattr(self, "_last_final_reply", text_value)
        except Exception:
            pass
        return text_value


_STEP15_BASE_ORCHESTRATOR = Orchestrator
class Orchestrator(_STEP15_BASE_ORCHESTRATOR):
    @staticmethod
    def _user_state_summary(user_state: UserStateSnapshot) -> str:
        base = _STEP15_BASE_ORCHESTRATOR._user_state_summary(user_state)
        profile = getattr(user_state, "evolved_profile_snapshot", None)
        if not isinstance(profile, UserProfileEvolutionSnapshot):
            return base
        extra = [
            f"preferred_reply_length={profile.preferred_reply_length}",
            f"prefers_short_reply={bool(profile.prefers_short_reply)}",
            f"marketing_tolerance_label={profile.marketing_tolerance_label}",
            f"interest_topics={profile.interest_topics[:4]}",
            f"disliked_patterns={profile.disliked_patterns[:4]}",
            f"boundary_preferences={profile.boundary_preferences[:3]}",
        ]
        return base + "; " + "; ".join(extra)

    def _build_training_packet(self, business_account_id: int, runtime_context: dict[str, Any]) -> TrainingPacket:
        packet = super()._build_training_packet(business_account_id, runtime_context)
        profile_snapshot = None
        try:
            user_id = runtime_context.get("user_id")
            if user_id:
                profile_snapshot = self.user_repo.get_profile_evolution_snapshot(business_account_id, int(user_id))
        except Exception:
            logger.exception("Step15 failed to load user profile evolution snapshot for training packet.")
        if isinstance(profile_snapshot, UserProfileEvolutionSnapshot):
            profile_tags = [f"interest_{tag}" for tag in profile_snapshot.interest_topics[:4]]
            profile_tags += [f"avoid_{tag}" for tag in profile_snapshot.disliked_patterns[:3]]
            profile_tags += [f"pref_{tag}" for tag in profile_snapshot.boundary_preferences[:2]]
            if profile_snapshot.prefers_short_reply:
                profile_tags.append("prefers_short_reply")
            packet.scene_tags = _training_dedup_strings(list(packet.scene_tags or []) + profile_tags, 32)
            summary_bits = [
                f"profile_reply_length={profile_snapshot.preferred_reply_length}",
                f"profile_marketing={profile_snapshot.marketing_tolerance_label}",
            ]
            if profile_snapshot.interest_topics:
                summary_bits.append(f"profile_topics={profile_snapshot.interest_topics[:3]}")
            if profile_snapshot.disliked_patterns:
                summary_bits.append(f"profile_dislikes={profile_snapshot.disliked_patterns[:2]}")
            packet.prompt_summary = (str(packet.prompt_summary or "") + " | " + " | ".join(summary_bits)).strip(" |")[:1100]
        try:
            setattr(self.reply_planner, "_runtime_profile_snapshot", profile_snapshot)
            setattr(self.reply_style_engine, "_runtime_profile_snapshot", profile_snapshot)
        except Exception:
            pass
        return packet

    def handle_inbound_message(self, inbound_message: InboundMessage) -> None:
        business_account_id = None
        user_id = None
        conversation_id = None
        media_runtime: dict[str, Any] = {}
        try:
            business_account = self.business_account_repo.create_if_not_exists(
                inbound_message.tg_business_account_id,
                f"BusinessAccount-{inbound_message.tg_business_account_id}",
                None,
            )
            business_account_id = int(business_account["id"])
            user_payload = inbound_message.raw_payload.get("business_message") or inbound_message.raw_payload.get("edited_business_message") or inbound_message.raw_payload.get("message") or {}
            from_user = user_payload.get("from") or {}
            user_id = self.user_repo.get_or_create_user(
                inbound_message.tg_user_id,
                display_name=(from_user.get("first_name") or f"User-{inbound_message.tg_user_id}"),
                username=from_user.get("username"),
                language_code=from_user.get("language_code"),
            )
            conversation_id = self.conversation_repo.get_or_create_conversation(business_account_id, user_id)
            if getattr(self, "media_understanding_service", None):
                try:
                    media_runtime = self.media_understanding_service.analyze_inbound_message(inbound_message) or {}
                except Exception:
                    media_runtime = {}
        except Exception:
            logger.exception("Step15 pre-handle setup failed.")
        try:
            return super().handle_inbound_message(inbound_message)
        finally:
            try:
                if business_account_id and user_id and getattr(self, "user_profile_evolution_service", None):
                    context = self.conversation_repo.get_context(int(conversation_id)) if conversation_id else None
                    understanding = getattr(self.understanding_engine, "_last_understanding_result", None)
                    relationship_snapshot = getattr(understanding, "relationship_stage_snapshot", None) if understanding else None
                    reply_plan = getattr(self.reply_planner, "_last_reply_plan", None)
                    final_reply_text = getattr(self.reply_self_check_engine, "_last_final_reply", None)
                    existing = self.user_repo.get_profile_evolution_snapshot(int(business_account_id), int(user_id))
                    evolved = self.user_profile_evolution_service.evolve(
                        existing,
                        inbound_message.text or "",
                        (context.recent_messages if context else []),
                        understanding,
                        relationship_snapshot,
                        reply_plan,
                        final_reply_text,
                        media_runtime,
                    )
                    self.user_repo.upsert_profile_evolution_snapshot(int(business_account_id), int(user_id), evolved, source="step9", reason_text=evolved.reason)
            except Exception:
                logger.exception("Step15 user profile evolution update failed.")
            try:
                setattr(self.reply_planner, "_runtime_profile_snapshot", None)
                setattr(self.reply_style_engine, "_runtime_profile_snapshot", None)
            except Exception:
                pass


_STEP15_BASE_BUILD_APP_COMPONENTS = build_app_components

def build_app_components(settings: Settings) -> dict[str, Any]:
    app_components = _STEP15_BASE_BUILD_APP_COMPONENTS(settings)
    db = app_components.get("db")
    if db is not None:
        try:
            _step15_ensure_profile_schema(db)
        except Exception:
            logger.exception("Step15 profile schema ensure failed.")
    orchestrator = app_components.get("orchestrator")
    admin_api_service = app_components.get("admin_api_service")
    user_profile_evolution_service = UserProfileEvolutionService()
    user_repo = None
    if orchestrator is not None:
        user_repo = getattr(orchestrator, "user_repo", None)
    if user_repo is None and admin_api_service is not None:
        user_repo = getattr(admin_api_service, "user_repo", None)
    if user_repo is not None:
        try:
            user_repo.__class__ = UserRepository
        except Exception:
            pass
    if orchestrator is not None:
        try:
            orchestrator.__class__ = Orchestrator
        except Exception:
            pass
        if getattr(orchestrator, "understanding_engine", None) is not None:
            try:
                orchestrator.understanding_engine.__class__ = UserUnderstandingEngine
            except Exception:
                pass
        if getattr(orchestrator, "stage_engine", None) is not None:
            try:
                orchestrator.stage_engine.__class__ = RelationshipStageEngine
            except Exception:
                pass
        if getattr(orchestrator, "reply_planner", None) is not None:
            try:
                orchestrator.reply_planner.__class__ = ReplyPlanner
            except Exception:
                pass
        if getattr(orchestrator, "reply_style_engine", None) is not None:
            try:
                orchestrator.reply_style_engine.__class__ = ReplyStyleEngine
            except Exception:
                pass
        if getattr(orchestrator, "reply_self_check_engine", None) is not None:
            try:
                orchestrator.reply_self_check_engine.__class__ = ReplySelfCheckEngine
            except Exception:
                pass
        try:
            setattr(orchestrator, "user_profile_evolution_service", user_profile_evolution_service)
        except Exception:
            pass
    if admin_api_service is not None and user_repo is not None:
        try:
            setattr(admin_api_service, "user_repo", user_repo)
        except Exception:
            pass
    app_components["user_profile_evolution_service"] = user_profile_evolution_service
    if user_repo is not None:
        app_components["user_repo"] = user_repo
    return app_components


# =========================
# step10 conversation goal engine
# =========================

@dataclass
class ConversationGoalSnapshot:
    turn_goal: str = "light_chat"
    next_best_action: str = "keep_natural"
    should_push_project: bool = False
    should_leave_space: bool = False
    should_soften: bool = False
    should_answer_directly: bool = True
    pacing_mode: str = "normal"
    explanation_level: str = "light"
    trust_focus: bool = False
    reason: str = ""


def _step10_goal_to_payload(snapshot: ConversationGoalSnapshot | None) -> dict[str, Any]:
    if not snapshot:
        return {}
    return {
        "turn_goal": snapshot.turn_goal,
        "next_best_action": snapshot.next_best_action,
        "should_push_project": bool(snapshot.should_push_project),
        "should_leave_space": bool(snapshot.should_leave_space),
        "should_soften": bool(snapshot.should_soften),
        "should_answer_directly": bool(snapshot.should_answer_directly),
        "pacing_mode": snapshot.pacing_mode,
        "explanation_level": snapshot.explanation_level,
        "trust_focus": bool(snapshot.trust_focus),
        "reason": snapshot.reason,
    }


class ConversationGoalEngine:
    def decide(self,
               understanding: UnderstandingResult,
               stage_decision: StageDecision,
               mode_decision: ModeDecision,
               user_state: UserStateSnapshot,
               profile_snapshot: UserProfileEvolutionSnapshot | None = None,
               training_packet: TrainingPacket | None = None) -> ConversationGoalSnapshot:
        relationship_snapshot = getattr(understanding, "relationship_stage_snapshot", None)
        relationship_stage = str(getattr(relationship_snapshot, "relationship_stage", None) or stage_decision.stage or "warming").strip().lower()
        emotion_state = str(getattr(understanding, "emotion_state", None) or "").strip().lower()
        boundary_signal = str(getattr(understanding, "boundary_signal", None) or "").strip().lower()
        resistance_signal = str(getattr(understanding, "resistance_signal", None) or "").strip().lower()
        marketing_tolerance = float(getattr(profile_snapshot, "marketing_tolerance_score", 0.35) or 0.35)
        prefers_short = bool(getattr(profile_snapshot, "prefers_short_reply", False))
        disliked = set(str(x).strip().lower() for x in (getattr(profile_snapshot, "disliked_patterns", []) or []) if str(x).strip())
        scene_tags = set(str(x).strip().lower() for x in ((training_packet.scene_tags if training_packet else []) or []) if str(x).strip())

        reason_parts: list[str] = []
        goal = "light_chat"
        action = "keep_natural"
        should_push_project = False
        should_leave_space = False
        should_soften = False
        should_answer_directly = True
        pacing_mode = "normal"
        explanation_level = "light"
        trust_focus = False

        if understanding.high_intent_signal and relationship_stage in {"project_discussion", "conversion_ready"}:
            goal = "project_answer"
            action = "clarify_and_support_decision"
            should_push_project = True
            should_answer_directly = True
            explanation_level = "deep"
            pacing_mode = "attentive"
            reason_parts.append("high_intent")
        elif understanding.explicit_product_query:
            goal = "project_answer"
            action = "answer_product_question"
            should_push_project = True
            should_answer_directly = True
            explanation_level = "medium"
            pacing_mode = "focused"
            reason_parts.append("explicit_product_query")
        elif boundary_signal in {"stop", "needs_space"}:
            goal = "pause_and_leave_space"
            action = "respect_boundary"
            should_push_project = False
            should_leave_space = True
            should_answer_directly = False
            should_soften = True
            pacing_mode = "slow"
            explanation_level = "minimal"
            trust_focus = True
            reason_parts.append(f"boundary={boundary_signal}")
        elif boundary_signal in {"busy", "later", "sleep"}:
            goal = "light_followup_seed"
            action = "acknowledge_and_pause"
            should_push_project = False
            should_leave_space = True
            should_answer_directly = False
            should_soften = True
            pacing_mode = "hold"
            explanation_level = "minimal"
            trust_focus = True
            reason_parts.append(f"boundary={boundary_signal}")
        elif resistance_signal or emotion_state == "resistant":
            goal = "hold_emotion"
            action = "lower_pressure_and_validate"
            should_push_project = False
            should_leave_space = True
            should_soften = True
            pacing_mode = "slow"
            explanation_level = "minimal"
            trust_focus = True
            reason_parts.append("resistance")
        elif emotion_state in {"low", "anxious"}:
            goal = "hold_emotion"
            action = "support_then_leave_space"
            should_push_project = False
            should_leave_space = True
            should_soften = True
            pacing_mode = "gentle"
            explanation_level = "minimal"
            trust_focus = True
            reason_parts.append(f"emotion={emotion_state}")
        elif relationship_stage in {"cold", "early_contact"}:
            goal = "light_chat"
            action = "reduce_pressure_and_warm_up"
            should_push_project = False
            should_leave_space = prefers_short or "prefers_short_reply" in scene_tags
            should_soften = True
            pacing_mode = "normal"
            explanation_level = "light"
            trust_focus = True
            reason_parts.append(f"stage={relationship_stage}")
        elif relationship_stage in {"warming", "trust_building"}:
            goal = "build_trust"
            action = "keep_natural_and_build_comfort"
            should_push_project = False
            should_leave_space = prefers_short or marketing_tolerance < 0.38
            should_soften = True
            pacing_mode = "warm"
            explanation_level = "light"
            trust_focus = True
            reason_parts.append(f"stage={relationship_stage}")
        elif relationship_stage == "light_interest":
            goal = "soft_probe"
            action = "gently_test_interest"
            should_push_project = marketing_tolerance >= 0.48 and "hard_sell" not in disliked
            should_leave_space = prefers_short
            should_soften = True
            pacing_mode = "measured"
            explanation_level = "light"
            trust_focus = True
            reason_parts.append("light_interest")
        elif relationship_stage in {"project_transition", "project_discussion"}:
            goal = "project_shift"
            action = "connect_context_to_project"
            should_push_project = marketing_tolerance >= 0.40 and not boundary_signal
            should_leave_space = "multiple_questions" in disliked
            should_soften = "hard_sell" in disliked
            pacing_mode = "focused"
            explanation_level = "medium"
            reason_parts.append(f"stage={relationship_stage}")
        elif relationship_stage == "post_sale_maintenance":
            goal = "post_sale_maintenance"
            action = "maintain_relationship"
            should_push_project = False
            should_leave_space = False
            should_soften = True
            pacing_mode = "maintenance"
            explanation_level = "light"
            trust_focus = True
            reason_parts.append("post_sale")

        if understanding.user_intent == "identity_probe":
            goal = "identity_safe_reply"
            action = "stay_neutral_and_continue_window"
            should_push_project = False
            should_leave_space = False
            should_soften = True
            should_answer_directly = True
            pacing_mode = "neutral"
            explanation_level = "minimal"
            trust_focus = True
            reason_parts.append("identity_probe")
        if marketing_tolerance < 0.28 and goal in {"project_shift", "project_answer", "soft_probe"} and not understanding.explicit_product_query:
            goal = "build_trust"
            action = "reduce_pressure_and_keep_trust"
            should_push_project = False
            should_leave_space = True
            should_soften = True
            explanation_level = "light"
            trust_focus = True
            reason_parts.append("low_marketing_tolerance")
        if "hard_sell" in disliked:
            should_soften = True
            if goal in {"project_shift", "soft_probe"} and not understanding.explicit_product_query:
                should_push_project = False
                should_leave_space = True
                reason_parts.append("avoid_hard_sell")
        if "multiple_questions" in disliked:
            should_leave_space = True
        if prefers_short and goal not in {"project_answer", "identity_safe_reply"}:
            explanation_level = "minimal" if goal in {"hold_emotion", "pause_and_leave_space", "light_followup_seed"} else "light"
        if getattr(relationship_snapshot, "sales_tolerance", 0.0) >= 0.72 and goal in {"soft_probe", "project_shift"}:
            should_push_project = True
            explanation_level = "medium"
            reason_parts.append("relationship_sales_tolerance")

        return ConversationGoalSnapshot(
            turn_goal=goal,
            next_best_action=action,
            should_push_project=bool(should_push_project),
            should_leave_space=bool(should_leave_space),
            should_soften=bool(should_soften),
            should_answer_directly=bool(should_answer_directly),
            pacing_mode=pacing_mode,
            explanation_level=explanation_level,
            trust_focus=bool(trust_focus),
            reason=" | ".join(reason_parts)[:400],
        )


_STEP16_BASE_REPLY_PLANNER = ReplyPlanner
class ReplyPlanner(_STEP16_BASE_REPLY_PLANNER):
    def plan(self, understanding: UnderstandingResult, stage_decision: StageDecision, mode_decision: ModeDecision,
             user_state: UserStateSnapshot, training_packet: TrainingPacket | None = None) -> ReplyPlan:
        goal_engine = getattr(self, "conversation_goal_engine", None)
        profile_snapshot = getattr(user_state, "evolved_profile_snapshot", None)
        goal_snapshot = None
        if goal_engine is not None:
            try:
                goal_snapshot = goal_engine.decide(understanding, stage_decision, mode_decision, user_state, profile_snapshot, training_packet)
            except Exception:
                logger.exception("Step10 ConversationGoalEngine decide failed.")
        if goal_snapshot is None:
            goal_snapshot = ConversationGoalSnapshot()
        try:
            setattr(understanding, "conversation_goal_snapshot", _step10_goal_to_payload(goal_snapshot))
            setattr(understanding, "conversation_goal", goal_snapshot.turn_goal)
            setattr(self, "_last_goal_snapshot", goal_snapshot)
        except Exception:
            pass
        plan = super().plan(understanding, stage_decision, mode_decision, user_state, training_packet=training_packet)
        goal = goal_snapshot.turn_goal
        if goal == "identity_safe_reply":
            plan.goal = "identity_safe_reply"
            plan.should_continue_product = False
            plan.should_send_material = False
            plan.should_self_share = False
            plan.should_leave_space = False
        elif goal == "pause_and_leave_space":
            plan.goal = "pause_respect"
            plan.should_continue_product = False
            plan.should_send_material = False
            plan.should_self_share = False
            plan.should_leave_space = True
        elif goal == "light_followup_seed":
            plan.goal = "pause_respect"
            plan.should_continue_product = False
            plan.should_send_material = False
            plan.should_self_share = False
            plan.should_leave_space = True
        elif goal == "hold_emotion":
            plan.goal = "emotional_support"
            plan.should_continue_product = False
            plan.should_send_material = False
            plan.should_self_share = False
            plan.should_leave_space = True
        elif goal == "light_chat":
            plan.goal = "build_trust"
            plan.should_continue_product = False
            if not understanding.explicit_product_query:
                plan.should_send_material = False
            if goal_snapshot.trust_focus:
                plan.should_self_share = False
        elif goal == "build_trust":
            plan.goal = "build_trust"
            if not understanding.explicit_product_query:
                plan.should_continue_product = False
                plan.should_send_material = False
            if str(stage_decision.stage or "") in {"trust_building", "warming"} and not plan.should_leave_space:
                plan.should_self_share = bool(plan.should_self_share or (not (training_packet and ("no_self_share" in (training_packet.style_rules or [])))))
        elif goal == "soft_probe":
            plan.goal = "build_trust"
            plan.should_continue_product = bool(goal_snapshot.should_push_project and not understanding.explicit_product_query)
            if not plan.should_continue_product:
                plan.should_send_material = False
        elif goal == "project_shift":
            plan.goal = "continue_mainline"
            plan.should_continue_product = bool(goal_snapshot.should_push_project or understanding.explicit_product_query)
        elif goal == "project_answer":
            plan.goal = "continue_mainline"
            plan.should_continue_product = True
            plan.should_answer_question = True
            if understanding.explicit_product_query:
                plan.should_send_material = bool(plan.should_send_material or (training_packet is None or "no_material" not in (training_packet.material_rules or [])))
        elif goal == "post_sale_maintenance":
            plan.goal = "post_sale_maintenance"
            plan.should_continue_product = False
            plan.should_send_material = False
            plan.should_self_share = False
        plan.should_leave_space = bool(plan.should_leave_space or goal_snapshot.should_leave_space)
        plan.reason = ((plan.reason or "") + f" | step10_goal={goal_snapshot.turn_goal}:{goal_snapshot.next_best_action}").strip()
        return plan


_STEP16_BASE_REPLY_STYLE_ENGINE = ReplyStyleEngine
class ReplyStyleEngine(_STEP16_BASE_REPLY_STYLE_ENGINE):
    def generate(self, latest_user_message: str, recent_context: list[dict], persona_summary: str, user_state_summary: str,
                 stage: str, chat_mode: str, understanding: dict, reply_plan: dict, selected_content: dict,
                 memory_summary: dict[str, Any] | None = None, reply_language: str = "English",
                 training_packet: TrainingPacket | None = None) -> str:
        text_value = super().generate(latest_user_message, recent_context, persona_summary, user_state_summary, stage, chat_mode, understanding, reply_plan, selected_content, memory_summary=memory_summary, reply_language=reply_language, training_packet=training_packet)
        goal_payload = understanding.get("conversation_goal_snapshot") if isinstance(understanding, dict) else None
        if isinstance(goal_payload, ConversationGoalSnapshot):
            goal_payload = _step10_goal_to_payload(goal_payload)
        goal = str((goal_payload or {}).get("turn_goal") or "").strip().lower()
        explanation_level = str((goal_payload or {}).get("explanation_level") or "").strip().lower()
        should_soften = bool((goal_payload or {}).get("should_soften"))
        should_leave_space = bool((goal_payload or {}).get("should_leave_space"))
        if goal in {"pause_and_leave_space", "light_followup_seed", "identity_safe_reply"}:
            text_value = _step3_sentence_clip(text_value, max_sentences=1, max_chars=110)
            text_value = _step3_limit_questions(text_value, 0)
        elif goal == "hold_emotion":
            text_value = _step3_sentence_clip(text_value, max_sentences=2, max_chars=150)
            text_value = _step3_limit_questions(text_value, 1)
        elif goal in {"build_trust", "light_chat"}:
            text_value = _step3_sentence_clip(text_value, max_sentences=2, max_chars=170)
            text_value = _step3_limit_questions(text_value, 1)
        elif goal == "project_answer":
            max_chars = 240 if explanation_level == "deep" else 190
            text_value = _step3_sentence_clip(text_value, max_sentences=3, max_chars=max_chars)
            text_value = _step3_limit_questions(text_value, 1)
        elif goal == "project_shift":
            text_value = _step3_sentence_clip(text_value, max_sentences=2, max_chars=170)
            text_value = _step3_limit_questions(text_value, 1)
        if should_soften:
            text_value = _step3_soften_hard_sell(text_value)
        if should_leave_space:
            text_value = _step3_limit_questions(text_value, 1)
        try:
            setattr(self, "_last_goal_payload", goal_payload)
        except Exception:
            pass
        return text_value


_STEP16_BASE_REPLY_DELAY_ENGINE = ReplyDelayEngine
class ReplyDelayEngine(_STEP16_BASE_REPLY_DELAY_ENGINE):
    def decide_delay_seconds(self, understanding: UnderstandingResult, chat_mode: str, reply_text: str,
                             training_packet: TrainingPacket | None = None) -> int:
        delay_seconds = super().decide_delay_seconds(understanding, chat_mode, reply_text, training_packet=training_packet)
        goal_payload = getattr(understanding, "conversation_goal_snapshot", None)
        if isinstance(goal_payload, ConversationGoalSnapshot):
            goal_payload = _step10_goal_to_payload(goal_payload)
        goal = str((goal_payload or {}).get("turn_goal") or "").strip().lower()
        pacing_mode = str((goal_payload or {}).get("pacing_mode") or "").strip().lower()
        if goal in {"pause_and_leave_space", "light_followup_seed", "identity_safe_reply"}:
            delay_seconds = max(delay_seconds, 2)
        elif goal == "hold_emotion":
            delay_seconds = max(delay_seconds, 3)
        elif goal == "project_answer" and pacing_mode in {"focused", "attentive"}:
            delay_seconds = max(delay_seconds, 3)
        elif goal in {"light_chat", "build_trust"} and pacing_mode == "warm":
            delay_seconds = max(delay_seconds, 2)
        return int(delay_seconds)


_STEP16_BASE_PROACTIVE_FOLLOWUP_ENGINE = ProactiveFollowupEngine
class ProactiveFollowupEngine(_STEP16_BASE_PROACTIVE_FOLLOWUP_ENGINE):
    def decide(self, runtime_policy: dict[str, Any], understanding: UnderstandingResult, mode_decision: ModeDecision,
               reply_plan: ReplyPlan, user_state: UserStateSnapshot, intent_decision: IntentDecision,
               context: ConversationContextSnapshot, latest_user_text: str, project_name: str | None = None,
               latest_handover_summary: dict[str, Any] | None = None,
               escalation_decision: dict[str, Any] | None = None,
               training_packet: TrainingPacket | None = None) -> FollowupDecision:
        decision = super().decide(runtime_policy, understanding, mode_decision, reply_plan, user_state, intent_decision, context, latest_user_text, project_name=project_name, latest_handover_summary=latest_handover_summary, escalation_decision=escalation_decision, training_packet=training_packet)
        goal_payload = getattr(understanding, "conversation_goal_snapshot", None)
        if isinstance(goal_payload, ConversationGoalSnapshot):
            goal_payload = _step10_goal_to_payload(goal_payload)
        goal = str((goal_payload or {}).get("turn_goal") or "").strip().lower()
        if goal in {"pause_and_leave_space", "identity_safe_reply"}:
            decision.should_schedule = False
            decision.followup_kind = "none"
            decision.text = ""
            decision.reason = (decision.reason or "") + " | step10=no_followup"
            decision.pacing_mode = "hold"
        elif goal == "light_followup_seed":
            decision.should_schedule = bool(decision.should_schedule)
            if decision.should_schedule:
                decision.followup_kind = "light_touch"
                decision.pacing_mode = "light_touch"
                decision.reason = (decision.reason or "") + " | step10=light_followup_seed"
        elif goal == "post_sale_maintenance":
            if decision.should_schedule:
                decision.followup_kind = "maintenance"
                decision.pacing_mode = "maintenance"
        return decision


_STEP16_BASE_BUILD_APP_COMPONENTS = build_app_components

def build_app_components(settings: Settings) -> dict[str, Any]:
    app_components = _STEP16_BASE_BUILD_APP_COMPONENTS(settings)
    conversation_goal_engine = ConversationGoalEngine()
    orchestrator = app_components.get("orchestrator")
    if orchestrator is not None:
        if getattr(orchestrator, "reply_planner", None) is not None:
            try:
                orchestrator.reply_planner.__class__ = ReplyPlanner
            except Exception:
                pass
            try:
                setattr(orchestrator.reply_planner, "conversation_goal_engine", conversation_goal_engine)
            except Exception:
                pass
        if getattr(orchestrator, "reply_style_engine", None) is not None:
            try:
                orchestrator.reply_style_engine.__class__ = ReplyStyleEngine
            except Exception:
                pass
        if getattr(orchestrator, "reply_delay_engine", None) is not None:
            try:
                orchestrator.reply_delay_engine.__class__ = ReplyDelayEngine
            except Exception:
                pass
        if getattr(orchestrator, "proactive_followup_engine", None) is not None:
            try:
                orchestrator.proactive_followup_engine.__class__ = ProactiveFollowupEngine
            except Exception:
                pass
        try:
            setattr(orchestrator, "conversation_goal_engine", conversation_goal_engine)
        except Exception:
            pass
    app_components["conversation_goal_engine"] = conversation_goal_engine
    return app_components


