# =========================
# Step11: 联调细修 / Decision tuning
# =========================

@dataclass
class DecisionTuningSnapshot:
    pressure_mode: str = "normal"
    material_mode: str = "default"
    max_question_count: int = 1
    max_sentences: int = 2
    max_chars: int = 170
    self_share_mode: str = "limited"
    followup_mode: str = "default"
    should_downshift_project: bool = False
    should_relax_daily_tone: bool = False
    conflict_flags: list[str] = field(default_factory=list)
    reason: str = ""


def _step11_tuning_to_payload(snapshot: DecisionTuningSnapshot | None) -> dict[str, Any]:
    if not snapshot:
        return {}
    return {
        "pressure_mode": snapshot.pressure_mode,
        "material_mode": snapshot.material_mode,
        "max_question_count": int(snapshot.max_question_count or 0),
        "max_sentences": int(snapshot.max_sentences or 0),
        "max_chars": int(snapshot.max_chars or 0),
        "self_share_mode": snapshot.self_share_mode,
        "followup_mode": snapshot.followup_mode,
        "should_downshift_project": bool(snapshot.should_downshift_project),
        "should_relax_daily_tone": bool(snapshot.should_relax_daily_tone),
        "conflict_flags": list(snapshot.conflict_flags or []),
        "reason": snapshot.reason,
    }


class DecisionTuningEngine:
    def tune(self,
             understanding: UnderstandingResult,
             stage_decision: StageDecision,
             mode_decision: ModeDecision,
             user_state: UserStateSnapshot,
             training_packet: TrainingPacket | None = None) -> DecisionTuningSnapshot:
        relationship_snapshot = getattr(understanding, "relationship_stage_snapshot", None)
        relationship_stage = str(getattr(relationship_snapshot, "relationship_stage", None) or stage_decision.stage or "warming").strip().lower()
        goal_payload = getattr(understanding, "conversation_goal_snapshot", None)
        if isinstance(goal_payload, ConversationGoalSnapshot):
            goal_payload = _step10_goal_to_payload(goal_payload)
        goal = str((goal_payload or {}).get("turn_goal") or getattr(understanding, "conversation_goal", "") or "").strip().lower()
        emotion_state = str(getattr(understanding, "emotion_state", None) or "").strip().lower()
        boundary_signal = str(getattr(understanding, "boundary_signal", None) or "").strip().lower()
        resistance_signal = str(getattr(understanding, "resistance_signal", None) or "").strip().lower()
        explicit_product_query = bool(getattr(understanding, "explicit_product_query", False))
        high_intent = bool(getattr(understanding, "high_intent_signal", False))
        profile_snapshot = getattr(user_state, "evolved_profile_snapshot", None)
        marketing_tolerance = float(getattr(profile_snapshot, "marketing_tolerance_score", 0.35) or 0.35)
        prefers_short = bool(getattr(profile_snapshot, "prefers_short_reply", False))
        disliked = set(str(x).strip().lower() for x in (getattr(profile_snapshot, "disliked_patterns", []) or []) if str(x).strip())
        interest_topics = set(str(x).strip().lower() for x in (getattr(profile_snapshot, "interest_topics", []) or []) if str(x).strip())
        scene_tags = set(str(x).strip().lower() for x in ((training_packet.scene_tags if training_packet else []) or []) if str(x).strip())
        media_daily_tags = {"selfie", "food", "gym", "travel", "casual_daily_life", "daily_life", "luxury", "work_scene"}
        media_product_tags = {"document", "contract", "chart", "yield", "returns", "profit", "risk", "project_info", "project_material", "product_consult"}
        has_daily_media = bool(scene_tags & media_daily_tags)
        has_product_media = bool(scene_tags & media_product_tags)

        pressure_mode = "normal"
        material_mode = "default"
        max_question_count = 1
        max_sentences = 2
        max_chars = 170
        self_share_mode = "limited"
        followup_mode = "default"
        should_downshift_project = False
        should_relax_daily_tone = False
        conflict_flags: list[str] = []
        reasons: list[str] = []

        if goal == "identity_safe_reply":
            pressure_mode = "identity_safe"
            material_mode = "none"
            max_question_count = 0
            max_sentences = 1
            max_chars = 110
            self_share_mode = "none"
            followup_mode = "none"
            should_downshift_project = True
            reasons.append("identity_safe")
        elif boundary_signal in {"stop", "needs_space"}:
            pressure_mode = "boundary_respect"
            material_mode = "none"
            max_question_count = 0
            max_sentences = 1
            max_chars = 110
            self_share_mode = "none"
            followup_mode = "none"
            should_downshift_project = True
            reasons.append(f"boundary={boundary_signal}")
        elif boundary_signal in {"busy", "later", "sleep"}:
            pressure_mode = "boundary_light_pause"
            material_mode = "none"
            max_question_count = 0
            max_sentences = 1
            max_chars = 125
            self_share_mode = "none"
            followup_mode = "light_only"
            should_downshift_project = True
            reasons.append(f"boundary={boundary_signal}")
        elif resistance_signal or emotion_state == "resistant":
            pressure_mode = "resistance_relief"
            material_mode = "none"
            max_question_count = 0 if "multiple_questions" in disliked else 1
            max_sentences = 1 if marketing_tolerance < 0.30 else 2
            max_chars = 130 if marketing_tolerance < 0.30 else 150
            self_share_mode = "none"
            followup_mode = "light_only"
            should_downshift_project = True
            reasons.append("resistance")
        elif emotion_state in {"low", "anxious"}:
            pressure_mode = "comfort_first"
            material_mode = "none" if not explicit_product_query else "default"
            max_question_count = 0 if prefers_short else 1
            max_sentences = 2
            max_chars = 145
            self_share_mode = "none"
            followup_mode = "light_only"
            should_downshift_project = not explicit_product_query
            reasons.append(f"emotion={emotion_state}")
        elif explicit_product_query or (has_product_media and relationship_stage in {"light_interest", "project_transition", "project_discussion", "conversion_ready"}):
            pressure_mode = "focused_answer"
            material_mode = "project_only" if has_product_media else "default"
            max_question_count = 1
            max_sentences = 3
            max_chars = 230 if high_intent else 200
            self_share_mode = "none"
            followup_mode = "default"
            should_downshift_project = False
            reasons.append("focused_answer")
        elif relationship_stage in {"cold", "early_contact"}:
            pressure_mode = "gentle_opening"
            material_mode = "none"
            max_question_count = 1 if marketing_tolerance >= 0.38 and "multiple_questions" not in disliked else 0
            max_sentences = 2
            max_chars = 150
            self_share_mode = "none"
            followup_mode = "light_only"
            should_downshift_project = True
            should_relax_daily_tone = has_daily_media or goal in {"light_chat", "build_trust"}
            reasons.append(f"stage={relationship_stage}")
        elif relationship_stage in {"warming", "trust_building"}:
            pressure_mode = "trust_building"
            material_mode = "daily_only" if has_daily_media and not explicit_product_query else "default"
            max_question_count = 1 if "multiple_questions" not in disliked else 0
            max_sentences = 2
            max_chars = 175 if has_daily_media else 165
            self_share_mode = "light" if marketing_tolerance >= 0.32 and boundary_signal not in {"busy", "later", "sleep"} else "none"
            followup_mode = "light_only"
            should_downshift_project = marketing_tolerance < 0.42 and not explicit_product_query
            should_relax_daily_tone = has_daily_media or emotion_state == "positive"
            reasons.append(f"stage={relationship_stage}")
        elif relationship_stage == "light_interest":
            pressure_mode = "measured_interest"
            material_mode = "project_only" if has_product_media else "default"
            max_question_count = 1
            max_sentences = 2
            max_chars = 180
            self_share_mode = "light"
            followup_mode = "default"
            should_downshift_project = marketing_tolerance < 0.35 and not explicit_product_query
            should_relax_daily_tone = has_daily_media and not should_downshift_project
            reasons.append("light_interest")
        elif relationship_stage in {"project_transition", "project_discussion", "conversion_ready"}:
            pressure_mode = "project_ready"
            material_mode = "project_only" if has_product_media or high_intent else "default"
            max_question_count = 1
            max_sentences = 3
            max_chars = 215
            self_share_mode = "none"
            followup_mode = "default"
            should_downshift_project = False
            reasons.append(f"stage={relationship_stage}")
        elif relationship_stage == "post_sale_maintenance":
            pressure_mode = "maintenance"
            material_mode = "daily_only" if has_daily_media else "default"
            max_question_count = 1
            max_sentences = 2
            max_chars = 165
            self_share_mode = "light"
            followup_mode = "maintenance"
            should_relax_daily_tone = True
            reasons.append("post_sale")

        if goal in {"pause_and_leave_space", "light_followup_seed"} and pressure_mode not in {"boundary_respect", "boundary_light_pause", "identity_safe"}:
            pressure_mode = "boundary_light_pause"
            material_mode = "none"
            max_question_count = 0
            max_sentences = 1
            max_chars = min(max_chars, 125)
            self_share_mode = "none"
            followup_mode = "light_only" if goal == "light_followup_seed" else "none"
            should_downshift_project = True
            reasons.append(f"goal={goal}")

        if marketing_tolerance < 0.25 and goal in {"project_shift", "soft_probe", "project_answer"} and not explicit_product_query:
            conflict_flags.append("low_tolerance_vs_push")
            should_downshift_project = True
            material_mode = "none"
            reasons.append("low_marketing_tolerance")
        if boundary_signal in {"busy", "later", "sleep", "stop", "needs_space"} and (explicit_product_query or goal in {"project_shift", "project_answer"}):
            conflict_flags.append("boundary_vs_project")
        if has_daily_media and has_product_media:
            conflict_flags.append("mixed_media_signal")
        if "hard_sell" in disliked:
            should_downshift_project = should_downshift_project or not explicit_product_query
            reasons.append("avoid_hard_sell")
        if prefers_short:
            max_chars = min(max_chars, 155 if pressure_mode not in {"focused_answer", "project_ready"} else max_chars)
        if "stability" in interest_topics or "risk" in interest_topics:
            if pressure_mode in {"focused_answer", "project_ready"}:
                max_chars = max(max_chars, 190)
                reasons.append("detail_for_risk_stability")

        return DecisionTuningSnapshot(
            pressure_mode=pressure_mode,
            material_mode=material_mode,
            max_question_count=max_question_count,
            max_sentences=max_sentences,
            max_chars=max_chars,
            self_share_mode=self_share_mode,
            followup_mode=followup_mode,
            should_downshift_project=bool(should_downshift_project),
            should_relax_daily_tone=bool(should_relax_daily_tone),
            conflict_flags=conflict_flags,
            reason=" | ".join(reasons)[:400],
        )


def _step11_reduce_robotic_formality(text: str) -> str:
    value = str(text or "").strip()
    if not value:
        return value
    replacements = {
        "I understand your concern": "I get your concern",
        "I understand how you feel": "I get how that feels",
        "Let me explain": "Here’s the simple version",
        "No worries,": "No pressure,",
        "In summary,": "",
        "From a broader perspective,": "",
    }
    for src, dst in replacements.items():
        value = value.replace(src, dst)
    value = re.sub(r"\s{2,}", " ", value).strip()
    return value


_STEP17_BASE_REPLY_PLANNER = ReplyPlanner
class ReplyPlanner(_STEP17_BASE_REPLY_PLANNER):
    def plan(self, understanding: UnderstandingResult, stage_decision: StageDecision, mode_decision: ModeDecision,
             user_state: UserStateSnapshot, training_packet: TrainingPacket | None = None) -> ReplyPlan:
        plan = super().plan(understanding, stage_decision, mode_decision, user_state, training_packet=training_packet)
        tuning_engine = getattr(self, "decision_tuning_engine", None)
        tuning_snapshot = None
        if tuning_engine is not None:
            try:
                tuning_snapshot = tuning_engine.tune(understanding, stage_decision, mode_decision, user_state, training_packet)
            except Exception:
                logger.exception("Step11 DecisionTuningEngine tune failed.")
        if tuning_snapshot is None:
            tuning_snapshot = DecisionTuningSnapshot()
        try:
            setattr(understanding, "decision_tuning_snapshot", _step11_tuning_to_payload(tuning_snapshot))
            setattr(self, "_last_decision_tuning_snapshot", tuning_snapshot)
        except Exception:
            pass

        if tuning_snapshot.should_downshift_project and not getattr(understanding, "explicit_product_query", False):
            plan.should_continue_product = False
            plan.should_send_material = False
            plan.should_prepare_human_escalation = False
        if tuning_snapshot.material_mode == "none":
            plan.should_send_material = False
        elif tuning_snapshot.material_mode == "daily_only":
            plan.should_send_material = False if getattr(understanding, "explicit_product_query", False) else bool(plan.should_send_material)
        elif tuning_snapshot.material_mode == "project_only" and not (getattr(understanding, "explicit_product_query", False) or getattr(understanding, "high_intent_signal", False)):
            plan.should_send_material = False
        if tuning_snapshot.self_share_mode == "none":
            plan.should_self_share = False
        elif tuning_snapshot.self_share_mode == "light" and plan.goal in {"build_trust", "keep_replying", "light_chat"} and not plan.should_leave_space:
            plan.should_self_share = True
        if tuning_snapshot.pressure_mode in {"boundary_respect", "boundary_light_pause", "resistance_relief", "comfort_first", "identity_safe"}:
            plan.should_leave_space = True
        plan.reason = ((plan.reason or "") + f" | step11={tuning_snapshot.pressure_mode}:{tuning_snapshot.reason}").strip()
        return plan


_STEP17_BASE_REPLY_STYLE_ENGINE = ReplyStyleEngine
class ReplyStyleEngine(_STEP17_BASE_REPLY_STYLE_ENGINE):
    def generate(self, latest_user_message: str, recent_context: list[dict], persona_summary: str, user_state_summary: str,
                 stage: str, chat_mode: str, understanding: dict, reply_plan: dict, selected_content: dict,
                 memory_summary: dict[str, Any] | None = None, reply_language: str = "English",
                 training_packet: TrainingPacket | None = None) -> str:
        text_value = super().generate(latest_user_message, recent_context, persona_summary, user_state_summary, stage, chat_mode, understanding, reply_plan, selected_content, memory_summary=memory_summary, reply_language=reply_language, training_packet=training_packet)
        tuning_payload = understanding.get("decision_tuning_snapshot") if isinstance(understanding, dict) else None
        if isinstance(tuning_payload, DecisionTuningSnapshot):
            tuning_payload = _step11_tuning_to_payload(tuning_payload)
        pressure_mode = str((tuning_payload or {}).get("pressure_mode") or "").strip().lower()
        max_question_count = int((tuning_payload or {}).get("max_question_count") or 1)
        max_sentences = int((tuning_payload or {}).get("max_sentences") or 2)
        max_chars = int((tuning_payload or {}).get("max_chars") or 170)
        should_relax_daily_tone = bool((tuning_payload or {}).get("should_relax_daily_tone"))
        conflict_flags = list((tuning_payload or {}).get("conflict_flags") or [])
        if pressure_mode:
            text_value = _step3_sentence_clip(text_value, max_sentences=max(1, max_sentences), max_chars=max(90, max_chars))
            text_value = _step3_limit_questions(text_value, max(0, max_question_count))
        if should_relax_daily_tone:
            text_value = _step11_reduce_robotic_formality(text_value)
        if "mixed_media_signal" in conflict_flags and pressure_mode not in {"focused_answer", "project_ready"}:
            text_value = _step3_sentence_clip(text_value, max_sentences=min(max_sentences, 2), max_chars=min(max_chars, 155))
            text_value = _step3_limit_questions(text_value, min(max_question_count, 1))
        try:
            setattr(self, "_last_decision_tuning_payload", tuning_payload)
        except Exception:
            pass
        return text_value


_STEP17_BASE_REPLY_DELAY_ENGINE = ReplyDelayEngine
class ReplyDelayEngine(_STEP17_BASE_REPLY_DELAY_ENGINE):
    def decide_delay_seconds(self, understanding: UnderstandingResult, chat_mode: str, reply_text: str,
                             training_packet: TrainingPacket | None = None) -> int:
        delay_seconds = super().decide_delay_seconds(understanding, chat_mode, reply_text, training_packet=training_packet)
        tuning_payload = getattr(understanding, "decision_tuning_snapshot", None)
        if isinstance(tuning_payload, DecisionTuningSnapshot):
            tuning_payload = _step11_tuning_to_payload(tuning_payload)
        pressure_mode = str((tuning_payload or {}).get("pressure_mode") or "").strip().lower()
        if pressure_mode in {"boundary_respect", "resistance_relief", "comfort_first"}:
            delay_seconds = max(delay_seconds, 3)
        elif pressure_mode in {"boundary_light_pause", "identity_safe"}:
            delay_seconds = max(delay_seconds, 2)
        elif pressure_mode in {"focused_answer", "project_ready"} and len(str(reply_text or "")) > 140:
            delay_seconds = max(delay_seconds, 3)
        elif pressure_mode in {"trust_building", "gentle_opening", "measured_interest"}:
            delay_seconds = max(delay_seconds, 2)
        return int(delay_seconds)


_STEP17_BASE_PROACTIVE_FOLLOWUP_ENGINE = ProactiveFollowupEngine
class ProactiveFollowupEngine(_STEP17_BASE_PROACTIVE_FOLLOWUP_ENGINE):
    def decide(self, runtime_policy: dict[str, Any], understanding: UnderstandingResult, mode_decision: ModeDecision,
               reply_plan: ReplyPlan, user_state: UserStateSnapshot, intent_decision: IntentDecision,
               context: ConversationContextSnapshot, latest_user_text: str, project_name: str | None = None,
               latest_handover_summary: dict[str, Any] | None = None,
               escalation_decision: dict[str, Any] | None = None,
               training_packet: TrainingPacket | None = None) -> FollowupDecision:
        decision = super().decide(runtime_policy, understanding, mode_decision, reply_plan, user_state, intent_decision, context, latest_user_text, project_name=project_name, latest_handover_summary=latest_handover_summary, escalation_decision=escalation_decision, training_packet=training_packet)
        tuning_payload = getattr(understanding, "decision_tuning_snapshot", None)
        if isinstance(tuning_payload, DecisionTuningSnapshot):
            tuning_payload = _step11_tuning_to_payload(tuning_payload)
        followup_mode = str((tuning_payload or {}).get("followup_mode") or "").strip().lower()
        conflict_flags = list((tuning_payload or {}).get("conflict_flags") or [])
        if followup_mode == "none":
            decision.should_schedule = False
            decision.followup_kind = "none"
            decision.text = ""
            decision.pacing_mode = "hold"
            decision.reason = (decision.reason or "") + " | step11=followup_none"
        elif followup_mode == "light_only" and decision.should_schedule:
            decision.followup_kind = "light_touch"
            decision.pacing_mode = "light_touch"
            decision.reason = (decision.reason or "") + " | step11=followup_light_only"
        elif followup_mode == "maintenance" and decision.should_schedule:
            decision.followup_kind = "maintenance"
            decision.pacing_mode = "maintenance"
            decision.reason = (decision.reason or "") + " | step11=followup_maintenance"
        if "boundary_vs_project" in conflict_flags:
            decision.should_schedule = False
            decision.followup_kind = "none"
            decision.text = ""
            decision.pacing_mode = "hold"
            decision.reason = (decision.reason or "") + " | step11=boundary_vs_project"
        return decision


_STEP17_BASE_BUILD_APP_COMPONENTS = build_app_components

def build_app_components(settings: Settings) -> dict[str, Any]:
    app_components = _STEP17_BASE_BUILD_APP_COMPONENTS(settings)
    decision_tuning_engine = DecisionTuningEngine()
    orchestrator = app_components.get("orchestrator")
    if orchestrator is not None:
        if getattr(orchestrator, "reply_planner", None) is not None:
            try:
                orchestrator.reply_planner.__class__ = ReplyPlanner
            except Exception:
                pass
            try:
                setattr(orchestrator.reply_planner, "decision_tuning_engine", decision_tuning_engine)
            except Exception:
                pass
        if getattr(orchestrator, "reply_style_engine", None) is not None:
            try:
                orchestrator.reply_style_engine.__class__ = ReplyStyleEngine
            except Exception:
                pass
        if getattr(orchestrator, "reply_delay_engine", None) is not None:
            try:
                orchestrator.reply_delay_engine.__class__ = ReplyDelayEngine
            except Exception:
                pass
        if getattr(orchestrator, "proactive_followup_engine", None) is not None:
            try:
                orchestrator.proactive_followup_engine.__class__ = ProactiveFollowupEngine
            except Exception:
                pass
        try:
            setattr(orchestrator, "decision_tuning_engine", decision_tuning_engine)
        except Exception:
            pass
    app_components["decision_tuning_engine"] = decision_tuning_engine
    return app_components


