_STEP18_BASE_CONTENT_SELECTOR = ContentSelector
class ContentSelector(_STEP18_BASE_CONTENT_SELECTOR):
    def select(self, business_account_id: int, project_id: int | None, mode: str, reply_plan: ReplyPlan,
               training_packet: TrainingPacket | None = None) -> dict:
        selected = super().select(business_account_id, project_id, mode, reply_plan, training_packet=training_packet)
        semantic_service: MaterialSemanticService | None = getattr(self, 'semantic_profile_service', None)
        query_tags = _step18_dedup(list(getattr(training_packet, 'scene_tags', []) or []), 24)
        if not query_tags:
            query_tags = _step18_dedup(list(selected.get('semantic_query_tags') or []), 24)
        query_tags.extend(_step18_dedup(list((selected.get('training_material_policy') or {}).get('scene_tags') or []), 12))
        query_tags = _step18_dedup(query_tags, 24)
        allow_material = bool(getattr(reply_plan, 'should_send_material', False))
        limit_persona = max(1, len(selected.get('persona_materials') or []) or 2)
        limit_daily = max(1, len(selected.get('daily_materials') or []) or 2)
        limit_project = max(1, len(selected.get('project_materials') or []) or 2)
        persona_pool = self.material_repo.get_persona_materials(business_account_id)
        daily_pool = self.material_repo.get_daily_materials(business_account_id)
        project_pool = self.material_repo.get_project_materials(project_id) if project_id else []
        selected['persona_materials'] = _step18_rank_semantic_rows(persona_pool, 'persona_material', semantic_service, query_tags, mode, allow_material, limit_persona)
        selected['daily_materials'] = _step18_rank_semantic_rows(daily_pool, 'daily_material', semantic_service, query_tags, mode, allow_material, limit_daily)
        if project_id:
            selected['project_materials'] = _step18_rank_semantic_rows(project_pool, 'project_material', semantic_service, query_tags, mode, allow_material, limit_project)
        package_limit = 1
        packages_by_scope: dict[str, list[dict[str, Any]]] = {}
        for scope in ('project', 'persona', 'daily'):
            package_rows = self.material_repo.list_material_packages(business_account_id, package_scope=scope, project_id=project_id)
            ranked_rows = _step18_rank_semantic_rows(package_rows, 'material_package', semantic_service, query_tags, mode, allow_material, package_limit)
            packages_by_scope[scope] = [self.material_repo.build_material_package(row) for row in ranked_rows]
            for built_payload, raw_row in zip(packages_by_scope[scope], ranked_rows):
                built_payload['semantic_profile'] = raw_row.get('semantic_profile') or {}
                built_payload['semantic_score'] = raw_row.get('semantic_score') or 0.0
                built_payload['semantic_match_summary'] = raw_row.get('semantic_match_summary') or ''
        selected['material_packages'] = packages_by_scope
        selected['semantic_query_tags'] = query_tags
        selected['semantic_persistence_enabled'] = True
        summaries: list[str] = []
        for bucket_name in ('persona_materials', 'daily_materials', 'project_materials'):
            for item in list(selected.get(bucket_name) or [])[:2]:
                summary = str((item.get('semantic_profile') or {}).get('summary') or item.get('semantic_match_summary') or '').strip()
                if summary:
                    summaries.append(summary)
        for scope in ('project', 'persona', 'daily'):
            for package in list((selected.get('material_packages') or {}).get(scope) or [])[:1]:
                summary = str((package.get('semantic_profile') or {}).get('summary') or package.get('semantic_match_summary') or '').strip()
                if summary:
                    summaries.append(summary)
        semantic_summary = ' | '.join(_step18_dedup(summaries, 6))
        if semantic_summary:
            selected['semantic_match_summary'] = semantic_summary[:500]
            prompt_summary = str(selected.get('prompt_summary') or '').strip()
            selected['prompt_summary'] = f"{prompt_summary} | persisted_semantic={selected['semantic_match_summary']}"[:950]
        return selected


_STEP18_BASE_BUILD_APP_COMPONENTS = build_app_components

def build_app_components(settings: Settings) -> dict[str, Any]:
    app_components = _STEP18_BASE_BUILD_APP_COMPONENTS(settings)
    db = app_components.get('db')
    orchestrator = app_components.get('orchestrator')
    admin_api_service = app_components.get('admin_api_service')
    semantic_repo = MaterialSemanticRepository(db) if db is not None else None
    material_repo = getattr(orchestrator, 'material_repo', None) if orchestrator is not None else None
    semantic_service = None
    if material_repo is not None:
        try:
            material_repo.__class__ = MaterialRepository
        except Exception:
            pass
    if material_repo is not None and semantic_repo is not None:
        semantic_service = MaterialSemanticService(semantic_repo, material_repo)
        try:
            setattr(material_repo, 'semantic_profile_service', semantic_service)
        except Exception:
            pass
        if getattr(orchestrator, 'content_selector', None) is not None:
            try:
                orchestrator.content_selector.__class__ = ContentSelector
            except Exception:
                pass
            try:
                setattr(orchestrator.content_selector, 'semantic_profile_service', semantic_service)
            except Exception:
                pass
        if admin_api_service is not None and getattr(admin_api_service, 'material_repo', None) is material_repo:
            try:
                setattr(admin_api_service.material_repo, 'semantic_profile_service', semantic_service)
            except Exception:
                pass
    app_components['material_semantic_repository'] = semantic_repo
    app_components['material_semantic_service'] = semantic_service
    return app_components



