# step19 multimodal strengthening (step13)
# =========================

_STEP19_DAILY_HINTS = {
    'selfie': ['selfie', 'portrait', 'face', 'mirror', 'smile'],
    'food': ['food', 'meal', 'dish', 'drink', 'coffee', 'restaurant'],
    'gym': ['gym', 'fitness', 'workout', 'training', 'sportswear'],
    'travel': ['travel', 'trip', 'airport', 'flight', 'hotel', 'beach', 'resort'],
    'work_scene': ['office', 'desk', 'computer', 'meeting', 'work'],
    'luxury': ['watch', 'car', 'jewelry', 'villa', 'luxury', 'fashion'],
}

_STEP19_PRODUCT_HINTS = {
    'chart': ['chart', 'graph', 'trend', 'report', 'analysis', 'data'],
    'document': ['document', 'contract', 'agreement', 'invoice', 'policy', 'statement', 'terms'],
    'yield': ['yield', 'return', 'returns', 'profit', 'income', 'apr', 'apy', 'roi'],
    'risk': ['risk', 'safe', 'safety', 'secure', 'loss', 'drawdown', 'hedge'],
    'process': ['process', 'steps', 'how it works', 'guide', 'instruction', 'workflow'],
    'project_media': ['project', 'proposal', 'plan', 'portfolio'],
}


def _step19_norm_text(*parts: Any) -> str:
    return ' | '.join(str(part or '').strip() for part in parts if str(part or '').strip()).strip().lower()


def _step19_add_tag(out: list[str], tag: str) -> None:
    normalized = str(tag or '').strip().lower().replace(' ', '_')
    if normalized and normalized not in out:
        out.append(normalized)


def _step19_extract_media_features(text: str, message_type: str = '') -> dict[str, Any]:
    blob = _step19_norm_text(text)
    tags: list[str] = []
    topic_tags: list[str] = []
    if not blob and message_type:
        base = {'image': 'image_shared', 'video': 'video_shared', 'voice': 'voice_shared'}.get(message_type)
        if base:
            tags.append(base)
        if message_type in ('image', 'video', 'voice', 'file'):
            tags.append('media_shared')
        return {'tags': tags, 'topic_tags': topic_tags, 'scene_type': _step13_media_scene_type(tags, message_type)}
    for tag, keywords in _STEP19_DAILY_HINTS.items():
        if any(keyword in blob for keyword in keywords):
            _step19_add_tag(tags, tag)
            _step19_add_tag(tags, 'daily_media')
            _step19_add_tag(topic_tags, tag)
    for tag, keywords in _STEP19_PRODUCT_HINTS.items():
        if any(keyword in blob for keyword in keywords):
            _step19_add_tag(tags, tag)
            _step19_add_tag(tags, 'product_media')
            _step19_add_tag(topic_tags, tag)
    for tag in _step13_media_extract_tags_from_text(blob, message_type):
        _step19_add_tag(tags, tag)
        if tag in STEP13_DAILY_MEDIA_TAGS or tag in STEP13_PRODUCT_MEDIA_TAGS:
            _step19_add_tag(topic_tags, tag)
    if message_type == 'image':
        _step19_add_tag(tags, 'image_shared')
    elif message_type == 'video':
        _step19_add_tag(tags, 'video_shared')
    elif message_type == 'voice':
        _step19_add_tag(tags, 'voice_shared')
    if message_type in ('image', 'video', 'voice', 'file'):
        _step19_add_tag(tags, 'media_shared')
    scene_type = _step13_media_scene_type(tags, message_type)
    if 'document' in tags or 'chart' in tags:
        scene_type = 'product_media'
    elif {'selfie', 'food', 'gym', 'travel', 'luxury', 'work_scene'} & set(tags):
        scene_type = 'daily_media'
    return {
        'tags': _training_dedup_strings(tags, 28),
        'topic_tags': _training_dedup_strings(topic_tags, 16),
        'scene_type': scene_type,
    }


def _step19_voice_emotion_hint(transcript: str) -> str:
    base = _step13_voice_emotion_from_transcript(transcript)
    lowered = str(transcript or '').strip().lower()
    if not lowered:
        return base
    if any(token in lowered for token in ('angry', 'upset', 'frustrated', 'annoyed', '烦', '别说', '别烦')):
        return 'annoyed'
    if any(token in lowered for token in ('sad', 'down', 'depressed', 'upset', '难过', '失落')):
        return 'low'
    if any(token in lowered for token in ('busy', 'working', 'meeting', '赶', '忙', 'later')) and base == 'neutral':
        return 'tired'
    return base


def _step19_media_url_kind(media_url: str) -> str:
    lowered = str(media_url or '').strip().lower()
    if not lowered:
        return ''
    if any(lowered.endswith(ext) for ext in ('.jpg', '.jpeg', '.png', '.webp', '.gif')):
        return 'image'
    if any(lowered.endswith(ext) for ext in ('.mp4', '.mov', '.mkv', '.webm')):
        return 'video'
    if any(lowered.endswith(ext) for ext in ('.mp3', '.ogg', '.wav', '.m4a')):
        return 'audio'
    return ''


_STEP19_BASE_OPENAI_CLIENT_ADAPTER = OpenAIClientAdapter
class OpenAIClientAdapter(_STEP19_BASE_OPENAI_CLIENT_ADAPTER):
    def summarize_video_context(self, media_url: str, context_text: str = '', model: str = 'gpt-4.1-mini') -> str:
        # 当前阶段不做逐帧视频理解；这里保留兼容接口，优先基于上下文做轻量摘要。
        url = str(media_url or '').strip()
        hint = str(context_text or '').strip()
        if not url:
            return hint[:180]
        kind = _step19_media_url_kind(url)
        if kind != 'video':
            return hint[:180]
        # 现阶段视频先使用 caption/文件名/上下文做摘要，后面可升级为更强的视频理解。
        return hint[:180]


_STEP19_BASE_MEDIA_UNDERSTANDING_SERVICE = MediaUnderstandingService
class MediaUnderstandingService(_STEP19_BASE_MEDIA_UNDERSTANDING_SERVICE):
    def _describe_video(self, media_url: str, media_meta: dict[str, Any]) -> str:
        caption = str(media_meta.get('caption') or media_meta.get('caption_text') or '').strip()
        file_name = str(media_meta.get('file_name') or '').strip()
        context_text = ' | '.join(part for part in [caption, file_name, _step6_basic_media_summary(media_meta)] if part)
        if self.llm_service and getattr(self.llm_service, 'client_adapter', None):
            try:
                return self.llm_service.client_adapter.summarize_video_context(media_url, context_text)
            except Exception:
                return context_text[:180]
        return context_text[:180]

    def analyze_inbound_message(self, inbound_message: InboundMessage) -> dict[str, Any]:
        analysis = super().analyze_inbound_message(inbound_message)
        media_meta = dict(analysis.get('media_meta') or {})
        message_type = str(analysis.get('message_type') or inbound_message.message_type or 'text').strip().lower()
        media_url = str(analysis.get('media_url') or inbound_message.media_url or '').strip()
        caption = str(media_meta.get('caption') or media_meta.get('caption_text') or '').strip()
        file_name = str(media_meta.get('file_name') or '').strip()
        video_summary = ''
        if message_type == 'video' and media_url:
            video_summary = self._describe_video(media_url, media_meta)
        semantic_blob = ' | '.join([
            str(analysis.get('media_summary') or ''),
            str(analysis.get('image_description') or ''),
            str(analysis.get('voice_transcript') or ''),
            video_summary,
            caption,
            file_name,
        ])
        features = _step19_extract_media_features(semantic_blob, message_type)
        voice_emotion = _step19_voice_emotion_hint(str(analysis.get('voice_transcript') or '')) if message_type == 'voice' else ''
        tags = list(features.get('tags') or [])
        if voice_emotion:
            tags = _training_dedup_strings(tags + [f'voice_{voice_emotion}'], 28)
        analysis['video_summary'] = video_summary
        analysis['media_tags'] = tags
        analysis['topic_tags'] = _training_dedup_strings(list(features.get('topic_tags') or []), 16)
        analysis['scene_type'] = str(features.get('scene_type') or analysis.get('scene_type') or '').strip() or _step13_media_scene_type(tags, message_type)
        analysis['voice_emotion'] = voice_emotion
        effective_user_text = _step6_build_effective_user_text(
            inbound_message.text,
            str(analysis.get('media_summary') or ''),
            str(analysis.get('voice_transcript') or ''),
            str(analysis.get('image_description') or '') or video_summary,
        )
        if video_summary and video_summary.lower() not in effective_user_text.lower():
            effective_user_text = (effective_user_text + f"\n\nMedia context: {video_summary}").strip()
        analysis['effective_user_text'] = effective_user_text
        return analysis

    def enrich_inbound_message(self, inbound_message: InboundMessage) -> InboundMessage:
        analysis = self.analyze_inbound_message(inbound_message)
        raw_payload = dict(inbound_message.raw_payload or {})
        raw_payload['step6_media_analysis'] = {
            'message_type': analysis.get('message_type'),
            'media_summary': analysis.get('media_summary'),
            'image_description': analysis.get('image_description'),
            'video_summary': analysis.get('video_summary'),
            'voice_transcript': analysis.get('voice_transcript'),
            'media_meta': analysis.get('media_meta'),
            'media_tags': analysis.get('media_tags') or [],
            'topic_tags': analysis.get('topic_tags') or [],
            'scene_type': analysis.get('scene_type') or '',
            'voice_emotion': analysis.get('voice_emotion') or None,
        }
        effective_text = str(analysis.get('effective_user_text') or '').strip()
        return replace(
            inbound_message,
            text=effective_text or inbound_message.text,
            media_url=analysis.get('media_url') or inbound_message.media_url,
            raw_payload=raw_payload,
        )


_STEP19_BASE_MATERIAL_SEMANTIC_SERVICE = MaterialSemanticService
class MaterialSemanticService(_STEP19_BASE_MATERIAL_SEMANTIC_SERVICE):
    def __init__(self, semantic_repo: MaterialSemanticRepository, material_repo: MaterialRepository, llm_service: LLMService | None = None) -> None:
        super().__init__(semantic_repo, material_repo)
        self.llm_service = llm_service

    def _material_media_description(self, row: dict[str, Any]) -> str:
        media_url = str((row or {}).get('media_url') or '').strip()
        if not media_url:
            return ''
        kind = _step19_media_url_kind(media_url)
        context_text = ' | '.join(
            str(part or '').strip()
            for part in [row.get('content_text'), row.get('caption_text'), row.get('description'), row.get('package_name'), row.get('title')]
            if str(part or '').strip()
        )[:300]
        if kind == 'image' and self.llm_service and getattr(self.llm_service, 'client_adapter', None):
            try:
                return self.llm_service.client_adapter.describe_image_from_url(media_url, f'Describe this material image for semantic tagging. Context: {context_text}')
            except Exception:
                return context_text
        if kind == 'video' and self.llm_service and getattr(self.llm_service, 'client_adapter', None):
            try:
                return self.llm_service.client_adapter.summarize_video_context(media_url, context_text)
            except Exception:
                return context_text
        return context_text

    def ensure_profile(self, material_scope: str, row: dict[str, Any]) -> dict[str, Any]:
        material_id = int((row or {}).get('id') or 0)
        if material_id <= 0:
            return {}
        package_payload = self._package_payload(row) if material_scope == 'material_package' else None
        enriched_row = dict(row or {})
        media_desc = self._material_media_description(enriched_row)
        if media_desc:
            enriched_row['step19_media_description'] = media_desc
        profile = _step18_build_material_profile(material_scope, material_id, enriched_row, package_payload=package_payload)
        extra_blob = ' | '.join([
            str(enriched_row.get('content_text') or ''),
            str(enriched_row.get('caption_text') or ''),
            str(enriched_row.get('description') or ''),
            str(enriched_row.get('package_name') or ''),
            str(enriched_row.get('media_url') or ''),
            str(media_desc or ''),
        ])
        features = _step19_extract_media_features(extra_blob, _step19_media_url_kind(str(enriched_row.get('media_url') or '')))
        profile.semantic_tags = _step18_dedup(list(profile.semantic_tags or []) + list(features.get('tags') or []), 28)
        profile.topic_tags = _step18_dedup(list(profile.topic_tags or []) + list(features.get('topic_tags') or []), 16)
        summary_parts = [profile.summary_text, media_desc]
        profile.summary_text = ' | '.join(part.strip() for part in summary_parts if str(part or '').strip())[:240]
        semantic_text_parts = [profile.semantic_text, media_desc]
        profile.semantic_text = ' | '.join(part.strip() for part in semantic_text_parts if str(part or '').strip())[:700]
        profile.scene_fit = _step18_dedup(list(profile.scene_fit or []) + _step18_guess_scene_fit(material_scope, profile.semantic_tags, enriched_row), 14)
        profile.do_not_use_in = _step18_dedup(list(profile.do_not_use_in or []) + _step18_guess_do_not_use_in(material_scope, profile.semantic_tags), 14)
        profile.source_hash = _step18_build_hash({
            'scope': material_scope,
            'material_id': material_id,
            'row': enriched_row,
            'package_payload': package_payload or {},
            'media_desc': media_desc,
            'semantic_tags': profile.semantic_tags,
            'topic_tags': profile.topic_tags,
        })
        existing = self.semantic_repo.get_profile(material_scope, material_id)
        if existing and str(existing.get('source_hash') or '') == profile.source_hash:
            return existing
        return self.semantic_repo.upsert_profile(profile)


_STEP19_BASE_CONTENT_SELECTOR = ContentSelector
class ContentSelector(_STEP19_BASE_CONTENT_SELECTOR):
    def select(self, business_account_id: int, project_id: int | None, mode: str, reply_plan: ReplyPlan,
               training_packet: TrainingPacket | None = None) -> dict:
        selected = super().select(business_account_id, project_id, mode, reply_plan, training_packet=training_packet)
        media_scene_bias = [tag for tag in (getattr(training_packet, 'scene_tags', []) or []) if tag in ('daily_media', 'product_media', 'document', 'chart', 'selfie', 'food', 'gym', 'travel', 'voice_annoyed', 'voice_tired')]
        if media_scene_bias:
            selected['semantic_query_tags'] = _step18_dedup(list(selected.get('semantic_query_tags') or []) + media_scene_bias, 28)
            summary = str(selected.get('semantic_match_summary') or '').strip()
            if media_scene_bias:
                bias_text = ','.join(media_scene_bias[:6])
                selected['semantic_match_summary'] = (summary + f' | media_bias={bias_text}').strip(' |')[:600]
        return selected


_STEP19_BASE_BUILD_APP_COMPONENTS = build_app_components

def build_app_components(settings: Settings) -> dict[str, Any]:
    app_components = _STEP19_BASE_BUILD_APP_COMPONENTS(settings)
    orchestrator = app_components.get('orchestrator')
    llm_service = app_components.get('llm_service')
    semantic_repo = app_components.get('material_semantic_repository')
    material_repo = getattr(orchestrator, 'material_repo', None) if orchestrator is not None else None
    if app_components.get('tg_client') is not None and llm_service is not None and orchestrator is not None:
        try:
            orchestrator.media_understanding_service = MediaUnderstandingService(app_components['tg_client'], llm_service)
        except Exception:
            pass
    if material_repo is not None and semantic_repo is not None:
        semantic_service = MaterialSemanticService(semantic_repo, material_repo, llm_service=llm_service)
        try:
            setattr(material_repo, 'semantic_profile_service', semantic_service)
        except Exception:
            pass
        if getattr(orchestrator, 'content_selector', None) is not None:
            try:
                orchestrator.content_selector.__class__ = ContentSelector
            except Exception:
                pass
            try:
                setattr(orchestrator.content_selector, 'semantic_profile_service', semantic_service)
            except Exception:
                pass
        app_components['material_semantic_service'] = semantic_service
    app_components['multimodal_step13_enabled'] = True
    return app_components


# =========================
# step20 acceptance audit and system reconciliation (step14)
# =========================

@dataclass
class AcceptanceAuditSnapshot:
    score: int = 100
    risk_level: str = "low"
    should_shorten_reply: bool = False
    should_soften_promotion: bool = False
    should_skip_followup: bool = False
    should_leave_space: bool = False
    max_question_count: int = 1
    max_sentences: int = 3
    max_chars: int = 220
    issue_flags: list[str] = field(default_factory=list)
    needs_human_review: bool = False
    reason: str = ""


def _step20_acceptance_to_payload(snapshot: AcceptanceAuditSnapshot | None) -> dict[str, Any]:
    if not snapshot:
        return {}
    return {
        "score": int(snapshot.score),
        "risk_level": str(snapshot.risk_level or "low"),
        "should_shorten_reply": bool(snapshot.should_shorten_reply),
        "should_soften_promotion": bool(snapshot.should_soften_promotion),
        "should_skip_followup": bool(snapshot.should_skip_followup),
        "should_leave_space": bool(snapshot.should_leave_space),
        "max_question_count": int(snapshot.max_question_count),
        "max_sentences": int(snapshot.max_sentences),
        "max_chars": int(snapshot.max_chars),
        "issue_flags": list(snapshot.issue_flags or []),
        "needs_human_review": bool(snapshot.needs_human_review),
        "reason": str(snapshot.reason or ""),
    }


def _step20_question_count(text: str) -> int:
    try:
        return str(text or "").count("?")
    except Exception:
        return 0


def _step20_contains_any(text: str, phrases: list[str]) -> bool:
    hay = str(text or "").lower()
    return any(str(p or "").lower() in hay for p in phrases if str(p or "").strip())


def _step20_daily_scene(scene_tags: list[str] | None) -> bool:
    tags = {str(x).strip().lower() for x in (scene_tags or []) if str(x).strip()}
    return bool(tags.intersection({
        "daily_chat", "daily_media", "selfie", "food", "gym", "travel", "casual_daily_life",
        "work_scene", "lifestyle"
    }))


def _step20_product_scene(scene_tags: list[str] | None) -> bool:
    tags = {str(x).strip().lower() for x in (scene_tags or []) if str(x).strip()}
    return bool(tags.intersection({
        "product_consult", "product_media", "document", "chart", "yield", "returns", "risk", "contract", "project_material"
    }))


def _step20_soft_daily_rewrite(text: str) -> str:
    value = str(text or "").strip()
    replacements = {
        "I understand your concern": "I get what you mean",
        "Let me explain": "Here’s the simple part",
        "please be informed that": "just so you know",
        "I would say that": "I’d say",
        "In summary": "So",
    }
    for old, new in replacements.items():
        value = re.sub(re.escape(old), new, value, flags=re.IGNORECASE)
    value = re.sub(r"\s{2,}", " ", value).strip()
    return value


def _step20_remove_product_push(text: str) -> str:
    value = str(text or "")
    patterns = [
        r"\bjoin now\b",
        r"\bstart now\b",
        r"\bact now\b",
        r"\bdon't miss this\b",
        r"\bguaranteed returns?\b",
        r"\bguaranteed return\b",
        r"\bno risk\b",
        r"\brisk[- ]?free\b",
    ]
    for pat in patterns:
        value = re.sub(pat, "", value, flags=re.IGNORECASE)
    value = re.sub(r"\s{2,}", " ", value).strip(" ,.;")
    return value.strip()


class AcceptanceAuditEngine:
    PRODUCT_WORDS = [
        "profit", "return", "returns", "yield", "package", "project", "investment", "opportunity", "earn",
        "stable return", "risk control", "materials"
    ]

    def audit(self,
              understanding: UnderstandingResult,
              reply_plan: ReplyPlan | None,
              reply_text: str,
              training_packet: TrainingPacket | None = None,
              profile_snapshot: UserProfileEvolutionSnapshot | None = None) -> AcceptanceAuditSnapshot:
        text = str(reply_text or "").strip()
        scene_tags = list((getattr(training_packet, 'scene_tags', None) if training_packet else []) or [])
        goal = str(getattr(reply_plan, 'goal', '') or '').strip().lower()
        emotion_state = str(getattr(understanding, 'emotion_state', None) or '').strip().lower()
        boundary_signal = str(getattr(understanding, 'boundary_signal', None) or '').strip().lower()
        resistance_signal = str(getattr(understanding, 'resistance_signal', None) or '').strip().lower()
        explicit_product_query = bool(getattr(understanding, 'explicit_product_query', False))
        high_intent_signal = bool(getattr(understanding, 'high_intent_signal', False))
        marketing_tolerance = float(getattr(profile_snapshot, 'marketing_tolerance_score', 0.4) or 0.4) if profile_snapshot else 0.4
        disliked = {str(x).strip().lower() for x in ((getattr(profile_snapshot, 'disliked_patterns', None) if profile_snapshot else []) or []) if str(x).strip()}

        score = 100
        flags: list[str] = []
        should_shorten = False
        should_soften = False
        should_skip_followup = False
        should_leave_space = False
        needs_human_review = False

        max_question_count = 1
        max_sentences = 3
        max_chars = 220
        risk_level = "low"
        reason_parts: list[str] = []

        identity_scene = goal == 'identity_safe_reply' or 'identity_probe' in {t.lower() for t in scene_tags}
        daily_scene = _step20_daily_scene(scene_tags)
        product_scene = explicit_product_query or high_intent_signal or _step20_product_scene(scene_tags) or goal in {'project_answer', 'project_shift'}
        contains_product_push = _step20_contains_any(text, self.PRODUCT_WORDS)
        question_count = _step20_question_count(text)

        if identity_scene:
            max_question_count = 0
            max_sentences = 2
            max_chars = 120
            should_skip_followup = True
            should_leave_space = True
            reason_parts.append('identity_scene')
        elif boundary_signal in {'stop', 'needs_space', 'sleep'}:
            max_question_count = 0
            max_sentences = 2
            max_chars = 120
            should_skip_followup = True
            should_leave_space = True
            flags.append('boundary_sensitive')
            score -= 12
            reason_parts.append(f'boundary={boundary_signal}')
        elif boundary_signal in {'busy', 'later'}:
            max_question_count = 0
            max_sentences = 2
            max_chars = 150
            should_skip_followup = True
            should_leave_space = True
            flags.append('busy_sensitive')
            score -= 8
            reason_parts.append(f'boundary={boundary_signal}')
        elif resistance_signal in {'resistant', 'high'} or emotion_state in {'anxious', 'low'}:
            max_question_count = 1
            max_sentences = 2
            max_chars = 165
            should_shorten = True
            should_soften = True
            reason_parts.append('comfort_mode')
        elif product_scene:
            max_question_count = 1
            max_sentences = 4
            max_chars = 300
            reason_parts.append('product_scene')

        if getattr(profile_snapshot, 'prefers_short_reply', False):
            max_sentences = min(max_sentences, 2)
            max_chars = min(max_chars, 160)
            should_shorten = True
            reason_parts.append('prefers_short_reply')
        if 'multiple_questions' in disliked:
            max_question_count = min(max_question_count, 1)
        if 'long_replies' in disliked:
            max_chars = min(max_chars, 150)
            max_sentences = min(max_sentences, 2)
            should_shorten = True
        if 'hard_sell' in disliked:
            should_soften = True

        if marketing_tolerance < 0.34 and not explicit_product_query and contains_product_push:
            flags.append('product_pressure_mismatch')
            score -= 18
            should_soften = True
            should_skip_followup = True
            if daily_scene:
                should_leave_space = True
            reason_parts.append('low_marketing_tolerance')

        if daily_scene and not explicit_product_query and contains_product_push:
            flags.append('daily_scene_product_push')
            score -= 14
            should_soften = True
            should_shorten = True
            reason_parts.append('daily_scene')

        if len(text) > max_chars:
            flags.append('reply_too_long')
            score -= 10
            should_shorten = True
        if question_count > max_question_count:
            flags.append('too_many_questions')
            score -= 8
            should_shorten = True
        if identity_scene and question_count > 0:
            flags.append('identity_overexplaining')
            score -= 8
            should_shorten = True
        if boundary_signal in {'busy', 'later', 'sleep', 'stop', 'needs_space'} and len(text) > 150:
            flags.append('boundary_overreply')
            score -= 10
            should_shorten = True
            should_leave_space = True

        if score < 65:
            risk_level = 'high'
        elif score < 82:
            risk_level = 'medium'
        if score < 55 and resistance_signal in {'resistant', 'high'}:
            needs_human_review = True
            flags.append('needs_human_review')

        return AcceptanceAuditSnapshot(
            score=max(0, score),
            risk_level=risk_level,
            should_shorten_reply=bool(should_shorten),
            should_soften_promotion=bool(should_soften),
            should_skip_followup=bool(should_skip_followup),
            should_leave_space=bool(should_leave_space),
            max_question_count=max(0, int(max_question_count)),
            max_sentences=max(1, int(max_sentences)),
            max_chars=max(90, int(max_chars)),
            issue_flags=_training_dedup_strings(flags, 12),
            needs_human_review=bool(needs_human_review),
            reason=' | '.join(reason_parts)[:320],
        )


_STEP20_BASE_REPLY_STYLE_ENGINE = ReplyStyleEngine
class ReplyStyleEngine(_STEP20_BASE_REPLY_STYLE_ENGINE):
    def generate(self, latest_user_message: str, recent_context: list[dict], persona_summary: str, user_state_summary: str,
                 stage: str, chat_mode: str, understanding: dict, reply_plan: dict, selected_content: dict,
                 memory_summary: dict[str, Any] | None = None, reply_language: str = "English",
                 training_packet: TrainingPacket | None = None) -> str:
        text_value = super().generate(latest_user_message, recent_context, persona_summary, user_state_summary, stage, chat_mode, understanding, reply_plan, selected_content, memory_summary=memory_summary, reply_language=reply_language, training_packet=training_packet)
        scene_tags = list((getattr(training_packet, 'scene_tags', None) if training_packet else []) or [])
        if _step20_daily_scene(scene_tags) and not _step20_product_scene(scene_tags):
            text_value = _step20_soft_daily_rewrite(text_value)
        return text_value


_STEP20_BASE_REPLY_SELF_CHECK_ENGINE = ReplySelfCheckEngine
class ReplySelfCheckEngine(_STEP20_BASE_REPLY_SELF_CHECK_ENGINE):
    def check_and_fix(self, draft_reply: str, mode: str, understanding: UnderstandingResult,
                      training_packet: TrainingPacket | None = None) -> str:
        text_value = super().check_and_fix(draft_reply, mode, understanding, training_packet=training_packet)
        profile_snapshot = getattr(self, '_runtime_profile_snapshot', None)
        reply_plan = None
        try:
            planner = getattr(self, 'reply_planner', None)
            reply_plan = getattr(planner, '_last_reply_plan', None) if planner is not None else None
        except Exception:
            reply_plan = None
        audit_engine = getattr(self, 'acceptance_audit_engine', None)
        audit_snapshot = None
        if audit_engine is not None:
            try:
                audit_snapshot = audit_engine.audit(understanding, reply_plan, text_value, training_packet=training_packet, profile_snapshot=profile_snapshot)
            except Exception:
                logger.exception('Step20 AcceptanceAuditEngine audit failed.')
        if audit_snapshot is None:
            audit_snapshot = AcceptanceAuditSnapshot()

        if audit_snapshot.should_soften_promotion:
            text_value = _step3_soften_hard_sell(text_value)
            text_value = _step20_remove_product_push(text_value)
        text_value = _step3_limit_questions(text_value, audit_snapshot.max_question_count)
        if audit_snapshot.should_shorten_reply:
            text_value = _step3_sentence_clip(text_value, max_sentences=audit_snapshot.max_sentences, max_chars=audit_snapshot.max_chars)
        elif len(str(text_value or '')) > audit_snapshot.max_chars:
            text_value = _step3_sentence_clip(text_value, max_sentences=audit_snapshot.max_sentences, max_chars=audit_snapshot.max_chars)
        if audit_snapshot.should_leave_space and len(str(text_value or '')) > 145:
            text_value = _step3_sentence_clip(text_value, max_sentences=2, max_chars=min(145, audit_snapshot.max_chars))
        if audit_snapshot.risk_level == 'high' and audit_snapshot.should_skip_followup and mode in {'pause', 'maintain'}:
            text_value = _step3_sentence_clip(text_value, max_sentences=1, max_chars=min(120, audit_snapshot.max_chars))
        try:
            setattr(understanding, 'acceptance_audit_snapshot', _step20_acceptance_to_payload(audit_snapshot))
            setattr(self, '_last_acceptance_audit_snapshot', audit_snapshot)
            setattr(self, '_last_final_reply', text_value)
        except Exception:
            pass
        return str(text_value or '').strip()


_STEP20_BASE_REPLY_DELAY_ENGINE = ReplyDelayEngine
class ReplyDelayEngine(_STEP20_BASE_REPLY_DELAY_ENGINE):
    def decide_delay_seconds(self, understanding: UnderstandingResult, chat_mode: str, reply_text: str,
                             training_packet: TrainingPacket | None = None) -> int:
        delay_seconds = super().decide_delay_seconds(understanding, chat_mode, reply_text, training_packet=training_packet)
        audit_payload = getattr(understanding, 'acceptance_audit_snapshot', None)
        if isinstance(audit_payload, AcceptanceAuditSnapshot):
            audit_payload = _step20_acceptance_to_payload(audit_payload)
        risk_level = str((audit_payload or {}).get('risk_level') or '').strip().lower()
        if risk_level == 'high':
            delay_seconds = max(delay_seconds, 3)
        elif risk_level == 'medium':
            delay_seconds = max(delay_seconds, 2)
        return int(delay_seconds)


_STEP20_BASE_PROACTIVE_FOLLOWUP_ENGINE = ProactiveFollowupEngine
class ProactiveFollowupEngine(_STEP20_BASE_PROACTIVE_FOLLOWUP_ENGINE):
    def decide(self, runtime_policy: dict[str, Any], understanding: UnderstandingResult, mode_decision: ModeDecision,
               reply_plan: ReplyPlan, user_state: UserStateSnapshot, intent_decision: IntentDecision,
               context: ConversationContextSnapshot, latest_user_text: str, project_name: str | None = None,
               latest_handover_summary: dict[str, Any] | None = None,
               escalation_decision: dict[str, Any] | None = None,
               training_packet: TrainingPacket | None = None) -> FollowupDecision:
        decision = super().decide(runtime_policy, understanding, mode_decision, reply_plan, user_state, intent_decision, context, latest_user_text, project_name=project_name, latest_handover_summary=latest_handover_summary, escalation_decision=escalation_decision, training_packet=training_packet)
        audit_payload = getattr(understanding, 'acceptance_audit_snapshot', None)
        if isinstance(audit_payload, AcceptanceAuditSnapshot):
            audit_payload = _step20_acceptance_to_payload(audit_payload)
        if bool((audit_payload or {}).get('should_skip_followup')):
            decision.should_schedule = False
            decision.followup_kind = 'none'
            decision.text = ''
            decision.pacing_mode = 'hold'
            decision.reason = ((decision.reason or '') + ' | step20=acceptance_skip_followup').strip()
        return decision


_STEP20_BASE_ORCHESTRATOR = Orchestrator
class Orchestrator(_STEP20_BASE_ORCHESTRATOR):
    def _build_training_packet(self, business_account_id: int, runtime_context: dict[str, Any]) -> TrainingPacket:
        packet = super()._build_training_packet(business_account_id, runtime_context)
        profile_snapshot = getattr(self.reply_planner, '_runtime_profile_snapshot', None)
        for target_name in ('reply_style_engine', 'reply_self_check_engine', 'proactive_followup_engine'):
            target = getattr(self, target_name, None)
            if target is not None:
                try:
                    setattr(target, '_runtime_profile_snapshot', profile_snapshot)
                except Exception:
                    pass
        return packet

    def handle_inbound_message(self, inbound_message: InboundMessage) -> None:
        try:
            return super().handle_inbound_message(inbound_message)
        finally:
            for target_name in ('reply_style_engine', 'reply_self_check_engine', 'proactive_followup_engine'):
                target = getattr(self, target_name, None)
                if target is not None:
                    try:
                        setattr(target, '_runtime_profile_snapshot', None)
                    except Exception:
                        pass


