# Step21 - Deep Video Understanding (future optimization step 1)
# =========================

def _step21_video_file_suffix(media_url: str, fallback: str = '.mp4') -> str:
    lowered = str(media_url or '').strip().lower()
    for ext in ('.mp4', '.mov', '.mkv', '.webm', '.avi', '.m4v'):
        if lowered.endswith(ext):
            return ext
    return fallback


def _step21_image_path_to_data_url(image_path: str) -> str:
    import base64
    normalized = str(image_path or '').strip()
    if not normalized or not os.path.exists(normalized):
        return ''
    mime = 'image/jpeg'
    lower = normalized.lower()
    if lower.endswith('.png'):
        mime = 'image/png'
    elif lower.endswith('.webp'):
        mime = 'image/webp'
    with open(normalized, 'rb') as fh:
        payload = fh.read()
    return f'data:{mime};base64,' + base64.b64encode(payload).decode('ascii')


def _step21_extract_video_frame_data_urls(video_url: str, max_frames: int = 3, timeout_seconds: int = 45) -> list[str]:
    import shutil
    import subprocess
    import tempfile
    from pathlib import Path as _Path

    url = str(video_url or '').strip()
    if not url:
        return []

    ffmpeg_bin = shutil.which('ffmpeg')
    if not ffmpeg_bin:
        return []

    temp_dir = tempfile.mkdtemp(prefix='step21_video_')
    video_path = os.path.join(temp_dir, f'input{_step21_video_file_suffix(url)}')
    frame_pattern = os.path.join(temp_dir, 'frame_%02d.jpg')
    data_urls: list[str] = []
    try:
        with urllib_request.urlopen(url, timeout=timeout_seconds) as resp:
            payload = resp.read()
        if not payload:
            return []
        with open(video_path, 'wb') as fh:
            fh.write(payload)

        # 先尽量抽取多个时间点的帧；失败时再退化到单帧缩略图。
        commands = [
            [
                ffmpeg_bin, '-hide_banner', '-loglevel', 'error', '-y',
                '-i', video_path,
                '-vf', 'fps=1/3,scale=min(960\\,iw):-2',
                '-frames:v', str(max_frames),
                frame_pattern,
            ],
            [
                ffmpeg_bin, '-hide_banner', '-loglevel', 'error', '-y',
                '-i', video_path,
                '-vf', 'thumbnail,scale=min(960\\,iw):-2',
                '-frames:v', '1',
                frame_pattern,
            ],
        ]
        for cmd in commands:
            try:
                subprocess.run(cmd, check=False, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, timeout=timeout_seconds)
            except Exception:
                continue
            frame_paths = sorted(str(p) for p in _Path(temp_dir).glob('frame_*.jpg'))[:max_frames]
            if frame_paths:
                for frame_path in frame_paths:
                    data_url = _step21_image_path_to_data_url(frame_path)
                    if data_url:
                        data_urls.append(data_url)
                if data_urls:
                    return data_urls[:max_frames]
        return []
    except Exception:
        return []
    finally:
        try:
            for child in os.listdir(temp_dir):
                try:
                    os.remove(os.path.join(temp_dir, child))
                except Exception:
                    pass
            os.rmdir(temp_dir)
        except Exception:
            pass


_STEP21_BASE_OPENAI_CLIENT_ADAPTER = OpenAIClientAdapter
class OpenAIClientAdapter(_STEP21_BASE_OPENAI_CLIENT_ADAPTER):
    def summarize_video_context(self, media_url: str, context_text: str = '', model: str = 'gpt-4.1-mini') -> str:
        url = str(media_url or '').strip()
        hint = str(context_text or '').strip()
        if not url:
            return hint[:220]
        kind = _step19_media_url_kind(url)
        if kind != 'video':
            return hint[:220]

        frame_data_urls = _step21_extract_video_frame_data_urls(url, max_frames=3)
        if not frame_data_urls:
            return hint[:220]

        prompt_text = (
            'You are helping a Telegram relationship-sales assistant understand a short user or material video. '
            'Based on a few sampled frames and optional text context, write a concise factual summary for reply planning. '
            'Focus on: visible subject, likely setting, obvious activity, social vibe, and likely chat-relevant topic tags. '
            'Do not invent hidden details. Keep it under 90 words. '
            f'Optional context: {hint[:300]}'
        )
        content_parts: list[dict[str, Any]] = [{'type': 'input_text', 'text': prompt_text}]
        for data_url in frame_data_urls[:3]:
            content_parts.append({'type': 'input_image', 'image_url': data_url})
        try:
            response = self.client.responses.create(
                model=model,
                input=[{'role': 'user', 'content': content_parts}],
                max_output_tokens=220,
                temperature=0.1,
            )
        except Exception:
            return hint[:220]
        text_parts: list[str] = []
        for item in getattr(response, 'output', []) or []:
            for content in getattr(item, 'content', []) or []:
                if getattr(content, 'type', None) == 'output_text':
                    text_parts.append(getattr(content, 'text', ''))
        summary = ' '.join(part.strip() for part in text_parts if str(part).strip()).strip()
        if not summary:
            return hint[:220]
        if hint and hint.lower() not in summary.lower():
            summary = f'{summary} | Context: {hint[:120]}'
        return summary[:320]


_STEP21_BASE_MEDIA_UNDERSTANDING_SERVICE = MediaUnderstandingService
class MediaUnderstandingService(_STEP21_BASE_MEDIA_UNDERSTANDING_SERVICE):
    def analyze_inbound_message(self, inbound_message: InboundMessage) -> dict[str, Any]:
        analysis = super().analyze_inbound_message(inbound_message)
        message_type = str(analysis.get('message_type') or inbound_message.message_type or 'text').strip().lower()
        if message_type != 'video':
            return analysis

        video_summary = str(analysis.get('video_summary') or '').strip()
        semantic_blob = ' | '.join([
            video_summary,
            str(analysis.get('media_summary') or ''),
            str(analysis.get('image_description') or ''),
            str((analysis.get('media_meta') or {}).get('caption') or ''),
            str((analysis.get('media_meta') or {}).get('file_name') or ''),
        ])
        deep_features = _step19_extract_media_features(semantic_blob, 'video')
        media_tags = _training_dedup_strings(list(analysis.get('media_tags') or []) + list(deep_features.get('tags') or []) + ['video_content'], 32)
        topic_tags = _training_dedup_strings(list(analysis.get('topic_tags') or []) + list(deep_features.get('topic_tags') or []), 18)
        scene_type = str(deep_features.get('scene_type') or analysis.get('scene_type') or '').strip() or 'product_media'
        analysis['media_tags'] = media_tags
        analysis['topic_tags'] = topic_tags
        analysis['scene_type'] = scene_type
        effective_user_text = str(analysis.get('effective_user_text') or '').strip()
        if video_summary and video_summary.lower() not in effective_user_text.lower():
            effective_user_text = (effective_user_text + f"\n\nVideo understanding: {video_summary}").strip()
        analysis['effective_user_text'] = effective_user_text
        return analysis

    def enrich_inbound_message(self, inbound_message: InboundMessage) -> InboundMessage:
        enriched = super().enrich_inbound_message(inbound_message)
        raw_payload = dict(enriched.raw_payload or {})
        media_analysis = dict(raw_payload.get('step6_media_analysis') or {})
        if str(media_analysis.get('message_type') or '').strip().lower() == 'video':
            media_analysis['deep_video_enabled'] = True
            media_analysis['video_semantic_tags'] = media_analysis.get('media_tags') or []
            raw_payload['step6_media_analysis'] = media_analysis
            return replace(enriched, raw_payload=raw_payload)
        return enriched


_STEP21_BASE_MATERIAL_SEMANTIC_SERVICE = MaterialSemanticService
class MaterialSemanticService(_STEP21_BASE_MATERIAL_SEMANTIC_SERVICE):
    def _material_media_description(self, row: dict[str, Any]) -> str:
        media_desc = super()._material_media_description(row)
        media_url = str((row or {}).get('media_url') or '').strip()
        kind = _step19_media_url_kind(media_url)
        if kind != 'video':
            return media_desc
        context_parts = [
            str((row or {}).get('title') or ''),
            str((row or {}).get('content_text') or ''),
            str((row or {}).get('caption_text') or ''),
            str((row or {}).get('description') or ''),
            str((row or {}).get('package_name') or ''),
        ]
        context_text = ' | '.join(part.strip() for part in context_parts if str(part).strip())[:360]
        if self.llm_service and getattr(self.llm_service, 'client_adapter', None):
            try:
                deep_summary = self.llm_service.client_adapter.summarize_video_context(media_url, context_text)
            except Exception:
                deep_summary = ''
            if deep_summary:
                merged = ' | '.join(part for part in [media_desc, deep_summary] if str(part or '').strip())
                return merged[:400]
        return media_desc


_STEP21_BASE_CONTENT_SELECTOR = ContentSelector
class ContentSelector(_STEP21_BASE_CONTENT_SELECTOR):
    def select(self, business_account_id: int, project_id: int | None, mode: str, reply_plan: ReplyPlan,
               training_packet: TrainingPacket | None = None) -> dict:
        selected = super().select(business_account_id, project_id, mode, reply_plan, training_packet=training_packet)
        media_tags = list((getattr(training_packet, 'scene_tags', None) if training_packet else []) or [])
        if any(tag in media_tags for tag in ('video_content', 'travel', 'gym', 'food', 'document', 'chart', 'yield', 'risk', 'contract')):
            query_tags = list(selected.get('semantic_query_tags') or [])
            selected['semantic_query_tags'] = _step18_dedup(query_tags + media_tags[:8], 32)
            summary = str(selected.get('semantic_match_summary') or '').strip()
            selected['semantic_match_summary'] = (summary + ' | step21=video_bias_applied').strip(' |')[:700]
        return selected


