class TGAdminCallbackRouter(TGAdminCallbackRouter):
    def handle(self, admin_chat_id: int, callback_data: str, operator: str = 'admin') -> None:
        parts = (callback_data or '').split(':')
        business_account_id = self._resolve_business_account_id()
        if parts[:3] == ['adm', 'content', 'material_hub'] and business_account_id is not None:
            summary_rows = self.admin_api_service.summarize_material_workspace_admin(business_account_id)
            self._send_text(admin_chat_id, TGAdminFormatter.format_material_workspace_home(summary_rows), TGAdminMenuBuilder.material_workspace_menu())
            return
        if len(parts) >= 4 and parts[:3] == ['adm', 'content', 'material_kind'] and business_account_id is not None:
            kind = parts[3]
            items = self.admin_api_service.list_material_workspace_items_admin(business_account_id, kind, include_inactive=True, limit=120)
            self._send_text(admin_chat_id, TGAdminFormatter.format_material_workspace_list(kind, items), TGAdminMenuBuilder.material_workspace_list_menu(kind, items))
            return
        if len(parts) >= 4 and parts[:3] == ['adm', 'content', 'package_detail'] and business_account_id is not None and parts[3].isdigit():
            package_id = int(parts[3])
            packages = self.admin_api_service.list_material_packages_admin(business_account_id, include_inactive=True)
            package = next((row for row in packages if int(row.get('id') or 0) == package_id), None)
            if not package:
                self._send_text(admin_chat_id, '❌ 未找到素材包。', [[{'text': '📚 返回素材工作台', 'callback_data': 'adm:content:material_hub'}]])
                return
            self._send_text(admin_chat_id, TGAdminFormatter.format_material_package_detail(package), [[{'text': '📚 返回素材包列表', 'callback_data': 'adm:content:material_kind:package'}], [{'text': '🧱 返回内容管理', 'callback_data': 'adm:content'}]])
            return
        if len(parts) >= 5 and parts[:3] == ['adm', 'content', 'material_quick_new'] and business_account_id is not None:
            scope_key = parts[3]
            kind = parts[4]
            if scope_key not in {'persona', 'daily', 'project'}:
                self._send_text(admin_chat_id, '⚠️ 未知素材范围。')
                return
            if kind in {'package', 'voice'}:
                self._send_text(admin_chat_id, '⚠️ 素材包/语音模板请在对应独立菜单维护，本轮先完成素材工作台与类型管理对齐。', [[{'text': '📚 返回素材工作台', 'callback_data': 'adm:content:material_hub'}]])
                return
            self._activate_text_input(
                admin_chat_id,
                business_account_id,
                f'content_material_quick_new_{scope_key}',
                TGAdminFormatter.format_material_quick_create_prompt(scope_key, kind),
                payload={'material_kind': kind, 'back_callback': f'adm:content:material_kind:{kind}'},
                reply_markup=[[{'text': '📚 返回类型列表', 'callback_data': f'adm:content:material_kind:{kind}'}], [{'text': '🧱 返回内容管理', 'callback_data': 'adm:content'}]],
            )
            return
        return super().handle(admin_chat_id, callback_data, operator)


class TGAdminHandlers(TGAdminHandlers):
    def _parse_material_quick_form(self, text_value: str, scope_key: str, kind: str) -> dict[str, Any] | None:
        fields = [part.strip() for part in (text_value or '').split('|')]
        result: dict[str, Any] = {'kind': kind}
        if scope_key == 'project':
            if kind == 'text':
                if len(fields) < 2 or not fields[0].isdigit():
                    return None
                result['project_id'] = int(fields[0])
                cursor = 1
                if len(fields) > 2 and re.match(r'^-?\d+$', fields[1] or ''):
                    result['priority'] = int(fields[1]); cursor = 2
                result['content_text'] = fields[cursor] if len(fields) > cursor else ''
                result['scene_tags'] = self._parse_scene_tags(fields[cursor + 1] if len(fields) > cursor + 1 else '')
                result['media_url'] = None
                return result
            if len(fields) < 3 or not fields[0].isdigit():
                return None
            result['project_id'] = int(fields[0])
            cursor = 1
            if len(fields) > 3 and re.match(r'^-?\d+$', fields[1] or ''):
                result['priority'] = int(fields[1]); cursor = 2
            result['content_text'] = fields[cursor] if len(fields) > cursor else ''
            result['media_url'] = fields[cursor + 1] if len(fields) > cursor + 1 else ''
            result['scene_tags'] = self._parse_scene_tags(fields[cursor + 2] if len(fields) > cursor + 2 else '')
            return result
        if kind == 'text':
            if len(fields) < 1:
                return None
            cursor = 0
            if len(fields) > 1 and re.match(r'^-?\d+$', fields[0] or ''):
                result['priority'] = int(fields[0]); cursor = 1
            result['content_text'] = fields[cursor] if len(fields) > cursor else ''
            result['scene_tags'] = self._parse_scene_tags(fields[cursor + 1] if len(fields) > cursor + 1 else '')
            result['media_url'] = None
            return result
        if len(fields) < 2:
            return None
        cursor = 0
        if len(fields) > 2 and re.match(r'^-?\d+$', fields[0] or ''):
            result['priority'] = int(fields[0]); cursor = 1
        result['content_text'] = fields[cursor] if len(fields) > cursor else ''
        result['media_url'] = fields[cursor + 1] if len(fields) > cursor + 1 else ''
        result['scene_tags'] = self._parse_scene_tags(fields[cursor + 2] if len(fields) > cursor + 2 else '')
        return result

    def handle_admin_text(self, admin_chat_id: int, text_value: str, operator: str = 'admin') -> None:
        session = self.admin_session_repo.get_session(admin_chat_id) or {}
        state = str(session.get('state') or '')
        payload = session.get('payload_json') or {}
        business_account_id = int(payload.get('business_account_id') or session.get('business_account_id') or 0)
        if state in {'content_material_quick_new_persona', 'content_material_quick_new_daily', 'content_material_quick_new_project'}:
            scope_key = state.rsplit('_', 1)[-1]
            kind = str(payload.get('material_kind') or 'text')
            parsed = self._parse_material_quick_form(text_value, scope_key, kind)
            if not parsed:
                self._send_text(admin_chat_id, '⚠️ 输入格式不正确，请按当前模板重新发送。')
                return
            priority = int(parsed.get('priority') or 100)
            media_url = (parsed.get('media_url') or None)
            scene_tags = parsed.get('scene_tags') or []
            content_text = str(parsed.get('content_text') or '').strip()
            result: dict[str, Any]
            if scope_key == 'persona':
                result = self.admin_api_service.create_persona_material(business_account_id, kind, content_text, media_url, scene_tags, priority)
                label = '人设素材'
            elif scope_key == 'daily':
                result = self.admin_api_service.create_daily_material(business_account_id, kind, content_text, media_url, scene_tags, priority)
                label = '日常素材'
            else:
                project_id = int(parsed.get('project_id') or 0)
                if project_id <= 0:
                    self._send_text(admin_chat_id, '⚠️ 项目ID无效。')
                    return
                result = self.admin_api_service.create_project_material(project_id, kind, content_text, media_url, scene_tags, priority)
                label = '项目素材'
            ok = bool(result.get('ok'))
            message = f"✅ 已新增{label}。" if ok else f"❌ 新增{label}失败：{result.get('reason') or '未知错误'}"
            self._record_action(business_account_id, admin_chat_id, state, message, payload={'material_kind': kind, 'priority': priority}, result_status='success' if ok else 'failed')
            self.admin_session_repo.clear_session(admin_chat_id)
            back_callback = str(payload.get('back_callback') or f'adm:content:material_kind:{kind}')
            self._send_text(admin_chat_id, message, [[{'text': '📚 返回类型列表', 'callback_data': back_callback}], [{'text': '🧱 返回内容管理', 'callback_data': 'adm:content'}]])
            return
        return super().handle_admin_text(admin_chat_id, text_value, operator)

