def build_handover_learning_prompt(pre_handover_state: dict[str, Any], handover_messages: list[dict[str, Any]], handover_summary: dict[str, Any] | None = None) -> str:
    normalized_messages = [
        {
            "sender_type": i.get("sender_type"),
            "message_type": i.get("message_type"),
            "content_text": i.get("content_text"),
            "created_at": str(i.get("created_at")),
        }
        for i in (handover_messages or [])[-80:]
    ]
    summary_payload = handover_summary or {}
    return f"""
You are extracting reusable handover learnings for a Telegram business AI sales/relationship assistant.
Pre-handover state: {json.dumps(pre_handover_state, ensure_ascii=False)}
Handover summary: {json.dumps(summary_payload, ensure_ascii=False)}
Messages during handover: {json.dumps(normalized_messages, ensure_ascii=False)}
Return JSON only using this schema:
{{
  "learning_candidates": [
    {{
      "title": "short title",
      "training_type": "identity_rule | daily_chat_rule | product_script_rule | objection_rule | rhythm_rule | persona_expression_rule | good_example | bad_example",
      "scene_summary": "when this learning applies",
      "user_signal_summary": "what the user showed or asked",
      "human_strategy_summary": "what the human actually did that worked",
      "recommended_rule": "clear reusable rule or reply guidance",
      "bad_example": "optional bad example",
      "good_example": "optional good example",
      "reason": "why this learning matters",
      "tags": ["tag1", "tag2"],
      "scope_type": "global | project | persona | project_stage | tag",
      "scope_id": null,
      "confidence": 0.0
    }}
  ]
}}
Only include candidates that are reusable for future AI behavior. Prefer 0 to 6 high-quality candidates.
""".strip()


class LLMService(LLMService):
    def extract_handover_learning_candidates(self, prompt: str) -> list[dict[str, Any]]:
        raw_text = self._call_text_model(prompt, 0.2, 1200)
        try:
            text = (raw_text or "").strip()
            if text.startswith("```"):
                parts = text.split("```")
                if len(parts) >= 2:
                    text = parts[1]
                text = text.removeprefix("json").strip()
            parsed = json.loads(text)
            if isinstance(parsed, dict):
                candidates = parsed.get("learning_candidates") or []
            elif isinstance(parsed, list):
                candidates = parsed
            else:
                candidates = []
            if not isinstance(candidates, list):
                return []
            return [item for item in candidates if isinstance(item, dict)]
        except Exception:
            return []


class HandoverLearningRepository:
    def __init__(self, db: Database) -> None:
        self.db = db

    def replace_learning_candidates(self, handover_session_id: int, candidates: list[dict[str, Any]]) -> int:
        with self.db.transaction():
            with self.db.cursor() as cur:
                cur.execute("DELETE FROM handover_learning_candidates WHERE handover_session_id=%s", (handover_session_id,))
                inserted = 0
                for item in candidates or []:
                    tags_json = json.dumps(item.get('tags') or [], ensure_ascii=False)
                    source_json = json.dumps(item.get('source_json') or {}, ensure_ascii=False)
                    cur.execute(
                        '''
                        INSERT INTO handover_learning_candidates (
                            handover_session_id, title, training_type, scene_summary, user_signal_summary,
                            human_strategy_summary, recommended_rule, bad_example, good_example,
                            reason_text, tags_json, scope_type, scope_id, confidence_score,
                            status, source_json, created_at, updated_at
                        ) VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s::jsonb,%s,%s,%s,%s,%s::jsonb,NOW(),NOW())
                        ''',
                        (
                            handover_session_id,
                            str(item.get('title') or '')[:200],
                            str(item.get('training_type') or 'good_example')[:80],
                            str(item.get('scene_summary') or '')[:1200],
                            str(item.get('user_signal_summary') or '')[:1200],
                            str(item.get('human_strategy_summary') or '')[:2000],
                            str(item.get('recommended_rule') or '')[:2000],
                            str(item.get('bad_example') or '')[:1200],
                            str(item.get('good_example') or '')[:1200],
                            str(item.get('reason') or '')[:1600],
                            tags_json,
                            str(item.get('scope_type') or 'global')[:40],
                            None if item.get('scope_id') in (None, '', 0) else str(item.get('scope_id'))[:120],
                            float(item.get('confidence') or 0.0),
                            str(item.get('status') or 'pending')[:40],
                            source_json,
                        ),
                    )
                    inserted += 1
                return inserted

    def list_learning_candidates_by_session(self, handover_session_id: int, limit: int = 20) -> list[dict]:
        with self.db.cursor() as cur:
            cur.execute(
                "SELECT * FROM handover_learning_candidates WHERE handover_session_id=%s ORDER BY confidence_score DESC, created_at DESC LIMIT %s",
                (handover_session_id, limit),
            )
            return cur.fetchall()

    def list_learning_candidates_by_conversation(self, conversation_id: int, limit: int = 20) -> list[dict]:
        with self.db.cursor() as cur:
            cur.execute(
                '''
                SELECT c.* FROM handover_learning_candidates c
                JOIN handover_sessions h ON c.handover_session_id=h.id
                WHERE h.conversation_id=%s
                ORDER BY c.created_at DESC, c.confidence_score DESC
                LIMIT %s
                ''',
                (conversation_id, limit),
            )
            return cur.fetchall()

    def get_learning_candidate(self, candidate_id: int) -> dict | None:
        with self.db.cursor() as cur:
            cur.execute("SELECT * FROM handover_learning_candidates WHERE id=%s LIMIT 1", (candidate_id,))
            return cur.fetchone()

    def mark_candidate_status(self, candidate_id: int, status: str, applied_training_item_id: int | None = None) -> None:
        with self.db.transaction():
            with self.db.cursor() as cur:
                cur.execute(
                    "UPDATE handover_learning_candidates SET status=%s, applied_training_item_id=%s, updated_at=NOW() WHERE id=%s",
                    (status, applied_training_item_id, candidate_id),
                )


class HandoverLearningService:
    def __init__(self, handover_repo: HandoverRepository, handover_learning_repo: HandoverLearningRepository,
                 conversation_repo: ConversationRepository, llm_service: LLMService) -> None:
        self.handover_repo = handover_repo
        self.handover_learning_repo = handover_learning_repo
        self.conversation_repo = conversation_repo
        self.llm_service = llm_service

    @staticmethod
    def _fallback_candidates(summary: dict[str, Any] | None) -> list[dict[str, Any]]:
        summary = summary or {}
        human_strategy = str(summary.get('human_strategy_summary') or '').strip()
        user_state = str(summary.get('user_state_summary') or '').strip()
        theme = str(summary.get('theme_summary') or '').strip()
        if not human_strategy and not user_state and not theme:
            return []
        return [{
            'title': '人工接管策略摘要',
            'training_type': 'good_example',
            'scene_summary': theme or 'human handover follow-up scene',
            'user_signal_summary': user_state or 'state extracted from handover summary',
            'human_strategy_summary': human_strategy or 'human handled the conversation manually',
            'recommended_rule': human_strategy or 'follow the human strategy summary as a future reference',
            'bad_example': '',
            'good_example': '',
            'reason': 'Fallback handover learning candidate built from handover summary.',
            'tags': ['handover', 'learning'],
            'scope_type': 'global',
            'scope_id': None,
            'confidence': 0.42,
        }]

    def build_learning_candidates(self, handover_session_id: int, conversation_id: int, handover_summary: dict[str, Any] | None = None) -> dict[str, Any]:
        context = self.conversation_repo.get_context(conversation_id)
        handover_messages = self.handover_repo.get_handover_messages(handover_session_id)
        pre_handover_state = {
            'conversation_id': context.conversation_id,
            'business_account_id': context.business_account_id,
            'user_id': context.user_id,
            'current_stage': context.current_stage,
            'current_chat_mode': context.current_chat_mode,
            'current_mainline': context.current_mainline,
            'recent_summary': context.recent_summary,
            'manual_takeover_status': context.manual_takeover_status,
        }
        candidates: list[dict[str, Any]] = []
        try:
            prompt = build_handover_learning_prompt(pre_handover_state, handover_messages, handover_summary)
            candidates = self.llm_service.extract_handover_learning_candidates(prompt)
        except Exception:
            candidates = []
        if not candidates:
            candidates = self._fallback_candidates(handover_summary)
        normalized: list[dict[str, Any]] = []
        for item in candidates[:6]:
            if not isinstance(item, dict):
                continue
            normalized.append({
                'title': str(item.get('title') or 'handover learning')[:200],
                'training_type': str(item.get('training_type') or 'good_example')[:80],
                'scene_summary': str(item.get('scene_summary') or '')[:1200],
                'user_signal_summary': str(item.get('user_signal_summary') or '')[:1200],
                'human_strategy_summary': str(item.get('human_strategy_summary') or '')[:2000],
                'recommended_rule': str(item.get('recommended_rule') or '')[:2000],
                'bad_example': str(item.get('bad_example') or '')[:1200],
                'good_example': str(item.get('good_example') or '')[:1200],
                'reason': str(item.get('reason') or '')[:1600],
                'tags': [str(t)[:80] for t in (item.get('tags') or []) if str(t).strip()][:10],
                'scope_type': str(item.get('scope_type') or 'global')[:40],
                'scope_id': item.get('scope_id'),
                'confidence': float(item.get('confidence') or 0.0),
                'status': 'pending',
                'source_json': {
                    'handover_summary': handover_summary or {},
                    'message_count': len(handover_messages or []),
                },
            })
        inserted = self.handover_learning_repo.replace_learning_candidates(handover_session_id, normalized)
        return {
            'ok': True,
            'candidate_count': inserted,
            'candidates': normalized,
            'reason': 'handover learnings extracted',
        }


class TrainingCenterRepository(TrainingCenterRepository):
    def create_training_item_from_handover_candidate(self, candidate: dict[str, Any], operator: str = 'admin') -> dict:
        title = str(candidate.get('title') or 'handover learning')[:200]
        training_type = str(candidate.get('training_type') or 'good_example')[:80]
        scope_type = str(candidate.get('scope_type') or 'global')[:40]
        scope_id = candidate.get('scope_id')
        summary = str(candidate.get('scene_summary') or '')[:600]
        content_payload = {
            'scene_summary': str(candidate.get('scene_summary') or ''),
            'user_signal_summary': str(candidate.get('user_signal_summary') or ''),
            'human_strategy_summary': str(candidate.get('human_strategy_summary') or ''),
            'recommended_rule': str(candidate.get('recommended_rule') or ''),
            'bad_example': str(candidate.get('bad_example') or ''),
            'good_example': str(candidate.get('good_example') or ''),
            'reason': str(candidate.get('reason') or ''),
            'source': 'handover_learning',
        }
        return self.create_training_item(
            training_type=training_type,
            title=title,
            summary=summary,
            content=content_payload,
            scope_type=scope_type,
            scope_id=None if scope_id in (None, '', 0) else str(scope_id),
            project_id=None,
            persona_id=None,
            priority=80,
            weight=float(candidate.get('confidence') or 0.5),
            source_type='handover_extract',
            created_by=operator,
            notes='imported from handover learning candidate',
            tags=list(candidate.get('tags') or []),
            examples=[{
                'example_type': 'contrast',
                'user_input': str(candidate.get('user_signal_summary') or ''),
                'bad_reply': str(candidate.get('bad_example') or ''),
                'good_reply': str(candidate.get('good_example') or ''),
                'reason': str(candidate.get('reason') or ''),
                'scene_summary': str(candidate.get('scene_summary') or ''),
            }],
            is_enabled=False,
        )


class CustomerActions(CustomerActions):
    def __init__(self, *args, handover_learning_service: HandoverLearningService | None = None, **kwargs) -> None:
        super().__init__(*args, **kwargs)
        self.handover_learning_service = handover_learning_service

    def end_handover(self, conversation_id: int, session_id: int, operator: str) -> dict:
        result = self.handover_manager.end_handover(conversation_id, session_id, operator)
        if not result.get('ok'):
            return result
        summary = self.handover_summary_builder.build_summary(session_id, conversation_id)
        learning_result = None
        if self.handover_learning_service is not None:
            try:
                learning_result = self.handover_learning_service.build_learning_candidates(session_id, conversation_id, summary)
            except Exception as e:
                learning_result = {'ok': False, 'reason': f'handover learning failed: {e}'}
        return {
            'ok': True,
            'reason': 'handover ended and summary generated',
            'summary': summary,
            'learning_result': learning_result,
        }


class AdminAPIService(AdminAPIService):
    def __init__(self, *args, handover_learning_repo: HandoverLearningRepository | None = None,
                 training_center_repo: TrainingCenterRepository | None = None, **kwargs) -> None:
        super().__init__(*args, **kwargs)
        self.handover_learning_repo = handover_learning_repo
        self.training_center_repo = training_center_repo

    def get_customer_detail(self, business_account_id: int, user_id: int) -> dict:
        result = super().get_customer_detail(business_account_id, user_id)
        if not result.get('ok'):
            return result
        conversation_id = result.get('conversation_id')
        if self.handover_learning_repo is not None and conversation_id:
            try:
                result['handover_learning_candidates'] = self.handover_learning_repo.list_learning_candidates_by_conversation(int(conversation_id), limit=8)
            except Exception:
                result['handover_learning_candidates'] = []
        return result

    def list_handover_learning_candidates_admin(self, conversation_id: int, limit: int = 20) -> list[dict]:
        if self.handover_learning_repo is None:
            return []
        return self.handover_learning_repo.list_learning_candidates_by_conversation(conversation_id, limit=limit)

    def import_handover_learning_candidate_admin(self, candidate_id: int, operator: str = 'admin') -> dict:
        if self.handover_learning_repo is None or self.training_center_repo is None:
            return {'ok': False, 'reason': 'handover learning import dependencies missing'}
        candidate = self.handover_learning_repo.get_learning_candidate(candidate_id)
        if not candidate:
            return {'ok': False, 'reason': 'candidate not found'}
        if str(candidate.get('status') or '') == 'applied':
            return {'ok': False, 'reason': 'candidate already applied'}
        created = self.training_center_repo.create_training_item_from_handover_candidate(candidate, operator)
        if not created.get('ok'):
            return created
        item = created.get('item') or {}
        item_id = int(item.get('id') or 0) if isinstance(item, dict) else 0
        self.handover_learning_repo.mark_candidate_status(candidate_id, 'applied', applied_training_item_id=item_id or None)
        return {'ok': True, 'reason': 'handover learning imported to training center', 'training_item_id': item_id}


class TGAdminFormatter(TGAdminFormatter):
    @staticmethod
    def format_handover_learning_candidates(items: list[dict[str, Any]]) -> str:
        if not items:
            return '🧠 人工接管学习\n\n暂无学习候选。'
        lines = ['🧠 人工接管学习候选']
        for idx, item in enumerate(items[:8], 1):
            lines.append(
                f"\n{idx}. {str(item.get('title') or '-')[:40]}"
                f"\n类型：{str(item.get('training_type') or '-')[:24]}"
                f"\n场景：{str(item.get('scene_summary') or '-')[:80]}"
                f"\n策略：{str(item.get('human_strategy_summary') or '-')[:120]}"
                f"\n规则：{str(item.get('recommended_rule') or '-')[:120]}"
                f"\n状态：{str(item.get('status') or 'pending')} | 置信度：{round(float(item.get('confidence_score') or 0.0), 2)}"
            )
        return '\n'.join(lines)[:3900]


_STEP23_BASE_INITIALIZE_DATABASE = initialize_database

def initialize_database(db: Database) -> None:
    _STEP23_BASE_INITIALIZE_DATABASE(db)
    extra_ddls = [
        '''
        CREATE TABLE IF NOT EXISTS handover_learning_candidates (
            id BIGSERIAL PRIMARY KEY,
            handover_session_id BIGINT NOT NULL REFERENCES handover_sessions(id) ON DELETE CASCADE,
            title TEXT NOT NULL DEFAULT '',
            training_type TEXT NOT NULL DEFAULT 'good_example',
            scene_summary TEXT NOT NULL DEFAULT '',
            user_signal_summary TEXT NOT NULL DEFAULT '',
            human_strategy_summary TEXT NOT NULL DEFAULT '',
            recommended_rule TEXT NOT NULL DEFAULT '',
            bad_example TEXT NOT NULL DEFAULT '',
            good_example TEXT NOT NULL DEFAULT '',
            reason_text TEXT NOT NULL DEFAULT '',
            tags_json JSONB NOT NULL DEFAULT '[]'::jsonb,
            scope_type TEXT NOT NULL DEFAULT 'global',
            scope_id TEXT,
            confidence_score DOUBLE PRECISION NOT NULL DEFAULT 0,
            status TEXT NOT NULL DEFAULT 'pending',
            applied_training_item_id BIGINT,
            source_json JSONB NOT NULL DEFAULT '{}'::jsonb,
            created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
        )
        ''',
        "CREATE INDEX IF NOT EXISTS idx_handover_learning_candidates_session ON handover_learning_candidates(handover_session_id, created_at DESC)",
    ]
    with db.transaction():
        with db.cursor() as cur:
            for sql in extra_ddls:
                cur.execute(sql)


_STEP23_BASE_BUILD_APP_COMPONENTS = build_app_components

def build_app_components(settings: Settings) -> dict[str, Any]:
    app_components = _STEP23_BASE_BUILD_APP_COMPONENTS(settings)
    db = app_components.get('db')
    llm_service = app_components.get('llm_service')
    customer_actions = app_components.get('customer_actions')
    handover_repo = app_components.get('handover_repo') or getattr(customer_actions, 'handover_repo', None)
    conversation_repo = getattr(customer_actions, 'conversation_repo', None)
    training_center_repo = app_components.get('training_center_repo')

    handover_learning_repo = HandoverLearningRepository(db)
    handover_learning_service = HandoverLearningService(handover_repo, handover_learning_repo, conversation_repo, llm_service)
    app_components['handover_learning_repo'] = handover_learning_repo
    app_components['handover_learning_service'] = handover_learning_service

    if customer_actions is not None:
        try:
            customer_actions.__class__ = CustomerActions
            customer_actions.handover_learning_service = handover_learning_service
        except Exception:
            pass

    admin_api_service = app_components.get('admin_api_service')
    if admin_api_service is not None:
        try:
            admin_api_service.__class__ = AdminAPIService
            admin_api_service.handover_learning_repo = handover_learning_repo
            admin_api_service.training_center_repo = training_center_repo
        except Exception:
            pass

    app_components['handover_learning_step3_enabled'] = True
    return app_components

