# Step24 - Auto Language Follow Formal Launch (future optimization step 4)
# =========================

_STEP24_BASE_NORMALIZE_LANGUAGE_CODE = normalize_language_code
_STEP24_BASE_LANGUAGE_NAME_BY_CODE = dict(LANGUAGE_NAME_BY_CODE)

LANGUAGE_NAME_BY_CODE = {
    **_STEP24_BASE_LANGUAGE_NAME_BY_CODE,
    "zh": "Chinese",
    "es": "Spanish",
}
LANGUAGE_CODE_BY_NAME = {v.lower(): k for k, v in LANGUAGE_NAME_BY_CODE.items()}


def normalize_language_code(value: str | None) -> str | None:
    raw = str(value or "").strip().lower().replace("_", "-")
    if not raw:
        return None
    for prefix in ("en", "de", "fr", "zh", "es"):
        if raw == prefix or raw.startswith(prefix + "-"):
            return prefix
    return _STEP24_BASE_NORMALIZE_LANGUAGE_CODE(value)


def language_code_to_name(value: str | None) -> str:
    return LANGUAGE_NAME_BY_CODE.get(normalize_language_code(value) or "en", "English")


def detect_language_snapshot(text: str | None, telegram_language_code: str | None = None) -> dict[str, Any]:
    normalized_text = str(text or '').strip()
    telegram_code = normalize_language_code(telegram_language_code)
    if not normalized_text:
        return {
            'language_code': telegram_code or 'en',
            'confidence': 0.5 if telegram_code else 0.2,
            'source': 'telegram_profile' if telegram_code else 'fallback',
        }
    lowered = normalized_text.lower()
    if any('\u4e00' <= ch <= '\u9fff' for ch in normalized_text):
        return {'language_code': 'zh', 'confidence': 0.98, 'source': 'heuristic'}

    token_list = [token.strip(".,!?;:-_()[]{}\"'`") for token in lowered.split() if token.strip()]
    scores = {code: 0.0 for code in ('en', 'de', 'fr', 'es')}
    english_tokens = {'the', 'and', 'you', 'your', 'with', 'for', 'that', 'have', 'just', 'okay', 'thanks', 'hello', 'today', 'tomorrow', 'what', 'how'}
    german_tokens = {'und', 'ich', 'nicht', 'ist', 'danke', 'bitte', 'heute', 'morgen', 'hallo', 'gut', 'aber', 'oder', 'schon', 'noch', 'gerne', 'möchte', 'wie', 'was'}
    french_tokens = {'bonjour', 'merci', 'avec', 'pour', 'vous', 'aujourd', 'demain', 'salut', 'être', 'avoir', 'pas', 'bien', 'très', 'peux', 'peut', 'comment', 'quoi'}
    spanish_tokens = {'hola', 'gracias', 'con', 'para', 'hoy', 'mañana', 'bien', 'puedo', 'puede', 'quiero', 'como', 'qué', 'porque', 'usted'}
    for token in token_list:
        if token in english_tokens:
            scores['en'] += 1.0
        if token in german_tokens:
            scores['de'] += 1.0
        if token in french_tokens:
            scores['fr'] += 1.0
        if token in spanish_tokens:
            scores['es'] += 1.0
    if any(ch in lowered for ch in 'äöüß'):
        scores['de'] += 2.5
    if any(ch in lowered for ch in 'àâçéèêëîïôùûüÿœæ'):
        scores['fr'] += 2.5
    if any(ch in lowered for ch in 'áéíóúñ¿¡'):
        scores['es'] += 2.5
    if telegram_code in scores:
        scores[telegram_code] += 0.75
    best_code = max(scores, key=scores.get)
    best_score = scores[best_code]
    total = sum(scores.values()) or 1.0
    confidence = max(0.35, min(0.99, best_score / total if total else 0.35)) if best_score > 0 else (0.55 if telegram_code else 0.35)
    source = 'telegram_profile' if best_score <= 0 and telegram_code else 'heuristic'
    if best_score <= 0 and telegram_code:
        best_code = telegram_code
    return {'language_code': best_code, 'confidence': round(confidence, 3), 'source': source}


def resolve_user_reply_language(user_profile: dict[str, Any]) -> str:
    user_row = (user_profile or {}).get('user') or {}
    mode = (user_row.get('reply_language_mode') or 'auto_follow').lower()
    if mode in ('fixed_en', 'manual_fixed_en'):
        return 'English'
    if mode in ('manual_fixed', 'manual', 'fixed'):
        preferred = normalize_language_code(user_row.get('preferred_language')) or 'en'
        return language_code_to_name(preferred)
    candidate = (
        normalize_language_code(user_row.get('detected_language'))
        or normalize_language_code(user_row.get('preferred_language'))
        or normalize_language_code(user_row.get('language_code'))
        or 'en'
    )
    return language_code_to_name(candidate)


def build_reply_prompt(latest_user_message: str, recent_context: list[dict[str, Any]], persona_summary: str,
                       user_state_summary: str, stage: str, chat_mode: str, understanding: dict[str, Any],
                       reply_plan: dict[str, Any], selected_content: dict[str, Any],
                       memory_summary: dict[str, Any] | None = None, reply_language: str = 'English') -> str:
    recent_messages = [{"sender_type": m.get("sender_type"), "content_text": m.get("content_text")} for m in recent_context[-10:]]
    memory_payload = memory_summary or {}
    selected_payload = dict(selected_content or {})
    selected_content_summary = str(selected_payload.get("prompt_summary") or "")
    selected_prompt_packages = selected_payload.get("prompt_packages") or {}
    compact_selected = {
        "project_scripts": [
            {"id": item.get("id"), "category": item.get("category"), "text": (item.get("content_text") or "")[:160]}
            for item in (selected_payload.get("project_scripts") or [])[:3]
        ],
        "project_materials": _summarize_material_items(selected_payload.get("project_materials") or [], 3),
        "persona_materials": _summarize_material_items(selected_payload.get("persona_materials") or [], 3),
        "daily_materials": _summarize_material_items(selected_payload.get("daily_materials") or [], 3),
        "material_packages": selected_prompt_packages,
    }
    return f"""
You are the live chat brain for a Telegram business account.
Write exactly one natural reply message in plain text.
Persona summary: {persona_summary}
User state summary: {user_state_summary}
Stage: {stage}
Chat mode: {chat_mode}
Long-term memory: {json.dumps(memory_payload, ensure_ascii=False)}
Understanding: {json.dumps(understanding, ensure_ascii=False)}
Reply plan: {json.dumps(reply_plan, ensure_ascii=False)}
Selected content summary: {selected_content_summary}
Selected content detail: {json.dumps(compact_selected, ensure_ascii=False)}
Recent messages: {json.dumps(recent_messages, ensure_ascii=False)}
Latest user message: {latest_user_message}
Rules:
- Reply language for this turn: {reply_language}.
- The user-facing reply must be fully and naturally written in {reply_language} for this turn.
- Match the user's language naturally; do not mix languages unless the user does.
- Use long-term memory to stay consistent with user preferences, boundaries, and prior progress.
- Use the selected scripts/materials/packages as optional support, not as a rigid script.
- If support materials are written in another language, naturally adapt the meaning into {reply_language} instead of exposing translation mechanics.
- Material packages may contain multiple images, videos, text snippets, or buttons; keep your reply naturally aligned with the most relevant package when useful.
- If mode is pause, respect the boundary and do not continue product pushing.
- If mode is emotional, acknowledge emotion first.
- If mode is product or high_intent, answer the user's product question directly and stay on the product mainline.
- Avoid sounding robotic, over-perfect, or overly salesy.
""".strip()


_STEP24_BASE_INITIALIZE_DATABASE = initialize_database

def initialize_database(db: Database) -> None:
    _STEP24_BASE_INITIALIZE_DATABASE(db)
    extra_statements = [
        "ALTER TABLE users ALTER COLUMN reply_language_mode SET DEFAULT 'auto_follow'",
        "ALTER TABLE users ALTER COLUMN preferred_language SET DEFAULT 'en'",
        """
        UPDATE users
        SET reply_language_mode='auto_follow',
            preferred_language=COALESCE(detected_language, language_code, preferred_language, 'en'),
            language_source=CASE
                WHEN language_source='system_default' OR language_source IS NULL THEN 'auto_follow_default'
                ELSE language_source
            END,
            updated_at=NOW()
        WHERE reply_language_mode='fixed_en'
          AND (language_source='system_default' OR language_source IS NULL)
        """,
    ]
    with db.transaction():
        with db.cursor() as cur:
            for stmt in extra_statements:
                cur.execute(stmt)


_STEP24_BASE_USER_REPOSITORY = UserRepository
class UserRepository(_STEP24_BASE_USER_REPOSITORY):
    def get_or_create_user(self, tg_user_id: str, display_name: str | None = None, username: str | None = None,
                           language_code: str | None = None) -> int:
        normalized_language = normalize_language_code(language_code)
        with self.db.cursor() as cur:
            cur.execute("SELECT id, reply_language_mode, language_source FROM users WHERE tg_user_id=%s LIMIT 1", (tg_user_id,))
            row = cur.fetchone()
            if row:
                user_id = int(row['id'])
                with self.db.transaction():
                    with self.db.cursor() as cur2:
                        cur2.execute(
                            "UPDATE users SET display_name=COALESCE(%s, display_name), username=COALESCE(%s, username), language_code=COALESCE(%s, language_code), last_seen_at=NOW(), updated_at=NOW() WHERE id=%s",
                            (display_name, username, normalized_language or language_code, user_id),
                        )
                        if normalized_language and ((row.get('reply_language_mode') or '') == 'auto_follow' or (row.get('language_source') or '') in ('system_default', 'auto_follow_default', 'telegram_profile')):
                            cur2.execute(
                                "UPDATE users SET detected_language=%s, preferred_language=COALESCE(preferred_language, %s), language_source='telegram_profile', updated_at=NOW() WHERE id=%s",
                                (normalized_language, normalized_language, user_id),
                            )
                return user_id
        with self.db.transaction():
            with self.db.cursor() as cur:
                cur.execute(
                    """
                    INSERT INTO users (tg_user_id, username, display_name, language_code, reply_language_mode, preferred_language, detected_language, language_confidence, language_source, first_seen_at, last_seen_at, is_blocked, created_at, updated_at)
                    VALUES (%s,%s,%s,%s,'auto_follow',%s,%s,%s,%s,NOW(),NOW(),FALSE,NOW(),NOW()) RETURNING id
                    """,
                    (
                        tg_user_id,
                        username,
                        display_name,
                        normalized_language or language_code,
                        normalized_language or 'en',
                        normalized_language,
                        0.72 if normalized_language else None,
                        'telegram_profile' if normalized_language else 'auto_follow_default',
                    ),
                )
                return int(cur.fetchone()['id'])


_STEP24_BASE_ADMIN_API_SERVICE = AdminAPIService
class AdminAPIService(_STEP24_BASE_ADMIN_API_SERVICE):
    def set_user_language_mode(self, business_account_id: int, user_id: int, mode: str,
                               preferred_language: str | None, operator: str) -> dict:
        normalized_mode = (mode or 'auto_follow').strip().lower()
        normalized_preferred = normalize_language_code(preferred_language)
        detail = self.get_customer_detail(business_account_id, user_id)
        if not detail.get('ok'):
            return {'ok': False, 'reason': 'user not found'}
        self.user_repo.set_reply_language_mode(user_id, normalized_mode, normalized_preferred, source='admin_set')
        return {'ok': True, 'profile': self.user_repo.get_user_profile(business_account_id, user_id)}


_STEP24_BASE_TG_ADMIN_FORMATTER = TGAdminFormatter
class TGAdminFormatter(_STEP24_BASE_TG_ADMIN_FORMATTER):
    @staticmethod
    def format_customer_detail(detail: dict) -> str:
        base = _STEP24_BASE_TG_ADMIN_FORMATTER.format_customer_detail(detail)
        profile = (detail.get('profile') or {})
        user_row = profile.get('user') or {}
        resolved = resolve_user_reply_language(profile)
        mode_map = {
            'auto_follow': '跟随用户语言',
            'fixed_en': '固定英文',
            'manual_fixed': '手动固定语言',
        }
        mode_text = mode_map.get((user_row.get('reply_language_mode') or '').lower(), user_row.get('reply_language_mode') or '-')
        language_line = (
            f"语言模式: {mode_text} | 当前回复语言: {resolved} | 偏好: {user_row.get('preferred_language') or '-'} | "
            f"检测: {user_row.get('detected_language') or '-'} | 置信度: {user_row.get('language_confidence') if user_row.get('language_confidence') is not None else '-'}"
        )
        if language_line not in base:
            if '运营分类:' in base:
                base = base.replace('运营分类:', language_line + '\n运营分类:', 1)
            else:
                base = base + '\n' + language_line
        return base


_STEP24_BASE_TG_ADMIN_MENU_BUILDER = TGAdminMenuBuilder
class TGAdminMenuBuilder(_STEP24_BASE_TG_ADMIN_MENU_BUILDER):
    @staticmethod
    def customer_action_menu(user_id: int, conversation_id: int | None, back_callback: str = 'adm:main') -> list[list[dict[str, str]]]:
        rows = _STEP24_BASE_TG_ADMIN_MENU_BUILDER.customer_action_menu(user_id, conversation_id, back_callback)
        for row in rows:
            for btn in row:
                if btn.get('callback_data', '').startswith(f'adm:lang:{user_id}:auto_follow'):
                    btn['text'] = '🌐 跟随用户语言'
        return rows


_STEP24_BASE_ORCHESTRATOR = Orchestrator
class Orchestrator(_STEP24_BASE_ORCHESTRATOR):
    def _detect_and_persist_language(self, inbound_message: InboundMessage) -> None:
        user_payload = inbound_message.raw_payload.get('business_message') or inbound_message.raw_payload.get('edited_business_message') or inbound_message.raw_payload.get('message') or {}
        from_user = user_payload.get('from') or {}
        telegram_language_code = from_user.get('language_code')
        media_analysis = inbound_message.raw_payload.get('step6_media_analysis') or {}
        candidate_text = (
            str(media_analysis.get('effective_user_text') or '').strip()
            or str(inbound_message.text or '').strip()
            or str((user_payload.get('caption') or ''))
        )
        user_id = self.user_repo.get_or_create_user(
            inbound_message.tg_user_id,
            display_name=(from_user.get('first_name') or f"User-{inbound_message.tg_user_id}"),
            username=from_user.get('username'),
            language_code=telegram_language_code,
        )
        language_snapshot = detect_language_snapshot(candidate_text, telegram_language_code)
        try:
            self.user_repo.update_detected_language(
                user_id,
                language_snapshot.get('language_code'),
                language_snapshot.get('confidence'),
                source=str(language_snapshot.get('source') or 'auto_detected'),
            )
        except Exception:
            logger.exception('Step24 failed to persist detected language.')

    def handle_inbound_message(self, inbound_message: InboundMessage) -> None:
        enriched = inbound_message
        media_service = getattr(self, 'media_understanding_service', None)
        if media_service is not None:
            try:
                enriched = media_service.enrich_inbound_message(inbound_message)
            except Exception:
                logger.exception('Step24 language-follow pre-enrichment failed; using original inbound message.')
                enriched = inbound_message
        try:
            self._detect_and_persist_language(enriched)
        except Exception:
            logger.exception('Step24 language detection failed; continuing with fallback reply language.')
        original_media_service = getattr(self, 'media_understanding_service', None)
        try:
            if original_media_service is not None:
                setattr(self, 'media_understanding_service', None)
            return super().handle_inbound_message(enriched)
        finally:
            if original_media_service is not None:
                try:
                    setattr(self, 'media_understanding_service', original_media_service)
                except Exception:
                    pass


_STEP24_BASE_BUILD_APP_COMPONENTS = build_app_components

def build_app_components(settings: Settings) -> dict[str, Any]:
    app_components = _STEP24_BASE_BUILD_APP_COMPONENTS(settings)
    orchestrator = app_components.get('orchestrator')
    if orchestrator is not None:
        try:
            orchestrator.__class__ = Orchestrator
        except Exception:
            pass
    app_components['language_follow_step4_enabled'] = True
    return app_components



# =========================
# Step25 - Humanlike Fine-tuning (future optimization step 5)
# =========================

STEP25_EN_FORMALITY_REPLACEMENTS = {
    "i understand your concern": "I get that",
    "i understand your worries": "I get that",
    "i completely understand": "I get that",
    "i fully understand": "I get that",
    "i appreciate you sharing that": "Thanks for saying that",
    "i appreciate your honesty": "Fair enough",
    "please let me know": "Tell me",
    "let me explain": "Here’s the thing",
    "allow me to explain": "Here’s the thing",
    "to be honest": "Honestly",
    "in summary": "",
    "from my perspective": "",
    "i would be happy to": "I can",
    "i would be glad to": "I can",
    "thank you for your patience": "Thanks",
}

STEP25_DAILY_RELAXERS_EN = {
    "that is understandable": "Fair enough",
    "that makes sense": "Fair enough",
    "we can continue later": "We can pick it up later",
    "we can discuss it later": "We can pick it up later",
    "i hope you are doing well": "Hope you’re doing well",
    "i am here to help": "I’m here",
}

STEP25_GENERIC_ROBOTIC_PATTERNS = [
    "please let me know if you have any questions",
    "i hope this helps",
    "thank you for your understanding",
    "feel free to reach out",
    "i would be happy to help",
]

STEP25_META_OPENERS = [
    "here’s a quick summary:",
    "in summary,",
    "to summarize,",
    "overall,",
    "first of all,",
]

@dataclass
class HumanLikePolishSnapshot:
    tone_mode: str = 'neutral'
    question_limit: int = 1
    sentence_limit: int = 2
    char_limit: int = 170
    removed_formality: bool = False
    relaxed_daily_tone: bool = False
    shortened: bool = False
    reason: str = ''


def _step25_detect_lang_family(text_value: str, reply_language: str | None = None) -> str:
    hint = str(reply_language or '').strip().lower()
    if 'german' in hint or hint == 'de':
        return 'de'
    if 'french' in hint or hint == 'fr':
        return 'fr'
    if 'spanish' in hint or hint == 'es':
        return 'es'
    if 'chinese' in hint or hint == 'zh':
        return 'zh'
    if 'english' in hint or hint == 'en':
        return 'en'
    detected = detect_language_snapshot(text_value or '')
    return str(detected.get('language_code') or 'en')


def _step25_sentence_count(text_value: str) -> int:
    return len([part for part in re.split(r'(?<=[.!?。！？])\s+', str(text_value or '').strip()) if part.strip()])


def _step25_remove_listy_shape(text_value: str) -> str:
    lines = [ln.strip() for ln in str(text_value or '').splitlines() if ln.strip()]
    if not lines:
        return ''
    cleaned = []
    for line in lines:
        line = re.sub(r'^[\-•\*]+\s*', '', line)
        line = re.sub(r'^\d+[\.)]\s*', '', line)
        cleaned.append(line)
    return ' '.join(cleaned).strip()


def _step25_reduce_formality_en(text_value: str) -> tuple[str, bool]:
    text = str(text_value or '')
    lowered = text.lower()
    changed = False
    for src, dst in STEP25_EN_FORMALITY_REPLACEMENTS.items():
        if src in lowered:
            pattern = re.compile(re.escape(src), re.IGNORECASE)
            text = pattern.sub(dst, text)
            lowered = text.lower()
            changed = True
    for src, dst in STEP25_DAILY_RELAXERS_EN.items():
        if src in lowered:
            pattern = re.compile(re.escape(src), re.IGNORECASE)
            text = pattern.sub(dst, text)
            lowered = text.lower()
            changed = True
    for phrase in STEP25_GENERIC_ROBOTIC_PATTERNS:
        if phrase in lowered:
            pattern = re.compile(re.escape(phrase), re.IGNORECASE)
            text = pattern.sub('', text)
            lowered = text.lower()
            changed = True
    for opener in STEP25_META_OPENERS:
        if lowered.startswith(opener):
            text = text[len(opener):].strip(' ,:')
            lowered = text.lower()
            changed = True
    text = re.sub(r'\bI understand\. I understand\b', 'I get that', text, flags=re.IGNORECASE)
    text = re.sub(r'\bThanks\. Thanks\b', 'Thanks', text, flags=re.IGNORECASE)
    text = re.sub(r'\s{2,}', ' ', text).strip()
    return text, changed


def _step25_reduce_formality_general(text_value: str, lang_family: str) -> tuple[str, bool]:
    text = _step25_remove_listy_shape(text_value)
    changed = text != str(text_value or '')
    text = re.sub(r'([!?])\1{1,}', r'\1', text)
    text = re.sub(r'([.])\1{1,}', '.', text)
    if lang_family == 'en':
        text, inner_changed = _step25_reduce_formality_en(text)
        changed = changed or inner_changed
    elif lang_family == 'zh':
        original = text
        text = text.replace('请告诉我', '你直接说就行').replace('感谢你的耐心', '谢谢你').replace('如果你有任何问题', '有问题就直接说')
        changed = changed or (text != original)
    return text.strip(), changed


def _step25_limit_emojis_soft(text_value: str) -> str:
    text = str(text_value or '')
    emoji_like = re.findall(r'[😀-🙏🌀-🛿🤀-🧿☀-⛿✀-➿💀-🫿❤️✨⭐️🌟🔥👍🙏😊😉😄😅😂🥰😌]', text)
    if len(emoji_like) <= 1:
        return text
    return _step3_remove_emojis(text)


def _step25_relax_daily_tone(text_value: str, lang_family: str) -> str:
    text = str(text_value or '').strip()
    if lang_family == 'en':
        text = re.sub(r'\bThat sounds reasonable\b', 'Fair enough', text, flags=re.IGNORECASE)
        text = re.sub(r'\bI understand\b', 'I get that', text, flags=re.IGNORECASE)
        text = re.sub(r'\bWe can continue this later\b', 'We can pick this up later', text, flags=re.IGNORECASE)
    elif lang_family == 'zh':
        text = text.replace('这是可以理解的', '也正常').replace('我们稍后可以继续', '晚点再聊也行')
    return text.strip()


class HumanLikePolishEngine:
    def polish(self, draft_reply: str, understanding: UnderstandingResult | None = None,
               reply_plan: ReplyPlan | None = None,
               profile_snapshot: UserProfileEvolutionSnapshot | None = None,
               training_packet: TrainingPacket | None = None,
               reply_language: str | None = None) -> tuple[str, HumanLikePolishSnapshot]:
        text = str(draft_reply or '').strip()
        if not text:
            return '', HumanLikePolishSnapshot(reason='empty')

        scene_tags = list((getattr(training_packet, 'scene_tags', None) if training_packet else []) or [])
        understanding_dict = understanding.to_dict() if hasattr(understanding, 'to_dict') else {}
        scene_tags.extend(list((understanding_dict.get('media_tags') or []) if isinstance(understanding_dict, dict) else []))
        scene_text = ' '.join(str(x) for x in scene_tags).lower()
        lang_family = _step25_detect_lang_family(text, reply_language)
        user_intent = str(getattr(understanding, 'user_intent', '') or '').lower()
        resistance_signal = str(getattr(understanding, 'resistance_signal', '') or '').lower()
        boundary_signal = str(getattr(understanding, 'boundary_signal', '') or '').lower()
        emotion_state = str(getattr(understanding, 'emotion_state', '') or '').lower()
        daily_like = any(tag in scene_text for tag in ('daily', 'selfie', 'food', 'travel', 'gym', 'casual', 'weekend', 'meal')) or user_intent == 'daily_chat'
        serious_like = any(tag in scene_text for tag in ('contract', 'document', 'chart', 'yield', 'risk', 'project', 'consult')) or bool(getattr(understanding, 'explicit_product_query', False))
        short_pref = bool(getattr(profile_snapshot, 'prefers_short_reply', False)) if profile_snapshot is not None else False
        low_tolerance = str(getattr(profile_snapshot, 'marketing_tolerance_label', '') or '').lower() == 'low' if profile_snapshot is not None else False

        question_limit = 1
        sentence_limit = 2
        char_limit = 170
        tone_mode = 'neutral'
        reason = []

        if daily_like and not serious_like:
            tone_mode = 'daily_relaxed'
            sentence_limit = 2
            char_limit = 150
            reason.append('daily_relaxed')
        if short_pref:
            char_limit = min(char_limit, 135)
            sentence_limit = min(sentence_limit, 2)
            reason.append('pref_short')
        if low_tolerance and not getattr(understanding, 'explicit_product_query', False):
            char_limit = min(char_limit, 145)
            reason.append('low_marketing_tolerance')
        if boundary_signal in {'busy', 'later', 'sleep', 'stop', 'needs_space'} or resistance_signal in {'resistant', 'high'}:
            tone_mode = 'space_respect'
            sentence_limit = 1
            char_limit = min(char_limit, 120)
            question_limit = 0
            reason.append('boundary_or_resistance')
        elif emotion_state in {'low', 'anxious'}:
            tone_mode = 'soft_support'
            sentence_limit = min(sentence_limit, 2)
            char_limit = min(char_limit, 145)
            question_limit = min(question_limit, 1)
            reason.append('soft_support')
        elif serious_like and getattr(understanding, 'explicit_product_query', False):
            tone_mode = 'focused_answer'
            sentence_limit = max(sentence_limit, 2)
            char_limit = max(char_limit, 170)
            question_limit = 0
            reason.append('focused_answer')

        if training_packet is not None:
            prompt_summary = str(getattr(training_packet, 'prompt_summary', '') or '').lower()
            if 'no emoji' in prompt_summary:
                text = _step3_remove_emojis(text)
            if 'max one question' in prompt_summary:
                question_limit = min(question_limit, 1)
            if 'short' in prompt_summary and tone_mode != 'focused_answer':
                char_limit = min(char_limit, 140)

        text, removed_formality = _step25_reduce_formality_general(text, lang_family)
        relaxed_daily_tone = False
        if daily_like and not serious_like:
            new_text = _step25_relax_daily_tone(text, lang_family)
            relaxed_daily_tone = new_text != text
            text = new_text
        text = _step25_limit_emojis_soft(text)
        text = _step3_limit_questions(text, question_limit)
        pre_clip = text
        if _step25_sentence_count(text) > sentence_limit or len(text) > char_limit:
            text = _step3_sentence_clip(text, max_sentences=sentence_limit, max_chars=char_limit)
        shortened = text != pre_clip
        text = re.sub(r'\s{2,}', ' ', text).strip(' .')
        if text and not re.search(r'[.!?。！？]$', text):
            text = text + ('' if lang_family == 'zh' else '.')
        snapshot = HumanLikePolishSnapshot(
            tone_mode=tone_mode,
            question_limit=question_limit,
            sentence_limit=sentence_limit,
            char_limit=char_limit,
            removed_formality=removed_formality,
            relaxed_daily_tone=relaxed_daily_tone,
            shortened=shortened,
            reason=' | '.join(reason)[:240],
        )
        return text, snapshot


def _step25_human_polish_to_payload(snapshot: HumanLikePolishSnapshot | None) -> dict[str, Any]:
    if snapshot is None:
        return {}
    return {
        'tone_mode': snapshot.tone_mode,
        'question_limit': snapshot.question_limit,
        'sentence_limit': snapshot.sentence_limit,
        'char_limit': snapshot.char_limit,
        'removed_formality': snapshot.removed_formality,
        'relaxed_daily_tone': snapshot.relaxed_daily_tone,
        'shortened': snapshot.shortened,
        'reason': snapshot.reason,
    }


_STEP25_BASE_BUILD_REPLY_PROMPT = build_reply_prompt

def build_reply_prompt(latest_user_message: str, recent_context: list[dict[str, Any]], persona_summary: str,
                       user_state_summary: str, stage: str, chat_mode: str, understanding: dict[str, Any],
                       reply_plan: dict[str, Any], selected_content: dict[str, Any],
                       memory_summary: dict[str, Any] | None = None, reply_language: str = 'English') -> str:
    base_prompt = _STEP25_BASE_BUILD_REPLY_PROMPT(
        latest_user_message,
        recent_context,
        persona_summary,
        user_state_summary,
        stage,
        chat_mode,
        understanding,
        reply_plan,
        selected_content,
        memory_summary=memory_summary,
        reply_language=reply_language,
    )
    extra_rules = """
Additional humanlike rules:
- Sound like a real person in chat, not like polished customer service copy.
- Prefer short, natural phrasing unless the user clearly wants a fuller explanation.
- Do not stack multiple acknowledgements or over-explain obvious points.
- Avoid list-like structure, summary-style intros, or formal sign-offs.
- In daily or casual scenes, keep the tone relaxed, light, and socially natural.
- Ask at most one question, and only when it feels necessary.
- Do not overuse emojis, exclamation marks, or overly enthusiastic phrasing.
""".strip()
    if extra_rules not in base_prompt:
        base_prompt = base_prompt + "\n" + extra_rules
    return base_prompt


_STEP25_BASE_REPLY_STYLE_ENGINE = ReplyStyleEngine
class ReplyStyleEngine(_STEP25_BASE_REPLY_STYLE_ENGINE):
    def generate(self, latest_user_message: str, recent_context: list[dict], persona_summary: str, user_state_summary: str,
                 stage: str, chat_mode: str, understanding: dict, reply_plan: dict, selected_content: dict,
                 memory_summary: dict[str, Any] | None = None, reply_language: str = "English",
                 training_packet: TrainingPacket | None = None) -> str:
        text_value = super().generate(
            latest_user_message,
            recent_context,
            persona_summary,
            user_state_summary,
            stage,
            chat_mode,
            understanding,
            reply_plan,
            selected_content,
            memory_summary=memory_summary,
            reply_language=reply_language,
            training_packet=training_packet,
        )
        polish_engine = getattr(self, 'human_like_polish_engine', None) or HumanLikePolishEngine()
        profile_snapshot = getattr(self, '_runtime_profile_snapshot', None)
        planner = getattr(self, 'reply_planner', None)
        plan_snapshot = getattr(planner, '_last_reply_plan', None) if planner is not None else None
        polished, snapshot = polish_engine.polish(
            text_value,
            understanding=understanding if isinstance(understanding, UnderstandingResult) else None,
            reply_plan=plan_snapshot,
            profile_snapshot=profile_snapshot,
            training_packet=training_packet,
            reply_language=reply_language,
        )
        try:
            if isinstance(understanding, UnderstandingResult):
                setattr(understanding, 'human_like_polish_snapshot', _step25_human_polish_to_payload(snapshot))
            setattr(self, '_last_human_like_polish_snapshot', snapshot)
            setattr(self, '_last_reply_language', reply_language)
        except Exception:
            pass
        return polished


_STEP25_BASE_REPLY_SELF_CHECK_ENGINE = ReplySelfCheckEngine
class ReplySelfCheckEngine(_STEP25_BASE_REPLY_SELF_CHECK_ENGINE):
    def check_and_fix(self, draft_reply: str, mode: str, understanding: UnderstandingResult,
                      training_packet: TrainingPacket | None = None) -> str:
        text_value = super().check_and_fix(draft_reply, mode, understanding, training_packet=training_packet)
        polish_engine = getattr(self, 'human_like_polish_engine', None) or HumanLikePolishEngine()
        profile_snapshot = getattr(self, '_runtime_profile_snapshot', None)
        reply_language = getattr(self, '_runtime_reply_language', None)
        planner = getattr(self, 'reply_planner', None)
        plan_snapshot = getattr(planner, '_last_reply_plan', None) if planner is not None else None
        polished, snapshot = polish_engine.polish(
            text_value,
            understanding=understanding,
            reply_plan=plan_snapshot,
            profile_snapshot=profile_snapshot,
            training_packet=training_packet,
            reply_language=reply_language,
        )
        try:
            setattr(understanding, 'human_like_polish_snapshot', _step25_human_polish_to_payload(snapshot))
            setattr(self, '_last_human_like_polish_snapshot', snapshot)
            setattr(self, '_last_final_reply', polished)
        except Exception:
            pass
        return polished


_STEP25_BASE_REPLY_DELAY_ENGINE = ReplyDelayEngine
class ReplyDelayEngine(_STEP25_BASE_REPLY_DELAY_ENGINE):
    def decide_delay_seconds(self, understanding: UnderstandingResult, chat_mode: str, reply_text: str,
                             training_packet: TrainingPacket | None = None) -> int:
        delay_seconds = super().decide_delay_seconds(understanding, chat_mode, reply_text, training_packet=training_packet)
        polish_payload = getattr(understanding, 'human_like_polish_snapshot', None) or {}
        tone_mode = str(polish_payload.get('tone_mode') or '').strip().lower()
        char_limit = int(polish_payload.get('char_limit') or 170)
        if tone_mode == 'daily_relaxed' and len(str(reply_text or '')) <= max(120, char_limit):
            delay_seconds = max(1, min(delay_seconds, 2))
        elif tone_mode == 'space_respect':
            delay_seconds = max(delay_seconds, 2)
        elif tone_mode == 'focused_answer' and len(str(reply_text or '')) > 160:
            delay_seconds = max(delay_seconds, 3)
        return int(delay_seconds)


_STEP25_BASE_ORCHESTRATOR = Orchestrator
class Orchestrator(_STEP25_BASE_ORCHESTRATOR):
    def handle_inbound_message(self, inbound_message: InboundMessage) -> None:
        try:
            return super().handle_inbound_message(inbound_message)
        finally:
            for target_name in ('reply_style_engine', 'reply_self_check_engine'):
                target = getattr(self, target_name, None)
                if target is not None:
                    try:
                        setattr(target, '_runtime_reply_language', None)
                    except Exception:
                        pass


_STEP25_BASE_BUILD_APP_COMPONENTS = build_app_components

def build_app_components(settings: Settings) -> dict[str, Any]:
    app_components = _STEP25_BASE_BUILD_APP_COMPONENTS(settings)
    orchestrator = app_components.get('orchestrator')
    human_like_polish_engine = HumanLikePolishEngine()
    if orchestrator is not None:
        try:
            orchestrator.__class__ = Orchestrator
        except Exception:
            pass
        if getattr(orchestrator, 'reply_style_engine', None) is not None:
            try:
                orchestrator.reply_style_engine.__class__ = ReplyStyleEngine
            except Exception:
                pass
            try:
                setattr(orchestrator.reply_style_engine, 'human_like_polish_engine', human_like_polish_engine)
                setattr(orchestrator.reply_style_engine, 'reply_planner', getattr(orchestrator, 'reply_planner', None))
            except Exception:
                pass
        if getattr(orchestrator, 'reply_self_check_engine', None) is not None:
            try:
                orchestrator.reply_self_check_engine.__class__ = ReplySelfCheckEngine
            except Exception:
                pass
            try:
                setattr(orchestrator.reply_self_check_engine, 'human_like_polish_engine', human_like_polish_engine)
                setattr(orchestrator.reply_self_check_engine, 'reply_planner', getattr(orchestrator, 'reply_planner', None))
            except Exception:
                pass
        if getattr(orchestrator, 'reply_delay_engine', None) is not None:
            try:
                orchestrator.reply_delay_engine.__class__ = ReplyDelayEngine
            except Exception:
                pass
        # patch orchestrator runtime language propagation
        original_handle = getattr(orchestrator, 'handle_inbound_message', None)
        # no wrapping needed; step25 orchestrator class handles cleanup
    app_components['human_like_polish_engine'] = human_like_polish_engine
    app_components['humanlike_step5_enabled'] = True
    return app_components


