_STEP28_BASE_BUILD_APP_COMPONENTS = build_app_components

def build_app_components(settings: Settings) -> dict[str, Any]:
    app_components = _STEP28_BASE_BUILD_APP_COMPONENTS(settings)
    workspace_repository = app_components.get('workspace_repository')
    workspace_binding_repository = app_components.get('workspace_binding_repository')

    def _upgrade_component(name: str, cls: type):
        target = app_components.get(name)
        if target is None:
            return None
        try:
            target.__class__ = cls
        except Exception:
            return target
        try:
            setattr(target, 'workspace_repository', workspace_repository)
            setattr(target, 'workspace_binding_repository', workspace_binding_repository)
        except Exception:
            pass
        return target

    _upgrade_component('bootstrap_repo', BootstrapRepository)
    _upgrade_component('runtime_policy_repo', RuntimePolicyRepository)
    _upgrade_component('user_repo', UserRepository)
    _upgrade_component('training_center_repo', TrainingCenterRepository)
    _upgrade_component('persona_profile_builder', PersonaProfileBuilder)
    _upgrade_component('project_classifier', ProjectClassifier)
    _upgrade_component('content_selector', ContentSelector)

    orchestrator = app_components.get('orchestrator')
    if orchestrator is not None:
        try:
            orchestrator.__class__ = Orchestrator
        except Exception:
            pass
        try:
            setattr(orchestrator, 'workspace_repository', workspace_repository)
            setattr(orchestrator, 'workspace_binding_repository', workspace_binding_repository)
        except Exception:
            pass

    admin_api_service = app_components.get('admin_api_service')
    if admin_api_service is not None:
        try:
            setattr(admin_api_service, 'workspace_repository', workspace_repository)
            setattr(admin_api_service, 'workspace_binding_repository', workspace_binding_repository)
        except Exception:
            pass

    app_components['workspace_step3_enabled'] = True
    return app_components


# =========================
# Step29 - Workspace Admin Management (workspace step4)
# =========================

_STEP29_BASE_ADMIN_API_SERVICE = AdminAPIService
class AdminAPIService(_STEP29_BASE_ADMIN_API_SERVICE):
    def _workspace_repos(self):
        return (
            getattr(self, 'workspace_repository', None),
            getattr(self, 'workspace_binding_repository', None),
            getattr(self, 'business_account_repo', None),
        )

    def list_workspaces_admin(self) -> list[dict[str, Any]]:
        workspace_repo, binding_repo, _ = self._workspace_repos()
        if workspace_repo is None or binding_repo is None:
            return []
        rows: list[dict[str, Any]] = []
        for ws in workspace_repo.list_workspaces(active_only=False):
            bindings = binding_repo.list_workspace_bindings(ws.id, enabled_only=False)
            primary = next((b for b in bindings if b.is_primary), None)
            rows.append({
                'id': ws.id,
                'workspace_key': ws.workspace_key,
                'display_name': ws.display_name,
                'owner_label': ws.owner_label,
                'is_active': ws.is_active,
                'max_bound_accounts': ws.max_bound_accounts,
                'binding_count': len(bindings),
                'enabled_binding_count': len([b for b in bindings if b.is_enabled]),
                'primary_binding_id': primary.id if primary else None,
                'primary_business_account_id': primary.business_account_id if primary else None,
                'primary_display_name': primary.display_name if primary else None,
            })
        return rows

    def get_workspace_detail_admin(self, workspace_id: int) -> dict[str, Any]:
        workspace_repo, binding_repo, _ = self._workspace_repos()
        if workspace_repo is None or binding_repo is None:
            return {'ok': False, 'reason': 'workspace service unavailable'}
        ws = workspace_repo.get_by_id(workspace_id)
        if ws is None:
            return {'ok': False, 'reason': 'workspace not found'}
        bindings = binding_repo.list_workspace_bindings(workspace_id, enabled_only=False)
        return {
            'ok': True,
            'workspace': {
                'id': ws.id,
                'workspace_key': ws.workspace_key,
                'display_name': ws.display_name,
                'owner_label': ws.owner_label,
                'is_active': ws.is_active,
                'max_bound_accounts': ws.max_bound_accounts,
                'metadata_json': ws.metadata_json,
            },
            'bindings': [
                {
                    'id': b.id,
                    'workspace_id': b.workspace_id,
                    'business_account_id': b.business_account_id,
                    'tg_business_account_id': b.tg_business_account_id,
                    'display_name': b.display_name,
                    'username': b.username,
                    'is_primary': b.is_primary,
                    'is_enabled': b.is_enabled,
                    'binding_label': b.binding_label,
                    'entry_alias': b.entry_alias,
                }
                for b in bindings
            ],
        }

    def list_workspace_bindings_admin(self, workspace_id: int) -> list[dict[str, Any]]:
        detail = self.get_workspace_detail_admin(workspace_id)
        return detail.get('bindings') or [] if detail.get('ok') else []

    def list_workspace_candidate_accounts_admin(self, workspace_id: int) -> list[dict[str, Any]]:
        _, _, business_account_repo = self._workspace_repos()
        if business_account_repo is None:
            return []
        db = getattr(business_account_repo, 'db', None)
        if db is None:
            return []
        with db.cursor() as cur:
            cur.execute(
                """
                SELECT ba.*, wab.workspace_id AS bound_workspace_id, wab.is_enabled AS binding_enabled
                FROM business_accounts ba
                LEFT JOIN workspace_account_bindings wab ON wab.business_account_id = ba.id
                ORDER BY ba.id ASC
                """
            )
            rows = cur.fetchall() or []
        result: list[dict[str, Any]] = []
        for row in rows:
            current_ws = row.get('bound_workspace_id')
            result.append({
                'id': int(row.get('id') or 0),
                'tg_business_account_id': row.get('tg_business_account_id'),
                'display_name': row.get('display_name'),
                'username': row.get('username'),
                'bound_workspace_id': int(current_ws) if current_ws is not None else None,
                'is_current_workspace': int(current_ws or 0) == int(workspace_id),
                'binding_enabled': bool(row.get('binding_enabled')) if row.get('binding_enabled') is not None else None,
            })
        return result

    def bind_business_account_to_workspace_admin(self, workspace_id: int, business_account_id: int, operator: str = 'admin') -> dict[str, Any]:
        workspace_repo, binding_repo, _ = self._workspace_repos()
        if workspace_repo is None or binding_repo is None:
            return {'ok': False, 'reason': 'workspace service unavailable'}
        ws = workspace_repo.get_by_id(workspace_id)
        if ws is None:
            return {'ok': False, 'reason': 'workspace not found'}
        existing = binding_repo.get_binding_by_business_account_id(business_account_id)
        try:
            binding = binding_repo.bind_business_account(
                workspace_id,
                business_account_id,
                is_primary=(existing is None and not binding_repo.list_workspace_bindings(workspace_id, enabled_only=True)),
                is_enabled=True,
            )
        except Exception as exc:
            return {'ok': False, 'reason': str(exc)}
        return {'ok': True, 'binding': binding, 'workspace': ws}

    def set_workspace_primary_binding_admin(self, binding_id: int, operator: str = 'admin') -> dict[str, Any]:
        _, binding_repo, _ = self._workspace_repos()
        if binding_repo is None:
            return {'ok': False, 'reason': 'workspace service unavailable'}
        current = None
        for ws in self.list_workspaces_admin():
            for item in binding_repo.list_workspace_bindings(int(ws['id']), enabled_only=False):
                if item.id == binding_id:
                    current = item
                    break
            if current is not None:
                break
        if current is None:
            return {'ok': False, 'reason': 'binding not found'}
        binding_repo.set_primary_binding(binding_id)
        return {'ok': True, 'binding': binding_repo.get_binding_by_business_account_id(current.business_account_id)}

    def toggle_workspace_binding_admin(self, binding_id: int, is_enabled: bool, operator: str = 'admin') -> dict[str, Any]:
        _, binding_repo, _ = self._workspace_repos()
        if binding_repo is None:
            return {'ok': False, 'reason': 'workspace service unavailable'}
        current = None
        for ws in self.list_workspaces_admin():
            for item in binding_repo.list_workspace_bindings(int(ws['id']), enabled_only=False):
                if item.id == binding_id:
                    current = item
                    break
            if current is not None:
                break
        if current is None:
            return {'ok': False, 'reason': 'binding not found'}
        binding_repo.set_binding_enabled(binding_id, is_enabled)
        return {'ok': True, 'binding': binding_repo.get_binding_by_business_account_id(current.business_account_id)}

    def update_workspace_limit_admin(self, workspace_id: int, max_bound_accounts: int, operator: str = 'admin') -> dict[str, Any]:
        workspace_repo, _, _ = self._workspace_repos()
        if workspace_repo is None:
            return {'ok': False, 'reason': 'workspace service unavailable'}
        ws = workspace_repo.get_by_id(workspace_id)
        if ws is None:
            return {'ok': False, 'reason': 'workspace not found'}
        workspace_repo.update_max_bound_accounts(workspace_id, max(1, min(int(max_bound_accounts), 100)))
        updated = workspace_repo.get_by_id(workspace_id)
        return {'ok': True, 'workspace': updated}


_STEP29_BASE_TG_ADMIN_FORMATTER = TGAdminFormatter
class TGAdminFormatter(_STEP29_BASE_TG_ADMIN_FORMATTER):
    @staticmethod
    def format_workspace_overview(rows: list[dict[str, Any]]) -> str:
        lines = ['🧩 工作区管理', '', '当前共享工作区列表：', '']
        if not rows:
            lines.append('暂无工作区。')
            return '\n'.join(lines)
        for row in rows:
            lines.append(
                f"- #{row.get('id')} {row.get('display_name') or row.get('workspace_key')} | 绑定 {row.get('enabled_binding_count') or 0}/{row.get('max_bound_accounts') or 0} | 主账号: {row.get('primary_display_name') or '-'}"
            )
        lines.append('')
        lines.append('说明：一个 workspace 下共享人设、项目、素材、训练与运行策略；入口账号来源仍然分开记录。')
        return '\n'.join(lines)

    @staticmethod
    def format_workspace_detail(detail: dict[str, Any]) -> str:
        if not detail.get('ok'):
            return f"❌ {detail.get('reason') or '未找到工作区。'}"
        ws = detail.get('workspace') or {}
        bindings = detail.get('bindings') or []
        lines = [
            '🧩 工作区详情', '',
            f"ID: {ws.get('id')}",
            f"名称: {ws.get('display_name') or '-'}",
            f"Key: {ws.get('workspace_key') or '-'}",
            f"状态: {'启用' if ws.get('is_active') else '停用'}",
            f"绑定上限: {ws.get('max_bound_accounts') or '-'}",
            f"当前绑定账号: {len(bindings)}",
        ]
        if bindings:
            lines.append('')
            lines.append('已绑定账号：')
            for idx, row in enumerate(bindings[:12], start=1):
                flags = []
                if row.get('is_primary'):
                    flags.append('主账号')
                flags.append('启用' if row.get('is_enabled') else '停用')
                lines.append(f"{idx}. 绑定#{row.get('id')} | 账号#{row.get('business_account_id')} | {row.get('display_name') or row.get('tg_business_account_id') or '-'} | {'/'.join(flags)}")
        else:
            lines.append('')
            lines.append('暂无绑定账号。')
        return '\n'.join(lines)

    @staticmethod
    def format_workspace_candidate_accounts(workspace_id: int, rows: list[dict[str, Any]]) -> str:
        lines = [f'➕ 可绑定账号（工作区 #{workspace_id}）', '']
        if not rows:
            lines.append('暂无可展示账号。')
            return '\n'.join(lines)
        for idx, row in enumerate(rows[:20], start=1):
            status = '当前工作区' if row.get('is_current_workspace') else (f"已绑定到 workspace #{row.get('bound_workspace_id')}" if row.get('bound_workspace_id') else '未绑定')
            lines.append(f"{idx}. 账号#{row.get('id')} | {row.get('display_name') or row.get('tg_business_account_id') or '-'} | {status}")
        lines.append('')
        lines.append('点击下方按钮可绑定/重绑定账号到当前工作区。')
        return '\n'.join(lines)


_STEP29_BASE_TG_ADMIN_MENU_BUILDER = TGAdminMenuBuilder
class TGAdminMenuBuilder(_STEP29_BASE_TG_ADMIN_MENU_BUILDER):
    @staticmethod
    def main_menu() -> dict:
        menu = copy.deepcopy(_STEP29_BASE_TG_ADMIN_MENU_BUILDER.main_menu())
        reply_markup = list(menu.get('reply_markup') or [])
        workspace_row = [{"text": "🧩 工作区管理", "callback_data": "adm:workspace"}]
        if workspace_row not in reply_markup:
            reply_markup.insert(4, workspace_row)
        menu['reply_markup'] = reply_markup
        return menu

    @staticmethod
    def workspace_menu(rows: list[dict[str, Any]]) -> dict:
        buttons: list[list[dict[str, str]]] = []
        for row in rows[:12]:
            buttons.append([{'text': f"#{row.get('id')} {str(row.get('display_name') or row.get('workspace_key') or '-')[:24]}", 'callback_data': f"adm:workspace:view:{row.get('id')}"}])
        buttons.append([{'text': '🏠 主菜单', 'callback_data': 'adm:main'}])
        return {'text': '🧩 工作区管理', 'reply_markup': buttons}

    @staticmethod
    def workspace_detail_menu(workspace_id: int, bindings: list[dict[str, Any]]) -> list[list[dict[str, str]]]:
        rows: list[list[dict[str, str]]] = [
            [{'text': '➕ 绑定账号', 'callback_data': f'adm:workspace:bindable:{workspace_id}'}, {'text': '⚙️ 设置上限', 'callback_data': f'adm:workspace:limit:{workspace_id}'}],
        ]
        for row in bindings[:12]:
            actions: list[dict[str, str]] = []
            if not row.get('is_primary'):
                actions.append({'text': f"设主 #{row.get('business_account_id')}", 'callback_data': f"adm:workspace:primary:{row.get('id')}"})
            actions.append({'text': ('停用' if row.get('is_enabled') else '启用') + f" #{row.get('business_account_id')}", 'callback_data': f"adm:workspace:toggle:{row.get('id')}:{0 if row.get('is_enabled') else 1}"})
            rows.append(actions)
        rows.append([{'text': '🔄 刷新', 'callback_data': f'adm:workspace:view:{workspace_id}'}, {'text': '🧩 工作区列表', 'callback_data': 'adm:workspace'}])
        rows.append([{'text': '🏠 主菜单', 'callback_data': 'adm:main'}])
        return rows

    @staticmethod
    def workspace_candidate_accounts_menu(workspace_id: int, rows: list[dict[str, Any]]) -> list[list[dict[str, str]]]:
        buttons: list[list[dict[str, str]]] = []
        for row in rows[:20]:
            buttons.append([{'text': f"绑定账号#{row.get('id')} {str(row.get('display_name') or row.get('tg_business_account_id') or '-')[:18]}", 'callback_data': f"adm:workspace:bind:{workspace_id}:{row.get('id')}"}])
        buttons.append([{'text': '🔙 返回工作区详情', 'callback_data': f'adm:workspace:view:{workspace_id}'}, {'text': '🧩 工作区列表', 'callback_data': 'adm:workspace'}])
        return buttons


_STEP29_BASE_TG_ADMIN_CALLBACK_ROUTER = TGAdminCallbackRouter
class TGAdminCallbackRouter(_STEP29_BASE_TG_ADMIN_CALLBACK_ROUTER):
    def handle(self, admin_chat_id: int, callback_data: str, operator: str = 'admin') -> None:
        parts = (callback_data or '').split(':')
        if parts[:2] == ['adm', 'workspace']:
            business_account_id = self._resolve_business_account_id() or 0
            if len(parts) == 2:
                rows = self.admin_api_service.list_workspaces_admin()
                menu = TGAdminMenuBuilder.workspace_menu(rows)
                self._send_text(admin_chat_id, TGAdminFormatter.format_workspace_overview(rows), menu['reply_markup'])
                return
            action = parts[2] if len(parts) > 2 else ''
            if action == 'view' and len(parts) > 3 and parts[3].isdigit():
                workspace_id = int(parts[3])
                detail = self.admin_api_service.get_workspace_detail_admin(workspace_id)
                bindings = detail.get('bindings') or []
                self._send_text(admin_chat_id, TGAdminFormatter.format_workspace_detail(detail), TGAdminMenuBuilder.workspace_detail_menu(workspace_id, bindings))
                return
            if action == 'bindable' and len(parts) > 3 and parts[3].isdigit():
                workspace_id = int(parts[3])
                rows = self.admin_api_service.list_workspace_candidate_accounts_admin(workspace_id)
                self._send_text(admin_chat_id, TGAdminFormatter.format_workspace_candidate_accounts(workspace_id, rows), TGAdminMenuBuilder.workspace_candidate_accounts_menu(workspace_id, rows))
                return
            if action == 'bind' and len(parts) > 4 and parts[3].isdigit() and parts[4].isdigit():
                workspace_id = int(parts[3])
                target_business_account_id = int(parts[4])
                result = self.admin_api_service.bind_business_account_to_workspace_admin(workspace_id, target_business_account_id, operator=operator)
                if result.get('ok'):
                    message = f"✅ 已将账号 #{target_business_account_id} 绑定到工作区 #{workspace_id}。"
                    self._record_action(business_account_id, admin_chat_id, 'workspace_bind', message, payload={'workspace_id': workspace_id, 'business_account_id': target_business_account_id})
                    self._send_text(admin_chat_id, message, [[{'text': '🔙 返回工作区详情', 'callback_data': f'adm:workspace:view:{workspace_id}'}], [{'text': '🧩 工作区列表', 'callback_data': 'adm:workspace'}]])
                else:
                    self._send_text(admin_chat_id, f"❌ 绑定失败：{result.get('reason') or '未知错误'}", [[{'text': '🔙 返回候选账号', 'callback_data': f'adm:workspace:bindable:{workspace_id}'}]])
                return
            if action == 'primary' and len(parts) > 3 and parts[3].isdigit():
                binding_id = int(parts[3])
                result = self.admin_api_service.set_workspace_primary_binding_admin(binding_id, operator=operator)
                if result.get('ok'):
                    binding = result.get('binding')
                    workspace_id = int(binding.workspace_id) if binding else 0
                    self._send_text(admin_chat_id, '✅ 已设置主账号。', [[{'text': '🔙 返回工作区详情', 'callback_data': f'adm:workspace:view:{workspace_id}'}]])
                else:
                    self._send_text(admin_chat_id, f"❌ 设置失败：{result.get('reason') or '未知错误'}", [[{'text': '🧩 工作区列表', 'callback_data': 'adm:workspace'}]])
                return
            if action == 'toggle' and len(parts) > 4 and parts[3].isdigit():
                binding_id = int(parts[3])
                is_enabled = str(parts[4]) in {'1', 'true', 'yes'}
                result = self.admin_api_service.toggle_workspace_binding_admin(binding_id, is_enabled, operator=operator)
                if result.get('ok'):
                    binding = result.get('binding')
                    workspace_id = int(binding.workspace_id) if binding else 0
                    self._send_text(admin_chat_id, f"✅ 绑定账号已{'启用' if is_enabled else '停用'}。", [[{'text': '🔙 返回工作区详情', 'callback_data': f'adm:workspace:view:{workspace_id}'}]])
                else:
                    self._send_text(admin_chat_id, f"❌ 操作失败：{result.get('reason') or '未知错误'}", [[{'text': '🧩 工作区列表', 'callback_data': 'adm:workspace'}]])
                return
            if action == 'limit' and len(parts) > 3 and parts[3].isdigit():
                workspace_id = int(parts[3])
                self._activate_text_input(
                    admin_chat_id,
                    business_account_id,
                    'workspace_set_limit',
                    '请输入新的绑定上限（建议 1-20）：',
                    payload={'workspace_id': workspace_id, 'back_callback': f'adm:workspace:view:{workspace_id}'},
                    reply_markup=[[{'text': '🔙 返回工作区详情', 'callback_data': f'adm:workspace:view:{workspace_id}'}], [{'text': '🧩 工作区列表', 'callback_data': 'adm:workspace'}]],
                )
                return
        return super().handle(admin_chat_id, callback_data, operator)


_STEP29_BASE_TG_ADMIN_HANDLERS = TGAdminHandlers
class TGAdminHandlers(_STEP29_BASE_TG_ADMIN_HANDLERS):
    def handle_admin_text(self, admin_chat_id: int, text_value: str, operator: str = 'admin') -> None:
        session = self.admin_session_repo.get_session(admin_chat_id) or {}
        state = str(session.get('state') or '')
        payload = session.get('payload_json') or {}
        if state == 'workspace_set_limit':
            workspace_id = int(payload.get('workspace_id') or 0)
            try:
                limit_value = max(1, min(int(str(text_value or '').strip()), 100))
            except Exception:
                self._send_text(admin_chat_id, '⚠️ 请输入有效数字，例如 6。')
                return
            result = self.admin_api_service.update_workspace_limit_admin(workspace_id, limit_value, operator=operator)
            if result.get('ok'):
                self.admin_session_repo.clear_session(admin_chat_id)
                self._send_text(admin_chat_id, f'✅ 已更新工作区绑定上限为 {limit_value}。', [[{'text': '🔙 返回工作区详情', 'callback_data': f'adm:workspace:view:{workspace_id}'}], [{'text': '🧩 工作区列表', 'callback_data': 'adm:workspace'}]])
            else:
                self._send_text(admin_chat_id, f"❌ 更新失败：{result.get('reason') or '未知错误'}", [[{'text': '🔙 返回工作区详情', 'callback_data': f'adm:workspace:view:{workspace_id}'}]])
            return
        return super().handle_admin_text(admin_chat_id, text_value, operator)


_STEP29_BASE_BUILD_APP_COMPONENTS = build_app_components

def build_app_components(settings: Settings) -> dict[str, Any]:
    app_components = _STEP29_BASE_BUILD_APP_COMPONENTS(settings)
    workspace_repository = app_components.get('workspace_repository')
    workspace_binding_repository = app_components.get('workspace_binding_repository')
    business_account_repo = app_components.get('business_account_repo')
    admin_api_service = app_components.get('admin_api_service')
    if admin_api_service is not None:
        try:
            admin_api_service.__class__ = AdminAPIService
        except Exception:
            pass
        try:
            setattr(admin_api_service, 'workspace_repository', workspace_repository)
            setattr(admin_api_service, 'workspace_binding_repository', workspace_binding_repository)
            setattr(admin_api_service, 'business_account_repo', business_account_repo)
        except Exception:
            pass
    router = app_components.get('tg_admin_callback_router')
    if router is not None:
        try:
            router.__class__ = TGAdminCallbackRouter
        except Exception:
            pass
        try:
            setattr(router, 'workspace_repository', workspace_repository)
            setattr(router, 'workspace_binding_repository', workspace_binding_repository)
        except Exception:
            pass
    handlers = app_components.get('tg_admin_handlers')
    if handlers is not None:
        try:
            handlers.__class__ = TGAdminHandlers
        except Exception:
            pass
    app_components['workspace_step4_enabled'] = True
    return app_components


# =========================
# Step30 - Workspace launch protection & expansion reserve (workspace step5)
# 上线保护与扩容预留：默认上限6但不写死、账号级开关、来源账号保护
# =========================
from dataclasses import field


def _workspace_default_max_bound_accounts() -> int:
    raw = (os.getenv('WORKSPACE_DEFAULT_MAX_BOUND_ACCOUNTS', '6') or '6').strip()
    try:
        value = int(raw)
    except Exception:
        value = 6
    return max(1, min(value, 500))


_STEP30_BASE_INITIALIZE_DATABASE = initialize_database

def initialize_database(db: Database) -> None:
    _STEP30_BASE_INITIALIZE_DATABASE(db)
    default_limit = _workspace_default_max_bound_accounts()
    with db.cursor() as cur:
        cur.execute("ALTER TABLE workspace_account_bindings ADD COLUMN IF NOT EXISTS ai_reply_enabled BOOLEAN NOT NULL DEFAULT TRUE")
        cur.execute("ALTER TABLE workspace_account_bindings ADD COLUMN IF NOT EXISTS followup_enabled BOOLEAN NOT NULL DEFAULT TRUE")
        cur.execute("ALTER TABLE workspace_account_bindings ADD COLUMN IF NOT EXISTS binding_metadata_json JSONB NOT NULL DEFAULT '{}'::jsonb")
        cur.execute(f"ALTER TABLE workspaces ALTER COLUMN max_bound_accounts SET DEFAULT {default_limit}")
        cur.execute(
            """
            UPDATE workspaces
            SET max_bound_accounts=%s,
                metadata_json = COALESCE(metadata_json, '{}'::jsonb) || %s::jsonb,
                updated_at=NOW()
            WHERE workspace_key='default' AND (max_bound_accounts IS NULL OR max_bound_accounts < 1)
            """,
            (default_limit, json.dumps({'default_limit': default_limit, 'expansion_ready': True, 'soft_limit_warning_ratio': 0.85}, ensure_ascii=False)),
        )
        cur.execute(
            """
            UPDATE workspaces
            SET metadata_json = COALESCE(metadata_json, '{}'::jsonb) || %s::jsonb,
                updated_at=NOW()
            WHERE workspace_key='default' AND (metadata_json->>'default_limit') IS NULL
            """,
            (json.dumps({'default_limit': default_limit, 'expansion_ready': True, 'soft_limit_warning_ratio': 0.85}, ensure_ascii=False),),
        )
        cur.execute(
            "UPDATE workspace_account_bindings SET ai_reply_enabled=COALESCE(ai_reply_enabled, TRUE), followup_enabled=COALESCE(followup_enabled, TRUE), updated_at=NOW() WHERE ai_reply_enabled IS NULL OR followup_enabled IS NULL"
        )


@dataclass(slots=True)
class WorkspaceAccountBindingRecord:
    id: int
    workspace_id: int
    business_account_id: int
    tg_business_account_id: str
    display_name: str
    username: str | None
    is_primary: bool
    is_enabled: bool
    ai_reply_enabled: bool
    followup_enabled: bool
    binding_label: str | None
    entry_alias: str | None
    binding_metadata_json: dict[str, Any] = field(default_factory=dict)
    created_at: datetime | None = None
    updated_at: datetime | None = None


def _workspace_binding_record_from_row(row: dict | None) -> WorkspaceAccountBindingRecord | None:
    if not row:
        return None
    metadata_json = row.get('binding_metadata_json') or {}
    if isinstance(metadata_json, str):
        try:
            metadata_json = json.loads(metadata_json)
        except Exception:
            metadata_json = {}
    return WorkspaceAccountBindingRecord(
        id=int(row['id']),
        workspace_id=int(row['workspace_id']),
        business_account_id=int(row['business_account_id']),
        tg_business_account_id=str(row.get('tg_business_account_id') or ''),
        display_name=str(row.get('display_name') or row.get('tg_business_account_id') or '-'),
        username=row.get('username'),
        is_primary=bool(row.get('is_primary')),
        is_enabled=bool(row.get('is_enabled')),
        ai_reply_enabled=bool(row.get('ai_reply_enabled', True)),
        followup_enabled=bool(row.get('followup_enabled', True)),
        binding_label=row.get('binding_label'),
        entry_alias=row.get('entry_alias'),
        binding_metadata_json=metadata_json if isinstance(metadata_json, dict) else {},
        created_at=row.get('created_at'),
        updated_at=row.get('updated_at'),
    )


_STEP30_BASE_WORKSPACE_REPOSITORY = WorkspaceRepository
class WorkspaceRepository(_STEP30_BASE_WORKSPACE_REPOSITORY):
    def ensure_default_workspace(self) -> WorkspaceRecord:
        existing = self.get_by_key('default')
        if existing:
            if int(existing.max_bound_accounts or 0) < 1:
                self.update_max_bound_accounts(existing.id, _workspace_default_max_bound_accounts())
                existing = self.get_by_id(existing.id) or existing
            return existing
        return self.create_workspace(
            'default',
            'Default Shared Workspace',
            owner_label='shared',
            max_bound_accounts=_workspace_default_max_bound_accounts(),
            metadata_json={'default_limit': _workspace_default_max_bound_accounts(), 'expansion_ready': True, 'soft_limit_warning_ratio': 0.85},
        )

    def create_workspace(self, workspace_key: str, display_name: str, owner_label: str = 'shared',
                         max_bound_accounts: int | None = None, metadata_json: dict[str, Any] | None = None) -> WorkspaceRecord:
        resolved_limit = max_bound_accounts if max_bound_accounts is not None else _workspace_default_max_bound_accounts()
        metadata_json = dict(metadata_json or {})
        metadata_json.setdefault('default_limit', resolved_limit)
        metadata_json.setdefault('expansion_ready', True)
        metadata_json.setdefault('soft_limit_warning_ratio', 0.85)
        return super().create_workspace(workspace_key, display_name, owner_label=owner_label, max_bound_accounts=int(resolved_limit), metadata_json=metadata_json)


_STEP30_BASE_WORKSPACE_BINDING_REPOSITORY = WorkspaceBindingRepository
class WorkspaceBindingRepository(_STEP30_BASE_WORKSPACE_BINDING_REPOSITORY):
    def get_binding_by_id(self, binding_id: int) -> WorkspaceAccountBindingRecord | None:
        with self.db.cursor() as cur:
            cur.execute(
                """
                SELECT wab.*, ba.tg_business_account_id, ba.display_name, ba.username
                FROM workspace_account_bindings wab
                JOIN business_accounts ba ON ba.id = wab.business_account_id
                WHERE wab.id=%s
                LIMIT 1
                """,
                (binding_id,),
            )
            row = cur.fetchone()
        return _workspace_binding_record_from_row(row)

    def get_binding_by_business_account_id(self, business_account_id: int) -> WorkspaceAccountBindingRecord | None:
        with self.db.cursor() as cur:
            cur.execute(
                """
                SELECT wab.*, ba.tg_business_account_id, ba.display_name, ba.username
                FROM workspace_account_bindings wab
                JOIN business_accounts ba ON ba.id = wab.business_account_id
                WHERE wab.business_account_id=%s
                LIMIT 1
                """,
                (business_account_id,),
            )
            row = cur.fetchone()
        return _workspace_binding_record_from_row(row)

    def list_workspace_bindings(self, workspace_id: int, enabled_only: bool = False) -> list[WorkspaceAccountBindingRecord]:
        with self.db.cursor() as cur:
            if enabled_only:
                cur.execute(
                    """
                    SELECT wab.*, ba.tg_business_account_id, ba.display_name, ba.username
                    FROM workspace_account_bindings wab
                    JOIN business_accounts ba ON ba.id = wab.business_account_id
                    WHERE wab.workspace_id=%s AND wab.is_enabled=TRUE
                    ORDER BY wab.is_primary DESC, wab.id ASC
                    """,
                    (workspace_id,),
                )
            else:
                cur.execute(
                    """
                    SELECT wab.*, ba.tg_business_account_id, ba.display_name, ba.username
                    FROM workspace_account_bindings wab
                    JOIN business_accounts ba ON ba.id = wab.business_account_id
                    WHERE wab.workspace_id=%s
                    ORDER BY wab.is_primary DESC, wab.id ASC
                    """,
                    (workspace_id,),
                )
            rows = cur.fetchall() or []
        return [rec for rec in (_workspace_binding_record_from_row(r) for r in rows) if rec]

    def bind_business_account(self, workspace_id: int, business_account_id: int, *, is_primary: bool = False,
                              is_enabled: bool = True, binding_label: str | None = None,
                              entry_alias: str | None = None,
                              ai_reply_enabled: bool = True,
                              followup_enabled: bool = True,
                              binding_metadata_json: dict[str, Any] | None = None) -> WorkspaceAccountBindingRecord:
        binding_metadata_json = binding_metadata_json or {}
        with self.db.cursor() as cur:
            cur.execute("SELECT max_bound_accounts FROM workspaces WHERE id=%s LIMIT 1", (workspace_id,))
            ws_row = cur.fetchone()
            if not ws_row:
                raise RuntimeError(f'workspace not found: {workspace_id}')
            max_bound_accounts = int(ws_row.get('max_bound_accounts') or _workspace_default_max_bound_accounts())
            existing_binding = self.get_binding_by_business_account_id(business_account_id)
            current_enabled_count = self._count_enabled_bindings(workspace_id)
            if existing_binding is None and current_enabled_count >= max_bound_accounts:
                raise RuntimeError(f'workspace binding limit reached: {max_bound_accounts}')
            cur.execute(
                """
                INSERT INTO workspace_account_bindings (
                    workspace_id, business_account_id, is_primary, is_enabled, binding_label, entry_alias,
                    ai_reply_enabled, followup_enabled, binding_metadata_json
                ) VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s::jsonb)
                ON CONFLICT (business_account_id)
                DO UPDATE SET
                    workspace_id = EXCLUDED.workspace_id,
                    is_primary = EXCLUDED.is_primary,
                    is_enabled = EXCLUDED.is_enabled,
                    binding_label = EXCLUDED.binding_label,
                    entry_alias = EXCLUDED.entry_alias,
                    ai_reply_enabled = EXCLUDED.ai_reply_enabled,
                    followup_enabled = EXCLUDED.followup_enabled,
                    binding_metadata_json = EXCLUDED.binding_metadata_json,
                    updated_at = NOW()
                RETURNING id
                """,
                (workspace_id, business_account_id, is_primary, is_enabled, binding_label, entry_alias, ai_reply_enabled, followup_enabled, json.dumps(binding_metadata_json, ensure_ascii=False)),
            )
            row = cur.fetchone() or {}
            binding_id = int(row.get('id') or 0)
        if is_primary and binding_id:
            self.set_primary_binding(binding_id)
        result = self.get_binding_by_business_account_id(business_account_id)
        if result is None:
            raise RuntimeError('failed to persist workspace binding')
        return result

    def update_binding_runtime_switches(self, binding_id: int, *, ai_reply_enabled: bool | None = None,
                                       followup_enabled: bool | None = None,
                                       binding_metadata_json: dict[str, Any] | None = None) -> WorkspaceAccountBindingRecord | None:
        sets: list[str] = []
        params: list[Any] = []
        if ai_reply_enabled is not None:
            sets.append('ai_reply_enabled=%s')
            params.append(bool(ai_reply_enabled))
        if followup_enabled is not None:
            sets.append('followup_enabled=%s')
            params.append(bool(followup_enabled))
        if binding_metadata_json is not None:
            sets.append('binding_metadata_json=%s::jsonb')
            params.append(json.dumps(binding_metadata_json, ensure_ascii=False))
        if not sets:
            return self.get_binding_by_id(binding_id)
        params.append(binding_id)
        with self.db.cursor() as cur:
            cur.execute(f"UPDATE workspace_account_bindings SET {', '.join(sets)}, updated_at=NOW() WHERE id=%s", tuple(params))
        return self.get_binding_by_id(binding_id)


_STEP30_BASE_WORKSPACE_RUNTIME_SNAPSHOT = WorkspaceRuntimeSnapshot
class WorkspaceRuntimeSnapshot(_STEP30_BASE_WORKSPACE_RUNTIME_SNAPSHOT):
    pass


_STEP30_BASE_AISWITCH_ENGINE = AISwitchEngine
class AISwitchEngine(_STEP30_BASE_AISWITCH_ENGINE):
    def decide(self, business_account_id: int, conversation_id: int, ops_category: str, manual_takeover_status: str) -> tuple[bool, str]:
        snapshot = getattr(self, '_runtime_workspace_snapshot', None) or {}
        if snapshot and not bool(snapshot.get('binding_active', True)):
            return False, 'workspace binding disabled'
        if snapshot and not bool(snapshot.get('source_binding_ai_reply_enabled', True)):
            return False, 'source binding ai disabled'
        return super().decide(business_account_id, conversation_id, ops_category, manual_takeover_status)


_STEP30_BASE_PROACTIVE_FOLLOWUP_ENGINE = ProactiveFollowupEngine
class ProactiveFollowupEngine(_STEP30_BASE_PROACTIVE_FOLLOWUP_ENGINE):
    def decide(self, *args, **kwargs):
        decision = super().decide(*args, **kwargs)
        snapshot = getattr(self, '_runtime_workspace_snapshot', None) or {}
        if snapshot and not bool(snapshot.get('source_binding_followup_enabled', True)):
            decision.should_schedule = False
            decision.followup_kind = 'none'
            decision.text = ''
            decision.reason = ((decision.reason or '') + ' | step30=source_binding_followup_disabled').strip()
        return decision


_STEP30_BASE_ORCHESTRATOR = Orchestrator
class Orchestrator(_STEP30_BASE_ORCHESTRATOR):
    def _resolve_workspace_runtime(self, inbound_message: InboundMessage) -> WorkspaceRuntimeSnapshot:
        snapshot = super()._resolve_workspace_runtime(inbound_message)
        try:
            source_binding_id = snapshot.get('source_binding_id')
            binding_repo = getattr(self, 'workspace_binding_repository', None)
            source_binding = binding_repo.get_binding_by_id(int(source_binding_id)) if binding_repo and source_binding_id else None
            if source_binding is not None:
                snapshot['binding_active'] = bool(source_binding.is_enabled)
                snapshot['source_binding_ai_reply_enabled'] = bool(getattr(source_binding, 'ai_reply_enabled', True))
                snapshot['source_binding_followup_enabled'] = bool(getattr(source_binding, 'followup_enabled', True))
                snapshot['source_binding_label'] = source_binding.binding_label
                snapshot['source_entry_alias'] = source_binding.entry_alias
                snapshot['source_binding_metadata_json'] = getattr(source_binding, 'binding_metadata_json', {}) or {}
            else:
                snapshot.setdefault('binding_active', True)
                snapshot.setdefault('source_binding_ai_reply_enabled', True)
                snapshot.setdefault('source_binding_followup_enabled', True)
            workspace_repo = getattr(self, 'workspace_repository', None)
            workspace_id = snapshot.get('workspace_id')
            if workspace_repo is not None and workspace_id:
                ws = workspace_repo.get_by_id(int(workspace_id))
                if ws is not None:
                    snapshot['workspace_max_bound_accounts'] = int(ws.max_bound_accounts or _workspace_default_max_bound_accounts())
                    snapshot['workspace_metadata_json'] = ws.metadata_json or {}
        except Exception:
            pass
        return snapshot

    def _set_workspace_runtime_context(self, snapshot: WorkspaceRuntimeSnapshot | None) -> None:
        super()._set_workspace_runtime_context(snapshot)
        snapshot = snapshot or WorkspaceRuntimeSnapshot()
        for target_name in ('ai_switch_engine', 'proactive_followup_engine', 'reply_style_engine', 'reply_self_check_engine'):
            target = getattr(self, target_name, None)
            if target is not None:
                try:
                    setattr(target, '_runtime_workspace_snapshot', snapshot)
                except Exception:
                    pass

    def _clear_workspace_runtime_context(self) -> None:
        super()._clear_workspace_runtime_context()
        for target_name in ('ai_switch_engine', 'proactive_followup_engine', 'reply_style_engine', 'reply_self_check_engine'):
            target = getattr(self, target_name, None)
            if target is not None:
                try:
                    setattr(target, '_runtime_workspace_snapshot', None)
                except Exception:
                    pass


_STEP30_BASE_ADMIN_API_SERVICE = AdminAPIService
class AdminAPIService(_STEP30_BASE_ADMIN_API_SERVICE):
    def get_workspace_protection_config_admin(self, workspace_id: int) -> dict[str, Any]:
        workspace_repo, binding_repo, _ = self._workspace_repos()
        if workspace_repo is None or binding_repo is None:
            return {'ok': False, 'reason': 'workspace service unavailable'}
        ws = workspace_repo.get_by_id(workspace_id)
        if ws is None:
            return {'ok': False, 'reason': 'workspace not found'}
        bindings = binding_repo.list_workspace_bindings(workspace_id, enabled_only=False)
        return {
            'ok': True,
            'workspace': ws,
            'default_limit': _workspace_default_max_bound_accounts(),
            'bindings': bindings,
        }

    def update_workspace_binding_ai_admin(self, binding_id: int, ai_reply_enabled: bool, operator: str = 'admin') -> dict[str, Any]:
        _, binding_repo, _ = self._workspace_repos()
        if binding_repo is None:
            return {'ok': False, 'reason': 'workspace service unavailable'}
        binding = binding_repo.update_binding_runtime_switches(binding_id, ai_reply_enabled=ai_reply_enabled)
        if binding is None:
            return {'ok': False, 'reason': 'binding not found'}
        return {'ok': True, 'binding': binding}

    def update_workspace_binding_followup_admin(self, binding_id: int, followup_enabled: bool, operator: str = 'admin') -> dict[str, Any]:
        _, binding_repo, _ = self._workspace_repos()
        if binding_repo is None:
            return {'ok': False, 'reason': 'workspace service unavailable'}
        binding = binding_repo.update_binding_runtime_switches(binding_id, followup_enabled=followup_enabled)
        if binding is None:
            return {'ok': False, 'reason': 'binding not found'}
        return {'ok': True, 'binding': binding}

    def get_workspace_detail_admin(self, workspace_id: int) -> dict[str, Any]:
        detail = super().get_workspace_detail_admin(workspace_id)
        if detail.get('ok'):
            detail['default_limit'] = _workspace_default_max_bound_accounts()
            detail['expansion_ready'] = True
        return detail


_STEP30_BASE_TG_ADMIN_FORMATTER = TGAdminFormatter
class TGAdminFormatter(_STEP30_BASE_TG_ADMIN_FORMATTER):
    @staticmethod
    def format_workspace_detail(detail: dict[str, Any]) -> str:
        if not detail.get('ok'):
            return _STEP30_BASE_TG_ADMIN_FORMATTER.format_workspace_detail(detail)
        ws = detail.get('workspace') or {}
        bindings = detail.get('bindings') or []
        lines = [
            f"🧩 工作区详情 #{ws.get('id')}",
            '',
            f"名称: {ws.get('display_name') or ws.get('workspace_key') or '-'}",
            f"Key: {ws.get('workspace_key') or '-'}",
            f"共享上限: {ws.get('max_bound_accounts') or '-'}（默认建议 {detail.get('default_limit') or 6}）",
            f"状态: {'启用' if ws.get('is_active') else '停用'}",
            f"扩容预留: {'是' if detail.get('expansion_ready', True) else '否'}",
            '',
            '绑定账号：',
        ]
        if not bindings:
            lines.append('暂无绑定账号。')
        for row in bindings:
            suffix = []
            if row.get('is_primary'):
                suffix.append('主账号')
            if not row.get('is_enabled'):
                suffix.append('已停用')
            if not row.get('ai_reply_enabled', True):
                suffix.append('AI关')
            if not row.get('followup_enabled', True):
                suffix.append('跟进关')
            suffix_text = f" [{' / '.join(suffix)}]" if suffix else ''
            lines.append(
                f"- 绑定#{row.get('id')} 账号#{row.get('business_account_id')} {row.get('display_name') or row.get('tg_business_account_id') or '-'}{suffix_text}"
            )
        return '\n'.join(lines)


