                {'text': f"{'取消跟进' if row.get('followup_enabled', True) else '开启跟进'} #{row.get('business_account_id')}", 'callback_data': f"adm:workspace:followup:{row.get('id')}:{0 if row.get('followup_enabled', True) else 1}"},
