_STEP30_BASE_TG_ADMIN_CALLBACK_ROUTER = TGAdminCallbackRouter
class TGAdminCallbackRouter(_STEP30_BASE_TG_ADMIN_CALLBACK_ROUTER):
    def handle(self, admin_chat_id: int, callback_data: str, operator: str = 'admin') -> None:
        parts = (callback_data or '').split(':')
        if parts[:2] == ['adm', 'workspace']:
            if len(parts) > 4 and parts[2] == 'ai' and parts[3].isdigit():
                binding_id = int(parts[3])
                ai_enabled = str(parts[4]) in {'1', 'true', 'yes'}
                result = self.admin_api_service.update_workspace_binding_ai_admin(binding_id, ai_enabled, operator=operator)
                if result.get('ok'):
                    binding = result.get('binding')
                    workspace_id = int(binding.workspace_id) if binding else 0
                    self._send_text(admin_chat_id, f"✅ 账号AI已{'开启' if ai_enabled else '关闭'}。", [[{'text': '🔙 返回工作区详情', 'callback_data': f'adm:workspace:view:{workspace_id}'}]])
                else:
                    self._send_text(admin_chat_id, f"❌ 操作失败：{result.get('reason') or '未知错误'}", [[{'text': '🧩 工作区列表', 'callback_data': 'adm:workspace'}]])
                return
            if len(parts) > 4 and parts[2] == 'followup' and parts[3].isdigit():
                binding_id = int(parts[3])
                followup_enabled = str(parts[4]) in {'1', 'true', 'yes'}
                result = self.admin_api_service.update_workspace_binding_followup_admin(binding_id, followup_enabled, operator=operator)
                if result.get('ok'):
                    binding = result.get('binding')
                    workspace_id = int(binding.workspace_id) if binding else 0
                    self._send_text(admin_chat_id, f"✅ 账号跟进已{'开启' if followup_enabled else '关闭'}。", [[{'text': '🔙 返回工作区详情', 'callback_data': f'adm:workspace:view:{workspace_id}'}]])
                else:
                    self._send_text(admin_chat_id, f"❌ 操作失败：{result.get('reason') or '未知错误'}", [[{'text': '🧩 工作区列表', 'callback_data': 'adm:workspace'}]])
                return
        return super().handle(admin_chat_id, callback_data, operator)


_STEP30_BASE_BUILD_APP_COMPONENTS = build_app_components

def build_app_components(settings: Settings) -> dict[str, Any]:
    app_components = _STEP30_BASE_BUILD_APP_COMPONENTS(settings)
    workspace_repository = app_components.get('workspace_repository')
    workspace_binding_repository = app_components.get('workspace_binding_repository')
    business_account_repo = app_components.get('business_account_repo')
    _upgrade_targets = []
    for key in ('workspace_repository', 'workspace_binding_repository'):
        target = app_components.get(key)
        if target is not None:
            _upgrade_targets.append((key, target))
    for key, target in _upgrade_targets:
        try:
            if key == 'workspace_repository':
                target.__class__ = WorkspaceRepository
            elif key == 'workspace_binding_repository':
                target.__class__ = WorkspaceBindingRepository
        except Exception:
            pass
    orchestrator = app_components.get('orchestrator')
    if orchestrator is not None:
        try:
            orchestrator.__class__ = Orchestrator
        except Exception:
            pass
        try:
            setattr(orchestrator, 'workspace_repository', workspace_repository)
            setattr(orchestrator, 'workspace_binding_repository', workspace_binding_repository)
        except Exception:
            pass
        if getattr(orchestrator, 'ai_switch_engine', None) is not None:
            try:
                orchestrator.ai_switch_engine.__class__ = AISwitchEngine
            except Exception:
                pass
        if getattr(orchestrator, 'proactive_followup_engine', None) is not None:
            try:
                orchestrator.proactive_followup_engine.__class__ = ProactiveFollowupEngine
            except Exception:
                pass
    admin_api_service = app_components.get('admin_api_service')
    if admin_api_service is not None:
        try:
            admin_api_service.__class__ = AdminAPIService
        except Exception:
            pass
        try:
            setattr(admin_api_service, 'workspace_repository', workspace_repository)
            setattr(admin_api_service, 'workspace_binding_repository', workspace_binding_repository)
            setattr(admin_api_service, 'business_account_repo', business_account_repo)
        except Exception:
            pass
    router = app_components.get('tg_admin_callback_router')
    if router is not None:
        try:
            router.__class__ = TGAdminCallbackRouter
        except Exception:
            pass
    menu_builder = TGAdminMenuBuilder
    formatter = TGAdminFormatter
    handlers = app_components.get('tg_admin_handlers')
    if handlers is not None:
        try:
            setattr(handlers, 'workspace_repository', workspace_repository)
            setattr(handlers, 'workspace_binding_repository', workspace_binding_repository)
        except Exception:
            pass
    app_components['workspace_default_max_bound_accounts'] = _workspace_default_max_bound_accounts()
    app_components['workspace_step5_enabled'] = True
    return app_components



# =========================
# Step31 - Stability hardening for deployment
# 1) media size/duration caps
# 2) remove webhook blocking reply sleep
# 3) reduce default-account fallback by resolving admin scope via workspace primary binding
# =========================

def _step31_env_int(name: str, default: int, min_value: int = 1, max_value: int = 1_000_000_000) -> int:
    raw = str(os.getenv(name, default) or default).strip()
    try:
        value = int(raw)
    except Exception:
        value = int(default)
    return max(min_value, min(int(value), max_value))


def _step31_media_limits() -> dict[str, int]:
    return {
        'image_max_bytes': _step31_env_int('MEDIA_MAX_IMAGE_BYTES', 8 * 1024 * 1024, 256 * 1024, 50 * 1024 * 1024),
        'audio_max_bytes': _step31_env_int('MEDIA_MAX_AUDIO_BYTES', 12 * 1024 * 1024, 256 * 1024, 50 * 1024 * 1024),
        'video_max_bytes': _step31_env_int('MEDIA_MAX_VIDEO_BYTES', 20 * 1024 * 1024, 512 * 1024, 100 * 1024 * 1024),
        'audio_max_seconds': _step31_env_int('MEDIA_MAX_AUDIO_SECONDS', 180, 10, 3600),
        'video_max_seconds': _step31_env_int('MEDIA_MAX_VIDEO_SECONDS', 180, 10, 3600),
    }


def _step31_download_bytes_with_limit(url: str, max_bytes: int, timeout_seconds: int = 45) -> tuple[bytes | None, str | None]:
    normalized = str(url or '').strip()
    if not normalized:
        return None, 'empty_url'
    try:
        with urllib_request.urlopen(normalized, timeout=timeout_seconds) as resp:
            try:
                header_len = int(str(resp.headers.get('Content-Length') or '0') or '0')
            except Exception:
                header_len = 0
            if header_len and header_len > max_bytes:
                return None, 'too_large'
            chunks: list[bytes] = []
            total = 0
            while True:
                chunk = resp.read(min(256 * 1024, max_bytes + 1 - total))
                if not chunk:
                    break
                chunks.append(chunk)
                total += len(chunk)
                if total > max_bytes:
                    return None, 'too_large'
            return b''.join(chunks), None
    except Exception as exc:
        return None, str(exc)


def _step31_extract_video_frame_data_urls_from_payload(payload: bytes, suffix: str = '.mp4', max_frames: int = 3,
                                                       timeout_seconds: int = 45) -> list[str]:
    import shutil
    import subprocess
    import tempfile
    from pathlib import Path as _Path

    if not payload:
        return []
    ffmpeg_bin = shutil.which('ffmpeg')
    if not ffmpeg_bin:
        return []
    temp_dir = tempfile.mkdtemp(prefix='step31_video_')
    video_path = os.path.join(temp_dir, f'input{suffix if str(suffix).startswith(".") else ".mp4"}')
    frame_pattern = os.path.join(temp_dir, 'frame_%02d.jpg')
    try:
        with open(video_path, 'wb') as fh:
            fh.write(payload)
        commands = [
            [
                ffmpeg_bin, '-hide_banner', '-loglevel', 'error', '-y',
                '-i', video_path,
                '-vf', 'fps=1/3,scale=min(960\\,iw):-2',
                '-frames:v', str(max_frames),
                frame_pattern,
            ],
            [
                ffmpeg_bin, '-hide_banner', '-loglevel', 'error', '-y',
                '-i', video_path,
                '-vf', 'thumbnail,scale=min(960\\,iw):-2',
                '-frames:v', '1',
                frame_pattern,
            ],
        ]
        for cmd in commands:
            try:
                subprocess.run(cmd, check=False, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, timeout=timeout_seconds)
            except Exception:
                continue
            frame_paths = sorted(str(p) for p in _Path(temp_dir).glob('frame_*.jpg'))[:max_frames]
            if frame_paths:
                data_urls: list[str] = []
                for frame_path in frame_paths:
                    data_url = _step21_image_path_to_data_url(frame_path)
                    if data_url:
                        data_urls.append(data_url)
                if data_urls:
                    return data_urls[:max_frames]
        return []
    finally:
        try:
            for child in os.listdir(temp_dir):
                try:
                    os.remove(os.path.join(temp_dir, child))
                except Exception:
                    pass
            os.rmdir(temp_dir)
        except Exception:
            pass


def _step31_parse_media_limits_flags(media_meta: dict[str, Any], message_type: str) -> dict[str, Any]:
    limits = _step31_media_limits()
    duration = int(media_meta.get('duration') or 0) if str(media_meta.get('duration') or '').isdigit() else int(media_meta.get('duration') or 0 or 0)
    file_size = int(media_meta.get('file_size') or 0) if str(media_meta.get('file_size') or '').isdigit() else int(media_meta.get('file_size') or 0 or 0)
    result = {
        'skip_image_deep': False,
        'skip_audio_deep': False,
        'skip_video_deep': False,
        'limit_reason': None,
    }
    if message_type == 'image' and file_size and file_size > limits['image_max_bytes']:
        result['skip_image_deep'] = True
        result['limit_reason'] = f'image_too_large:{file_size}'
    elif message_type == 'voice':
        if duration and duration > limits['audio_max_seconds']:
            result['skip_audio_deep'] = True
            result['limit_reason'] = f'audio_too_long:{duration}'
        elif file_size and file_size > limits['audio_max_bytes']:
            result['skip_audio_deep'] = True
            result['limit_reason'] = f'audio_too_large:{file_size}'
    elif message_type == 'video':
        if duration and duration > limits['video_max_seconds']:
            result['skip_video_deep'] = True
            result['limit_reason'] = f'video_too_long:{duration}'
        elif file_size and file_size > limits['video_max_bytes']:
            result['skip_video_deep'] = True
            result['limit_reason'] = f'video_too_large:{file_size}'
    return result


_STEP31_BASE_OPENAI_CLIENT_ADAPTER = OpenAIClientAdapter
class OpenAIClientAdapter(_STEP31_BASE_OPENAI_CLIENT_ADAPTER):
    def transcribe_audio_from_url(self, audio_url: str, filename_hint: str = 'voice.ogg', model: str = 'gpt-4o-mini-transcribe') -> str:
        url = str(audio_url or '').strip()
        if not url:
            return ''
        import tempfile
        temp_path = None
        limits = _step31_media_limits()
        try:
            suffix = '.ogg'
            if '.' in filename_hint:
                suffix = '.' + filename_hint.split('.')[-1]
            payload, error_code = _step31_download_bytes_with_limit(url, limits['audio_max_bytes'], timeout_seconds=45)
            if not payload:
                logger.info('Audio transcription skipped | reason=%s', error_code or 'empty_payload')
                return ''
            with tempfile.NamedTemporaryFile(delete=False, suffix=suffix) as tmp:
                tmp.write(payload)
                temp_path = tmp.name
            with open(temp_path, 'rb') as audio_file:
                result = self.client.audio.transcriptions.create(
                    model=model,
                    file=audio_file,
                )
            text_value = getattr(result, 'text', '') or ''
            return str(text_value).strip()
        except Exception:
            return ''
        finally:
            if temp_path and os.path.exists(temp_path):
                try:
                    os.remove(temp_path)
                except Exception:
                    pass

    def summarize_video_context(self, media_url: str, context_text: str = '', model: str = 'gpt-4.1-mini') -> str:
        url = str(media_url or '').strip()
        hint = str(context_text or '').strip()
        if not url:
            return hint[:220]
        kind = _step19_media_url_kind(url)
        if kind != 'video':
            return hint[:220]
        limits = _step31_media_limits()
        payload, error_code = _step31_download_bytes_with_limit(url, limits['video_max_bytes'], timeout_seconds=45)
        if not payload:
            logger.info('Video deep summary skipped | reason=%s', error_code or 'empty_payload')
            return hint[:220]
        frame_data_urls = _step31_extract_video_frame_data_urls_from_payload(payload, suffix=_step21_video_file_suffix(url), max_frames=3)
        if not frame_data_urls:
            return hint[:220]
        prompt_text = (
            'You are helping a Telegram relationship-sales assistant understand a short user or material video. '
            'Based on a few sampled frames and optional text context, write a concise factual summary for reply planning. '
            'Focus on: visible subject, likely setting, obvious activity, social vibe, and likely chat-relevant topic tags. '
            'Do not invent hidden details. Keep it under 90 words. '
            f'Optional context: {hint[:300]}'
        )
        content_parts: list[dict[str, Any]] = [{'type': 'input_text', 'text': prompt_text}]
        for data_url in frame_data_urls[:3]:
            content_parts.append({'type': 'input_image', 'image_url': data_url})
        try:
            response = self.client.responses.create(
                model=model,
                input=[{'role': 'user', 'content': content_parts}],
                max_output_tokens=220,
                temperature=0.1,
            )
        except Exception:
            return hint[:220]
        text_parts: list[str] = []
        for item in getattr(response, 'output', []) or []:
            for content in getattr(item, 'content', []) or []:
                if getattr(content, 'type', None) == 'output_text':
                    text_parts.append(getattr(content, 'text', ''))
        summary = ' '.join(part.strip() for part in text_parts if str(part).strip()).strip()
        if not summary:
            return hint[:220]
        if hint and hint.lower() not in summary.lower():
            summary = f'{summary} | Context: {hint[:120]}'
        return summary[:320]


_STEP31_BASE_MEDIA_UNDERSTANDING_SERVICE = MediaUnderstandingService
class MediaUnderstandingService(_STEP31_BASE_MEDIA_UNDERSTANDING_SERVICE):
    def analyze_inbound_message(self, inbound_message: InboundMessage) -> dict[str, Any]:
        raw_payload = dict(inbound_message.raw_payload or {})
        message_obj = _step6_extract_message_obj(raw_payload)
        message_type = str(inbound_message.message_type or _detect_telegram_message_type(message_obj) or 'text').strip().lower()
        media_meta = _step6_extract_media_meta(message_obj, message_type)
        file_id = str(media_meta.get('file_id') or '').strip()
        if file_id:
            try:
                file_info = self.tg_client.get_file_info(file_id) or {}
            except Exception:
                file_info = {}
            if file_info and not media_meta.get('file_size') and file_info.get('file_size'):
                media_meta['file_size'] = file_info.get('file_size')
        limit_flags = _step31_parse_media_limits_flags(media_meta, message_type)
        analysis = super().analyze_inbound_message(inbound_message)
        media_analysis = dict(analysis.get('media_meta') or {})
        if media_meta.get('file_size') and not media_analysis.get('file_size'):
            media_analysis['file_size'] = media_meta.get('file_size')
        analysis['media_meta'] = media_analysis
        analysis['limit_flags'] = limit_flags
        analysis['limit_reason'] = limit_flags.get('limit_reason')

        if limit_flags.get('skip_image_deep'):
            analysis['image_description'] = ''
            analysis['effective_user_text'] = _step6_build_effective_user_text(inbound_message.text, analysis.get('media_summary') or '')
        if limit_flags.get('skip_audio_deep'):
            analysis['voice_transcript'] = ''
            analysis['effective_user_text'] = _step6_build_effective_user_text(inbound_message.text, analysis.get('media_summary') or '')
        if limit_flags.get('skip_video_deep'):
            # 保留基础摘要，但不做深视频增强。
            analysis['video_summary'] = str(analysis.get('video_summary') or analysis.get('media_summary') or '').strip()
            effective_user_text = str(analysis.get('effective_user_text') or '').strip()
            basic_summary = str(analysis.get('media_summary') or '').strip()
            if basic_summary and basic_summary.lower() not in effective_user_text.lower():
                analysis['effective_user_text'] = (effective_user_text + f'\n\nMedia context: {basic_summary}').strip()
        return analysis

    def enrich_inbound_message(self, inbound_message: InboundMessage) -> InboundMessage:
        enriched = super().enrich_inbound_message(inbound_message)
        raw_payload = dict(enriched.raw_payload or {})
        media_analysis = dict(raw_payload.get('step6_media_analysis') or {})
        if media_analysis:
            media_analysis['limit_reason'] = ((enriched.raw_payload or {}).get('step6_media_analysis') or {}).get('limit_reason') or media_analysis.get('limit_reason')
            raw_payload['step6_media_analysis'] = media_analysis
        return replace(enriched, raw_payload=raw_payload)


_STEP31_BASE_SENDER_SERVICE = SenderService
class SenderService(_STEP31_BASE_SENDER_SERVICE):
    def send_text_reply(self, conversation_id: int, text: str, delay_seconds: int = 0,
                        business_account_id: int | None = None, target_chat_id: int | None = None,
                        target_user_id: int | None = None, source_inbound_message_id: int | None = None,
                        delivery_plan: dict[str, Any] | None = None) -> None:
        delay_seconds = max(0, int(delay_seconds or 0))
        plan = delivery_plan or {'plan_version': 1, 'steps': [], 'summary': ''}
        has_followup_steps = bool(plan.get('steps'))
        # webhook 主链不再因为小延迟而 sleep 阻塞；只在“立即发送且无延迟”时直发。
        if self.immediate_sender is not None and not has_followup_steps and delay_seconds <= 0:
            self.immediate_sender.send_text(conversation_id, text)
            logger.info('AI reply delivered immediately | conversation_id=%s', conversation_id)
            return
        send_after = utc_now() + timedelta(seconds=delay_seconds)
        dedup_key = f'text_reply:{source_inbound_message_id}' if source_inbound_message_id else None
        self.outbound_job_repo.enqueue(
            job_type='text_reply',
            business_account_id=business_account_id or 0,
            target_chat_id=target_chat_id or 0,
            target_user_id=target_user_id,
            payload={
                'conversation_id': conversation_id,
                'text': text,
                'delivery_plan': plan,
            },
            send_after=send_after,
            dedup_key=dedup_key,
            source_inbound_message_id=source_inbound_message_id,
        )
        logger.info('AI reply enqueued | conversation_id=%s | send_after=%s', conversation_id, send_after.isoformat())


_STEP31_BASE_TG_ADMIN_CALLBACK_ROUTER = TGAdminCallbackRouter
class TGAdminCallbackRouter(_STEP31_BASE_TG_ADMIN_CALLBACK_ROUTER):
    def _resolve_workspace_primary_business_account_id(self, workspace_id: int | None = None) -> int | None:
        workspace_repo = getattr(self, 'workspace_repository', None)
        binding_repo = getattr(self, 'workspace_binding_repository', None)
        if binding_repo is None:
            return None
        ws_id = int(workspace_id or 0) if workspace_id else 0
        if ws_id <= 0 and workspace_repo is not None:
            try:
                default_ws = workspace_repo.get_by_key('default') or workspace_repo.ensure_default_workspace()
            except Exception:
                default_ws = None
            ws_id = int(getattr(default_ws, 'id', 0) or 0)
        if ws_id <= 0:
            return None
        try:
            primary = binding_repo.get_primary_binding(ws_id)
        except Exception:
            primary = None
        return int(primary.business_account_id) if primary else None

    def _resolve_business_account_id(self) -> int | None:
        session = None
        try:
            # 稳定性修复：管理员回调优先解析当前 workspace 的主绑定账号，避免回落到默认账号空间。
            session = self.admin_session_repo.get_session(getattr(self, '_current_admin_chat_id', 0)) if getattr(self, '_current_admin_chat_id', 0) else None
        except Exception:
            session = None
        payload = (session or {}).get('payload_json') or {}
        explicit = payload.get('business_account_id') or (session or {}).get('business_account_id')
        if explicit:
            try:
                return int(explicit)
            except Exception:
                pass
        workspace_id = int(payload.get('workspace_id') or (session or {}).get('workspace_id') or 0)
        resolved = self._resolve_workspace_primary_business_account_id(workspace_id)
        if resolved:
            return resolved
        return None

    def handle(self, admin_chat_id: int, callback_data: str, operator: str = 'admin') -> None:
        try:
            setattr(self, '_current_admin_chat_id', int(admin_chat_id or 0))
        except Exception:
            pass
        try:
            return super().handle(admin_chat_id, callback_data, operator)
        finally:
            try:
                setattr(self, '_current_admin_chat_id', 0)
            except Exception:
                pass


_STEP31_BASE_TG_ADMIN_HANDLERS = TGAdminHandlers
class TGAdminHandlers(_STEP31_BASE_TG_ADMIN_HANDLERS):
    def _resolve_admin_business_account_id(self, session: dict[str, Any] | None = None, payload: dict[str, Any] | None = None) -> int | None:
        session = session or {}
        payload = payload or {}
        explicit = payload.get('business_account_id') or session.get('business_account_id')
        if explicit:
            try:
                return int(explicit)
            except Exception:
                pass
        workspace_repo = getattr(self, 'workspace_repository', None)
        binding_repo = getattr(self, 'workspace_binding_repository', None)
        workspace_id = int(payload.get('workspace_id') or session.get('workspace_id') or 0)
        if binding_repo is not None:
            if workspace_id <= 0 and workspace_repo is not None:
                try:
                    default_ws = workspace_repo.get_by_key('default') or workspace_repo.ensure_default_workspace()
                except Exception:
                    default_ws = None
                workspace_id = int(getattr(default_ws, 'id', 0) or 0)
            if workspace_id > 0:
                try:
                    primary = binding_repo.get_primary_binding(workspace_id)
                except Exception:
                    primary = None
                if primary is not None:
                    return int(primary.business_account_id)
        # 稳定性修复：这里不再回落到默认账号，避免 workspace 后台操作误写到非共享空间。
        return None

    def handle_admin_text(self, admin_chat_id: int, text_value: str, operator: str = 'admin') -> None:
        session = self.admin_session_repo.get_session(admin_chat_id) or {}
        state = str(session.get('state') or '')
        payload = dict(session.get('payload_json') or {})
        resolved_business_account_id = self._resolve_admin_business_account_id(session=session, payload=payload)
        if resolved_business_account_id and not payload.get('business_account_id'):
            payload['business_account_id'] = resolved_business_account_id
            try:
                self.admin_session_repo.set_session(
                    admin_chat_id,
                    state,
                    payload,
                    business_account_id=resolved_business_account_id,
                    expires_at=session.get('expires_at'),
                )
            except Exception:
                pass
        return super().handle_admin_text(admin_chat_id, text_value, operator)


_STEP31_BASE_BUILD_APP_COMPONENTS = build_app_components

def build_app_components(settings: Settings) -> dict[str, Any]:
    app_components = _STEP31_BASE_BUILD_APP_COMPONENTS(settings)
    try:
        adapter = app_components.get('llm_service').client_adapter if app_components.get('llm_service') else None
        if adapter is not None:
            adapter.__class__ = OpenAIClientAdapter
    except Exception:
        pass
    media_understanding_service = app_components.get('media_understanding_service')
    if media_understanding_service is not None:
        try:
            media_understanding_service.__class__ = MediaUnderstandingService
        except Exception:
            pass
    sender_service = app_components.get('sender_service')
    if sender_service is not None:
        try:
            sender_service.__class__ = SenderService
        except Exception:
            pass
    router = app_components.get('tg_admin_callback_router')
    if router is not None:
        try:
            router.__class__ = TGAdminCallbackRouter
        except Exception:
            pass
        try:
            setattr(router, 'workspace_repository', app_components.get('workspace_repository'))
            setattr(router, 'workspace_binding_repository', app_components.get('workspace_binding_repository'))
        except Exception:
            pass
    handlers = app_components.get('tg_admin_handlers')
    if handlers is not None:
        try:
            handlers.__class__ = TGAdminHandlers
        except Exception:
            pass
        try:
            setattr(handlers, 'workspace_repository', app_components.get('workspace_repository'))
            setattr(handlers, 'workspace_binding_repository', app_components.get('workspace_binding_repository'))
        except Exception:
            pass
    app_components['stability_step31_enabled'] = True
    return app_components


# =========================
# Step32 - deployment hardening follow-up
# 4) clearer failure logs to avoid silent degradation
# 5) tighten workspace-aware shared read/write consistency in admin paths
# 6) explicit dependency checks for ffmpeg / psycopg at startup
# =========================

def _step32_runtime_dependency_status() -> dict[str, Any]:
    import shutil
    status = {
        'psycopg_available': True,
        'psycopg_version': getattr(psycopg, '__version__', 'unknown'),
        'ffmpeg_available': bool(shutil.which('ffmpeg')),
        'ffmpeg_path': shutil.which('ffmpeg') or '',
    }
    return status


def _step32_log_runtime_dependency_status() -> dict[str, Any]:
    status = _step32_runtime_dependency_status()
    logger.info(
        'Runtime dependency status | psycopg_available=%s | psycopg_version=%s | ffmpeg_available=%s | ffmpeg_path=%s',
        status.get('psycopg_available'),
        status.get('psycopg_version'),
        status.get('ffmpeg_available'),
        status.get('ffmpeg_path') or '-',
    )
    if not status.get('ffmpeg_available'):
        logger.warning('ffmpeg is unavailable; deep video enhancement will fall back to lightweight summaries.')
    return status


_STEP32_BASE_OPENAI_CLIENT_ADAPTER = OpenAIClientAdapter
class OpenAIClientAdapter(_STEP32_BASE_OPENAI_CLIENT_ADAPTER):
    def describe_image_from_url(self, image_url: str, instruction: str = '', model: str = 'gpt-4.1-mini') -> str:
        url = str(image_url or '').strip()
        if not url:
            logger.info('Image description skipped | reason=empty_url')
            return ''
        try:
            result = super().describe_image_from_url(url, instruction=instruction, model=model)
        except Exception:
            logger.exception('Image description failed | model=%s | url=%s', model, _mask_url(url))
            return ''
        if not str(result or '').strip():
            logger.warning('Image description returned empty result | model=%s | url=%s', model, _mask_url(url))
        return str(result or '').strip()

    def transcribe_audio_from_url(self, audio_url: str, filename_hint: str = 'voice.ogg', model: str = 'gpt-4o-mini-transcribe') -> str:
        url = str(audio_url or '').strip()
        if not url:
            logger.info('Audio transcription skipped | reason=empty_url')
            return ''
        try:
            result = super().transcribe_audio_from_url(url, filename_hint=filename_hint, model=model)
        except Exception:
            logger.exception('Audio transcription failed | model=%s | url=%s', model, _mask_url(url))
            return ''
        if not str(result or '').strip():
            logger.warning('Audio transcription returned empty result | model=%s | url=%s', model, _mask_url(url))
        return str(result or '').strip()

    def summarize_video_context(self, media_url: str, context_text: str = '', model: str = 'gpt-4.1-mini') -> str:
        url = str(media_url or '').strip()
        if not url:
            logger.info('Video summary skipped | reason=empty_url')
            return str(context_text or '')[:220]
        if not _step32_runtime_dependency_status().get('ffmpeg_available'):
            logger.info('Video deep summary downgraded | reason=ffmpeg_unavailable | url=%s', _mask_url(url))
        try:
            result = super().summarize_video_context(url, context_text=context_text, model=model)
        except Exception:
            logger.exception('Video summary failed | model=%s | url=%s', model, _mask_url(url))
            return str(context_text or '')[:220]
        normalized = str(result or '').strip()
        if not normalized:
            logger.warning('Video summary returned empty result | model=%s | url=%s', model, _mask_url(url))
            return str(context_text or '')[:220]
        return normalized


_STEP32_BASE_MEDIA_UNDERSTANDING_SERVICE = MediaUnderstandingService
class MediaUnderstandingService(_STEP32_BASE_MEDIA_UNDERSTANDING_SERVICE):
    def analyze_inbound_message(self, inbound_message: InboundMessage) -> dict[str, Any]:
        try:
            analysis = super().analyze_inbound_message(inbound_message)
        except Exception:
            logger.exception(
                'Media understanding failed | message_type=%s | business_account_id=%s | user_id=%s',
                inbound_message.message_type,
                inbound_message.business_account_id,
                inbound_message.user_id,
            )
            raise
        message_type = str(inbound_message.message_type or '').strip().lower()
        limit_reason = str(analysis.get('limit_reason') or '').strip()
        if limit_reason:
            logger.info('Media deep analysis limited | message_type=%s | reason=%s', message_type or '-', limit_reason)
        if message_type in {'image', 'video', 'voice'}:
            media_tags = list(analysis.get('media_tags') or [])
            if not media_tags:
                logger.warning('Media understanding produced no tags | message_type=%s | user_id=%s', message_type or '-', inbound_message.user_id)
        return analysis

    def enrich_inbound_message(self, inbound_message: InboundMessage) -> InboundMessage:
        try:
            return super().enrich_inbound_message(inbound_message)
        except Exception:
            logger.exception(
                'Media enrichment failed | message_type=%s | business_account_id=%s | user_id=%s',
                inbound_message.message_type,
                inbound_message.business_account_id,
                inbound_message.user_id,
            )
            raise


