_STEP32_BASE_ADMIN_API_SERVICE = AdminAPIService
class AdminAPIService(_STEP32_BASE_ADMIN_API_SERVICE):
    def _resolve_workspace_write_business_account_id(self, business_account_id: int | None = None,
                                                     workspace_id: int | None = None) -> int | None:
        workspace_repo = getattr(self, 'workspace_repository', None)
        binding_repo = getattr(self, 'workspace_binding_repository', None)
        explicit_workspace_id = int(workspace_id or 0) if workspace_id else 0
        explicit_business_account_id = int(business_account_id or 0) if business_account_id else 0
        if binding_repo is None:
            return explicit_business_account_id or None
        if explicit_workspace_id > 0:
            try:
                primary = binding_repo.get_primary_binding(explicit_workspace_id)
            except Exception:
                logger.exception('Workspace primary lookup failed | workspace_id=%s', explicit_workspace_id)
                primary = None
            if primary is not None:
                return int(primary.business_account_id)
        if explicit_business_account_id > 0:
            try:
                binding = binding_repo.get_binding_by_business_account_id(explicit_business_account_id)
            except Exception:
                logger.exception('Workspace binding lookup failed | business_account_id=%s', explicit_business_account_id)
                binding = None
            if binding is not None:
                try:
                    primary = binding_repo.get_primary_binding(int(binding.workspace_id))
                except Exception:
                    logger.exception('Workspace primary lookup failed | workspace_id=%s', getattr(binding, 'workspace_id', None))
                    primary = None
                if primary is not None:
                    return int(primary.business_account_id)
        if explicit_workspace_id <= 0 and workspace_repo is not None:
            try:
                default_ws = workspace_repo.get_by_key('default') or workspace_repo.ensure_default_workspace()
            except Exception:
                logger.exception('Default workspace resolution failed during admin write normalization.')
                default_ws = None
            if default_ws is not None:
                try:
                    primary = binding_repo.get_primary_binding(int(default_ws.id))
                except Exception:
                    logger.exception('Default workspace primary binding lookup failed | workspace_id=%s', getattr(default_ws, 'id', None))
                    primary = None
                if primary is not None:
                    return int(primary.business_account_id)
        return explicit_business_account_id or None

    def list_projects_for_business_account(self, business_account_id: int) -> list[dict]:
        effective_id = self._resolve_workspace_write_business_account_id(business_account_id)
        return super().list_projects_for_business_account(int(effective_id or business_account_id))

    def list_projects_admin(self, business_account_id: int, include_inactive: bool = True) -> list[dict]:
        effective_id = self._resolve_workspace_write_business_account_id(business_account_id)
        return super().list_projects_admin(int(effective_id or business_account_id), include_inactive=include_inactive)

    def create_project(self, business_account_id: int, name: str, description: str | None = None) -> dict:
        effective_id = self._resolve_workspace_write_business_account_id(business_account_id)
