    def list_voice_templates_admin(self, business_account_id: int, include_inactive: bool = True) -> list[dict]:
        effective_id = self._resolve_workspace_write_business_account_id(business_account_id)
        return super().list_voice_templates_admin(int(effective_id or business_account_id), include_inactive=include_inactive)

