# ======================
# Step33 consistency hardening
# 目标：
# 1）继续压缩 workspace 共享下的后台读写不一致风险
# 2）给高频增长表补索引，降低长期查询压力
# 3）补充关键路径的清晰日志，减少静默降级
# 注意：这是稳定性增强，不是功能回退。
# ======================

_STEP32_BASE_INITIALIZE_DATABASE = initialize_database

def initialize_database(db: Database) -> None:
    _STEP32_BASE_INITIALIZE_DATABASE(db)
    with db.cursor() as cur:
        # 训练日志：按时间、会话、训练项检索会越来越频繁。
        cur.execute(
            "CREATE INDEX IF NOT EXISTS idx_training_usage_logs_created_at ON training_usage_logs (created_at DESC)"
        )
        cur.execute(
            "CREATE INDEX IF NOT EXISTS idx_training_usage_logs_conversation_item ON training_usage_logs (conversation_id, training_item_id, created_at DESC)"
        )
        # 用户画像状态：后续按用户/账号查询会频繁。
        cur.execute(
            "CREATE INDEX IF NOT EXISTS idx_user_profile_evolution_states_user_ba ON user_profile_evolution_states (user_id, business_account_id)"
        )
        cur.execute(
            "CREATE INDEX IF NOT EXISTS idx_user_profile_evolution_states_updated_at ON user_profile_evolution_states (updated_at DESC)"
        )
        # 素材语义画像：按作用域、类型、更新时间查找更稳。
        cur.execute(
            "CREATE INDEX IF NOT EXISTS idx_material_semantic_profiles_scope_material ON material_semantic_profiles (material_scope, material_id)"
        )
        cur.execute(
            "CREATE INDEX IF NOT EXISTS idx_material_semantic_profiles_updated_at ON material_semantic_profiles (updated_at DESC)"
        )
        # 接管学习候选：按业务空间和时间看候选更稳。
        cur.execute(
            "CREATE INDEX IF NOT EXISTS idx_handover_learning_candidates_ba_created_at ON handover_learning_candidates (business_account_id, created_at DESC)"
        )
        # workspace 绑定表：按工作区和启用状态查询更稳。
        cur.execute(
            "CREATE INDEX IF NOT EXISTS idx_workspace_account_bindings_workspace_enabled ON workspace_account_bindings (workspace_id, is_enabled, is_primary)"
        )


_STEP32_BASE_WORKSPACE_BINDING_REPOSITORY = WorkspaceBindingRepository
class WorkspaceBindingRepository(_STEP32_BASE_WORKSPACE_BINDING_REPOSITORY):
    def get_primary_binding(self, workspace_id: int) -> WorkspaceAccountBindingRecord | None:
        try:
            binding = super().get_primary_binding(workspace_id)
        except Exception:
            logger.exception('Workspace primary binding resolution failed | workspace_id=%s', workspace_id)
            raise
        if binding is None:
            logger.warning('Workspace primary binding missing | workspace_id=%s', workspace_id)
        return binding

    def ensure_binding_for_business_account(self, business_account_id: int) -> WorkspaceAccountBindingRecord:
        try:
            binding = super().ensure_binding_for_business_account(business_account_id)
        except Exception:
            logger.exception('Workspace ensure binding failed | business_account_id=%s', business_account_id)
            raise
        logger.info(
            'Workspace ensure binding complete | business_account_id=%s | workspace_id=%s | binding_id=%s',
            business_account_id,
            getattr(binding, 'workspace_id', None),
            getattr(binding, 'id', None),
        )
        return binding


