class MediaUnderstandingService(_STEP32_BASE_MEDIA_UNDERSTANDING_SERVICE):
    def enrich_inbound_message(self, inbound_message: InboundMessage) -> InboundMessage:
        enriched = super().enrich_inbound_message(inbound_message)
        analysis = ((getattr(enriched, 'raw_payload', None) or {}).get('step6_media_analysis') or {})
        if getattr(enriched, 'message_type', '') in {'photo', 'image', 'video', 'voice', 'audio'}:
            if not (analysis.get('media_tags') or analysis.get('topic_tags') or analysis.get('scene_type') or analysis.get('transcript_text')):
                logger.warning(
                    'Media enrichment produced weak result | message_type=%s | business_account_id=%s | user_id=%s',
                    enriched.message_type,
                    enriched.business_account_id,
                    enriched.user_id,
                )
        return enriched


