    # 继续升级关键运行时组件，保证最终生效的是 step33 版本。
    for key, cls, label in [
        ('workspace_binding_repository', WorkspaceBindingRepository, 'WorkspaceBindingRepository'),
        ('training_center_repository', TrainingCenterRepository, 'TrainingCenterRepository'),
        ('admin_api_service', AdminAPIService, 'AdminAPIService'),
        ('media_understanding_service', MediaUnderstandingService, 'MediaUnderstandingService'),
    ]:
        inst = app_components.get(key)
        if inst is None:
            continue
        try:
            inst.__class__ = cls
        except Exception:
            logger.exception('Step33 failed to upgrade %s.', label)
    app_components['stability_step33_enabled'] = True
    return app_components

