_STEP34_BASE_ADMIN_API_SERVICE = AdminAPIService
class AdminAPIService(_STEP34_BASE_ADMIN_API_SERVICE):
    def update_training_item_admin(self, item_id: int, payload: dict[str, Any]) -> dict[str, Any]:
        workspace_id = int((payload or {}).get('workspace_id') or 0)
        business_account_id = int((payload or {}).get('business_account_id') or 0)
        effective_id = self._workspace_effective_id(business_account_id or None, workspace_id or None)
        if effective_id:
            payload = dict(payload or {})
            payload.setdefault('business_account_id', int(effective_id))
        return super().update_training_item_admin(item_id, payload)

    def summarize_training_items_admin(self, business_account_id: int) -> list[dict[str, Any]]:
        effective_id = self._workspace_effective_id(business_account_id)
        return super().summarize_training_items_admin(int(effective_id or business_account_id))

