    def _runtime_workspace_id_hint(self) -> int | None:
        snapshot = _workspace_runtime_snapshot_of(self)
        raw_workspace_id = snapshot.get('workspace_id')
        if raw_workspace_id in (None, '', 0, '0'):
            return None
        try:
            return int(raw_workspace_id)
        except Exception:
            logger.exception('Workspace runtime hint contains invalid workspace_id | raw_value=%r', raw_workspace_id)
            return None

    def _validate_workspace_scope(self, workspace_id: int, context: str = 'admin_write') -> int:
        workspace_repo = getattr(self, 'workspace_repository', None)
        if workspace_repo is not None:
            workspace = workspace_repo.get_by_id(int(workspace_id))
            if workspace is None:
                raise RuntimeError(f'{context}: workspace not found: {workspace_id}')
        runtime_workspace_id = self._runtime_workspace_id_hint()
        if runtime_workspace_id and int(runtime_workspace_id) != int(workspace_id):
            raise RuntimeError(
                f'{context}: target workspace {workspace_id} does not match current runtime workspace {runtime_workspace_id}'
            )
        logger.info('Workspace scope validation passed | workspace_id=%s | runtime_workspace_id=%s | context=%s', workspace_id, runtime_workspace_id, context)
        return int(workspace_id)

    def _validate_binding_scope(self, binding_id: int, context: str = 'admin_write') -> Any:
        binding_repo = getattr(self, 'workspace_binding_repository', None)
        if binding_repo is None:
            raise RuntimeError(f'{context}: workspace binding repository unavailable')
        binding = binding_repo.get_binding_by_id(int(binding_id))
        if binding is None:
            raise RuntimeError(f'{context}: binding not found: {binding_id}')
        workspace_id = int(getattr(binding, 'workspace_id', 0) or 0)
        if workspace_id:
            self._validate_workspace_scope(workspace_id, context=context)
        logger.info(
            'Workspace binding scope validation passed | binding_id=%s | workspace_id=%s | business_account_id=%s | context=%s',
            binding_id,
            workspace_id,
            getattr(binding, 'business_account_id', None),
            context,
        )
        return binding

