_STEP36_BASE_ORCHESTRATOR = Orchestrator
class Orchestrator(_STEP36_BASE_ORCHESTRATOR):
    def _step37_safe_set_runtime_attr(self, target: Any, attr_name: str, value: Any, context: str) -> None:
        try:
            setattr(target, attr_name, value)
        except Exception:
            logger.exception('Workspace runtime context attribute write failed | context=%s | target_type=%s | attr=%s', context, type(target).__name__, attr_name)
            raise

    def _set_workspace_runtime_context(self, snapshot: WorkspaceRuntimeSnapshot | None) -> None:
        snapshot = snapshot or WorkspaceRuntimeSnapshot()
        self._step37_safe_set_runtime_attr(self, '_runtime_workspace_snapshot', snapshot, 'orchestrator')
        self._step37_safe_set_runtime_attr(self, '_runtime_workspace_id', snapshot.get('workspace_id'), 'orchestrator')
        self._step37_safe_set_runtime_attr(self, '_runtime_source_business_account_id', snapshot.get('source_business_account_id'), 'orchestrator')
        self._step37_safe_set_runtime_attr(self, '_runtime_effective_business_account_id', snapshot.get('effective_business_account_id'), 'orchestrator')
        self._step37_safe_set_runtime_attr(self, '_runtime_source_binding_id', snapshot.get('source_binding_id'), 'orchestrator')
        for target_name in (
            'reply_planner', 'reply_style_engine', 'reply_self_check_engine', 'reply_delay_engine',
            'content_selector', 'proactive_followup_engine', 'understanding_engine'
        ):
            target = getattr(self, target_name, None)
            if target is None:
                logger.warning('Workspace runtime propagation skipped because component is missing | component=%s', target_name)
                continue
            self._step37_safe_set_runtime_attr(target, '_runtime_workspace_snapshot', snapshot, f'orchestrator.{target_name}')

    def _clear_workspace_runtime_context(self) -> None:
        for attr_name in (
            '_runtime_workspace_snapshot', '_runtime_workspace_id', '_runtime_source_business_account_id',
            '_runtime_effective_business_account_id', '_runtime_source_binding_id'
        ):
            self._step37_safe_set_runtime_attr(self, attr_name, None, 'orchestrator.clear')
        for target_name in (
            'reply_planner', 'reply_style_engine', 'reply_self_check_engine', 'reply_delay_engine',
            'content_selector', 'proactive_followup_engine', 'understanding_engine'
        ):
            target = getattr(self, target_name, None)
            if target is None:
                continue
            self._step37_safe_set_runtime_attr(target, '_runtime_workspace_snapshot', None, f'orchestrator.clear.{target_name}')


    def _resolve_workspace_runtime(self, inbound_message: InboundMessage) -> WorkspaceRuntimeSnapshot:
        snapshot = super()._resolve_workspace_runtime(inbound_message)
        try:
            source_binding_id = snapshot.get('source_binding_id')
            binding_repo = getattr(self, 'workspace_binding_repository', None)
            source_binding = binding_repo.get_binding_by_id(int(source_binding_id)) if binding_repo and source_binding_id else None
            if source_binding is not None:
                snapshot['binding_active'] = bool(source_binding.is_enabled)
                snapshot['source_binding_ai_reply_enabled'] = bool(getattr(source_binding, 'ai_reply_enabled', True))
                snapshot['source_binding_followup_enabled'] = bool(getattr(source_binding, 'followup_enabled', True))
                snapshot['source_binding_label'] = source_binding.binding_label
                snapshot['source_entry_alias'] = source_binding.entry_alias
                snapshot['source_binding_metadata_json'] = getattr(source_binding, 'binding_metadata_json', {}) or {}
            else:
                snapshot.setdefault('binding_active', True)
                snapshot.setdefault('source_binding_ai_reply_enabled', True)
                snapshot.setdefault('source_binding_followup_enabled', True)
            workspace_repo = getattr(self, 'workspace_repository', None)
            workspace_id = snapshot.get('workspace_id')
            if workspace_repo is not None and workspace_id:
                ws = workspace_repo.get_by_id(int(workspace_id))
                if ws is not None:
                    snapshot['workspace_max_bound_accounts'] = int(ws.max_bound_accounts or _workspace_default_max_bound_accounts())
                    snapshot['workspace_metadata_json'] = ws.metadata_json or {}
        except Exception:
            logger.exception(
                'Workspace runtime enrichment failed during step37 replay | tg_business_account_id=%s | user_id=%s | workspace_id=%s | source_binding_id=%s',
                inbound_message.tg_business_account_id,
                inbound_message.user_id,
                snapshot.get('workspace_id'),
                snapshot.get('source_binding_id'),
            )
        return snapshot

    def _set_workspace_runtime_context(self, snapshot: WorkspaceRuntimeSnapshot | None) -> None:
        snapshot = snapshot or WorkspaceRuntimeSnapshot()
        self._step37_safe_set_runtime_attr(self, '_runtime_workspace_snapshot', snapshot, 'orchestrator')
        self._step37_safe_set_runtime_attr(self, '_runtime_workspace_id', snapshot.get('workspace_id'), 'orchestrator')
        self._step37_safe_set_runtime_attr(self, '_runtime_source_business_account_id', snapshot.get('source_business_account_id'), 'orchestrator')
        self._step37_safe_set_runtime_attr(self, '_runtime_effective_business_account_id', snapshot.get('effective_business_account_id'), 'orchestrator')
        self._step37_safe_set_runtime_attr(self, '_runtime_source_binding_id', snapshot.get('source_binding_id'), 'orchestrator')
        for target_name in (
            'reply_planner', 'reply_style_engine', 'reply_self_check_engine', 'reply_delay_engine',
            'content_selector', 'proactive_followup_engine', 'understanding_engine',
            'ai_switch_engine'
        ):
            target = getattr(self, target_name, None)
            if target is None:
                logger.warning('Workspace runtime propagation skipped because component is missing | component=%s', target_name)
                continue
            self._step37_safe_set_runtime_attr(target, '_runtime_workspace_snapshot', snapshot, f'orchestrator.{target_name}')

    def _clear_workspace_runtime_context(self) -> None:
        for attr_name in (
            '_runtime_workspace_snapshot', '_runtime_workspace_id', '_runtime_source_business_account_id',
            '_runtime_effective_business_account_id', '_runtime_source_binding_id'
        ):
            self._step37_safe_set_runtime_attr(self, attr_name, None, 'orchestrator.clear')
        for target_name in (
            'reply_planner', 'reply_style_engine', 'reply_self_check_engine', 'reply_delay_engine',
            'content_selector', 'proactive_followup_engine', 'understanding_engine',
            'ai_switch_engine'
        ):
            target = getattr(self, target_name, None)
            if target is None:
                continue
            self._step37_safe_set_runtime_attr(target, '_runtime_workspace_snapshot', None, f'orchestrator.clear.{target_name}')


_STEP36_BASE_BUILD_APP_COMPONENTS = build_app_components

def build_app_components(settings: Settings) -> dict[str, Any]:
    app_components = _STEP36_BASE_BUILD_APP_COMPONENTS(settings)
    workspace_repository = app_components.get('workspace_repository')
    workspace_binding_repository = _step37_upgrade_runtime_component(
        app_components,
        'workspace_binding_repository',
        WorkspaceBindingRepository,
        'WorkspaceBindingRepository',
    ) or app_components.get('workspace_binding_repository')

    _step37_upgrade_runtime_component(
        app_components,
        'admin_api_service',
        AdminAPIService,
        'AdminAPIService',
        inject_attrs={
            'workspace_repository': workspace_repository,
            'workspace_binding_repository': workspace_binding_repository,
        },
    )
    _step37_upgrade_runtime_component(
        app_components,
        'tg_admin_callback_router',
        TGAdminCallbackRouter,
        'TGAdminCallbackRouter',
        inject_attrs={
            'workspace_repository': workspace_repository,
            'workspace_binding_repository': workspace_binding_repository,
        },
    )
    _step37_upgrade_runtime_component(
        app_components,
        'tg_admin_handlers',
        TGAdminHandlers,
        'TGAdminHandlers',
        inject_attrs={
            'workspace_repository': workspace_repository,
            'workspace_binding_repository': workspace_binding_repository,
        },
    )
    _step37_upgrade_runtime_component(
        app_components,
        'orchestrator',
        Orchestrator,
        'Orchestrator',
        inject_attrs={
            'workspace_repository': workspace_repository,
            'workspace_binding_repository': workspace_binding_repository,
        },
    )

    app_components['stability_step37_enabled'] = True
    app_components['stability_step37_strict_rehydration_enabled'] = True
    return app_components




# =========================
# Step39 - precision hardening
# 1) secure media downloader for external URLs
# 2) admin operator-level authorization
# 3) final runtime component fresh-instance rehydration
# =========================

import ipaddress
import socket
from urllib.parse import urlsplit


_STEP39_BASE_SETTINGS = Settings


def _step39_parse_int_list(raw: str) -> list[int]:
    values: list[int] = []
    for item in str(raw or '').split(','):
        item = item.strip()
        if not item:
            continue
        try:
            values.append(int(item))
        except Exception:
            logger.warning('Step39 ignored invalid integer configuration item | raw=%r', item)
    return values


@dataclass
class Settings(_STEP39_BASE_SETTINGS):
    admin_user_ids: list[int] = field(default_factory=list)

    @classmethod
    def load(cls) -> 'Settings':
        base = _STEP39_BASE_SETTINGS.load()
        admin_user_ids = _step39_parse_int_list(os.getenv('ADMIN_USER_IDS', '').strip())
        return cls(**{**base.__dict__, 'admin_user_ids': admin_user_ids})

    def validate(self) -> None:
        super().validate()
        # ADMIN_USER_IDS is intentionally optional for backward compatibility.
        # When omitted, Step39 still enforces operator==chat_id for private admin chats
        # and rejects shared/group admin chats without explicit operator allow-list.
        admin_user_ids = getattr(self, 'admin_user_ids', None)
        if admin_user_ids is None:
            self.admin_user_ids = []


class _Step39NoRedirectHandler(urllib_request.HTTPRedirectHandler):
    def redirect_request(self, req, fp, code, msg, headers, newurl):
        raise HTTPError(req.full_url, code, 'redirect blocked', headers, fp)


def _step39_validate_public_media_url(url: str) -> tuple[bool, str | None]:
    normalized = str(url or '').strip()
    if not normalized:
        return False, 'empty_url'
    try:
        parts = urlsplit(normalized)
    except Exception:
        return False, 'invalid_url'
    scheme = (parts.scheme or '').lower()
    if scheme != 'https':
        return False, 'unsupported_scheme'
    if parts.username or parts.password:
        return False, 'embedded_credentials_forbidden'
    hostname = (parts.hostname or '').strip()
    if not hostname:
        return False, 'missing_host'
    if hostname.lower() == 'localhost':
        return False, 'private_host'
    port = parts.port or 443
    try:
        addr_info = socket.getaddrinfo(hostname, port, proto=socket.IPPROTO_TCP)
    except Exception:
        logger.exception('Step39 media URL DNS resolution failed | host=%s', hostname)
        return False, 'dns_resolution_failed'
    resolved_any = False
    for entry in addr_info:
        sockaddr = entry[4] if len(entry) >= 5 else None
        if not sockaddr:
            continue
        ip_text = str(sockaddr[0] or '').strip()
        if not ip_text:
            continue
        resolved_any = True
        try:
            ip_obj = ipaddress.ip_address(ip_text)
        except Exception:
            logger.warning('Step39 media URL returned unparsable IP address | host=%s | ip=%r', hostname, ip_text)
            return False, 'invalid_resolved_ip'
        if (
            ip_obj.is_private
            or ip_obj.is_loopback
            or ip_obj.is_link_local
            or ip_obj.is_multicast
            or ip_obj.is_reserved
            or ip_obj.is_unspecified
        ):
            logger.warning('Step39 blocked non-public media URL target | host=%s | ip=%s', hostname, ip_text)
            return False, 'non_public_address'
    if not resolved_any:
        return False, 'dns_resolution_failed'
    return True, None


def _step39_open_external_url(url: str, timeout_seconds: int):
    req = urllib_request.Request(
        url=str(url or '').strip(),
        headers={
            'User-Agent': 'TelegramBusinessAI/step39',
            'Accept': '*/*',
        },
        method='GET',
    )
    opener = urllib_request.build_opener(_Step39NoRedirectHandler())
    return opener.open(req, timeout=timeout_seconds)


def _step31_download_bytes_with_limit(url: str, max_bytes: int, timeout_seconds: int = 45) -> tuple[bytes | None, str | None]:
    normalized = str(url or '').strip()
    if not normalized:
        return None, 'empty_url'
    allowed, reason = _step39_validate_public_media_url(normalized)
    if not allowed:
        logger.warning('Step39 blocked external media download | url=%s | reason=%s', normalized, reason)
        return None, reason
    try:
        with _step39_open_external_url(normalized, timeout_seconds=timeout_seconds) as resp:
            try:
                header_len = int(str(resp.headers.get('Content-Length') or '0') or '0')
            except Exception:
                header_len = 0
            if header_len and header_len > max_bytes:
                return None, 'too_large'
            chunks: list[bytes] = []
            total = 0
            while True:
                remaining = max_bytes + 1 - total
                if remaining <= 0:
                    return None, 'too_large'
                chunk = resp.read(min(256 * 1024, remaining))
                if not chunk:
                    break
                chunks.append(chunk)
                total += len(chunk)
                if total > max_bytes:
                    return None, 'too_large'
            return b''.join(chunks), None
    except HTTPError as exc:
        if 300 <= int(getattr(exc, 'code', 0) or 0) < 400:
            return None, 'redirect_blocked'
        return None, f'http_error:{getattr(exc, "code", "unknown")}'
    except Exception as exc:
        logger.exception('Step39 external media download failed | url=%s', normalized)
        return None, str(exc)


def _step21_extract_video_frame_data_urls(video_url: str, max_frames: int = 3, timeout_seconds: int = 45) -> list[str]:
    url = str(video_url or '').strip()
    if not url:
        return []
    limits = _step31_media_limits()
    payload, error_code = _step31_download_bytes_with_limit(url, limits['video_max_bytes'], timeout_seconds=timeout_seconds)
    if not payload:
        logger.info('Step39 video frame extraction skipped | reason=%s', error_code or 'empty_payload')
        return []
    return _step31_extract_video_frame_data_urls_from_payload(payload, suffix=_step21_video_file_suffix(url), max_frames=max_frames, timeout_seconds=timeout_seconds)


def _step39_extract_admin_operator_id(raw_update: dict[str, Any], event: NormalizedInboundEvent | None = None) -> int | None:
    try:
        callback_user_id = (raw_update.get('callback_query') or {}).get('from', {}).get('id')
        if callback_user_id is not None:
            return int(callback_user_id)
    except Exception:
        logger.exception('Step39 failed to parse callback operator id')
    try:
        message_user_id = (raw_update.get('message') or {}).get('from', {}).get('id')
        if message_user_id is not None:
            return int(message_user_id)
    except Exception:
        logger.exception('Step39 failed to parse message operator id')
    try:
        if event and event.telegram_user_id is not None:
            return int(event.telegram_user_id)
    except Exception:
        logger.exception('Step39 failed to parse event operator id')
    return None


def _step39_extract_admin_chat_type(raw_update: dict[str, Any]) -> str | None:
    callback_message = (raw_update.get('callback_query') or {}).get('message') or {}
    callback_chat = callback_message.get('chat') or {}
    if callback_chat.get('type'):
        return str(callback_chat.get('type'))
    message_chat = (raw_update.get('message') or {}).get('chat') or {}
    if message_chat.get('type'):
        return str(message_chat.get('type'))
    return None


def _is_admin_operator_allowed(settings: Settings, admin_chat_id: int | None, operator_id: int | None,
                               raw_update: dict[str, Any] | None = None) -> tuple[bool, str | None]:
    if operator_id is None:
        return False, 'admin_operator_missing'
    configured_user_ids = list(getattr(settings, 'admin_user_ids', []) or [])
    if configured_user_ids:
        return (operator_id in configured_user_ids, None if operator_id in configured_user_ids else 'admin_operator_not_in_allowlist')
    chat_type = _step39_extract_admin_chat_type(raw_update or {})
    if chat_type == 'private' and admin_chat_id is not None and int(admin_chat_id) > 0:
        return (int(operator_id) == int(admin_chat_id), None if int(operator_id) == int(admin_chat_id) else 'private_chat_operator_mismatch')
    return False, 'admin_user_ids_required_for_shared_admin_chat'


_STEP39_BASE_CREATE_WEB_APP = create_web_app


def create_web_app(settings: Settings, app_components: dict[str, Any]) -> Flask:
    flask_app = Flask(__name__)
    admin_api_service = app_components['admin_api_service']
    dashboard_service = app_components['dashboard_service']
    gateway = app_components['gateway']
    tg_admin_handlers = app_components['tg_admin_handlers']
    tg_client = app_components['tg_client']
    event_lock_repo: WebhookEventLockRepository = app_components['event_lock_repo']
    business_account_repo: BusinessAccountRepository = app_components['business_account_repo']
    db: Database = app_components['db']

    flask_app.register_blueprint(build_admin_blueprint(admin_api_service, dashboard_service))

    @flask_app.teardown_appcontext
    def _close_request_db(_exc=None):
        try:
            db.close()
        except Exception:
            logger.exception('Failed to close request db connection.')

    @flask_app.get('/health')
    def health():
        return jsonify({'ok': True, 'service': 'tg-business-ai-chat'})

    @flask_app.post('/webhook/telegram')
    def telegram_webhook():
        raw_update = request.get_json(silent=True) or {}
        if settings.telegram_webhook_secret_token:
            header_token = request.headers.get('X-Telegram-Bot-Api-Secret-Token', '')
            if not hmac.compare_digest(header_token, settings.telegram_webhook_secret_token):
                return jsonify({'ok': False, 'error': 'invalid webhook secret'}), 403
        try:
            event = normalize_telegram_update(raw_update)
            if event and event.event_type in ('admin_callback', 'admin_text'):
                admin_chat_id = int(event.telegram_chat_id or 0)
                if not _is_admin_chat_allowed(settings, admin_chat_id):
                    return jsonify({'ok': False, 'error': 'admin not allowed'}), 403
                operator_id = _step39_extract_admin_operator_id(raw_update, event)
                operator_allowed, operator_reason = _is_admin_operator_allowed(settings, admin_chat_id, operator_id, raw_update)
                if not operator_allowed:
                    logger.warning(
                        'Step39 rejected admin operator | admin_chat_id=%s | operator_id=%s | reason=%s | admin_user_ids_configured=%s',
                        admin_chat_id,
                        operator_id,
                        operator_reason,
                        bool(getattr(settings, 'admin_user_ids', []) or []),
                    )
                    callback_id = (raw_update.get('callback_query') or {}).get('id')
                    if callback_id:
                        try:
                            tg_client.answer_callback_query(str(callback_id))
                        except Exception:
                            logger.exception('Step39 failed to answer rejected callback query | callback_id=%s', callback_id)
                    return jsonify({'ok': False, 'error': operator_reason or 'admin operator not allowed'}), 403
                operator = str(operator_id)
                event.idempotency_key = build_event_idempotency_key(event)
                account = business_account_repo.resolve_from_connection(event.business_connection_id)
                event.business_account_id = None if not account else int(account['id'])
                locked = event_lock_repo.acquire(
                    event.idempotency_key,
                    event.event_type,
                    event.business_account_id,
                    event.business_connection_id,
                    event.telegram_chat_id,
                    event.telegram_user_id,
                    event.telegram_message_id,
                    event.telegram_update_id,
                    event.is_edited,
                )
                if not locked:
                    event_lock_repo.record_duplicate_skip(event.idempotency_key)
                    if event.event_type == 'admin_callback' and raw_update.get('callback_query', {}).get('id'):
                        tg_client.answer_callback_query(str(raw_update['callback_query']['id']))
                    return jsonify({'ok': True, 'dispatched': 'duplicate'})
                try:
                    if event.event_type == 'admin_callback':
                        tg_admin_handlers.handle_admin_callback(admin_chat_id=admin_chat_id, callback_data=event.callback_data or '', operator=operator)
                        callback_id = (raw_update.get('callback_query') or {}).get('id')
                        if callback_id:
                            tg_client.answer_callback_query(str(callback_id))
                    else:
                        text = str(event.text or '')
                        if text.startswith('/admin') or text.startswith('/startadmin'):
                            tg_admin_handlers.handle_admin_command(admin_chat_id, text, operator=operator)
                            dispatched = 'admin_command'
                        else:
                            tg_admin_handlers.handle_admin_text(admin_chat_id, text, operator=operator)
                            dispatched = 'admin_text'
                        event_lock_repo.mark_processed(event.idempotency_key)
                        return jsonify({'ok': True, 'dispatched': dispatched})
                    event_lock_repo.mark_processed(event.idempotency_key)
                    return jsonify({'ok': True, 'dispatched': event.event_type})
                except Exception as admin_exc:
                    event_lock_repo.mark_failed(event.idempotency_key, str(admin_exc))
                    raise
            dispatched = gateway.handle_raw_update(raw_update)
            return jsonify({'ok': True, 'dispatched': dispatched})
        except Exception as e:
            try:
                db.rollback()
            except Exception:
                logger.exception('Step39 db rollback failed during telegram_webhook error handling')
            logger.exception('telegram_webhook failed')
            return jsonify({'ok': False, 'error': str(e)}), 500

    return flask_app


def _step39_fresh_runtime_component(app_components: dict[str, Any], key: str, cls: type, label: str,
                                    inject_attrs: dict[str, Any] | None = None) -> Any:
    target = app_components.get(key)
    if target is None:
        return None
    try:
        state = _step37_component_state(target)
        upgraded = cls.__new__(cls)
        new_state = getattr(upgraded, '__dict__', None)
        if new_state is None:
            raise TypeError(f'{cls.__name__} has no __dict__; cannot rehydrate safely')
        upgraded.__dict__.update(state)
        for attr_name, attr_value in (inject_attrs or {}).items():
            setattr(upgraded, attr_name, attr_value)
        app_components[key] = upgraded
        logger.info('Step39 rebuilt runtime component as fresh instance | key=%s | target_type=%s | cls=%s', key, type(target).__name__, cls.__name__)
        return upgraded
    except Exception:
        logger.exception('Step39 fresh-instance rehydration failed | key=%s | target_type=%s | desired_type=%s', key, type(target).__name__, cls.__name__)
        degraded = app_components.setdefault('stability_step39_degraded_components', [])
        degraded.append({
            'key': key,
            'target_type': type(target).__name__,
            'desired_type': cls.__name__,
        })
        return target


_STEP39_BASE_BUILD_APP_COMPONENTS = build_app_components


def build_app_components(settings: Settings) -> dict[str, Any]:
    app_components = _STEP39_BASE_BUILD_APP_COMPONENTS(settings)
    workspace_repository = app_components.get('workspace_repository')
    workspace_binding_repository = _step39_fresh_runtime_component(
        app_components,
        'workspace_binding_repository',
        WorkspaceBindingRepository,
        'WorkspaceBindingRepository',
    ) or app_components.get('workspace_binding_repository')

    _step39_fresh_runtime_component(
        app_components,
        'admin_api_service',
        AdminAPIService,
        'AdminAPIService',
        inject_attrs={
            'workspace_repository': workspace_repository,
            'workspace_binding_repository': workspace_binding_repository,
        },
    )
    _step39_fresh_runtime_component(
        app_components,
        'tg_admin_callback_router',
        TGAdminCallbackRouter,
        'TGAdminCallbackRouter',
        inject_attrs={
            'workspace_repository': workspace_repository,
            'workspace_binding_repository': workspace_binding_repository,
        },
    )
    _step39_fresh_runtime_component(
        app_components,
        'tg_admin_handlers',
        TGAdminHandlers,
        'TGAdminHandlers',
        inject_attrs={
            'workspace_repository': workspace_repository,
            'workspace_binding_repository': workspace_binding_repository,
        },
    )
    _step39_fresh_runtime_component(
        app_components,
        'orchestrator',
        Orchestrator,
        'Orchestrator',
        inject_attrs={
            'workspace_repository': workspace_repository,
            'workspace_binding_repository': workspace_binding_repository,
        },
    )

    app_components['stability_step39_enabled'] = True
    app_components['stability_step39_secure_media_enabled'] = True
    app_components['stability_step39_admin_operator_auth_enabled'] = True
    app_components['stability_step39_fresh_instances_enabled'] = True
    return app_components



# =========================
# Step40 - webhook error sanitization / secure image handling / resolved-IP media download /
#          deeper fresh-instance convergence for runtime components
# =========================

import base64
import http.client
import mimetypes
import ssl
from urllib.parse import urlunsplit


def _mask_url(url: str | None) -> str:
    normalized = str(url or '').strip()
    if not normalized:
        return ''
    if normalized.startswith('data:'):
        prefix = normalized.split(',', 1)[0][:48]
        return prefix + ',...'
    try:
        parts = urlsplit(normalized)
    except Exception:
        return normalized[:96]
    host = parts.hostname or ''
    scheme = parts.scheme or ''
    path = parts.path or ''
    if len(path) > 48:
        path = path[:20] + '...' + path[-20:]
    masked = urlunsplit((scheme, host, path, '', ''))
    return masked[:128]


def _step40_is_public_ip_text(ip_text: str) -> bool:
    try:
        ip_obj = ipaddress.ip_address(str(ip_text or '').strip())
    except Exception:
        return False
    return not (
        ip_obj.is_private
        or ip_obj.is_loopback
        or ip_obj.is_link_local
        or ip_obj.is_multicast
        or ip_obj.is_reserved
        or ip_obj.is_unspecified
    )


def _step40_resolve_public_ip(hostname: str, port: int) -> tuple[str | None, str | None]:
    normalized_host = str(hostname or '').strip()
    if not normalized_host:
        return None, 'missing_host'
    try:
        addr_info = socket.getaddrinfo(normalized_host, int(port), type=socket.SOCK_STREAM, proto=socket.IPPROTO_TCP)
    except Exception:
        logger.exception('Step40 media URL DNS resolution failed | host=%s', normalized_host)
        return None, 'dns_resolution_failed'
    public_ips: list[str] = []
    for entry in addr_info:
        sockaddr = entry[4] if len(entry) >= 5 else None
        if not sockaddr:
            continue
        ip_text = str(sockaddr[0] or '').strip()
        if not ip_text:
            continue
        if _step40_is_public_ip_text(ip_text):
            public_ips.append(ip_text)
        else:
            logger.warning('Step40 blocked non-public resolved media address | host=%s | ip=%s', normalized_host, ip_text)
    if not public_ips:
        return None, 'non_public_address'
    return public_ips[0], None


class _Step40ResolvedHTTPSConnection(http.client.HTTPSConnection):
    def __init__(self, hostname: str, resolved_ip: str, port: int, timeout: int, context: ssl.SSLContext | None = None):
        super().__init__(host=hostname, port=port, timeout=timeout, context=context)
        self._resolved_ip = str(resolved_ip or '').strip()

    def connect(self):
        conn = self._create_connection((self._resolved_ip, self.port), self.timeout, self.source_address)
        if self._tunnel_host:
            self.sock = conn
            self._tunnel()
            server_hostname = self._tunnel_host
        else:
            server_hostname = self.host
        self.sock = self._context.wrap_socket(conn, server_hostname=server_hostname)


def _step40_download_external_media_payload(url: str, max_bytes: int, timeout_seconds: int = 45) -> tuple[bytes | None, str | None, str | None]:
    normalized = str(url or '').strip()
    if not normalized:
        return None, 'empty_url', None
    allowed, reason = _step39_validate_public_media_url(normalized)
    if not allowed:
        logger.warning('Step40 blocked external media download during validation | url=%s | reason=%s', _mask_url(normalized), reason)
        return None, reason, None
    try:
        parts = urlsplit(normalized)
    except Exception:
        return None, 'invalid_url', None
    hostname = str(parts.hostname or '').strip()
    if not hostname:
        return None, 'missing_host', None
    port = parts.port or 443
    resolved_ip, resolve_reason = _step40_resolve_public_ip(hostname, port)
    if not resolved_ip:
        return None, resolve_reason or 'dns_resolution_failed', None
    path = parts.path or '/'
    if parts.query:
        path = f'{path}?{parts.query}'
    host_header = hostname if port == 443 else f'{hostname}:{port}'
    conn = None
    response = None
    try:
        context = ssl.create_default_context()
        conn = _Step40ResolvedHTTPSConnection(hostname=hostname, resolved_ip=resolved_ip, port=port, timeout=timeout_seconds, context=context)
        conn.request(
            'GET',
            path,
            headers={
                'Host': host_header,
                'User-Agent': 'TelegramBusinessAI/step40',
                'Accept': '*/*',
                'Connection': 'close',
            },
        )
        response = conn.getresponse()
        content_type = str(response.getheader('Content-Type') or '').split(';', 1)[0].strip().lower() or None
        status_code = int(getattr(response, 'status', 0) or 0)
        if 300 <= status_code < 400:
            return None, 'redirect_blocked', content_type
        if status_code >= 400:
            return None, f'http_error:{status_code}', content_type
        try:
            header_len = int(str(response.getheader('Content-Length') or '0') or '0')
        except Exception:
            header_len = 0
        if header_len and header_len > max_bytes:
            return None, 'too_large', content_type
        chunks: list[bytes] = []
        total = 0
        while True:
            remaining = max_bytes + 1 - total
            if remaining <= 0:
                return None, 'too_large', content_type
            chunk = response.read(min(256 * 1024, remaining))
            if not chunk:
                break
            chunks.append(chunk)
            total += len(chunk)
            if total > max_bytes:
                return None, 'too_large', content_type
        return b''.join(chunks), None, content_type
    except ssl.SSLError:
        logger.exception('Step40 TLS validation failed during media download | url=%s | resolved_ip=%s', _mask_url(normalized), resolved_ip)
        return None, 'tls_validation_failed', None
    except Exception:
        logger.exception('Step40 external media download failed | url=%s | resolved_ip=%s', _mask_url(normalized), resolved_ip)
        return None, 'download_failed', None
    finally:
        try:
            if response is not None:
                response.close()
        except Exception:
            logger.exception('Step40 failed to close HTTP response cleanly | url=%s', _mask_url(normalized))
        try:
            if conn is not None:
                conn.close()
        except Exception:
            logger.exception('Step40 failed to close HTTP connection cleanly | url=%s', _mask_url(normalized))


def _step31_download_bytes_with_limit(url: str, max_bytes: int, timeout_seconds: int = 45) -> tuple[bytes | None, str | None]:
    payload, error_code, _content_type = _step40_download_external_media_payload(url, max_bytes=max_bytes, timeout_seconds=timeout_seconds)
    return payload, error_code


def _step40_guess_image_mime(image_url: str, content_type: str | None, payload: bytes | None) -> str | None:
    normalized_type = str(content_type or '').split(';', 1)[0].strip().lower()
    allowed_types = {'image/jpeg', 'image/png', 'image/webp', 'image/gif'}
    if normalized_type in allowed_types:
        return normalized_type
    guessed, _ = mimetypes.guess_type(str(image_url or '').split('?', 1)[0])
    guessed = str(guessed or '').strip().lower()
    if guessed in allowed_types:
        return guessed
    blob = payload or b''
    if blob.startswith(b'\xff\xd8\xff'):
        return 'image/jpeg'
    if blob.startswith(b'\x89PNG\r\n\x1a\n'):
        return 'image/png'
    if blob[:4] == b'RIFF' and b'WEBP' in blob[:16]:
        return 'image/webp'
    if blob.startswith((b'GIF87a', b'GIF89a')):
        return 'image/gif'
    return None


def _step40_image_url_to_data_url(image_url: str, timeout_seconds: int = 45) -> tuple[str | None, str | None]:
    url = str(image_url or '').strip()
    if not url:
        return None, 'empty_url'
    if url.startswith('data:image/'):
        return url, None
    limits = _step31_media_limits()
    payload, error_code, content_type = _step40_download_external_media_payload(url, limits['image_max_bytes'], timeout_seconds=timeout_seconds)
    if not payload:
        return None, error_code or 'download_failed'
    mime = _step40_guess_image_mime(url, content_type, payload)
    if not mime:
        logger.warning('Step40 blocked non-image payload for image description | url=%s | content_type=%s', _mask_url(url), content_type)
        return None, 'unsupported_image_type'
    data_url = f'data:{mime};base64,' + base64.b64encode(payload).decode('ascii')
    return data_url, None


_STEP40_BASE_OPENAI_CLIENT_ADAPTER = OpenAIClientAdapter
class OpenAIClientAdapter(_STEP40_BASE_OPENAI_CLIENT_ADAPTER):
    def describe_image_from_url(self, image_url: str, instruction: str = '', model: str = 'gpt-4.1-mini') -> str:
        url = str(image_url or '').strip()
        if not url:
            logger.info('Step40 image description skipped | reason=empty_url')
            return ''
        safe_image_ref = url
        if not url.startswith('data:image/'):
            safe_image_ref, reason = _step40_image_url_to_data_url(url)
            if not safe_image_ref:
                logger.warning('Step40 image description blocked or downgraded | url=%s | reason=%s', _mask_url(url), reason)
                return ''
        try:
            return super().describe_image_from_url(safe_image_ref, instruction=instruction, model=model)
        except Exception:
            logger.exception('Step40 image description failed after safe image conversion | model=%s | url=%s', model, _mask_url(url))
            return ''


_STEP40_BASE_CREATE_WEB_APP = create_web_app

def create_web_app(settings: Settings, app_components: dict[str, Any]) -> Flask:
    flask_app = Flask(__name__)
    admin_api_service = app_components['admin_api_service']
    dashboard_service = app_components['dashboard_service']
    gateway = app_components['gateway']
    tg_admin_handlers = app_components['tg_admin_handlers']
    tg_client = app_components['tg_client']
    event_lock_repo: WebhookEventLockRepository = app_components['event_lock_repo']
    business_account_repo: BusinessAccountRepository = app_components['business_account_repo']
    db: Database = app_components['db']

    flask_app.register_blueprint(build_admin_blueprint(admin_api_service, dashboard_service))

    @flask_app.teardown_appcontext
    def _close_request_db(_exc=None):
        try:
            db.close()
        except Exception:
            logger.exception('Failed to close request db connection.')

    @flask_app.get('/health')
    def health():
        return jsonify({'ok': True, 'service': 'tg-business-ai-chat'})

    @flask_app.post('/webhook/telegram')
    def telegram_webhook():
        raw_update = request.get_json(silent=True) or {}
        update_id = raw_update.get('update_id')
        if settings.telegram_webhook_secret_token:
            header_token = request.headers.get('X-Telegram-Bot-Api-Secret-Token', '')
            if not hmac.compare_digest(header_token, settings.telegram_webhook_secret_token):
                return jsonify({'ok': False, 'error': 'invalid webhook secret'}), 403
        try:
            event = normalize_telegram_update(raw_update)
            if event and event.event_type in ('admin_callback', 'admin_text'):
                admin_chat_id = int(event.telegram_chat_id or 0)
                if not _is_admin_chat_allowed(settings, admin_chat_id):
                    return jsonify({'ok': False, 'error': 'admin not allowed'}), 403
                operator_id = _step39_extract_admin_operator_id(raw_update, event)
                operator_allowed, operator_reason = _is_admin_operator_allowed(settings, admin_chat_id, operator_id, raw_update)
                if not operator_allowed:
                    logger.warning(
                        'Step40 rejected admin operator | admin_chat_id=%s | operator_id=%s | reason=%s | admin_user_ids_configured=%s',
                        admin_chat_id,
                        operator_id,
                        operator_reason,
                        bool(getattr(settings, 'admin_user_ids', []) or []),
                    )
                    callback_id = (raw_update.get('callback_query') or {}).get('id')
                    if callback_id:
                        try:
                            tg_client.answer_callback_query(str(callback_id))
                        except Exception:
                            logger.exception('Step40 failed to answer rejected callback query | callback_id=%s', callback_id)
                    return jsonify({'ok': False, 'error': operator_reason or 'admin operator not allowed'}), 403
                operator = str(operator_id)
                event.idempotency_key = build_event_idempotency_key(event)
                account = business_account_repo.resolve_from_connection(event.business_connection_id)
                event.business_account_id = None if not account else int(account['id'])
                locked = event_lock_repo.acquire(
                    event.idempotency_key,
                    event.event_type,
                    event.business_account_id,
                    event.business_connection_id,
                    event.telegram_chat_id,
                    event.telegram_user_id,
                    event.telegram_message_id,
                    event.telegram_update_id,
                    event.is_edited,
                )
                if not locked:
                    event_lock_repo.record_duplicate_skip(event.idempotency_key)
                    if event.event_type == 'admin_callback' and raw_update.get('callback_query', {}).get('id'):
                        tg_client.answer_callback_query(str(raw_update['callback_query']['id']))
                    return jsonify({'ok': True, 'dispatched': 'duplicate'})
                try:
                    if event.event_type == 'admin_callback':
                        tg_admin_handlers.handle_admin_callback(admin_chat_id=admin_chat_id, callback_data=event.callback_data or '', operator=operator)
                        callback_id = (raw_update.get('callback_query') or {}).get('id')
                        if callback_id:
                            tg_client.answer_callback_query(str(callback_id))
                        dispatched = event.event_type
                    else:
                        text = str(event.text or '')
                        if text.startswith('/admin') or text.startswith('/startadmin'):
                            tg_admin_handlers.handle_admin_command(admin_chat_id, text, operator=operator)
                            dispatched = 'admin_command'
                        else:
                            tg_admin_handlers.handle_admin_text(admin_chat_id, text, operator=operator)
                            dispatched = 'admin_text'
                    event_lock_repo.mark_processed(event.idempotency_key)
                    return jsonify({'ok': True, 'dispatched': dispatched})
                except Exception as admin_exc:
                    event_lock_repo.mark_failed(event.idempotency_key, str(admin_exc))
                    raise
            dispatched = gateway.handle_raw_update(raw_update)
            return jsonify({'ok': True, 'dispatched': dispatched})
        except Exception:
            try:
                db.rollback()
            except Exception:
                logger.exception('Step40 db rollback failed during telegram_webhook error handling | update_id=%s', update_id)
            logger.exception('telegram_webhook failed | update_id=%s', update_id)
            return jsonify({'ok': False, 'error': 'internal_server_error'}), 500

    return flask_app


def _step40_fresh_nested_component(owner: Any, attr_name: str, cls: type, inject_attrs: dict[str, Any] | None = None) -> Any:
    target = getattr(owner, attr_name, None)
    if target is None:
        return None
    try:
        state = _step37_component_state(target)
        upgraded = cls.__new__(cls)
        upgraded.__dict__.update(state)
        for key, value in (inject_attrs or {}).items():
            setattr(upgraded, key, value)
        setattr(owner, attr_name, upgraded)
        logger.info('Step40 rebuilt nested runtime component | owner_type=%s | attr=%s | from=%s | to=%s', type(owner).__name__, attr_name, type(target).__name__, cls.__name__)
        return upgraded
    except Exception:
        logger.exception('Step40 failed to rebuild nested runtime component | owner_type=%s | attr=%s | from=%s | to=%s', type(owner).__name__, attr_name, type(target).__name__, cls.__name__)
        return target


_STEP40_BASE_BUILD_APP_COMPONENTS = build_app_components

def build_app_components(settings: Settings) -> dict[str, Any]:
    app_components = _STEP40_BASE_BUILD_APP_COMPONENTS(settings)

    llm_service = app_components.get('llm_service')
    if llm_service is not None:
        _step40_fresh_nested_component(llm_service, 'client_adapter', OpenAIClientAdapter)

    media_understanding_service = app_components.get('media_understanding_service')
    if media_understanding_service is not None:
        _step39_fresh_runtime_component(
            app_components,
            'media_understanding_service',
            MediaUnderstandingService,
            'MediaUnderstandingService',
            inject_attrs={
                'tg_client': app_components.get('tg_client'),
                'llm_service': llm_service,
            },
        )

    orchestrator = app_components.get('orchestrator')
    if orchestrator is not None:
        nested_specs = [
            ('understanding_engine', UserUnderstandingEngine),
            ('stage_engine', RelationshipStageEngine),
            ('reply_planner', ReplyPlanner),
            ('reply_style_engine', ReplyStyleEngine),
            ('reply_self_check_engine', ReplySelfCheckEngine),
            ('reply_delay_engine', ReplyDelayEngine),
            ('proactive_followup_engine', ProactiveFollowupEngine),
            ('content_selector', ContentSelector),
            ('ai_switch_engine', AISwitchEngine),
        ]
        for attr_name, cls in nested_specs:
            if hasattr(orchestrator, attr_name):
                _step40_fresh_nested_component(orchestrator, attr_name, cls)

    app_components['stability_step40_enabled'] = True
    app_components['stability_step40_webhook_error_sanitized'] = True
    app_components['stability_step40_secure_image_input_enabled'] = True
    app_components['stability_step40_resolved_ip_media_download_enabled'] = True
    app_components['stability_step40_nested_fresh_instances_enabled'] = True
    return app_components


# =========================
# Step41 (from step40 baseline) - request-local workspace runtime / reference rewiring / safer app factory
# Focused hardening only: do not change the database connection model.
# =========================
import contextvars

_STEP41_WORKSPACE_RUNTIME_STACK: contextvars.ContextVar[tuple[dict[str, Any], ...]] = contextvars.ContextVar(
    'step41_workspace_runtime_stack', default=()
)

_STEP41_RUNTIME_ATTRS = {
    '_runtime_workspace_snapshot',
    '_runtime_workspace_id',
    '_runtime_source_business_account_id',
    '_runtime_effective_business_account_id',
    '_runtime_source_binding_id',
}


def _step41_current_workspace_snapshot() -> dict[str, Any]:
    stack = _STEP41_WORKSPACE_RUNTIME_STACK.get(())
    if not stack:
        return {}
    current = stack[-1] or {}
    if isinstance(current, dict):
        return dict(current)
    try:
        return dict(current)
    except Exception:
        logger.exception('Step41 workspace runtime snapshot conversion failed | snapshot_type=%s', type(current).__name__)
        return {}


def _step41_runtime_attr_value(attr_name: str):
    snapshot = _step41_current_workspace_snapshot()
    if not snapshot:
        return None
    if attr_name == '_runtime_workspace_snapshot':
        return WorkspaceRuntimeSnapshot(snapshot)
    mapping = {
        '_runtime_workspace_id': snapshot.get('workspace_id'),
        '_runtime_source_business_account_id': snapshot.get('source_business_account_id'),
        '_runtime_effective_business_account_id': snapshot.get('effective_business_account_id'),
        '_runtime_source_binding_id': snapshot.get('source_binding_id'),
    }
    return mapping.get(attr_name)


def _workspace_runtime_snapshot_of(owner: Any) -> dict[str, Any]:
    snapshot = _step41_current_workspace_snapshot()
    if snapshot:
        return snapshot
    snap = getattr(owner, '_runtime_workspace_snapshot', None)
    if snap is None:
        return {}
    if isinstance(snap, dict):
        return dict(snap)
    try:
        return dict(snap)
    except Exception:
        logger.exception('Step41 workspace runtime snapshot fallback conversion failed | owner_type=%s', type(owner).__name__)
        return {}


_STEP41_BASE_AISWITCH_ENGINE = AISwitchEngine
class AISwitchEngine(_STEP41_BASE_AISWITCH_ENGINE):
    def __getattribute__(self, name: str):
        if name in _STEP41_RUNTIME_ATTRS:
            return _step41_runtime_attr_value(name)
        return super().__getattribute__(name)


_STEP41_BASE_PROACTIVE_FOLLOWUP_ENGINE = ProactiveFollowupEngine
class ProactiveFollowupEngine(_STEP41_BASE_PROACTIVE_FOLLOWUP_ENGINE):
    def __getattribute__(self, name: str):
        if name in _STEP41_RUNTIME_ATTRS:
            return _step41_runtime_attr_value(name)
        return super().__getattribute__(name)


_STEP41_BASE_ORCHESTRATOR = Orchestrator
class Orchestrator(_STEP41_BASE_ORCHESTRATOR):
    def __getattribute__(self, name: str):
        if name in _STEP41_RUNTIME_ATTRS:
            return _step41_runtime_attr_value(name)
        return super().__getattribute__(name)

    def _set_workspace_runtime_context(self, snapshot: WorkspaceRuntimeSnapshot | None) -> None:
        current_stack = _STEP41_WORKSPACE_RUNTIME_STACK.get(())
        normalized = dict(snapshot or {})
        _STEP41_WORKSPACE_RUNTIME_STACK.set(tuple(current_stack) + (normalized,))

    def _clear_workspace_runtime_context(self) -> None:
        current_stack = _STEP41_WORKSPACE_RUNTIME_STACK.get(())
        if not current_stack:
            return
        _STEP41_WORKSPACE_RUNTIME_STACK.set(tuple(current_stack[:-1]))

    @contextmanager
    def _workspace_shared_scope(self, snapshot: WorkspaceRuntimeSnapshot):
        # Step40 baseline already has repository/service-level workspace resolution.
        # Avoid mutating shared repository methods at runtime because it is unsafe under concurrent requests.
        yield


def _step41_rehydrate_instance(target: Any, cls: type, inject_attrs: dict[str, Any] | None = None, label: str = '') -> Any:
    if target is None:
        return None
    try:
        state = _step37_component_state(target)
        upgraded = cls.__new__(cls)
        upgraded.__dict__.update(state)
        for attr_name, attr_value in (inject_attrs or {}).items():
            setattr(upgraded, attr_name, attr_value)
        if label:
            logger.info('Step41 rehydrated runtime instance | label=%s | from=%s | to=%s', label, type(target).__name__, cls.__name__)
        return upgraded
    except Exception:
        logger.exception('Step41 failed to rehydrate runtime instance | label=%s | from=%s | to=%s', label or type(target).__name__, type(target).__name__, cls.__name__)
        raise


def _step41_rewire_runtime_graph(app_components: dict[str, Any]) -> None:
    workspace_repository = app_components.get('workspace_repository')
    workspace_binding_repository = app_components.get('workspace_binding_repository')
    business_account_repo = app_components.get('business_account_repo')
    event_lock_repo = app_components.get('event_lock_repo')
    edit_repo = app_components.get('business_message_edit_repo')
    admin_session_repo = app_components.get('admin_session_repo')
    admin_api_service = app_components.get('admin_api_service')
    dashboard_service = app_components.get('dashboard_service')
    tg_client = app_components.get('tg_client')
    media_understanding_service = app_components.get('media_understanding_service')

    orchestrator = app_components.get('orchestrator')
    if orchestrator is not None:
        orchestrator.workspace_repository = workspace_repository
        orchestrator.workspace_binding_repository = workspace_binding_repository
        if media_understanding_service is not None:
            orchestrator.media_understanding_service = media_understanding_service

        if getattr(orchestrator, 'ai_switch_engine', None) is not None and not isinstance(orchestrator.ai_switch_engine, AISwitchEngine):
            orchestrator.ai_switch_engine = _step41_rehydrate_instance(
                orchestrator.ai_switch_engine,
                AISwitchEngine,
                label='orchestrator.ai_switch_engine',
            )
        if getattr(orchestrator, 'proactive_followup_engine', None) is not None and not isinstance(orchestrator.proactive_followup_engine, ProactiveFollowupEngine):
            orchestrator.proactive_followup_engine = _step41_rehydrate_instance(
                orchestrator.proactive_followup_engine,
                ProactiveFollowupEngine,
                label='orchestrator.proactive_followup_engine',
            )

    gateway = app_components.get('gateway')
    if gateway is not None:
        gateway.business_account_repo = business_account_repo
        gateway.event_lock_repo = event_lock_repo
        gateway.edit_repo = edit_repo
        if orchestrator is not None:
            gateway.message_handler = orchestrator.handle_inbound_message

    router = app_components.get('tg_admin_callback_router')
    if router is not None:
        router.admin_api_service = admin_api_service
        router.dashboard_service = dashboard_service
        router.tg_sender = tg_client
        router.business_account_repo = business_account_repo
        router.admin_session_repo = admin_session_repo
        if workspace_repository is not None:
            router.workspace_repository = workspace_repository
        if workspace_binding_repository is not None:
            router.workspace_binding_repository = workspace_binding_repository

    handlers = app_components.get('tg_admin_handlers')
    if handlers is not None:
        handlers.tg_admin_callback_router = router
        handlers.tg_sender = tg_client
        handlers.admin_session_repo = admin_session_repo
        handlers.business_account_repo = business_account_repo
        handlers.admin_api_service = admin_api_service
        if workspace_repository is not None:
            handlers.workspace_repository = workspace_repository
        if workspace_binding_repository is not None:
            handlers.workspace_binding_repository = workspace_binding_repository

    if admin_api_service is not None:
        if workspace_repository is not None:
            admin_api_service.workspace_repository = workspace_repository
        if workspace_binding_repository is not None:
            admin_api_service.workspace_binding_repository = workspace_binding_repository
        if business_account_repo is not None:
            admin_api_service.business_account_repo = business_account_repo


def _step41_runtime_graph_issues(app_components: dict[str, Any]) -> list[str]:
    issues: list[str] = []
    orchestrator = app_components.get('orchestrator')
    gateway = app_components.get('gateway')
    router = app_components.get('tg_admin_callback_router')
    handlers = app_components.get('tg_admin_handlers')
    admin_api_service = app_components.get('admin_api_service')
    business_account_repo = app_components.get('business_account_repo')
    event_lock_repo = app_components.get('event_lock_repo')
    edit_repo = app_components.get('business_message_edit_repo')
    admin_session_repo = app_components.get('admin_session_repo')
    media_understanding_service = app_components.get('media_understanding_service')

    if orchestrator is None or not isinstance(orchestrator, Orchestrator):
        issues.append('orchestrator is missing or not upgraded to final class')
    if gateway is not None:
        handler = getattr(gateway, 'message_handler', None)
        if orchestrator is not None:
            if getattr(handler, '__self__', None) is not orchestrator:
                issues.append('gateway.message_handler is not bound to current orchestrator')
        if getattr(gateway, 'business_account_repo', None) is not business_account_repo:
            issues.append('gateway.business_account_repo is stale')
        if getattr(gateway, 'event_lock_repo', None) is not event_lock_repo:
            issues.append('gateway.event_lock_repo is stale')
        if getattr(gateway, 'edit_repo', None) is not edit_repo:
            issues.append('gateway.edit_repo is stale')
    if orchestrator is not None:
        if getattr(orchestrator, 'media_understanding_service', None) is not media_understanding_service:
            issues.append('orchestrator.media_understanding_service is stale')
        if getattr(orchestrator, 'workspace_binding_repository', None) is not app_components.get('workspace_binding_repository'):
            issues.append('orchestrator.workspace_binding_repository is stale')
        if getattr(orchestrator, 'ai_switch_engine', None) is not None and not isinstance(orchestrator.ai_switch_engine, AISwitchEngine):
            issues.append('orchestrator.ai_switch_engine is not upgraded')
        if getattr(orchestrator, 'proactive_followup_engine', None) is not None and not isinstance(orchestrator.proactive_followup_engine, ProactiveFollowupEngine):
            issues.append('orchestrator.proactive_followup_engine is not upgraded')
    if router is not None:
        if getattr(router, 'admin_api_service', None) is not admin_api_service:
            issues.append('tg_admin_callback_router.admin_api_service is stale')
        if getattr(router, 'business_account_repo', None) is not business_account_repo:
            issues.append('tg_admin_callback_router.business_account_repo is stale')
        if getattr(router, 'admin_session_repo', None) is not admin_session_repo:
            issues.append('tg_admin_callback_router.admin_session_repo is stale')
    if handlers is not None:
        if getattr(handlers, 'tg_admin_callback_router', None) is not router:
            issues.append('tg_admin_handlers.tg_admin_callback_router is stale')
        if getattr(handlers, 'admin_api_service', None) is not admin_api_service:
            issues.append('tg_admin_handlers.admin_api_service is stale')
        if getattr(handlers, 'business_account_repo', None) is not business_account_repo:
            issues.append('tg_admin_handlers.business_account_repo is stale')
        if getattr(handlers, 'admin_session_repo', None) is not admin_session_repo:
            issues.append('tg_admin_handlers.admin_session_repo is stale')
    return issues


_STEP41_BASE_BUILD_APP_COMPONENTS = build_app_components

def build_app_components(settings: Settings) -> dict[str, Any]:
    app_components = _STEP41_BASE_BUILD_APP_COMPONENTS(settings)

    workspace_repository = app_components.get('workspace_repository')
    workspace_binding_repository = app_components.get('workspace_binding_repository')
    media_understanding_service = app_components.get('media_understanding_service')

    orchestrator = app_components.get('orchestrator')
    if orchestrator is not None and not isinstance(orchestrator, Orchestrator):
        app_components['orchestrator'] = _step41_rehydrate_instance(
            orchestrator,
            Orchestrator,
            inject_attrs={
                'workspace_repository': workspace_repository,
                'workspace_binding_repository': workspace_binding_repository,
                'media_understanding_service': media_understanding_service,
            },
            label='orchestrator',
        )

    _step41_rewire_runtime_graph(app_components)

    issues = _step41_runtime_graph_issues(app_components)
    if issues:
        raise RuntimeError('Step41 runtime graph validation failed: ' + '; '.join(issues))

    app_components['stability_step41_enabled'] = True
    app_components['stability_step41_request_local_workspace_runtime'] = True
    app_components['stability_step41_runtime_graph_rewired'] = True
    app_components['stability_step41_runtime_graph_validated'] = True
    return app_components


_STEP41_BASE_CREATE_WEB_APP = create_web_app

def create_web_app(settings: Settings, app_components: dict[str, Any]) -> Flask:
    flask_app = Flask(__name__)
    admin_api_service = app_components['admin_api_service']
    dashboard_service = app_components['dashboard_service']
    gateway = app_components['gateway']
    tg_admin_handlers = app_components['tg_admin_handlers']
    tg_client = app_components['tg_client']
    event_lock_repo: WebhookEventLockRepository = app_components['event_lock_repo']
    business_account_repo: BusinessAccountRepository = app_components['business_account_repo']
    db: Database = app_components['db']

    flask_app.register_blueprint(build_admin_blueprint(admin_api_service, dashboard_service))

    @flask_app.before_request
    def _ensure_request_db_connection():
        try:
            db.connect()
        except Exception:
            logger.exception('Step41 failed to ensure database connection before request.')
            raise

    @flask_app.get('/health')
    def health():
        return jsonify({'ok': True, 'service': 'tg-business-ai-chat'})

    @flask_app.post('/webhook/telegram')
    def telegram_webhook():
        raw_update = request.get_json(silent=True) or {}
        update_id = raw_update.get('update_id')
        if settings.telegram_webhook_secret_token:
            header_token = request.headers.get('X-Telegram-Bot-Api-Secret-Token', '')
            if not hmac.compare_digest(header_token, settings.telegram_webhook_secret_token):
                return jsonify({'ok': False, 'error': 'invalid webhook secret'}), 403
        try:
            event = normalize_telegram_update(raw_update)
            if event and event.event_type in ('admin_callback', 'admin_text'):
                admin_chat_id = int(event.telegram_chat_id or 0)
                if not _is_admin_chat_allowed(settings, admin_chat_id):
                    return jsonify({'ok': False, 'error': 'admin not allowed'}), 403
                operator_id = _step39_extract_admin_operator_id(raw_update, event)
                operator_allowed, operator_reason = _is_admin_operator_allowed(settings, admin_chat_id, operator_id, raw_update)
                if not operator_allowed:
                    logger.warning(
                        'Step41 rejected admin operator | admin_chat_id=%s | operator_id=%s | reason=%s | admin_user_ids_configured=%s',
                        admin_chat_id,
                        operator_id,
                        operator_reason,
                        bool(getattr(settings, 'admin_user_ids', []) or []),
                    )
                    callback_id = (raw_update.get('callback_query') or {}).get('id')
                    if callback_id:
                        try:
                            tg_client.answer_callback_query(str(callback_id))
                        except Exception:
                            logger.exception('Step41 failed to answer rejected callback query | callback_id=%s', callback_id)
                    return jsonify({'ok': False, 'error': operator_reason or 'admin operator not allowed'}), 403
                operator = str(operator_id)
                event.idempotency_key = build_event_idempotency_key(event)
                account = business_account_repo.resolve_from_connection(event.business_connection_id)
                event.business_account_id = None if not account else int(account['id'])
                locked = event_lock_repo.acquire(
                    event.idempotency_key,
                    event.event_type,
                    event.business_account_id,
                    event.business_connection_id,
                    event.telegram_chat_id,
                    event.telegram_user_id,
                    event.telegram_message_id,
                    event.telegram_update_id,
                    event.is_edited,
                )
                if not locked:
                    event_lock_repo.record_duplicate_skip(event.idempotency_key)
                    if event.event_type == 'admin_callback' and raw_update.get('callback_query', {}).get('id'):
                        tg_client.answer_callback_query(str(raw_update['callback_query']['id']))
                    return jsonify({'ok': True, 'dispatched': 'duplicate'})
                try:
                    if event.event_type == 'admin_callback':
                        tg_admin_handlers.handle_admin_callback(admin_chat_id=admin_chat_id, callback_data=event.callback_data or '', operator=operator)
                        callback_id = (raw_update.get('callback_query') or {}).get('id')
                        if callback_id:
                            tg_client.answer_callback_query(str(callback_id))
                        dispatched = event.event_type
                    else:
                        text = str(event.text or '')
                        if text.startswith('/admin') or text.startswith('/startadmin'):
                            tg_admin_handlers.handle_admin_command(admin_chat_id, text, operator=operator)
                            dispatched = 'admin_command'
                        else:
                            tg_admin_handlers.handle_admin_text(admin_chat_id, text, operator=operator)
                            dispatched = 'admin_text'
                    event_lock_repo.mark_processed(event.idempotency_key)
                    return jsonify({'ok': True, 'dispatched': dispatched})
                except Exception as admin_exc:
                    event_lock_repo.mark_failed(event.idempotency_key, str(admin_exc))
                    raise
            dispatched = gateway.handle_raw_update(raw_update)
            return jsonify({'ok': True, 'dispatched': dispatched})
        except Exception:
            try:
                db.rollback()
            except Exception:
                logger.exception('Step41 db rollback failed during telegram_webhook error handling | update_id=%s', update_id)
            logger.exception('telegram_webhook failed | update_id=%s', update_id)
            return jsonify({'ok': False, 'error': 'internal_server_error'}), 500

    return flask_app


# =========================
# Step42 - medium/low risk cleanup only
# 1) stop persisting workspace runtime metadata into inbound raw_payload
# 2) sanitize admin-side internal exception texts returned in reason fields
# =========================
import re

_STEP42_BASE_ORCHESTRATOR = Orchestrator
class Orchestrator(_STEP42_BASE_ORCHESTRATOR):
    def handle_inbound_message(self, inbound_message: InboundMessage) -> None:
        snapshot = self._resolve_workspace_runtime(inbound_message)
        self._set_workspace_runtime_context(snapshot)
        try:
            with self._workspace_shared_scope(snapshot):
                return _STEP26_BASE_ORCHESTRATOR.handle_inbound_message(self, inbound_message)
        finally:
            self._clear_workspace_runtime_context()


_STEP42_INTERNAL_REASON_PATTERNS = (
    'traceback', 'psycopg', 'programmingerror', 'operationalerror', 'integrityerror',
    'attributeerror', 'keyerror', 'typeerror', 'valueerror', 'nameerror', 'indexerror',
    'object has no attribute', 'nonetype', 'undefined', 'column ', 'table ', 'relation ',
    'select ', 'insert ', 'update ', 'delete ', 'syntax error', 'cursor', 'database',
    'connection', 'rollback', 'commit', 'json', 'sql', 'http_error', 'dns_resolution_failed',
)


def _step42_contains_cjk(text: str) -> bool:
    return any('\u4e00' <= ch <= '\u9fff' for ch in str(text or ''))


def _step42_reason_is_safe_for_admin(reason: Any) -> bool:
    if reason is None:
        return False
    text = str(reason or '').strip()
    if not text:
        return False
    lowered = text.lower()
    if any(pat in lowered for pat in _STEP42_INTERNAL_REASON_PATTERNS):
        return False
    if len(text) > 120:
        return False
    if _step42_contains_cjk(text):
        return True
    if re.fullmatch(r'[a-z0-9_:-]{1,48}', lowered):
        return True
    return False


def _step42_sanitize_admin_result(result: Any, method_name: str) -> Any:
    if not isinstance(result, dict):
        return result
    if result.get('ok', True) is not False:
        return result
    if 'reason' not in result:
        return result
    reason = result.get('reason')
    if _step42_reason_is_safe_for_admin(reason):
        return result
    logger.warning(
        'Step42 sanitized admin error reason | method=%s | original_reason=%r',
        method_name,
        str(reason or '')[:240],
    )
    patched = dict(result)
    patched['reason'] = '操作失败，请检查系统日志'
    return patched


_STEP42_BASE_ADMIN_API_SERVICE = AdminAPIService
class AdminAPIService(_STEP42_BASE_ADMIN_API_SERVICE):
    pass


def _step42_wrap_admin_method(method_name: str) -> None:
    original = getattr(_STEP42_BASE_ADMIN_API_SERVICE, method_name, None)
    if original is None or not callable(original):
        return

    def _wrapped(self, *args, **kwargs):
        return _step42_sanitize_admin_result(original(self, *args, **kwargs), method_name)

    setattr(AdminAPIService, method_name, _wrapped)


for _step42_method_name in (
    'create_project', 'create_project_script', 'create_project_material',
    'create_persona_material', 'create_daily_material', 'create_voice_template',
    'create_training_item_admin', 'update_training_item_admin', 'update_training_config_admin',
    'update_project', 'archive_project', 'update_marketing_entry', 'archive_marketing_entry',
    'update_persona_material_admin', 'update_daily_material_admin', 'update_project_material_admin',
    'update_voice_template_admin', 'update_material_priority', 'archive_material_admin',
    'create_marketing_entry', 'update_marketing_entry_priority', 'update_project_script',
    'update_project_material', 'delete_training_item_admin', 'bind_business_account_to_workspace_admin',
    'set_workspace_primary_binding_admin', 'toggle_workspace_binding_admin', 'update_workspace_limit_admin',
    'update_workspace_binding_ai_admin', 'update_workspace_binding_followup_admin'
):
    _step42_wrap_admin_method(_step42_method_name)

del _step42_method_name


_STEP42_BASE_BUILD_APP_COMPONENTS = build_app_components

def build_app_components(settings: Settings) -> dict[str, Any]:
    app_components = _STEP42_BASE_BUILD_APP_COMPONENTS(settings)
    workspace_repository = app_components.get('workspace_repository')
    workspace_binding_repository = app_components.get('workspace_binding_repository')
    media_understanding_service = app_components.get('media_understanding_service')
    business_account_repo = app_components.get('business_account_repo')

    orchestrator = app_components.get('orchestrator')
    if orchestrator is not None and not isinstance(orchestrator, Orchestrator):
        app_components['orchestrator'] = _step41_rehydrate_instance(
            orchestrator,
            Orchestrator,
            inject_attrs={
                'workspace_repository': workspace_repository,
                'workspace_binding_repository': workspace_binding_repository,
                'media_understanding_service': media_understanding_service,
                'business_account_repo': business_account_repo,
            },
            label='step42.orchestrator',
        )

    admin_api_service = app_components.get('admin_api_service')
    if admin_api_service is not None and not isinstance(admin_api_service, AdminAPIService):
        app_components['admin_api_service'] = _step41_rehydrate_instance(
            admin_api_service,
            AdminAPIService,
            inject_attrs={
                'workspace_repository': workspace_repository,
                'workspace_binding_repository': workspace_binding_repository,
                'business_account_repo': business_account_repo,
            },
            label='step42.admin_api_service',
        )

    _step41_rewire_runtime_graph(app_components)

    issues = _step41_runtime_graph_issues(app_components)
    if issues:
        raise RuntimeError('Step42 runtime graph validation failed: ' + '; '.join(issues))

    app_components['stability_step42_medium_low_cleanup_enabled'] = True
    app_components['stability_step42_no_workspace_runtime_in_raw_payload'] = True
    app_components['stability_step42_admin_reason_sanitized'] = True
    return app_components


def create_production_app() -> Flask:
    settings = Settings.load()
    settings.validate()
    setup_logging(settings.log_level)
    logger.info('Starting production app factory.')
    app_components = initialize_runtime(settings)
    flask_app = create_web_app(settings, app_components)
    logger.info('Step41 production app factory initialized. Use a non-threaded worker model for deployment stability.')
    return flask_app


def main() -> None:
    settings = Settings.load()
    settings.validate()
    setup_logging(settings.log_level)
    logger.info('Starting application.')
    app_components = initialize_runtime(settings)
    flask_app = create_web_app(settings, app_components)
    logger.info('Application initialized successfully | host=%s | port=%s', settings.webhook_host, settings.webhook_port)
    flask_app.run(host=settings.webhook_host, port=settings.webhook_port, threaded=False)


