def _step43_training_center_list_training_items(self, business_account_id: int, training_category: str | None = None,
                                                search: str | None = None, include_inactive: bool = True,
                                                include_deleted: bool = False, limit: int = 50,
                                                include_disabled: bool | None = None, **kwargs) -> list[dict[str, Any]]:
    effective_id = None
    try:
        effective_id = self._workspace_effective_id(business_account_id)
    except Exception:
        effective_id = None
    target_business_account_id = int(effective_id or business_account_id)

    if include_disabled is not None:
        include_inactive = bool(include_disabled)

    query = ['SELECT * FROM training_items WHERE business_account_id=%s']
    params: list[Any] = [target_business_account_id]
    if not include_deleted:
        query.append('AND is_deleted=FALSE')
    if training_category and training_category != 'all':
        query.append('AND training_category=%s')
        params.append(training_category)
    if not include_inactive:
        query.append('AND is_enabled=TRUE')
    if search:
        pattern = f"%{str(search).strip()}%"
        query.append("AND (title ILIKE %s OR COALESCE(scene_text,'') ILIKE %s OR COALESCE(user_input_example,'') ILIKE %s)")
        params.extend([pattern, pattern, pattern])
    query.append('ORDER BY is_enabled DESC, priority DESC, updated_at DESC, id DESC LIMIT %s')
    params.append(max(1, min(int(limit or 50), 200)))

    with self.db.cursor() as cur:
        cur.execute(' '.join(query), tuple(params))
        rows = cur.fetchall() or []

    result = []
    for row in rows:
        item = dict(row)
        try:
            item['tags'] = self.list_training_item_tags(int(item.get('id') or 0))
        except Exception:
            item['tags'] = []
        result.append(item)
    return result


def _step43_training_center_search_training_items(self, business_account_id: int, keyword: str,
                                                  training_category: str | None = None, limit: int = 50) -> list[dict[str, Any]]:
    return self.list_training_items(
        business_account_id,
        training_category=training_category,
        search=keyword,
        include_inactive=True,
        include_deleted=False,
        limit=limit,
    )


def _step43_user_update_project_state(self, business_account_id: int, user_id: int, project_id: int | None, reason: str,
                                      candidate_projects: list[dict[str, Any]] | None = None,
                                      confidence: float | None = None,
                                      source: str = "system",
                                      status: str = "classified",
                                      updated_by: str = "system",
                                      lock_state: bool = False,
                                      **kwargs) -> dict[str, Any]:
    effective_id = None
    try:
        effective_id = self._workspace_effective_id(business_account_id)
    except Exception:
        effective_id = None
    target_business_account_id = int(effective_id or business_account_id)

    final_source = 'manual' if lock_state and source == 'system' else source
    final_updated_by = kwargs.get('updated_by') or updated_by or 'system'
    final_status = kwargs.get('status') or status or 'classified'

    return _BaseUserRepository.update_project_state(
        self,
        target_business_account_id,
        user_id,
        project_id,
        reason,
        candidate_projects=candidate_projects,
        confidence=confidence,
        source=final_source,
        status=final_status,
        updated_by=final_updated_by,
    )


