# ===== Step49 one-shot convergence from step42 baseline =====
# Goal:
# - keep step42/43/44 feature surface intact
# - load all runtime compatibility patches before boot
# - harden request-local runtime state for non-workspace attrs
# - tighten webhook validation before DB connect
# - expose a single final boot entry at file end

_STEP49_RUNTIME_TRAINING_PACKET: contextvars.ContextVar[Any | None] = contextvars.ContextVar(
    'step49_runtime_training_packet', default=None
)
_STEP49_RUNTIME_PROFILE_SNAPSHOT: contextvars.ContextVar[Any | None] = contextvars.ContextVar(
    'step49_runtime_profile_snapshot', default=None
)
_STEP49_RUNTIME_REPLY_LANGUAGE: contextvars.ContextVar[Any | None] = contextvars.ContextVar(
    'step49_runtime_reply_language', default=None
)
_STEP49_RUNTIME_CURRENT_STAGE: contextvars.ContextVar[Any | None] = contextvars.ContextVar(
    'step49_runtime_current_stage', default=None
)


class _Step49RequestLocalProxyMixin:
    _step49_runtime_proxy_map: dict[str, contextvars.ContextVar[Any | None]] = {}

    def __getattribute__(self, name: str):
        if name != '_step49_runtime_proxy_map':
            proxy_map = getattr(type(self), '_step49_runtime_proxy_map', {})
            if name in proxy_map:
                return proxy_map[name].get()
        return super().__getattribute__(name)

    def __setattr__(self, name: str, value: Any) -> None:
        proxy_map = getattr(type(self), '_step49_runtime_proxy_map', {})
        if name in proxy_map:
            proxy_map[name].set(value)
            return
        super().__setattr__(name, value)


_STEP49_BASE_USER_UNDERSTANDING_ENGINE = UserUnderstandingEngine
class UserUnderstandingEngine(_Step49RequestLocalProxyMixin, _STEP49_BASE_USER_UNDERSTANDING_ENGINE):
    _step49_runtime_proxy_map = {
        '_runtime_training_packet': _STEP49_RUNTIME_TRAINING_PACKET,
        '_runtime_current_stage': _STEP49_RUNTIME_CURRENT_STAGE,
    }


_STEP49_BASE_REPLY_PLANNER = ReplyPlanner
class ReplyPlanner(_Step49RequestLocalProxyMixin, _STEP49_BASE_REPLY_PLANNER):
    _step49_runtime_proxy_map = {
        '_runtime_training_packet': _STEP49_RUNTIME_TRAINING_PACKET,
        '_runtime_profile_snapshot': _STEP49_RUNTIME_PROFILE_SNAPSHOT,
    }


_STEP49_BASE_REPLY_STYLE_ENGINE = ReplyStyleEngine
class ReplyStyleEngine(_Step49RequestLocalProxyMixin, _STEP49_BASE_REPLY_STYLE_ENGINE):
    _step49_runtime_proxy_map = {
        '_runtime_profile_snapshot': _STEP49_RUNTIME_PROFILE_SNAPSHOT,
        '_runtime_reply_language': _STEP49_RUNTIME_REPLY_LANGUAGE,
    }


_STEP49_BASE_REPLY_SELF_CHECK_ENGINE = ReplySelfCheckEngine
class ReplySelfCheckEngine(_Step49RequestLocalProxyMixin, _STEP49_BASE_REPLY_SELF_CHECK_ENGINE):
    _step49_runtime_proxy_map = {
        '_runtime_profile_snapshot': _STEP49_RUNTIME_PROFILE_SNAPSHOT,
        '_runtime_reply_language': _STEP49_RUNTIME_REPLY_LANGUAGE,
    }


@contextmanager
def _step49_workspace_runtime_payload_guard(inbound_message: InboundMessage):
    raw_payload = getattr(inbound_message, 'raw_payload', None)
    if isinstance(raw_payload, dict):
        raw_payload.pop('workspace_runtime', None)
    try:
        yield
    finally:
        raw_payload = getattr(inbound_message, 'raw_payload', None)
        if isinstance(raw_payload, dict):
            raw_payload.pop('workspace_runtime', None)


def _step49_clear_request_local_runtime() -> None:
    _STEP49_RUNTIME_TRAINING_PACKET.set(None)
    _STEP49_RUNTIME_PROFILE_SNAPSHOT.set(None)
    _STEP49_RUNTIME_REPLY_LANGUAGE.set(None)
    _STEP49_RUNTIME_CURRENT_STAGE.set(None)


_STEP49_BASE_ORCHESTRATOR = Orchestrator
class Orchestrator(_STEP49_BASE_ORCHESTRATOR):
    def handle_inbound_message(self, inbound_message: InboundMessage) -> None:
        _step49_clear_request_local_runtime()
        snapshot = self._resolve_workspace_runtime(inbound_message)
        self._set_workspace_runtime_context(snapshot)
        try:
            with _step49_workspace_runtime_payload_guard(inbound_message):
                with self._workspace_shared_scope(snapshot):
                    return _STEP26_BASE_ORCHESTRATOR.handle_inbound_message(self, inbound_message)
        except Exception:
            logger.exception(
                'Step49 inbound handling failed | tg_business_account_id=%s | tg_user_id=%s | workspace_id=%s | effective_business_account_id=%s',
                getattr(inbound_message, 'tg_business_account_id', None),
                getattr(inbound_message, 'tg_user_id', None),
                snapshot.get('workspace_id') if isinstance(snapshot, dict) else None,
                snapshot.get('effective_business_account_id') if isinstance(snapshot, dict) else None,
            )
            raise
        finally:
            _step49_clear_request_local_runtime()
            self._clear_workspace_runtime_context()


def _step49_upgrade_orchestrator_runtime(orchestrator: Any) -> Any:
    if orchestrator is None:
        return None
    if not isinstance(orchestrator, Orchestrator):
        orchestrator = _step41_rehydrate_instance(orchestrator, Orchestrator, label='step49.orchestrator')
    for attr_name, cls in (
        ('understanding_engine', UserUnderstandingEngine),
        ('reply_planner', ReplyPlanner),
        ('reply_style_engine', ReplyStyleEngine),
        ('reply_self_check_engine', ReplySelfCheckEngine),
    ):
        target = getattr(orchestrator, attr_name, None)
        if target is not None and not isinstance(target, cls):
            setattr(
                orchestrator,
                attr_name,
                _step41_rehydrate_instance(target, cls, label=f'step49.{attr_name}')
            )
    if getattr(orchestrator, 'reply_style_engine', None) is not None:
        try:
            orchestrator.reply_style_engine.reply_planner = getattr(orchestrator, 'reply_planner', None)
        except Exception:
            logger.exception('Step49 failed to rebind reply_style_engine.reply_planner')
            raise
    if getattr(orchestrator, 'reply_self_check_engine', None) is not None:
        try:
            orchestrator.reply_self_check_engine.reply_planner = getattr(orchestrator, 'reply_planner', None)
        except Exception:
            logger.exception('Step49 failed to rebind reply_self_check_engine.reply_planner')
            raise
    return orchestrator


_STEP49_BASE_BUILD_APP_COMPONENTS = build_app_components

def build_app_components(settings: Settings) -> dict[str, Any]:
    app_components = _STEP49_BASE_BUILD_APP_COMPONENTS(settings)
    orchestrator = _step49_upgrade_orchestrator_runtime(app_components.get('orchestrator'))
    if orchestrator is not None:
        app_components['orchestrator'] = orchestrator
    _step41_rewire_runtime_graph(app_components)
    gateway = app_components.get('gateway')
    if gateway is not None and orchestrator is not None:
        gateway.message_handler = orchestrator.handle_inbound_message
    issues = _step41_runtime_graph_issues(app_components)
    if issues:
        raise RuntimeError('Step49 runtime graph validation failed: ' + '; '.join(issues))
    app_components['stability_step49_one_shot_converged'] = True
    app_components['stability_step49_request_local_training_profile_language_stage'] = True
    app_components['stability_step49_all_tail_patches_loaded_pre_boot'] = True
    return app_components


_STEP49_BASE_CREATE_WEB_APP = create_web_app

def create_web_app(settings: Settings, app_components: dict[str, Any]) -> Flask:
    flask_app = _STEP49_BASE_CREATE_WEB_APP(settings, app_components)
    max_payload_bytes = int(os.getenv('TELEGRAM_WEBHOOK_MAX_BYTES', '262144') or '262144')
    flask_app.config['MAX_CONTENT_LENGTH'] = max_payload_bytes
    known_update_keys = {
        'message', 'edited_message', 'channel_post', 'edited_channel_post', 'business_connection',
        'business_message', 'edited_business_message', 'deleted_business_messages', 'message_reaction',
        'message_reaction_count', 'inline_query', 'chosen_inline_result', 'callback_query', 'shipping_query',
        'pre_checkout_query', 'poll', 'poll_answer', 'my_chat_member', 'chat_member', 'chat_join_request'
    }

    def _step49_validate_telegram_webhook_request():
        if request.method != 'POST' or request.path != '/webhook/telegram':
            return None
        if not request.is_json:
            logger.warning('Step49 rejected non-json telegram webhook request | mimetype=%s', request.mimetype)
            return jsonify({'ok': False, 'error': 'invalid_content_type'}), 415
        content_length = request.content_length
        if content_length is not None and int(content_length) > max_payload_bytes:
            logger.warning(
                'Step49 rejected oversized telegram webhook payload via content-length | bytes=%s | limit=%s',
                content_length,
                max_payload_bytes,
            )
            return jsonify({'ok': False, 'error': 'payload_too_large'}), 413
        raw_body = request.get_data(cache=True, as_text=False)
        if len(raw_body) > max_payload_bytes:
            logger.warning(
                'Step49 rejected oversized telegram webhook payload via raw-body | bytes=%s | limit=%s',
                len(raw_body),
                max_payload_bytes,
            )
            return jsonify({'ok': False, 'error': 'payload_too_large'}), 413
        try:
            payload = request.get_json(force=False, silent=False)
        except Exception:
            logger.warning('Step49 rejected invalid json telegram webhook request')
            return jsonify({'ok': False, 'error': 'invalid_json'}), 400
        if not isinstance(payload, dict):
            return jsonify({'ok': False, 'error': 'invalid_update_schema'}), 400
        if payload.get('update_id') is not None and not isinstance(payload.get('update_id'), int):
            return jsonify({'ok': False, 'error': 'invalid_update_id'}), 400
        if not any(key in payload for key in known_update_keys):
            return jsonify({'ok': False, 'error': 'unknown_update_shape'}), 400
        return None

    before_request_funcs = flask_app.before_request_funcs.setdefault(None, [])
    before_request_funcs.insert(0, _step49_validate_telegram_webhook_request)
    return flask_app


def create_production_app() -> Flask:
    settings = Settings.load()
    settings.validate()
    setup_logging(settings.log_level)
    logger.info('Starting production app factory.')
    app_components = initialize_runtime(settings)
    flask_app = create_web_app(settings, app_components)
    logger.info('Step49 production app factory initialized. One-shot convergence is loaded before app bootstrap.')
    return flask_app



def main() -> None:
    settings = Settings.load()
    settings.validate()
    setup_logging(settings.log_level)
    logger.info('Starting application.')
    app_components = initialize_runtime(settings)
    flask_app = create_web_app(settings, app_components)
    logger.info('Application initialized successfully | host=%s | port=%s', settings.webhook_host, settings.webhook_port)
    flask_app.run(host=settings.webhook_host, port=settings.webhook_port, threaded=False)


if False and _STEP49_SHOULD_RUN_MAIN:
    main()


# =========================
# Step50 - single-path runtime convergence
# - instantiate final active graph directly
# - avoid historical builder chain and runtime rehydrate on boot
# - keep tail patches loaded before startup
# =========================

_STEP50_SHOULD_RUN_MAIN = (__name__ == '__main__')


def _step50_link_runtime_components(app_components: dict[str, Any]) -> None:
    orchestrator = app_components['orchestrator']
    gateway = app_components['gateway']
    admin_api_service = app_components['admin_api_service']
    tg_admin_callback_router = app_components['tg_admin_callback_router']
    tg_admin_handlers = app_components['tg_admin_handlers']

    workspace_repository = app_components['workspace_repository']
    workspace_binding_repository = app_components['workspace_binding_repository']
    media_understanding_service = app_components['media_understanding_service']
