def create_web_app(settings: Settings, app_components: dict[str, Any]) -> Flask:
    flask_app = Flask(__name__)
    admin_api_service = app_components['admin_api_service']
    dashboard_service = app_components['dashboard_service']
    gateway = app_components['gateway']
    tg_admin_handlers = app_components['tg_admin_handlers']
    tg_client = app_components['tg_client']
    event_lock_repo: WebhookEventLockRepository = app_components['event_lock_repo']
    business_account_repo: BusinessAccountRepository = app_components['business_account_repo']
    db: Database = app_components['db']

    flask_app.config['MAX_CONTENT_LENGTH'] = int(os.getenv('TELEGRAM_WEBHOOK_MAX_BYTES', '262144') or '262144')
    known_update_keys = {
        'message', 'edited_message', 'channel_post', 'edited_channel_post', 'business_connection',
        'business_message', 'edited_business_message', 'deleted_business_messages', 'message_reaction',
        'message_reaction_count', 'inline_query', 'chosen_inline_result', 'callback_query', 'shipping_query',
        'pre_checkout_query', 'poll', 'poll_answer', 'my_chat_member', 'chat_member', 'chat_join_request'
    }

    flask_app.register_blueprint(build_admin_blueprint(admin_api_service, dashboard_service))

    @flask_app.before_request
    def _step50_validate_telegram_webhook_request():
        if request.method != 'POST' or request.path != '/webhook/telegram':
            return None
        max_payload_bytes = int(flask_app.config.get('MAX_CONTENT_LENGTH') or 262144)
        if not request.is_json:
            logger.warning('Step50 rejected non-json telegram webhook request | mimetype=%s', request.mimetype)
            return jsonify({'ok': False, 'error': 'invalid_content_type'}), 415
        content_length = request.content_length
        if content_length is not None and int(content_length) > max_payload_bytes:
            logger.warning(
                'Step50 rejected oversized telegram webhook payload via content-length | bytes=%s | limit=%s',
                content_length,
                max_payload_bytes,
            )
            return jsonify({'ok': False, 'error': 'payload_too_large'}), 413
        raw_body = request.get_data(cache=True, as_text=False)
        if len(raw_body) > max_payload_bytes:
            logger.warning(
                'Step50 rejected oversized telegram webhook payload via raw-body | bytes=%s | limit=%s',
                len(raw_body),
                max_payload_bytes,
            )
            return jsonify({'ok': False, 'error': 'payload_too_large'}), 413
        try:
            payload = request.get_json(force=False, silent=False)
        except Exception:
            logger.warning('Step50 rejected invalid json telegram webhook request')
            return jsonify({'ok': False, 'error': 'invalid_json'}), 400
        if not isinstance(payload, dict):
            return jsonify({'ok': False, 'error': 'invalid_update_schema'}), 400
        update_id = payload.get('update_id')
        if update_id is not None and not isinstance(update_id, int):
            return jsonify({'ok': False, 'error': 'invalid_update_id'}), 400
        if not any(key in payload for key in known_update_keys):
            return jsonify({'ok': False, 'error': 'unknown_update_shape'}), 400
        return None

    @flask_app.before_request
    def _ensure_request_db_connection():
        try:
            db.connect()
        except Exception:
            logger.exception('Step50 failed to ensure database connection before request.')
            raise

    @flask_app.get('/health')
    def health():
        return jsonify({'ok': True, 'service': 'tg-business-ai-chat'})

    @flask_app.post('/webhook/telegram')
    def telegram_webhook():
        raw_update = request.get_json(silent=True) or {}
        update_id = raw_update.get('update_id')
        if settings.telegram_webhook_secret_token:
            header_token = request.headers.get('X-Telegram-Bot-Api-Secret-Token', '')
            if not hmac.compare_digest(header_token, settings.telegram_webhook_secret_token):
                return jsonify({'ok': False, 'error': 'invalid webhook secret'}), 403
        try:
            event = normalize_telegram_update(raw_update)
            if event and event.event_type in ('admin_callback', 'admin_text'):
                admin_chat_id = int(event.telegram_chat_id or 0)
                if not _is_admin_chat_allowed(settings, admin_chat_id):
                    return jsonify({'ok': False, 'error': 'admin not allowed'}), 403
                operator_id = _step39_extract_admin_operator_id(raw_update, event)
                operator_allowed, operator_reason = _is_admin_operator_allowed(settings, admin_chat_id, operator_id, raw_update)
                if not operator_allowed:
                    logger.warning(
                        'Step50 rejected admin operator | admin_chat_id=%s | operator_id=%s | reason=%s | admin_user_ids_configured=%s',
                        admin_chat_id,
                        operator_id,
                        operator_reason,
                        bool(getattr(settings, 'admin_user_ids', []) or []),
                    )
                    callback_id = (raw_update.get('callback_query') or {}).get('id')
                    if callback_id:
                        try:
                            tg_client.answer_callback_query(str(callback_id))
                        except Exception:
                            logger.exception('Step50 failed to answer rejected callback query | callback_id=%s', callback_id)
                    return jsonify({'ok': False, 'error': operator_reason or 'admin operator not allowed'}), 403
                operator = str(operator_id)
                event.idempotency_key = build_event_idempotency_key(event)
                account = business_account_repo.resolve_from_connection(event.business_connection_id)
                event.business_account_id = None if not account else int(account['id'])
                locked = event_lock_repo.acquire(
                    event.idempotency_key,
                    event.event_type,
                    event.business_account_id,
                    event.business_connection_id,
                    event.telegram_chat_id,
                    event.telegram_user_id,
                    event.telegram_message_id,
                    event.telegram_update_id,
                    event.is_edited,
                )
                if not locked:
                    event_lock_repo.record_duplicate_skip(event.idempotency_key)
                    if event.event_type == 'admin_callback' and raw_update.get('callback_query', {}).get('id'):
                        tg_client.answer_callback_query(str(raw_update['callback_query']['id']))
                    return jsonify({'ok': True, 'dispatched': 'duplicate'})
                try:
                    if event.event_type == 'admin_callback':
                        tg_admin_handlers.handle_admin_callback(admin_chat_id=admin_chat_id, callback_data=event.callback_data or '', operator=operator)
                        callback_id = (raw_update.get('callback_query') or {}).get('id')
                        if callback_id:
                            tg_client.answer_callback_query(str(callback_id))
                        dispatched = event.event_type
                    else:
                        text = str(event.text or '')
                        if text.startswith('/admin') or text.startswith('/startadmin'):
                            tg_admin_handlers.handle_admin_command(admin_chat_id, text, operator=operator)
                            dispatched = 'admin_command'
                        else:
                            tg_admin_handlers.handle_admin_text(admin_chat_id, text, operator=operator)
                            dispatched = 'admin_text'
                    event_lock_repo.mark_processed(event.idempotency_key)
                    return jsonify({'ok': True, 'dispatched': dispatched})
                except Exception as admin_exc:
                    event_lock_repo.mark_failed(event.idempotency_key, str(admin_exc))
                    raise
            dispatched = gateway.handle_raw_update(raw_update)
            return jsonify({'ok': True, 'dispatched': dispatched})
        except Exception:
            try:
                db.rollback()
            except Exception:
                logger.exception('Step50 db rollback failed during telegram_webhook error handling | update_id=%s', update_id)
            logger.exception('telegram_webhook failed | update_id=%s', update_id)
            return jsonify({'ok': False, 'error': 'internal_server_error'}), 500

    return flask_app


def initialize_runtime(settings: Settings) -> dict[str, Any]:
    global _STEP11_RUNTIME_COMPONENTS
    with _STEP11_RUNTIME_LOCK:
        if _STEP11_RUNTIME_COMPONENTS is None:
            app_components = build_app_components(settings)
            outbound_sender_worker = app_components.get('outbound_sender_worker')
            if outbound_sender_worker is not None:
                outbound_sender_worker.start()
            _run_startup_preflight(app_components)
            _ensure_webhook_once(settings, app_components)
            _STEP11_RUNTIME_COMPONENTS = app_components
        return _STEP11_RUNTIME_COMPONENTS


def create_production_app() -> Flask:
    settings = Settings.load()
    settings.validate()
    setup_logging(settings.log_level)
    logger.info('Starting production app factory.')
    app_components = initialize_runtime(settings)
    flask_app = create_web_app(settings, app_components)
    logger.info('Step50 production app factory initialized with single-path runtime convergence.')
    return flask_app


def main() -> None:
    settings = Settings.load()
    settings.validate()
    setup_logging(settings.log_level)
    logger.info('Starting application.')
    app_components = initialize_runtime(settings)
    flask_app = create_web_app(settings, app_components)
    logger.info('Application initialized successfully | host=%s | port=%s', settings.webhook_host, settings.webhook_port)
    flask_app.run(host=settings.webhook_host, port=settings.webhook_port, threaded=False)


if False and _STEP50_SHOULD_RUN_MAIN:
    main()


# ===== Step51 precise inbound main-chain convergence =====
# Goal:
# - keep step50 single-path boot/builder/webhook structure
# - make the final inbound chain explicit and self-documented
# - request-localize workspace runtime attrs used on shared live objects
# - keep workspace sharing behavior while avoiding raw_payload runtime writes

_STEP51_RUNTIME_WORKSPACE_SNAPSHOT: contextvars.ContextVar[Any | None] = contextvars.ContextVar(
    'step51_runtime_workspace_snapshot', default=None
)
_STEP51_RUNTIME_WORKSPACE_ID: contextvars.ContextVar[Any | None] = contextvars.ContextVar(
    'step51_runtime_workspace_id', default=None
)
_STEP51_RUNTIME_SOURCE_BUSINESS_ACCOUNT_ID: contextvars.ContextVar[Any | None] = contextvars.ContextVar(
    'step51_runtime_source_business_account_id', default=None
)
_STEP51_RUNTIME_EFFECTIVE_BUSINESS_ACCOUNT_ID: contextvars.ContextVar[Any | None] = contextvars.ContextVar(
    'step51_runtime_effective_business_account_id', default=None
)
_STEP51_RUNTIME_SOURCE_BINDING_ID: contextvars.ContextVar[Any | None] = contextvars.ContextVar(
    'step51_runtime_source_binding_id', default=None
)


class _Step51RequestLocalProxyMixin:
    _step51_runtime_proxy_map: dict[str, contextvars.ContextVar[Any | None]] = {}

    def __getattribute__(self, name: str):
        if name != '_step51_runtime_proxy_map':
            proxy_map = getattr(type(self), '_step51_runtime_proxy_map', {})
            if name in proxy_map:
                return proxy_map[name].get()
        return super().__getattribute__(name)

    def __setattr__(self, name: str, value: Any) -> None:
        proxy_map = getattr(type(self), '_step51_runtime_proxy_map', {})
        if name in proxy_map:
            proxy_map[name].set(value)
            return
        super().__setattr__(name, value)


_STEP51_BASE_USER_UNDERSTANDING_ENGINE = UserUnderstandingEngine
class UserUnderstandingEngine(_Step51RequestLocalProxyMixin, _STEP51_BASE_USER_UNDERSTANDING_ENGINE):
    _step51_runtime_proxy_map = {
        '_runtime_workspace_snapshot': _STEP51_RUNTIME_WORKSPACE_SNAPSHOT,
    }


_STEP51_BASE_REPLY_PLANNER = ReplyPlanner
class ReplyPlanner(_Step51RequestLocalProxyMixin, _STEP51_BASE_REPLY_PLANNER):
    _step51_runtime_proxy_map = {
        '_runtime_workspace_snapshot': _STEP51_RUNTIME_WORKSPACE_SNAPSHOT,
    }


_STEP51_BASE_REPLY_STYLE_ENGINE = ReplyStyleEngine
class ReplyStyleEngine(_Step51RequestLocalProxyMixin, _STEP51_BASE_REPLY_STYLE_ENGINE):
    _step51_runtime_proxy_map = {
        '_runtime_workspace_snapshot': _STEP51_RUNTIME_WORKSPACE_SNAPSHOT,
    }


_STEP51_BASE_REPLY_SELF_CHECK_ENGINE = ReplySelfCheckEngine
class ReplySelfCheckEngine(_Step51RequestLocalProxyMixin, _STEP51_BASE_REPLY_SELF_CHECK_ENGINE):
    _step51_runtime_proxy_map = {
        '_runtime_workspace_snapshot': _STEP51_RUNTIME_WORKSPACE_SNAPSHOT,
    }


_STEP51_BASE_REPLY_DELAY_ENGINE = ReplyDelayEngine
class ReplyDelayEngine(_Step51RequestLocalProxyMixin, _STEP51_BASE_REPLY_DELAY_ENGINE):
    _step51_runtime_proxy_map = {
        '_runtime_workspace_snapshot': _STEP51_RUNTIME_WORKSPACE_SNAPSHOT,
    }


_STEP51_BASE_CONTENT_SELECTOR = ContentSelector
class ContentSelector(_Step51RequestLocalProxyMixin, _STEP51_BASE_CONTENT_SELECTOR):
    _step51_runtime_proxy_map = {
        '_runtime_workspace_snapshot': _STEP51_RUNTIME_WORKSPACE_SNAPSHOT,
    }


_STEP51_BASE_PROACTIVE_FOLLOWUP_ENGINE = ProactiveFollowupEngine
class ProactiveFollowupEngine(_Step51RequestLocalProxyMixin, _STEP51_BASE_PROACTIVE_FOLLOWUP_ENGINE):
    _step51_runtime_proxy_map = {
        '_runtime_workspace_snapshot': _STEP51_RUNTIME_WORKSPACE_SNAPSHOT,
    }


_STEP51_PRE_WORKSPACE_CORE_HANDLE = _STEP26_BASE_ORCHESTRATOR.handle_inbound_message


def _step51_clear_request_local_runtime() -> None:
    _step49_clear_request_local_runtime()
    _STEP51_RUNTIME_WORKSPACE_SNAPSHOT.set(None)
    _STEP51_RUNTIME_WORKSPACE_ID.set(None)
    _STEP51_RUNTIME_SOURCE_BUSINESS_ACCOUNT_ID.set(None)
    _STEP51_RUNTIME_EFFECTIVE_BUSINESS_ACCOUNT_ID.set(None)
    _STEP51_RUNTIME_SOURCE_BINDING_ID.set(None)


def _step51_handle_inbound_message_core(orchestrator: Any, inbound_message: InboundMessage) -> None:
    """
    Final inbound core = pre-step26 inbound chain.
    This is intentional: step26 only added workspace runtime wrapping plus the raw_payload
    workspace_runtime write that we do not want on the active path.
    """
    return _STEP51_PRE_WORKSPACE_CORE_HANDLE(orchestrator, inbound_message)


_STEP51_BASE_ORCHESTRATOR = Orchestrator
class Orchestrator(_Step51RequestLocalProxyMixin, _STEP51_BASE_ORCHESTRATOR):
    _step51_runtime_proxy_map = {
        '_runtime_workspace_snapshot': _STEP51_RUNTIME_WORKSPACE_SNAPSHOT,
        '_runtime_workspace_id': _STEP51_RUNTIME_WORKSPACE_ID,
        '_runtime_source_business_account_id': _STEP51_RUNTIME_SOURCE_BUSINESS_ACCOUNT_ID,
        '_runtime_effective_business_account_id': _STEP51_RUNTIME_EFFECTIVE_BUSINESS_ACCOUNT_ID,
        '_runtime_source_binding_id': _STEP51_RUNTIME_SOURCE_BINDING_ID,
    }

    def handle_inbound_message(self, inbound_message: InboundMessage) -> None:
        _step51_clear_request_local_runtime()
        snapshot = self._resolve_workspace_runtime(inbound_message)
        self._set_workspace_runtime_context(snapshot)
        try:
            with _step49_workspace_runtime_payload_guard(inbound_message):
                with self._workspace_shared_scope(snapshot):
                    return _step51_handle_inbound_message_core(self, inbound_message)
        except Exception:
            logger.exception(
                'Step51 inbound main-chain failed | tg_business_account_id=%s | tg_user_id=%s | workspace_id=%s | effective_business_account_id=%s',
                getattr(inbound_message, 'tg_business_account_id', None),
                getattr(inbound_message, 'tg_user_id', None),
                snapshot.get('workspace_id') if isinstance(snapshot, dict) else None,
                snapshot.get('effective_business_account_id') if isinstance(snapshot, dict) else None,
            )
            raise
        finally:
            _step51_clear_request_local_runtime()
            self._clear_workspace_runtime_context()


_STEP51_BASE_BUILD_APP_COMPONENTS = build_app_components

def build_app_components(settings: Settings) -> dict[str, Any]:
    app_components = _STEP51_BASE_BUILD_APP_COMPONENTS(settings)
    orchestrator = app_components.get('orchestrator')
    gateway = app_components.get('gateway')

    nested_specs = (
        ('understanding_engine', UserUnderstandingEngine),
        ('reply_planner', ReplyPlanner),
        ('reply_style_engine', ReplyStyleEngine),
        ('reply_self_check_engine', ReplySelfCheckEngine),
        ('reply_delay_engine', ReplyDelayEngine),
        ('content_selector', ContentSelector),
        ('proactive_followup_engine', ProactiveFollowupEngine),
    )

    if orchestrator is not None:
        if not isinstance(orchestrator, Orchestrator):
            orchestrator = _step39_fresh_runtime_component(
                app_components,
                'orchestrator',
                Orchestrator,
                'Step51Orchestrator',
                inject_attrs={
                    'workspace_repository': app_components.get('workspace_repository'),
                    'workspace_binding_repository': app_components.get('workspace_binding_repository'),
                },
            ) or app_components.get('orchestrator')

        for attr_name, expected_cls in nested_specs:
            if hasattr(orchestrator, attr_name):
                _step40_fresh_nested_component(orchestrator, attr_name, expected_cls)
                app_components[attr_name] = getattr(orchestrator, attr_name, None)

    if gateway is not None and orchestrator is not None:
        gateway.message_handler = orchestrator.handle_inbound_message

    app_components['orchestrator'] = orchestrator

    expected_types = (
        ('orchestrator', Orchestrator),
        ('understanding_engine', UserUnderstandingEngine),
        ('reply_planner', ReplyPlanner),
        ('reply_style_engine', ReplyStyleEngine),
        ('reply_self_check_engine', ReplySelfCheckEngine),
        ('reply_delay_engine', ReplyDelayEngine),
        ('content_selector', ContentSelector),
        ('proactive_followup_engine', ProactiveFollowupEngine),
    )

    issues: list[str] = []
    for name, expected_cls in expected_types:
        target = app_components.get(name)
        if target is None:
            issues.append(f'{name}:missing')
            continue
        if not isinstance(target, expected_cls):
            issues.append(f'{name}:{type(target).__name__}->{expected_cls.__name__}')

    if issues:
        raise RuntimeError('Step51 final runtime graph mismatch: ' + ', '.join(issues))

    return app_components


if _STEP50_SHOULD_RUN_MAIN:
    main()
